    ('./data/macro/function/api/cmd/clear.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\n# ─────────────────────────────────────────────────────────────────\n# SANDBOX GUARD — dangerous commands are blocked in sandbox mode.\n# Enable:  /data modify storage macro:engine sandbox set value 1b\n# Disable: /data modify storage macro:engine sandbox set value 0b\n# ─────────────────────────────────────────────────────────────────\nexecute if data storage macro:engine {sandbox:1b} run data modify storage macro:engine _sandbox_cmd set value "clear"\nexecute if data storage macro:engine {sandbox:1b} run function macro:api/cmd/internal/sandbox_blocked\nexecute if data storage macro:engine {sandbox:1b} run return 0\nexecute unless data storage macro:engine {sandbox:1b} run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"TIP ","color":"yellow","bold":true},{"text":"Sandbox mode recommended → ","color":"gray"},{"text":"/data modify storage macro:engine sandbox set value 1b","color":"aqua"}]\n$execute as @a[name=$(player),limit=1] at @s run clear @s\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/clear ","color":"aqua"},{"text":"$(player)","color":"white"}]\n'),
    ('./data/macro/function/api/cmd/clear_item.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\n$execute as @a[name=$(player),limit=1] at @s run clear @s $(item) $(count)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/clear_item ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(item)","color":"aqua"}]\n'),
    ('./data/macro/function/api/cmd/clone.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\n# ─────────────────────────────────────────────────────────────────\n# SANDBOX GUARD — dangerous commands are blocked in sandbox mode.\n# Enable:  /data modify storage macro:engine sandbox set value 1b\n# Disable: /data modify storage macro:engine sandbox set value 0b\n# ─────────────────────────────────────────────────────────────────\nexecute if data storage macro:engine {sandbox:1b} run data modify storage macro:engine _sandbox_cmd set value "clone"\nexecute if data storage macro:engine {sandbox:1b} run function macro:api/cmd/internal/sandbox_blocked\nexecute if data storage macro:engine {sandbox:1b} run return 0\n\n$clone $(x1) $(y1) $(z1) $(x2) $(y2) $(z2) $(dx) $(dy) $(dz)\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/clone ","color":"aqua"}]\n'),
    ('./data/macro/function/api/cmd/clone_masked.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\n# ─────────────────────────────────────────────────────────────────\n# SANDBOX GUARD — dangerous commands are blocked in sandbox mode.\n# Enable:  /data modify storage macro:engine sandbox set value 1b\n# Disable: /data modify storage macro:engine sandbox set value 0b\n# ─────────────────────────────────────────────────────────────────\nexecute if data storage macro:engine {sandbox:1b} run data modify storage macro:engine _sandbox_cmd set value "clone_masked"\nexecute if data storage macro:engine {sandbox:1b} run function macro:api/cmd/internal/sandbox_blocked\nexecute if data storage macro:engine {sandbox:1b} run return 0\n\n$clone $(x1) $(y1) $(z1) $(x2) $(y2) $(z2) $(dx) $(dy) $(dz) masked\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/clone_masked ","color":"aqua"}]\n'),
    ('./data/macro/function/api/cmd/console_me.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/console_me  [REMOVED]\n#\n# The /me command produces shell-script-like execution behavior,\n# and intent detection is not reliably possible, so this function has been removed.\n# See: SECURITY.md — "Intent Detection" section.\n#\n# Alternative: macro:systems/log/info or macro:api/cmd/msg\n# ─────────────────────────────────────────────────────────────────\nreturn 0\n'),
    ('./data/macro/function/api/cmd/console_say.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/console_say  [REMOVED]\n#\n# /say sends a server-level message to all players;\n# it produces shell-script-like execution behavior and intent\n# detection is not reliably possible, so this function has been removed.\n# See: SECURITY.md — "Intent Detection" section.\n#\n# Alternative: macro:systems/string/announce\n# ─────────────────────────────────────────────────────────────────\nreturn 0\n'),
