    ('./data/macro/function/api/cmd/internal/sandbox_blocked.mcfunction', '# macro:api/cmd/internal/sandbox_blocked\n# Called by cmd/ files when macro:engine {sandbox:1b} is set.\n# Reads macro:engine _sandbox_cmd (set by the caller before this call).\n# Passes the entire macro:engine storage as macro input so that\n# sandbox_blocked_macro can read $(_sandbox_cmd) directly.\nfunction macro:api/cmd/internal/sandbox_blocked_macro with storage macro:engine {}\n'),
    ('./data/macro/function/api/cmd/internal/sandbox_blocked_macro.mcfunction', '# macro:api/cmd/internal/sandbox_blocked_macro [MACRO]\n# INPUT: $(_sandbox_cmd) — read from macro:engine storage via `with storage macro:engine {}`\n# Appends a WARN entry to the log buffer and notifies debug admins.\n# Do NOT call directly — use macro:api/cmd/internal/sandbox_blocked.\n$data modify storage macro:input message set value "[SANDBOX] cmd/$(_sandbox_cmd) blocked"\ndata modify storage macro:input level set value "WARN"\ndata modify storage macro:input color set value "yellow"\nexecute if score #ame.log_level ame.log_level matches 2.. run function macro:systems/log/add with storage macro:input {}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"SANDBOX ","color":"red","bold":true},{"text":"cmd/$(_sandbox_cmd) blocked","color":"red"}]\ndata remove storage macro:input message\ndata remove storage macro:input level\ndata remove storage macro:input color\n'),
    ('./data/macro/function/api/cmd/other/action_run.mcfunction', '$execute as @a[name=$(player),limit=1] at @s run function macro:api/cmd/$(type) $(arguments)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/other/action_run ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(type)","color":"aqua"}]\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd.mcfunction', 'execute unless entity @s[tag=macro.admin] run return 0\n\n$data modify storage macro:engine _mcmd_queue set value $(commands)\ndata modify storage macro:engine _mcmd_options set value {error_mode:"continue",profile:0b,spread:0}\n\nexecute at @s run function macro:api/cmd/other/multi_cmd/run\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/other/multi_cmd ","color":"aqua"},{"text":"▶ executing batch","color":"#555555"}]'),
    ('./data/macro/function/api/cmd/other/multi_cmd_adv.mcfunction', '$data merge storage macro:input {list:$(list),options:$(options)}\n\nfunction macro:api/cmd/other/multi_cmd/advanced/run_with_options'),
