    ('./data/macro/function/api/cmd/other/storage_reset.mcfunction', '$data modify storage $(storageName) $(nbt) set value []\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/other/storage_reset ","color":"aqua"},{"text":"$(storageName)","color":"white"},{"text":".","color":"#555555"},{"text":"$(nbt)","color":"aqua"},{"text":" → []","color":"#555555"}]\n'),
    ('./data/macro/function/api/cmd/other/storage_set.mcfunction', '$execute at @s run data modify storage $(storageName) $(nbt) set $(actionType) $(value)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/other/storage_set ","color":"aqua"},{"text":"$(storageName)","color":"white"},{"text":".","color":"#555555"},{"text":"$(nbt)","color":"aqua"},{"text":" ← ","color":"#555555"},{"text":"$(value)","color":"green"}]\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/from_input.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/from_input\n# Execute a simple command list (backward compatible)\n#\n# INPUT (storage macro:input):\n# list → command list ["cmd1", "cmd2", ...]\n#\n# EXAMPLE:\n# data modify storage macro:input list set value ["say Hello", "say World"]\n# function macro:api/cmd/other/multi_cmd/from_input\n# ─────────────────────────────────────────────────────────────────\n\n# Copy list to queue\ndata modify storage macro:engine _mcmd_queue set from storage macro:input list\n\n# Set default options\ndata modify storage macro:engine _mcmd_options set value {error_mode:"continue",profile:0b,spread:0}\n\n# Execute\nfunction macro:api/cmd/other/multi_cmd/run\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/from_input ","color":"aqua"},{"text":"▶ list → run","color":"#555555"}]\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/from_input_as.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/from_input_as\n# Execute as a specific selector\n#\n# INPUT (storage macro:input):\n# list → komut listesi\n# selector → entity selector (default: @s)\n# ─────────────────────────────────────────────────────────────────\n\nexecute unless data storage macro:input selector run data modify storage macro:input selector set value "@s"\n\ndata modify storage macro:engine _mcmd_queue set from storage macro:input list\ndata modify storage macro:engine _mcmd_options set value {error_mode:"continue",profile:0b,spread:0}\n\nfunction macro:api/cmd/other/multi_cmd/internal/run_as_exec with storage macro:input\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/run.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/run\n# Execute queued commands\n# ─────────────────────────────────────────────────────────────────\n\n# Reset statistics\nexecute if data storage macro:engine _mcmd_options{profile:1b} run data modify storage macro:engine _mcmd_stats set value {total:0,success:0,failed:0,start_time:0}\nexecute if data storage macro:engine _mcmd_options{profile:1b} run execute store result storage macro:engine _mcmd_stats.start_time int 1 run time query gametime\n\n# Start recursive stepping\nfunction macro:api/cmd/other/multi_cmd/internal/step\n\n# Cleanup\nfunction macro:api/cmd/other/multi_cmd/internal/cleanup\n\n# Show statistics\nexecute if data storage macro:engine _mcmd_options{profile:1b} run function macro:api/cmd/other/multi_cmd/internal/show_stats\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/run ","color":"aqua"},{"text":"✔ batch done","color":"green"}]\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/run_as.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/run_as\n# Run queue as a specific entity\n#\n# INPUT (storage macro:input):\n# selector → entity selector\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:api/cmd/other/multi_cmd/internal/run_as_exec with storage macro:input\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/run_at.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/run_at\n# Run queue at a specific location\n#\n# INPUT (storage macro:input):\n# selector → entity selector\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:api/cmd/other/multi_cmd/internal/run_at_exec with storage macro:input\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/run_func.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/run_func\n# Run function list\n#\n# INPUT (storage macro:input):\n# list → function list ["pack:func1", "pack:func2"]\n# ─────────────────────────────────────────────────────────────────\n\n# Convert strings to {func:"..."} format\ndata modify storage macro:engine _mcmd_queue set value []\nfunction macro:api/cmd/other/multi_cmd/internal/func_convert_loop\n\ndata modify storage macro:engine _mcmd_options set value {error_mode:"continue",profile:0b,spread:0}\nfunction macro:api/cmd/other/multi_cmd/run\n\ndata remove storage macro:engine _mcmd_func_tmp\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/advanced/run_with_options.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/advanced/run_with_options\n# Run with advanced options\n#\n# INPUT (storage macro:input):\n# list → command list (string or object)\n# options → {priority_sort:1b, spread_ticks:0, error_mode:"continue", profile:1b}\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:engine _mcmd_queue set from storage macro:input list\nexecute unless data storage macro:input options run data modify storage macro:input options set value {}\ndata modify storage macro:engine _mcmd_options merge from storage macro:input options\n\nexecute unless data storage macro:engine _mcmd_options.error_mode run data modify storage macro:engine _mcmd_options.error_mode set value "continue"\nexecute unless data storage macro:engine _mcmd_options.profile run data modify storage macro:engine _mcmd_options.profile set value 0b\nexecute unless data storage macro:engine _mcmd_options.spread_ticks run data modify storage macro:engine _mcmd_options.spread_ticks set value 0\n\nexecute if data storage macro:engine _mcmd_options{priority_sort:1b} run function macro:api/cmd/other/multi_cmd/advanced/internal/sort_by_priority\nexecute if data storage macro:engine _mcmd_options.spread_ticks unless data storage macro:engine _mcmd_options{spread_ticks:0} run return run function macro:api/cmd/other/multi_cmd/advanced/internal/run_spread\n\nfunction macro:api/cmd/other/multi_cmd/run\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/advanced ","color":"aqua"},{"text":"✔ with options","color":"green"}]\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/advanced/internal/run_spread.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/advanced/internal/run_spread\n# Spreads _mcmd_queue execution: one item per tick.\n# Schedules run_spread_tick which self-reschedules until queue is drained.\n# Supports full item format (conditions, hooks, cmd, func).\n# ─────────────────────────────────────────────────────────────────\n\nexecute if data storage macro:engine _mcmd_queue[0] run schedule function macro:api/cmd/other/multi_cmd/advanced/internal/run_spread_tick 1t append\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/run_spread ","color":"aqua"},{"text":"↷ spread scheduled","color":"gray"}]'),
    ('./data/macro/function/api/cmd/other/multi_cmd/advanced/internal/run_spread_tick.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/advanced/internal/run_spread_tick\n# Called once per tick by `schedule` to process the next spread command.\n# Self-schedules until _mcmd_queue is drained.\n# ─────────────────────────────────────────────────────────────────\n\nexecute unless data storage macro:engine _mcmd_queue[0] run return 0\n\ndata modify storage macro:engine _mcmd_current set from storage macro:engine _mcmd_queue[0]\ndata remove storage macro:engine _mcmd_queue[0]\n\nexecute if data storage macro:engine _mcmd_current{} run function macro:api/cmd/other/multi_cmd/internal/exec_object\nexecute unless data storage macro:engine _mcmd_current{} run function macro:api/cmd/other/multi_cmd/internal/exec_string\n\ndata remove storage macro:engine _mcmd_current\n\n# Continue draining the queue — schedule next tick\nexecute if data storage macro:engine _mcmd_queue[0] run schedule function macro:api/cmd/other/multi_cmd/advanced/internal/run_spread_tick 1t append\n\n# Cleanup options when fully done\nexecute unless data storage macro:engine _mcmd_queue[0] run data remove storage macro:engine _mcmd_options\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/spread ","color":"aqua"},{"text":"◉ tick","color":"#555555"}]\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/advanced/internal/sort_append_loop.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/advanced/internal/sort_append_loop\n# Recursive: drain _sort_tmp into _mcmd_queue one item at a time.\n# ─────────────────────────────────────────────────────────────────\n\nexecute unless data storage macro:engine _sort_tmp[0] run return 0\n\ndata modify storage macro:engine _mcmd_queue append from storage macro:engine _sort_tmp[0]\ndata remove storage macro:engine _sort_tmp[0]\n\nfunction macro:api/cmd/other/multi_cmd/advanced/internal/sort_append_loop\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/advanced/internal/sort_by_priority.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/advanced/internal/sort_by_priority\n# Sorts _mcmd_queue by priority field (ascending).\n# Items with no priority field default to 0 (middle bucket).\n# Buckets: negative | zero/unset | positive\n# Uses sort_scan_loop (classify) + sort_append_loop (merge).\n# ─────────────────────────────────────────────────────────────────\n\n# Move queue to sort_buf; initialize buckets\ndata modify storage macro:engine _sort_buf set from storage macro:engine _mcmd_queue\ndata modify storage macro:engine _sort_neg set value []\ndata modify storage macro:engine _sort_zero set value []\ndata modify storage macro:engine _sort_pos set value []\n\n# Classify each item into the correct bucket\nfunction macro:api/cmd/other/multi_cmd/advanced/internal/sort_scan_loop\n\n# Rebuild queue: neg → zero → pos\ndata modify storage macro:engine _mcmd_queue set value []\n\ndata modify storage macro:engine _sort_tmp set from storage macro:engine _sort_neg\nfunction macro:api/cmd/other/multi_cmd/advanced/internal/sort_append_loop\n\ndata modify storage macro:engine _sort_tmp set from storage macro:engine _sort_zero\nfunction macro:api/cmd/other/multi_cmd/advanced/internal/sort_append_loop\n\ndata modify storage macro:engine _sort_tmp set from storage macro:engine _sort_pos\nfunction macro:api/cmd/other/multi_cmd/advanced/internal/sort_append_loop\n\n# Cleanup\ndata remove storage macro:engine _sort_buf\ndata remove storage macro:engine _sort_neg\ndata remove storage macro:engine _sort_zero\ndata remove storage macro:engine _sort_pos\ndata remove storage macro:engine _sort_tmp\ndata remove storage macro:engine _sort_cur\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/sort ","color":"aqua"},{"text":"✔ sorted by priority","color":"green"}]'),
    ('./data/macro/function/api/cmd/other/multi_cmd/advanced/internal/sort_scan_loop.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/advanced/internal/sort_scan_loop\n# Recursive: dequeue one item from _sort_buf and classify it.\n# ─────────────────────────────────────────────────────────────────\n\nexecute unless data storage macro:engine _sort_buf[0] run return 0\n\ndata modify storage macro:engine _sort_cur set from storage macro:engine _sort_buf[0]\ndata remove storage macro:engine _sort_buf[0]\n\n# Read priority into scoreboard — returns 0 if field absent (desired default)\nexecute store result score $sort_pri macro.tmp run data get storage macro:engine _sort_cur.priority\n\nexecute if score $sort_pri macro.tmp matches ..-1 run data modify storage macro:engine _sort_neg append from storage macro:engine _sort_cur\nexecute if score $sort_pri macro.tmp matches 0 run data modify storage macro:engine _sort_zero append from storage macro:engine _sort_cur\nexecute if score $sort_pri macro.tmp matches 1.. run data modify storage macro:engine _sort_pos append from storage macro:engine _sort_cur\n\nscoreboard players reset $sort_pri macro.tmp\n\nfunction macro:api/cmd/other/multi_cmd/advanced/internal/sort_scan_loop\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/check_condition.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/check_condition\n# Check condition and write result to $mcmd_cond_result\n# _mcmd_current.condition: {tag:"...", score:{...}, predicate:"..."}\n# ─────────────────────────────────────────────────────────────────\n\n# Default: condition passed\nscoreboard players set $mcmd_cond_result macro.tmp 1\n\n# Tag check\nexecute if data storage macro:engine _mcmd_current.condition.tag run function macro:api/cmd/other/multi_cmd/internal/cond_check_tag\n\n# Score check\nexecute if data storage macro:engine _mcmd_current.condition.score run function macro:api/cmd/other/multi_cmd/internal/cond_check_score\n\n# Predicate check\nexecute if data storage macro:engine _mcmd_current.condition.predicate run function macro:api/cmd/other/multi_cmd/internal/cond_check_predicate\n\n# Entity check (selector)\nexecute if data storage macro:engine _mcmd_current.condition.entity run function macro:api/cmd/other/multi_cmd/internal/cond_check_entity\n\n# Storage check\nexecute if data storage macro:engine _mcmd_current.condition.storage run function macro:api/cmd/other/multi_cmd/internal/cond_check_storage\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cleanup.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/cleanup\n# Cleanup — remove temporary storages\n# ─────────────────────────────────────────────────────────────────\n\ndata remove storage macro:engine _mcmd_queue\ndata remove storage macro:engine _mcmd_current\ndata remove storage macro:engine _mcmd_exec\ndata remove storage macro:engine _mcmd_cond_tmp\n\n# Sort temporaries (no-op if sort was not used)\ndata remove storage macro:engine _sort_neg\ndata remove storage macro:engine _sort_zero\ndata remove storage macro:engine _sort_pos\ndata remove storage macro:engine _sort_buf\ndata remove storage macro:engine _sort_tmp\ndata remove storage macro:engine _sort_cur\n\nscoreboard players reset $mcmd_cond_result macro.tmp\nscoreboard players reset $mcmd_cond_score macro.tmp\nscoreboard players reset $sort_pri macro.tmp\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_check_entity.mcfunction', '# Entity selector checker\nfunction macro:api/cmd/other/multi_cmd/internal/cond_entity_exec with storage macro:engine _mcmd_current.condition\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_check_predicate.mcfunction', '# Predicate checker\nfunction macro:api/cmd/other/multi_cmd/internal/cond_pred_exec with storage macro:engine _mcmd_current.condition\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_check_score.mcfunction', '# Score checker\nexecute store result score $mcmd_cond_score macro.tmp run scoreboard players get @s dummy\ndata modify storage macro:engine _mcmd_cond_tmp set from storage macro:engine _mcmd_current.condition.score\nfunction macro:api/cmd/other/multi_cmd/internal/cond_score_exec with storage macro:engine _mcmd_cond_tmp\ndata remove storage macro:engine _mcmd_cond_tmp\nscoreboard players reset $mcmd_cond_score macro.tmp\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_check_storage.mcfunction', '# Storage data checker\nfunction macro:api/cmd/other/multi_cmd/internal/cond_storage_exec with storage macro:engine _mcmd_current.condition.storage\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_check_tag.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/cond_check_tag\n# Tag check — @s must have the specified tag\n# condition.tag: "admin" or {name:"admin", has:1b}\n# ─────────────────────────────────────────────────────────────────\n\n# Simple string format\nexecute unless data storage macro:engine _mcmd_current.condition.tag{} run function macro:api/cmd/other/multi_cmd/internal/cond_tag_simple\n\n# Object format {name:"...", has:1b/0b}\nexecute if data storage macro:engine _mcmd_current.condition.tag{} run function macro:api/cmd/other/multi_cmd/internal/cond_tag_object\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_entity_exec.mcfunction', '# [MACRO] INPUT: $(entity)\n$execute unless entity $(entity) run scoreboard players set $mcmd_cond_result macro.tmp 0\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_pred_exec.mcfunction', '# [MACRO] INPUT: $(predicate)\n$execute unless predicate $(predicate) run scoreboard players set $mcmd_cond_result macro.tmp 0\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_score_exec.mcfunction', '# [MACRO] INPUT: $(objective), $(min), $(max)\n$execute store result score $mcmd_cond_score macro.tmp run scoreboard players get @s $(objective)\n$execute if score $mcmd_cond_score macro.tmp matches $(min)..$(max) run return 0\nscoreboard players set $mcmd_cond_result macro.tmp 0\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_storage_exec.mcfunction', '# [MACRO] INPUT: $(path)\n$execute unless data storage $(path) run scoreboard players set $mcmd_cond_result macro.tmp 0\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_tag_exec.mcfunction', '# [MACRO] INPUT: $(tag)\n$execute unless entity @s[tag=$(tag)] run scoreboard players set $mcmd_cond_result macro.tmp 0\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_tag_obj_exec.mcfunction', '# [MACRO] INPUT: $(name), $(has)\n$execute if data storage macro:engine _mcmd_cond_tmp{has:1b} unless entity @s[tag=$(name)] run scoreboard players set $mcmd_cond_result macro.tmp 0\n$execute if data storage macro:engine _mcmd_cond_tmp{has:0b} if entity @s[tag=$(name)] run scoreboard players set $mcmd_cond_result macro.tmp 0\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_tag_object.mcfunction', '# Tag object checker - {name:"...", has:1b/0b}\n\ndata modify storage macro:engine _mcmd_cond_tmp set from storage macro:engine _mcmd_current.condition.tag\nexecute unless data storage macro:engine _mcmd_cond_tmp.has run data modify storage macro:engine _mcmd_cond_tmp.has set value 1b\n\nfunction macro:api/cmd/other/multi_cmd/internal/cond_tag_obj_exec with storage macro:engine _mcmd_cond_tmp\ndata remove storage macro:engine _mcmd_cond_tmp\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/cond_tag_simple.mcfunction', '# macro:api/cmd/other/multi_cmd/internal/cond_tag_simple\n# Simple string tag check\n\ndata modify storage macro:engine _mcmd_cond_tmp set value {}\ndata modify storage macro:engine _mcmd_cond_tmp.tag set from storage macro:engine _mcmd_current.condition.tag\nfunction macro:api/cmd/other/multi_cmd/internal/cond_tag_exec with storage macro:engine _mcmd_cond_tmp\ndata remove storage macro:engine _mcmd_cond_tmp\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/exec.mcfunction', '$execute run $(current_cmd)\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/exec_func.mcfunction', '$function $(current_cmd)\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/exec_func_macro.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/exec_func_macro [MACRO]\n# INPUT: $(func)\n# ─────────────────────────────────────────────────────────────────\n\n$function $(func)\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/exec_macro.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/exec_macro [MACRO]\n# INPUT: $(cmd)\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @a[tag=macro.admin] [{"selector":"@s","color":"gold"},{"text":" - command executed","color":"yellow"}]\n\n$$(cmd)\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/exec_object.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/exec_object\n# Execute advanced object command\n# _mcmd_current format: {cmd:"...", condition:{}, priority:0}\n# ─────────────────────────────────────────────────────────────────\n\n# Check condition (if present)\nexecute if data storage macro:engine _mcmd_current.condition run function macro:api/cmd/other/multi_cmd/internal/check_condition\nexecute if data storage macro:engine _mcmd_current.condition if score $mcmd_cond_result macro.tmp matches 0 run return 0\n\n# Run pre-hook (if present)\nexecute if data storage macro:engine _mcmd_current.pre_hook run function macro:api/cmd/other/multi_cmd/internal/run_pre_hook\n\n# Start profiling (if present)\nexecute if data storage macro:engine _mcmd_options{profile:1b} run execute store result score $mcmd_exec_start macro.tmp run time query gametime\n\n# Execute command\nexecute if data storage macro:engine _mcmd_current.cmd run function macro:api/cmd/other/multi_cmd/internal/exec_macro with storage macro:engine _mcmd_current\nexecute if data storage macro:engine _mcmd_current.func run function macro:api/cmd/other/multi_cmd/internal/exec_func_macro with storage macro:engine _mcmd_current\n\n# End profiling (if present)\nexecute if data storage macro:engine _mcmd_options{profile:1b} run function macro:api/cmd/other/multi_cmd/internal/record_exec_time\n\n# Run post-hook (if present)\nexecute if data storage macro:engine _mcmd_current.post_hook run function macro:api/cmd/other/multi_cmd/internal/run_post_hook\n\n# Track stats\nexecute if data storage macro:engine _mcmd_options{profile:1b} run scoreboard players add $mcmd_success macro.tmp 1\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/exec_string.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/exec_string\n# Execute simple string command\n# _mcmd_current is a plain string e.g. "say Hello"\n# ─────────────────────────────────────────────────────────────────\n\n# Wrap string into object\ndata modify storage macro:engine _mcmd_exec set value {}\ndata modify storage macro:engine _mcmd_exec.cmd set from storage macro:engine _mcmd_current\n\n# Execute via macro\nfunction macro:api/cmd/other/multi_cmd/internal/exec_macro with storage macro:engine _mcmd_exec\n\n# Cleanup\ndata remove storage macro:engine _mcmd_exec\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/func_convert_loop.mcfunction', '# Convert string list to {func:"..."} objects\nexecute unless data storage macro:input list[0] run return 0\n\ndata modify storage macro:engine _mcmd_func_tmp set value {}\ndata modify storage macro:engine _mcmd_func_tmp.func set from storage macro:input list[0]\ndata modify storage macro:engine _mcmd_queue append from storage macro:engine _mcmd_func_tmp\n\ndata remove storage macro:input list[0]\nfunction macro:api/cmd/other/multi_cmd/internal/func_convert_loop\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/hook_post_exec.mcfunction', '# [MACRO] INPUT: $(post_hook)\n$function $(post_hook)\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/hook_pre_exec.mcfunction', '# [MACRO] INPUT: $(pre_hook)\n$function $(pre_hook)\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/record_exec_time.mcfunction', '# Record execution time for profiling\nexecute store result score $mcmd_exec_end macro.tmp run time query gametime\nscoreboard players operation $mcmd_exec_dur macro.tmp = $mcmd_exec_end macro.tmp\nscoreboard players operation $mcmd_exec_dur macro.tmp -= $mcmd_exec_start macro.tmp\n\nscoreboard players reset $mcmd_exec_start macro.tmp\nscoreboard players reset $mcmd_exec_end macro.tmp\nscoreboard players reset $mcmd_exec_dur macro.tmp\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/run_as_exec.mcfunction', '# [MACRO] INPUT: $(selector)\n$execute as $(selector) run function macro:api/cmd/other/multi_cmd/run\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/run_at_exec.mcfunction', '# [MACRO] INPUT: $(selector)\n$execute at $(selector) run function macro:api/cmd/other/multi_cmd/run\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/run_post_hook.mcfunction', '# Post-hook runner\nfunction macro:api/cmd/other/multi_cmd/internal/hook_post_exec with storage macro:engine _mcmd_current\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/run_pre_hook.mcfunction', '# Pre-hook runner\nfunction macro:api/cmd/other/multi_cmd/internal/hook_pre_exec with storage macro:engine _mcmd_current\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/show_stats.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/show_stats\n# Show statistics\n# ─────────────────────────────────────────────────────────────────\n\nexecute store result score $mcmd_end_time macro.tmp run time query gametime\nexecute store result score $mcmd_duration macro.tmp run data get storage macro:engine _mcmd_stats.start_time\nscoreboard players operation $mcmd_duration macro.tmp = $mcmd_end_time macro.tmp\nscoreboard players operation $mcmd_duration macro.tmp -= $mcmd_duration macro.tmp\n\nexecute store result storage macro:engine _mcmd_stats.total int 1 run scoreboard players get $mcmd_total macro.tmp\nexecute store result storage macro:engine _mcmd_stats.success int 1 run scoreboard players get $mcmd_success macro.tmp\nexecute store result storage macro:engine _mcmd_stats.duration int 1 run scoreboard players get $mcmd_duration macro.tmp\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/stats ","color":"aqua"},{"text":"Total: ","color":"#555555"},{"nbt":"_mcmd_stats.total","storage":"macro:engine","color":"white"},{"text":" | Success: ","color":"#555555"},{"nbt":"_mcmd_stats.success","storage":"macro:engine","color":"green"},{"text":" | Duration: ","color":"#555555"},{"nbt":"_mcmd_stats.duration","storage":"macro:engine","color":"yellow"},{"text":"t","color":"yellow"}]\n\nscoreboard players reset $mcmd_total macro.tmp\nscoreboard players reset $mcmd_success macro.tmp\nscoreboard players reset $mcmd_duration macro.tmp\nscoreboard players reset $mcmd_end_time macro.tmp\ndata remove storage macro:engine _mcmd_stats\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/step.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/internal/step\n# Dequeue one command and execute it, then recurse\n# ─────────────────────────────────────────────────────────────────\n\n# Return if queue is empty\nexecute unless data storage macro:engine _mcmd_queue[0] run return 0\n\n# Dequeue first command\ndata modify storage macro:engine _mcmd_current set from storage macro:engine _mcmd_queue[0]\ndata remove storage macro:engine _mcmd_queue[0]\n\n# Increment stats counter\nexecute if data storage macro:engine _mcmd_options{profile:1b} run scoreboard players add $mcmd_total macro.tmp 1\n\n# Execute command (string or object)\nexecute if data storage macro:engine _mcmd_current{} run function macro:api/cmd/other/multi_cmd/internal/exec_object\nexecute unless data storage macro:engine _mcmd_current{} run function macro:api/cmd/other/multi_cmd/internal/exec_string\n\n# Process next command\nfunction macro:api/cmd/other/multi_cmd/internal/step\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/internal/step_func.mcfunction', 'execute unless data storage macro:engine _mcmd_list[0] run return 0\n\ndata modify storage macro:engine _mcmd_entry set value {}\ndata modify storage macro:engine _mcmd_entry.current_cmd set from storage macro:engine _mcmd_list[0]\ndata remove storage macro:engine _mcmd_list[0]\n\nfunction macro:api/cmd/other/multi_cmd/internal/exec_func with storage macro:engine _mcmd_entry\n\nfunction macro:api/cmd/other/multi_cmd/internal/step_func\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/utils/add_command.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/utils/add_command\n# Add a command to queue at runtime\n#\n# INPUT (storage macro:input):\n# cmd or func → command/function to add\n# ─────────────────────────────────────────────────────────────────\n\nexecute if data storage macro:input cmd run data modify storage macro:engine _mcmd_queue append value {}\nexecute if data storage macro:input cmd run data modify storage macro:engine _mcmd_queue[-1].cmd set from storage macro:input cmd\n\nexecute if data storage macro:input func run data modify storage macro:engine _mcmd_queue append value {}\nexecute if data storage macro:input func run data modify storage macro:engine _mcmd_queue[-1].func set from storage macro:input func\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/utils/add ","color":"aqua"},{"text":"✔ added to queue","color":"green"}]\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/utils/clear_queue.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/utils/clear_queue\n# Clear the queue\n# ─────────────────────────────────────────────────────────────────\n\ndata remove storage macro:engine _mcmd_queue\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"multi_cmd/utils/clear ","color":"aqua"},{"text":"✔ queue cleared","color":"yellow"}]\n'),
    ('./data/macro/function/api/cmd/other/multi_cmd/utils/get_stats.mcfunction', "# ─────────────────────────────────────────────────────────────────\n# macro:api/cmd/other/multi_cmd/utils/get_stats\n# Mevcut istatistikleri macro:output'a kopyala\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output stats set from storage macro:engine _mcmd_stats\n"),
    ('./data/macro/function/api/cmd/other/multi_cmd/utils/run_with_options_tracked.mcfunction', 'data modify storage macro:output multiCommands.executed set value 0b\n\nexecute at @s store success storage macro:output multiCommands.executed byte 1 unless function macro:api/cmd/other/multi_cmd/advanced/run_with_options run return 1'),
    ('./data/macro/function/api/dialog/close.mcfunction', 'return run tellraw @s {"text":"This feature requires 1.21.5 or higher!","color":"red","italic":false}\n\ntag @s remove macro.dialog_opened\ntag @s add macro.dialog_closed\n'),
    ('./data/macro/function/api/dialog/is_open.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/dialog/is_open\n# Checks whether the executing player currently has a dialog open.\n# Output: macro:output result → 1b (open) or 0b (closed / not set)\n#\n# Example:\n# execute as @a run function macro:api/dialog/is_open\n# # Then read macro:output result per player context\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output result set value 0b\nexecute if entity @s[tag=macro.dialog_opened] unless entity @s[tag=macro.dialog_closed] run data modify storage macro:output result set value 1b\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"dialog/is_open ","color":"aqua"},{"text":"→ ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/api/dialog/load.mcfunction', 'return run tellraw @s {"text":"This feature requires 1.21.5 or higher!","color":"red","italic":false}\n'),
    ('./data/macro/function/api/dialog/notify_admins.mcfunction', '# Ensure this runs only for a valid player with an open dialog\nexecute unless entity @s[tag=macro.dialog_opened] run return 0\n\n# Notify all admins that a dialog has been opened\ntellraw @a[tag=macro.admin] ["",{"text":"[Dialog] ","color":"gold"},{"selector":"@s","color":"yellow"},{"text":" opened a dialog.","color":"white"}]\n'),
    ('./data/macro/function/api/dialog/open.mcfunction', 'execute unless data storage macro:engine dialog.DIALOG run return 0\n\nscoreboard players set @s macro.dialog_load -1\ntag @s remove macro.dialog_closed\ntag @s remove macro.dialog_opened\ntag @s add macro.dialog_opened\n\ntellraw @s ["",{"text":"[AME] ","color":"aqua","bold":true},{"text":"Dialog: ","color":"gray"},{"nbt":"dialog.DIALOG","storage":"macro:engine","color":"yellow"},{"text":" — ","color":"#555555"},{"text":"This feature requires Minecraft 1.21.6 or higher.","color":"red","italic":true}]\n\nfunction macro:api/dialog/notify_admins\n\nreturn 1\n'),
    ('./data/macro/function/api/interaction/bind_attack.mcfunction', '$data modify storage macro:engine interaction_binds.attack append value {tag:"$(tag)", func:"$(func)"}\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"interaction/bind_attack ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(tag)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./data/macro/function/api/interaction/bind_use.mcfunction', '$data modify storage macro:engine interaction_binds.use append value {tag:"$(tag)", func:"$(func)"}\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"interaction/bind_use ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(tag)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./data/macro/function/api/interaction/list.mcfunction', 'tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"interaction/list","color":"aqua"}]\ntellraw @a[tag=macro.debug] ["",{"text":" attack: ","color":"#555555"},{"storage":"macro:engine","nbt":"interaction_binds.attack","color":"white"}]\ntellraw @a[tag=macro.debug] ["",{"text":" use: ","color":"#555555"},{"storage":"macro:engine","nbt":"interaction_binds.use","color":"white"}]\n'),
    ('./data/macro/function/api/interaction/remove.mcfunction', '$kill @e[type=minecraft:interaction,tag=$(tag)]\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"interaction/remove ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"$(tag)","color":"white"},{"text":" killed","color":"#555555"}]\n'),
    ('./data/macro/function/api/interaction/spawn.mcfunction', '$summon minecraft:interaction ~ ~ ~ {width:$(width), height:$(height), response:$(response), Tags:["macro.interaction","macro.ia_new"]}\n\n$tag @e[type=minecraft:interaction,tag=macro.ia_new,limit=1,sort=nearest] add $(tag)\ntag @e[tag=macro.ia_new] remove macro.ia_new\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"interaction/spawn ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(tag)","color":"white"},{"text":" spawned","color":"#555555"}]\n'),
    ('./data/macro/function/api/interaction/unbind_attack.mcfunction', 'execute unless data storage macro:engine interaction_binds.attack[0] run return 0\n\ndata modify storage macro:engine _ia_ubinds set from storage macro:engine interaction_binds.attack\ndata modify storage macro:engine interaction_binds.attack set value []\n$data modify storage macro:engine _ia_ufilter set value {tag:"$(tag)", func:"$(func)", list:"attack"}\nfunction macro:api/interaction/internal/unbind_filter\ndata remove storage macro:engine _ia_ubinds\ndata remove storage macro:engine _ia_ufilter\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"interaction/unbind_attack ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"$(tag)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./data/macro/function/api/interaction/unbind_use.mcfunction', 'execute unless data storage macro:engine interaction_binds.use[0] run return 0\n\ndata modify storage macro:engine _ia_ubinds set from storage macro:engine interaction_binds.use\ndata modify storage macro:engine interaction_binds.use set value []\n$data modify storage macro:engine _ia_ufilter set value {tag:"$(tag)", func:"$(func)", list:"use"}\nfunction macro:api/interaction/internal/unbind_filter\ndata remove storage macro:engine _ia_ubinds\ndata remove storage macro:engine _ia_ufilter\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"interaction/unbind_use ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"$(tag)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./data/macro/function/api/interaction/internal/check_bind.mcfunction', '$data modify storage macro:engine _dispatch.func set value "$(func)"\n$execute if entity @e[type=minecraft:interaction,tag=macro.ia_active,tag=$(tag),limit=1] run function #macro:internal/dispatch\n'),
    ('./data/macro/function/api/interaction/internal/dispatch.mcfunction', 'data modify storage macro:engine _ia_cur set from storage macro:engine _ia_iter[0]\ndata remove storage macro:engine _ia_iter[0]\n\nfunction macro:api/interaction/internal/check_bind with storage macro:engine _ia_cur\n\nexecute if data storage macro:engine _ia_iter[0] run function macro:api/interaction/internal/dispatch\n'),
    ('./data/macro/function/api/interaction/internal/on_attack.mcfunction', 'tag @s add macro.ia_active\n\ndata modify storage macro:engine _ia_iter set from storage macro:engine interaction_binds.attack\nexecute if data storage macro:engine _ia_iter[0] run execute on attacker run function macro:api/interaction/internal/dispatch\n\ntag @s remove macro.ia_active\ndata remove entity @s attack\ndata remove storage macro:engine _ia_iter\ndata remove storage macro:engine _ia_cur\n'),
    ('./data/macro/function/api/interaction/internal/on_use.mcfunction', 'tag @s add macro.ia_active\n\ndata modify storage macro:engine _ia_iter set from storage macro:engine interaction_binds.use\nexecute if data storage macro:engine _ia_iter[0] run execute on target run function macro:api/interaction/internal/dispatch\n\ntag @s remove macro.ia_active\ndata remove entity @s interaction\ndata remove storage macro:engine _ia_iter\ndata remove storage macro:engine _ia_cur\n'),
    ('./data/macro/function/api/interaction/internal/tick_scan.mcfunction', 'execute unless entity @e[type=minecraft:interaction,tag=macro.interaction,limit=1] run return 0\n\nexecute if data storage macro:engine interaction_binds.attack[0] run execute as @e[type=minecraft:interaction,tag=macro.interaction] if data entity @s attack run function macro:api/interaction/internal/on_attack\n\nexecute if data storage macro:engine interaction_binds.use[0] run execute as @e[type=minecraft:interaction,tag=macro.interaction] if data entity @s interaction run function macro:api/interaction/internal/on_use\n'),
    ('./data/macro/function/api/interaction/internal/unbind_check.mcfunction', '$execute unless data storage macro:engine _ia_ucur{tag:"$(tag)",func:"$(func)"} run data modify storage macro:engine interaction_binds.$(list) append from storage macro:engine _ia_ucur\n'),
    ('./data/macro/function/api/interaction/internal/unbind_filter.mcfunction', 'execute unless data storage macro:engine _ia_ubinds[0] run return 0\n\ndata modify storage macro:engine _ia_ucur set from storage macro:engine _ia_ubinds[0]\ndata remove storage macro:engine _ia_ubinds[0]\n\nfunction macro:api/interaction/internal/unbind_check with storage macro:engine _ia_ufilter\n\nfunction macro:api/interaction/internal/unbind_filter\ndata remove storage macro:engine _ia_ucur\n'),
    ('./data/macro/function/api/macro/with_advancement.mcfunction', '# ─────────────────────────────────────────────\n# macro:engine/macro/with_advancement [MACRO]\n#\n# Checks whether a player has completed a specific advancement and\n# injects the boolean result as a named macro variable into the target function.\n#\n# Usage:\n#   function macro:engine/macro/with_advancement \\\n#     {func:"ns:path", player:"Name", advancement:"ns:adv/path", var:"done"}\n#\n# Parameters:\n#   func        — function to call (ns:path)\n#   player      — target player name\n#   advancement — advancement to check (ns:path/to/adv)\n#   var         — macro variable name to inject into the target function\n#\n# Output: $(done) → 1b (completed) or 0b (not completed)\n# ─────────────────────────────────────────────\n\n# Clear pipe\ndata remove storage macro:engine _macro_pipe\n\n# Default: not completed\n$data modify storage macro:engine _macro_pipe.$(var) set value "empty"\n\n# Set to 1b if the player has completed the advancement\n$execute as @a[name=$(player),limit=1,advancements={$(advancement)=true}] run data modify storage macro:engine _macro_pipe.$(var) set value 1b\n$execute as @a[name=$(player),limit=1,advancements={$(advancement)=false}] run data modify storage macro:engine _macro_pipe.$(var) set value 0b\n\n# Call target function with pipe as macro source\n$function $(func) with storage macro:engine _macro_pipe'),
    ('./data/macro/function/api/macro/with_function.mcfunction', '# ─────────────────────────────────────────────\n# macro:engine/macro/with_function [MACRO]\n#\n# Runs a provider (source) function; passes the data that function\n# wrote to macro:engine _macro_pipe storage as macro variable source\n# to a consumer (target) function.\n#\n# Establishes a type-safe data bridge between two functions.\n#\n# Usage:\n#   function macro:engine/macro/with_function \\\n#     {source:"ns:provider", target:"ns:consumer"}\n#\n# Parameters:\n#   source — function that produces data and writes it to macro:engine _macro_pipe\n#   target — function that consumes data from the pipe as macro variables\n#\n# Contract:\n#   source function must write its output to this storage:\n#     data modify storage macro:engine _macro_pipe.<key> set value <val>\n#   target function can access those keys as $(key).\n# ─────────────────────────────────────────────\n\n# Run provider function — it writes its output to _macro_pipe\n$function $(source)\n\n# Pass pipe to consumer as macro source\n$function $(target) with storage macro:engine _macro_pipe\n\n# Clear pipe before source runs\ndata remove storage macro:engine _macro_pipe'),
    ('./data/macro/function/api/macro/with_score.mcfunction', '# ─────────────────────────────────────────────\n# macro:engine/macro/with_score [MACRO]\n#\n# Reads a player\'s scoreboard value and injects it as a named\n# macro variable into the target function.\n#\n# Usage:\n#   function macro:engine/macro/with_score \\\n#     {func:"ns:path", player:"Name", objective:"myObj", var:"myVar"}\n#\n# Parameters:\n#   func      — function to call (ns:path)\n#   player    — target player name\n#   objective — scoreboard objective\n#   var       — macro variable name to inject into the target function\n#\n# Output: $(myVar) → scoreboard value (int)\n# ─────────────────────────────────────────────\n\n# Write score into pipe under the requested variable name\n$execute store result storage macro:engine _macro_pipe.$(var) int 1 run scoreboard players get $(player) $(objective)\n\n# Call target function with pipe as macro source\n$function $(func) with storage macro:engine _macro_pipe\n\n# Clear pipe\ndata remove storage macro:engine _macro_pipe'),
    ('./data/macro/function/api/perm/check.mcfunction', 'scoreboard players set $pc_pid macro.tmp 0\n$execute store result score $pc_pid macro.tmp run data get storage macro:engine player_pids.$(player)\nexecute if score $pc_pid macro.tmp matches 0 run return 0\n\nexecute as @a if score @s macro.pid = $pc_pid macro.tmp run execute if entity @s[tag=macro.admin] run return 1\n\n$execute as @a if score @s macro.pid = $pc_pid macro.tmp run execute if entity @s[tag=perm.$(perm)] run return 1\n\n$execute as @a if score @s macro.pid = $pc_pid macro.tmp run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"$(perm)","color":"yellow"},{"text":" — you don\'t have this permission.","color":"red"}]\nreturn 0\n'),
    ('./data/macro/function/api/perm/clear.mcfunction', 'execute unless entity @s[tag=macro.admin] run return run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$data remove storage macro:engine permissions.$(player)\n$advancement revoke @a[name=$(player),limit=1] from macro:hidden/root\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/clear ","color":"aqua"},{"text":"⚠ ","color":"yellow"},{"text":"$(player)","color":"white"},{"text":" — all permissions cleared","color":"#555555"}]\n'),
    ('./data/macro/function/api/perm/exec.mcfunction', 'scoreboard players set $pex_pid macro.tmp 0\n$execute store result score $pex_pid macro.tmp run data get storage macro:engine player_pids.$(player)\nexecute if score $pex_pid macro.tmp matches 0 run return 0\n\ndata modify storage macro:engine _pex_tmp set value {result:0b}\nexecute as @a if score @s macro.pid = $pex_pid macro.tmp run execute if entity @s[tag=macro.admin] run data modify storage macro:engine _pex_tmp.result set value 1b\n$execute if data storage macro:engine permissions.$(player).$(perm) run data modify storage macro:engine _pex_tmp.result set value 1b\n\n$execute if data storage macro:engine _pex_tmp{result:0b} run execute as @a if score @s macro.pid = $pex_pid macro.tmp run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"$(perm)","color":"yellow"},{"text":" — you don\'t have this permission.","color":"red"}]\nexecute if data storage macro:engine _pex_tmp{result:0b} run return 0\n\n$execute as @a if score @s macro.pid = $pex_pid macro.tmp at @s run $(cmd)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/exec ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" [","color":"#555555"},{"text":"$(perm)","color":"aqua"},{"text":"] → ","color":"#555555"},{"text":"$(cmd)","color":"green"}]\ndata remove storage macro:engine _pex_tmp\n'),
    ('./data/macro/function/api/perm/grant.mcfunction', 'execute if entity @s unless entity @s[tag=macro.admin] run return run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$data modify storage macro:engine permissions.$(player).$(perm) set value 1b\n\nscoreboard players set $pg_pid macro.tmp 0\n$execute store result score $pg_pid macro.tmp run data get storage macro:engine player_pids.$(player)\n$execute as @a if score @s macro.pid = $pg_pid macro.tmp run tag @s add perm.$(perm)\n$advancement grant @a[name=$(player),limit=1] only macro:api/perm/$(perm)\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/grant ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(player)","color":"white"},{"text":" ← ","color":"#555555"},{"text":"$(perm)","color":"aqua"}]\n'),
    ('./data/macro/function/api/perm/has.mcfunction', 'data modify storage macro:output result set value 0b\n\nscoreboard players set $ph_pid macro.tmp 0\n$execute store result score $ph_pid macro.tmp run data get storage macro:engine player_pids.$(player)\n\nexecute as @a if score @s macro.pid = $ph_pid macro.tmp run execute if entity @s[tag=macro.admin] run data modify storage macro:output result set value 1b\n$execute as @a if score @s macro.pid = $ph_pid macro.tmp run execute if entity @s[tag=perm.$(perm)] run data modify storage macro:output result set value 1b\n\n$execute if data storage macro:engine permissions.$(player).$(perm) run data modify storage macro:output result set value 1b\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/has ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(perm)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/api/perm/list.mcfunction', '$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Perms: ","color":"aqua"},{"text":"$(player)","color":"white","bold":true},{"text":" ━━━━━━━━━━━━━━","color":"#555555"}]\n$execute if data storage macro:engine permissions.$(player) run tellraw @a[tag=macro.debug] ["",{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"permissions.$(player)","interpret":false,"color":"yellow"}]\n$execute unless data storage macro:engine permissions.$(player) run tellraw @a[tag=macro.debug] ["",{"text":" ","color":"#555555"},{"text":"(no permissions)","color":"gray","italic":true}]\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]\n'),
    ('./data/macro/function/api/perm/revoke.mcfunction', 'execute unless entity @s[tag=macro.admin] run return run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$data remove storage macro:engine permissions.$(player).$(perm)\n\nscoreboard players set $prv_pid macro.tmp 0\n$execute store result score $prv_pid macro.tmp run data get storage macro:engine player_pids.$(player)\n$execute as @a if score @s macro.pid = $prv_pid macro.tmp run tag @s remove perm.$(perm)\n$advancement revoke @a[name=$(player),limit=1] only macro:api/perm/$(perm)\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/revoke ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"$(player)","color":"white"},{"text":" — ","color":"#555555"},{"text":"$(perm)","color":"aqua"},{"text":" revoked","color":"#555555"}]\n'),
    ('./data/macro/function/api/perm/run.mcfunction', 'scoreboard players set $pr_pid macro.tmp 0\n$execute store result score $pr_pid macro.tmp run data get storage macro:engine player_pids.$(player)\nexecute if score $pr_pid macro.tmp matches 0 run return 0\n\ndata modify storage macro:engine _pr_tmp set value {result:0b}\nexecute as @a if score @s macro.pid = $pr_pid macro.tmp run execute if entity @s[tag=macro.admin] run data modify storage macro:engine _pr_tmp.result set value 1b\n$execute as @a if score @s macro.pid = $pr_pid macro.tmp run execute if entity @s[tag=perm.$(perm)] run data modify storage macro:engine _pr_tmp.result set value 1b\n\n$execute if data storage macro:engine _pr_tmp{result:0b} run execute as @a if score @s macro.pid = $pr_pid macro.tmp run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"$(perm)","color":"yellow"},{"text":" — you don\'t have this permission.","color":"red"}]\nexecute if data storage macro:engine _pr_tmp{result:0b} run return 0\n\n$execute as @a if score @s macro.pid = $pr_pid macro.tmp at @s run $(cmd)\n\ndata remove storage macro:engine _pr_tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/run ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" [","color":"#555555"},{"text":"$(perm)","color":"green"},{"text":"] → ","color":"#555555"},{"text":"$(cmd)","color":"aqua"}]\n'),
    ('./data/macro/function/api/perm/trigger/bind.mcfunction', '$scoreboard objectives add $(name) trigger\n\n$execute unless data storage macro:engine perm_triggers.$(name) run data modify storage macro:engine perm_triggers.$(name) set value []\n$data modify storage macro:engine perm_triggers.$(name) append value {value:$(value), func:"$(func)", perm:"$(perm)"}\n\nexecute unless data storage macro:engine perm_trigger_names run data modify storage macro:engine perm_trigger_names set value []\n$execute unless data storage macro:engine perm_trigger_names[{name:"$(name)"}] run data modify storage macro:engine perm_trigger_names append value {name:"$(name)"}\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/trigger/bind ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(name)","color":"white"},{"text":":","color":"#555555"},{"text":"$(value)","color":"yellow"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"},{"text":" [","color":"#555555"},{"text":"$(perm)","color":"green"},{"text":"]","color":"#555555"}]\n'),
    ('./data/macro/function/api/perm/trigger/bind_cmd.mcfunction', '$scoreboard objectives add $(name) trigger\n\n$execute unless data storage macro:engine perm_triggers.$(name) run data modify storage macro:engine perm_triggers.$(name) set value []\n$data modify storage macro:engine perm_triggers.$(name) append value {value:$(value), cmd:"$(cmd)", perm:"$(perm)"}\n\nexecute unless data storage macro:engine perm_trigger_names run data modify storage macro:engine perm_trigger_names set value []\n$execute unless data storage macro:engine perm_trigger_names[{name:"$(name)"}] run data modify storage macro:engine perm_trigger_names append value {name:"$(name)"}\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/trigger/bind_cmd ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(name)","color":"white"},{"text":":","color":"#555555"},{"text":"$(value)","color":"yellow"},{"text":" → ","color":"#555555"},{"text":"$(cmd)","color":"aqua"},{"text":" [","color":"#555555"},{"text":"$(perm)","color":"green"},{"text":"]","color":"#555555"}]\n'),
    ('./data/macro/function/api/perm/trigger/clear.mcfunction', '$data remove storage macro:engine perm_triggers.$(name)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/trigger/clear ","color":"aqua"},{"text":"⚠ ","color":"yellow"},{"text":"$(name)","color":"white"},{"text":" — all binds cleanndi","color":"#555555"}]\n'),
    ('./data/macro/function/api/perm/trigger/enable.mcfunction', 'scoreboard players set $pte_pid macro.tmp 0\n$execute store result score $pte_pid macro.tmp run data get storage macro:engine player_pids.$(player)\nexecute if score $pte_pid macro.tmp matches 0 run return 0\n\ndata modify storage macro:engine _pte_tmp set value {result:0b}\nexecute as @a if score @s macro.pid = $pte_pid macro.tmp run execute if entity @s[tag=macro.admin] run data modify storage macro:engine _pte_tmp.result set value 1b\n$execute if data storage macro:engine permissions.$(player).$(perm) run data modify storage macro:engine _pte_tmp.result set value 1b\n\n$execute if data storage macro:engine _pte_tmp{result:0b} run execute as @a if score @s macro.pid = $pte_pid macro.tmp run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"$(perm)","color":"yellow"},{"text":" — you don\'t have this permission.","color":"red"}]\nexecute if data storage macro:engine _pte_tmp{result:0b} run return 0\n\n$execute as @a if score @s macro.pid = $pte_pid macro.tmp run scoreboard players enable @s $(name)\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/trigger/enable ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(player)","color":"white"},{"text":" — ","color":"#555555"},{"text":"$(name)","color":"aqua"},{"text":" enabled","color":"#555555"}]\ndata remove storage macro:engine _pte_tmp\n'),
    ('./data/macro/function/api/perm/trigger/unbind.mcfunction', '$execute unless data storage macro:engine perm_triggers.$(name) run return 0\n\n$data modify storage macro:engine _pt_unbind set from storage macro:engine perm_triggers.$(name)\n$data modify storage macro:engine perm_triggers.$(name) set value []\n$data modify storage macro:engine _pt_uval set value $(value)\n$data modify storage macro:engine _pt_filter_ctx set value {name:"$(name)"}\n\nfunction macro:api/perm/trigger/internal/unbind_filter\n\ndata remove storage macro:engine _pt_unbind\ndata remove storage macro:engine _pt_uval\ndata remove storage macro:engine _pt_filter_ctx\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"perm/trigger/unbind ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"$(name)","color":"white"},{"text":":","color":"#555555"},{"text":"$(value)","color":"yellow"},{"text":" removed","color":"#555555"}]\n'),
    ('./data/macro/function/api/perm/trigger/internal/check_bind.mcfunction', 'execute unless data storage macro:engine _ptd_binds[0] run return 0\n\ndata modify storage macro:engine _ptd_current set from storage macro:engine _ptd_binds[0]\ndata remove storage macro:engine _ptd_binds[0]\n\nexecute store result score $ptd_entry_val macro.tmp run data get storage macro:engine _ptd_current.value\nexecute if score $ptd_val macro.tmp = $ptd_entry_val macro.tmp run function macro:api/perm/trigger/internal/run_if_perm with storage macro:engine _ptd_current\n\nfunction macro:api/perm/trigger/internal/check_bind\n'),
    ('./data/macro/function/api/perm/trigger/internal/exec.mcfunction', 'execute if data storage macro:engine _ptd_current.func run function macro:api/trigger/internal/call with storage macro:engine _ptd_current\nexecute if data storage macro:engine _ptd_current.cmd run function macro:api/trigger/internal/call2 with storage macro:engine _ptd_current\n'),
    ('./data/macro/function/api/perm/trigger/internal/player_dispatch.mcfunction', '$scoreboard players operation $ptd_val macro.tmp = @s $(name)\n\n$scoreboard players set @s $(name) 0\n$scoreboard players enable @s $(name)\n\n$execute unless data storage macro:engine perm_triggers.$(name)[0] run return 0\n\n$data modify storage macro:engine _ptd_binds set from storage macro:engine perm_triggers.$(name)\n\nfunction macro:api/perm/trigger/internal/check_bind\ndata remove storage macro:engine _ptd_binds\ndata remove storage macro:engine _ptd_current\n'),
    ('./data/macro/function/api/perm/trigger/internal/run_if_perm.mcfunction', 'execute if entity @s[tag=macro.admin] run function macro:api/perm/trigger/internal/exec with storage macro:engine _ptd_current\n\n$execute unless entity @s[tag=macro.admin] if entity @s[tag=perm.$(perm)] run function macro:api/perm/trigger/internal/exec with storage macro:engine _ptd_current\n\n$execute unless entity @s[tag=macro.admin] unless entity @s[tag=perm.$(perm)] run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"$(perm)","color":"yellow"},{"text":" — you don\'t have this permission.","color":"red"}]\n'),
    ('./data/macro/function/api/perm/trigger/internal/tick_dispatch.mcfunction', '$execute as @a[scores={$(name)=1..}] run function macro:api/perm/trigger/internal/player_dispatch with storage macro:engine _pt_tick_ctx\n\n$execute as @a run scoreboard players enable @s $(name)\n'),
    ('./data/macro/function/api/perm/trigger/internal/tick_start.mcfunction', 'execute unless data storage macro:engine perm_trigger_names[0] run return 0\n\ndata modify storage macro:engine _pt_names_tmp set from storage macro:engine perm_trigger_names\nfunction macro:api/perm/trigger/internal/tick_step_loop\ndata remove storage macro:engine _pt_names_tmp\n'),
    ('./data/macro/function/api/perm/trigger/internal/tick_step_loop.mcfunction', 'execute unless data storage macro:engine _pt_names_tmp[0] run return 0\n\ndata modify storage macro:engine _pt_tick_ctx set from storage macro:engine _pt_names_tmp[0]\ndata remove storage macro:engine _pt_names_tmp[0]\n\nfunction macro:api/perm/trigger/internal/tick_dispatch with storage macro:engine _pt_tick_ctx\n\nfunction macro:api/perm/trigger/internal/tick_step_loop\n'),
    ('./data/macro/function/api/perm/trigger/internal/unbind_filter.mcfunction', 'execute unless data storage macro:engine _pt_unbind[0] run return 0\n\nexecute store result score $pt_fval macro.tmp run data get storage macro:engine _pt_unbind[0].value\nexecute store result score $pt_uval macro.tmp run data get storage macro:engine _pt_uval\n\nexecute unless score $pt_fval macro.tmp = $pt_uval macro.tmp run function macro:api/perm/trigger/internal/unbind_reinsert with storage macro:engine _pt_filter_ctx\n\ndata remove storage macro:engine _pt_unbind[0]\nfunction macro:api/perm/trigger/internal/unbind_filter\n'),
    ('./data/macro/function/api/perm/trigger/internal/unbind_reinsert.mcfunction', '$data modify storage macro:engine perm_triggers.$(name) append from storage macro:engine _pt_unbind[0]\n'),
    ('./data/macro/function/api/title/actionbar.mcfunction', '# macro:api/title/actionbar — Raw JSON actionbar display [MACRO]\n# Displays a full JSON component string in the actionbar of a named player.\n# Unlike cmd/actionbar (text + color only), this accepts any serialized component\n# including gradients, translate, score, selector, and nbt text sources.\n#\n# Input (macro args):\n#   player — player name selector string (e.g. "Steve")\n#   json   — serialized JSON component string\n#\n# Output → none\n#\n# Usage:\n#   function macro:api/title/actionbar {player:"Steve",json:\'{"text":"HP: 20/20","color":"red"}\'}\n#   function macro:api/title/actionbar {player:"Steve",\\\n#     json:\'[{"text":"Kills: "},{"score":{"name":"@s","objective":"kills"},"color":"gold"}]\'}\n\nexecute unless function macro:debug/tools/utils/check_all run return 0\n\n$title @a[name=$(player),limit=1] actionbar $(json)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"title/actionbar ","color":"aqua"},{"text":"$(player)","color":"white"}]\n'),
    ('./data/macro/function/api/title/broadcast.mcfunction', '# macro:api/title/broadcast — Broadcast title + subtitle + times to all players [MACRO]\n# Sends a complete title display (timing + title + subtitle) to every online player.\n# Unlike cmd/title_all which only sends a plain title to @a with no subtitle or\n# timing control, this sets times and subtitle in the same atomic call.\n#\n# Input (macro args):\n#   title     — title text\n#   subtitle  — subtitle text\n#   color     — title color    (e.g. "red", "#RRGGBB")\n#   sub_color — subtitle color (e.g. "yellow", "#RRGGBB")\n#   fade_in   — ticks to fade in  (e.g. 20)\n#   stay      — ticks to stay     (e.g. 100)\n#   fade_out  — ticks to fade out (e.g. 20)\n#\n# Output → none\n#\n# Usage:\n#   function macro:api/title/broadcast {title:"Server restart in 5 min",\\\n#     subtitle:"Save your progress!",color:"red",sub_color:"yellow",\\\n#     fade_in:20,stay:100,fade_out:20}\n\nexecute unless function macro:debug/tools/utils/check_all run return 0\n\n$title @a times $(fade_in) $(stay) $(fade_out)\n$title @a title {"text":"$(title)","color":"$(color)"}\n$title @a subtitle {"text":"$(subtitle)","color":"$(sub_color)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"title/broadcast ","color":"aqua"},{"text":"@a ","color":"gray"},{"text":"→ ","color":"#555555"},{"text":"$(title)","color":"$(color)"},{"text":" / ","color":"#555555"},{"text":"$(subtitle)","color":"$(sub_color)"}]\n'),
    ('./data/macro/function/api/title/show.mcfunction', '# macro:api/title/show — Atomic title display [MACRO]\n# Sets display timing then shows title + subtitle for one player in a single call.\n# Unlike calling cmd/title_times + cmd/title + cmd/subtitle separately,\n# this guarantees consistent timing for the title/subtitle pair.\n#\n# Input (macro args):\n#   player    — player name selector string (e.g. "Steve")\n#   title     — title text\n#   subtitle  — subtitle text\n#   color     — title color    (e.g. "gold", "#RRGGBB")\n#   sub_color — subtitle color (e.g. "gray", "#RRGGBB")\n#   fade_in   — ticks to fade in  (e.g. 10)\n#   stay      — ticks to stay     (e.g. 60)\n#   fade_out  — ticks to fade out (e.g. 10)\n#\n# Output → none\n#\n# Usage:\n#   function macro:api/title/show {player:"Steve",title:"Hello",subtitle:"welcome back",\\\n#     color:"gold",sub_color:"gray",fade_in:10,stay:60,fade_out:10}\n\nexecute unless function macro:debug/tools/utils/check_all run return 0\n\n$title @a[name=$(player),limit=1] times $(fade_in) $(stay) $(fade_out)\n$title @a[name=$(player),limit=1] title {"text":"$(title)","color":"$(color)"}\n$title @a[name=$(player),limit=1] subtitle {"text":"$(subtitle)","color":"$(sub_color)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"title/show ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(title)","color":"$(color)"},{"text":" / ","color":"#555555"},{"text":"$(subtitle)","color":"$(sub_color)"}]\n'),
    ('./data/macro/function/api/title/show_raw.mcfunction', '# macro:api/title/show_raw — Atomic title display with raw JSON [MACRO]\n# Like title/show but accepts full serialized JSON component strings,\n# allowing gradients, translate, score, selector, and nbt text sources.\n#\n# Input (macro args):\n#   player        — player name selector string (e.g. "Steve")\n#   title_json    — serialized JSON component for title    (must be a valid JSON text component)\n#   subtitle_json — serialized JSON component for subtitle (must be a valid JSON text component)\n#   fade_in       — ticks to fade in\n#   stay          — ticks to stay\n#   fade_out      — ticks to fade out\n#\n# Output → none\n#\n# Usage:\n#   function macro:api/title/show_raw {player:"Steve",\\\n#     title_json:\'{"text":"Hello","color":"gold","bold":true}\',\\\n#     subtitle_json:\'[{"text":"Welcome "},{"score":{"name":"@s","objective":"kills"}}]\',\\\n#     fade_in:10,stay:70,fade_out:20}\n\nexecute unless function macro:debug/tools/utils/check_all run return 0\n\n$title @a[name=$(player),limit=1] times $(fade_in) $(stay) $(fade_out)\n$title @a[name=$(player),limit=1] title $(title_json)\n$title @a[name=$(player),limit=1] subtitle $(subtitle_json)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"title/show_raw ","color":"aqua"},{"text":"$(player)","color":"white"}]\n'),
    ('./data/macro/function/api/trigger/bind.mcfunction', 'execute unless data storage macro:engine trigger_binds run data modify storage macro:engine trigger_binds set value []\n\n$data modify storage macro:engine trigger_binds append value {value:$(value), func:"$(func)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"trigger/bind ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(value)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./data/macro/function/api/trigger/bind_cmd.mcfunction', 'execute unless data storage macro:engine trigger_binds run data modify storage macro:engine trigger_binds set value []\n\n$data modify storage macro:engine trigger_binds append value {value:$(value), cmd:"$(cmd)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"trigger/bind_cmd ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(value)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(cmd)","color":"aqua"}]\n'),
    ('./data/macro/function/api/trigger/disable.mcfunction', '$scoreboard players reset $(player) macro_action\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"trigger/disable ","color":"aqua"},{"text":"· ","color":"#555555"},{"text":"$(player)","color":"white"},{"text":" — macro_action disabled","color":"#555555"}]\n'),
    ('./data/macro/function/api/trigger/enable.mcfunction', '$scoreboard players enable $(player) macro_action\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"trigger/enable ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(player)","color":"white"},{"text":" — macro_action enabled","color":"#555555"}]\n'),
    ('./data/macro/function/api/trigger/list.mcfunction', 'tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Trigger Binds ","color":"aqua"},{"text":"━━━━━━━━━━━━━","color":"#555555"}]\nexecute unless data storage macro:engine trigger_binds[0] run tellraw @s ["",{"text":" ","color":"#555555"},{"text":"(no binds registered)","color":"gray","italic":true}]\nexecute if data storage macro:engine trigger_binds[0] run tellraw @s ["",{"text":" ","color":"#555555"},{"nbt":"trigger_binds","storage":"macro:engine","interpret":false,"color":"yellow"}]\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]\n'),
    ('./data/macro/function/api/trigger/unbind.mcfunction', 'execute unless data storage macro:engine trigger_binds run return 0\n\ndata modify storage macro:engine _tc_unbind set from storage macro:engine trigger_binds\ndata modify storage macro:engine trigger_binds set value []\n\n$data modify storage macro:engine _tc_uval set value $(value)\nfunction macro:api/trigger/internal/unbind_filter\ndata remove storage macro:engine _tc_unbind\ndata remove storage macro:engine _tc_uval\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"trigger/unbind ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"value=$(value)","color":"white"},{"text":" removed","color":"#555555"}]\n'),
    ('./data/macro/function/api/trigger/unbind_all.mcfunction', 'data modify storage macro:engine trigger_binds set value []\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"trigger/unbind_all ","color":"aqua"},{"text":"⚠ ","color":"yellow"},{"text":"all trigger binds cleared","color":"#555555"}]\n'),
    ('./data/macro/function/api/trigger/internal/call.mcfunction', '$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n'),
    ('./data/macro/function/api/trigger/internal/call2.mcfunction', 'tellraw @a[tag=macro.admin] [{"selector":"@s","color":"gold"},{"text":" - command executed","color":"yellow"}]\n\n$$(cmd)\n'),
    ('./data/macro/function/api/trigger/internal/check_next.mcfunction', 'execute unless data storage macro:engine _tc_binds[0] run return 0\n\ndata modify storage macro:engine _tc_current set from storage macro:engine _tc_binds[0]\ndata remove storage macro:engine _tc_binds[0]\n\nexecute store result score $tc_val macro.tmp run data get storage macro:engine _tc_current.value\n\nexecute if score $tc_player macro.tmp = $tc_val macro.tmp if data storage macro:engine _tc_current.func run function macro:api/trigger/internal/call with storage macro:engine _tc_current\n\nexecute if score $tc_player macro.tmp = $tc_val macro.tmp if data storage macro:engine _tc_current.cmd run function macro:api/trigger/internal/call2 with storage macro:engine _tc_current\n\nfunction macro:api/trigger/internal/check_next\n'),
    ('./data/macro/function/api/trigger/internal/dispatch.mcfunction', 'scoreboard players operation $tc_player macro.tmp = @s macro_action\n\nscoreboard players set @s macro_action 0\nscoreboard players enable @s macro_action\n\nexecute unless data storage macro:engine trigger_binds[0] run return 0\n\ndata modify storage macro:engine _tc_binds set from storage macro:engine trigger_binds\n\nfunction macro:api/trigger/internal/check_next\ndata remove storage macro:engine _tc_binds\ndata remove storage macro:engine _tc_current\n'),
    ('./data/macro/function/api/trigger/internal/unbind_filter.mcfunction', 'execute unless data storage macro:engine _tc_unbind[0] run return 0\n\nexecute store result score $tc_fval macro.tmp run data get storage macro:engine _tc_unbind[0].value\n\nexecute store result score $tc_uval macro.tmp run data get storage macro:engine _tc_uval\n\nexecute unless score $tc_fval macro.tmp = $tc_uval macro.tmp run data modify storage macro:engine trigger_binds append from storage macro:engine _tc_unbind[0]\n\ndata remove storage macro:engine _tc_unbind[0]\nfunction macro:api/trigger/internal/unbind_filter\n'),
    ('./data/macro/function/api/wand/cooldown_check.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/cooldown_check\n# Checks whether the wand cooldown is active.\n# NOTE: Wand cooldowns are stored under macro:engine wand_cooldowns;\n#      this avoids collision with macro:cooldown module\'s "$(player).$(key)" path\n# so there is zero risk of key collision.\n#\n# INPUT:\n#   $(player) → player name\n#   $(tag)    → wand tag\n# OUTPUT:\n# macro:output result → 0b=ready (no cooldown), 1b=cooldown active\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output result set value 0b\n\n$execute unless data storage macro:engine wand_cooldowns.$(player).$(tag) run return 0\n\n$execute store result score $wcc_exp macro.tmp run data get storage macro:engine wand_cooldowns.$(player).$(tag)\nexecute store result score $wcc_now macro.tmp run scoreboard players get $epoch macro.time\n\nexecute if score $wcc_now macro.tmp < $wcc_exp macro.tmp run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/cooldown_check ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" [$(tag)] → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/api/wand/cooldown_set.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/cooldown_set\n# Applies a cooldown to wand usage.\n# NOTE: Wand cooldowns are stored under macro:engine wand_cooldowns;\n#      this avoids collision with macro:cooldown module\'s "$(player).$(key)" path\n# so there is zero risk of key collision.\n#\n# INPUT:\n#   $(player)   → player name\n#   $(tag)      → wand tag\n#   $(duration) → cooldown duration (in ticks)\n# ─────────────────────────────────────────────────────────────────\n\n$scoreboard players set $wcd_dur macro.tmp $(duration)\nexecute store result score $wcd_now macro.tmp run scoreboard players get $epoch macro.time\nscoreboard players operation $wcd_now macro.tmp += $wcd_dur macro.tmp\n$execute store result storage macro:engine wand_cooldowns.$(player).$(tag) int 1 run scoreboard players get $wcd_now macro.tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/cooldown_set ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" [$(tag)] ","color":"#555555"},{"text":"$(duration)t","color":"green"}]\n'),
    ('./data/macro/function/api/wand/give.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/give\n# Gives the player a carrot_on_a_stick marked as a wand.\n# The item is automatically tagged with custom_data.\n#\n# INPUT:\n#   $(player) → target player\n#   $(tag)    → wand tag (written into custom_data)\n#   $(name)   → item name (JSON text component, e.g. "Fire Wand")\n#\n# EXAMPLE:\n# data modify storage macro:input player set value "Steve"\n# data modify storage macro:input tag set value "fire_wand"\n# data modify storage macro:input name set value "Fire Wand"\n# function macro:api/wand/give with storage macro:input {}\n# ─────────────────────────────────────────────────────────────────\n\n$give @a[name=$(player),limit=1] minecraft:carrot_on_a_stick[minecraft:custom_data={wand:"$(tag)"},minecraft:item_name={"text":"$(name)"},minecraft:enchantment_glint_override=true]\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/give ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(tag)","color":"aqua"}]\n'),
    ('./data/macro/function/api/wand/give_custom.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/give_custom\n# Gives a custom item tagged as a wand.\n# Any item type can be used (sword, stick, etc.)\n# but right-click only works with carrot_on_a_stick.\n#\n# INPUT:\n#   $(player) → target player\n#   $(item)   → item ID (e.g. "minecraft:carrot_on_a_stick")\n#   $(tag)    → wand tag\n#   $(name)   → item name (JSON text string)\n#   $(count)  → quantity (default 1)\n#\n# EXAMPLE:\n# data modify storage macro:input player set value "Steve"\n# data modify storage macro:input item set value "minecraft:carrot_on_a_stick"\n# data modify storage macro:input tag set value "ice_wand"\n# data modify storage macro:input name set value "Ice Wand"\n# data modify storage macro:input count set value 1\n# function macro:api/wand/give_custom with storage macro:input {}\n# ─────────────────────────────────────────────────────────────────\n\n$give @a[name=$(player),limit=1] $(item)[minecraft:custom_data={wand:"$(tag)"},minecraft:item_name={"text":"$(name)"},minecraft:enchantment_glint_override=true] $(count)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/give_custom ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(item)","color":"aqua"},{"text":" [$(tag)]","color":"#555555"}]\n'),
    ('./data/macro/function/api/wand/give_lore.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/give_lore\n# Writes the wand with lore to mainhand (item replace).\n#\n# INPUT (storage macro:input):\n# player → target player name\n# tag → wand tag\n# name → item name (string)\n# lore → lore metni, TEK SATIR (string)\n# color → lore color (e.g. "red", "gold", "gray")\n#\n# EXAMPLE:\n# data modify storage macro:input player set value "Steve"\n# data modify storage macro:input tag set value "fire_wand"\n# data modify storage macro:input name set value "Fire Wand"\n# data modify storage macro:input lore set value "Fire Damage: +20"\n# data modify storage macro:input color set value "red"\n# function macro:api/wand/give_lore\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:api/wand/internal/give_lore_exec with storage macro:input {}\n'),
    ('./data/macro/function/api/wand/has.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/has\n# Does the player hold a specific wand in their main hand?\n#\n# INPUT:\n#   $(player) → player name\n#   $(tag)    → kontrol edilecek wand tag\n# OUTPUT:\n# macro:output result → 1b (found) / 0b (not found)\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output result set value 0b\n$execute as @a[name=$(player),limit=1] if items entity @s weapon.mainhand *[minecraft:custom_data~{wand:"$(tag)"}] run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/has ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" [$(tag)] → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/api/wand/list.mcfunction', '# macro:api/wand/list — Shows registered wand binds.\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Wand Binds ","color":"aqua"},{"text":"━━━━━━━━━━━━━━━","color":"#555555"}]\nexecute unless data storage macro:engine wand_binds[0] run tellraw @s ["",{"text":" ","color":"#555555"},{"text":"(no wand binds)","color":"gray","italic":true}]\nexecute if data storage macro:engine wand_binds[0] run tellraw @s ["",{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"wand_binds","interpret":false,"color":"yellow"}]\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]\n'),
    ('./data/macro/function/api/wand/register.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/register\n# Registers a wand with a specific custom_data tag.\n# On every item use, $(func) or $(cmd) runs.\n#\n# INPUT:\n#   $(tag)  → custom_data tag name (e.g. "my_wand")\n#   $(func) → (optional) function to run\n#   $(cmd)  → (optional) command to run (if no func)\n#\n# OUTPUT: record added to macro:engine wand_binds list\n#\n# EXAMPLE:\n# data modify storage macro:input tag set value "fire_wand"\n# data modify storage macro:input func set value "mypack:on_fire_wand"\n# function macro:api/wand/register with storage macro:input {}\n# ─────────────────────────────────────────────────────────────────\n\nexecute unless data storage macro:engine wand_binds run data modify storage macro:engine wand_binds set value []\n\n#$execute if data storage macro:input {func:"$(func)"} run data modify storage macro:engine wand_binds append value {tag:"$(tag)", func:"$(func)"}\n#$execute unless data storage macro:input {func:"$(func)"} run data modify storage macro:engine wand_binds append value {tag:"$(tag)", cmd:"$(cmd)"}\n\n$data modify storage macro:engine wand_binds append value {tag:"$(tag)", cmd:"$(cmd)",func:"$(func)"}\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/register ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(tag)","color":"white"}]\n'),
    ('./data/macro/function/api/wand/register_cmd.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/register_cmd\n# Binds a command to the wand (raw command instead of func).\n#\n# INPUT:\n#   $(tag) → custom_data tag name\n#   $(cmd) → raw command to run\n# ─────────────────────────────────────────────────────────────────\n\nexecute unless data storage macro:engine wand_binds run data modify storage macro:engine wand_binds set value []\n\n$data modify storage macro:engine wand_binds append value {tag:"$(tag)", cmd:"$(cmd)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/register_cmd ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(tag)","color":"white"},{"text":" → cmd","color":"#555555"}]\n'),
    ('./data/macro/function/api/wand/register_fn.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/register_cmd\n# Binds a command to the wand (raw command instead of func).\n#\n# INPUT:\n#   $(tag) → custom_data tag name\n#   $(cmd) → raw command to run\n# ─────────────────────────────────────────────────────────────────\n\nexecute unless data storage macro:engine wand_binds run data modify storage macro:engine wand_binds set value []\n\n$data modify storage macro:engine wand_binds append value {tag:"$(tag)", func:"$(func)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/register_cmd ","color":"aqua"},{"text":"✔ ","color":"green"},{"text":"$(tag)","color":"white"},{"text":" → func","color":"#555555"}]\n'),
    ('./data/macro/function/api/wand/unregister.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/unregister\n# Removes all wand binds belonging to a specific tag.\n#\n# INPUT (storage macro:input):\n# tag → wand tag to remove\n#\n# EXAMPLE:\n# data modify storage macro:input tag set value "fire_wand"\n# function macro:api/wand/unregister\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:api/wand/internal/unregister_exec with storage macro:input {}\n'),
    ('./data/macro/function/api/wand/unregister_all.mcfunction', '# macro:api/wand/unregister_all — Clears all wand binds.\ndata modify storage macro:engine wand_binds set value []\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/unregister_all ","color":"aqua"},{"text":"⚠ all wand binds cleared","color":"yellow"}]\n'),
    ('./data/macro/function/api/wand/internal/call_cmd.mcfunction', '# macro:api/wand/internal/call_cmd [MACRO]\ntellraw @a[tag=macro.admin] [{"selector":"@s","color":"gold"},{"text":" - command executed","color":"yellow"}]\n\n$$(cmd)\n'),
    ('./data/macro/function/api/wand/internal/call_func.mcfunction', '# macro:api/wand/internal/call_func [MACRO]\n$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n'),
    ('./data/macro/function/api/wand/internal/check_item.mcfunction', '# macro:api/wand/internal/check_item [MACRO]\n# $(tag) → custom_data tag name\n# If the item in the player\'s main hand has this tag, run the bind.\n\n$execute if items entity @s weapon.mainhand *[minecraft:custom_data~{wand:"$(tag)"}] run function macro:api/wand/internal/fire with storage macro:engine _wand_current\n'),
    ('./data/macro/function/api/wand/internal/check_next.mcfunction', '# macro:api/wand/internal/check_next\n# Iterate bind list: match the tag of the held item.\n\nexecute unless data storage macro:engine _wand_iter[0] run return 0\n\ndata modify storage macro:engine _wand_current set from storage macro:engine _wand_iter[0]\ndata remove storage macro:engine _wand_iter[0]\n\nfunction macro:api/wand/internal/check_item with storage macro:engine _wand_current\n\nfunction macro:api/wand/internal/check_next\n'),
    ('./data/macro/function/api/wand/internal/dispatch.mcfunction', '# macro:api/wand/internal/dispatch\n# Called as @s. Compare held items with the bind list.\n\ndata modify storage macro:engine _wand_iter set from storage macro:engine wand_binds\nexecute if data storage macro:engine _wand_iter[0] run function macro:api/wand/internal/check_next\ndata remove storage macro:engine _wand_iter\ndata remove storage macro:engine _wand_current\n'),
    ('./data/macro/function/api/wand/internal/fire.mcfunction', '# macro:api/wand/internal/fire [MACRO]\n# Run the bind based on func or cmd field.\n\nexecute if data storage macro:engine _wand_current.func run function macro:api/wand/internal/call_func with storage macro:engine _wand_current\nexecute if data storage macro:engine _wand_current.cmd run function macro:api/wand/internal/call_cmd with storage macro:engine _wand_current\n'),
    ('./data/macro/function/api/wand/internal/give_lore_exec.mcfunction', '# macro:api/wand/internal/give_lore_exec [MACRO]\n# INPUT (macro): $(player), $(tag), $(name), $(lore), $(color)\n#\n# Writes with lore directly to mainhand via item replace weapon.mainhand.\n# Not give but item replace — places directly in slot 0 (mainhand).\n\n$item replace entity @a[name=$(player),limit=1] weapon.mainhand with minecraft:carrot_on_a_stick[minecraft:custom_data={wand:"$(tag)"},minecraft:item_name={"text":"$(name)"},minecraft:lore=[{"text":"$(lore)","italic":false,"color":"$(color)"}],minecraft:enchantment_glint_override=true]\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/give_lore ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(tag)","color":"aqua"}]\n'),
    ('./data/macro/function/api/wand/internal/tick_scan.mcfunction', '# macro:api/wand/internal/tick_scan\n# Every tick: detect players with macro.rightClick score 1+,\n# check their held item, run the matching bind.\n\nexecute unless data storage macro:engine wand_binds[0] run return 0\n\nexecute as @a[scores={macro.rightClick=1..}] at @s run function macro:api/wand/internal/dispatch\nscoreboard players set @a[scores={macro.rightClick=1..}] macro.rightClick 0\n'),
    ('./data/macro/function/api/wand/internal/unbind_check.mcfunction', '# macro:api/wand/internal/unbind_check [MACRO]\n# $(tag) is the tag of the current record. Add back if it does not match _wand_filter_tag.\n\n$execute unless data storage macro:engine {_wand_filter_tag:"$(tag)"} run data modify storage macro:engine wand_binds append from storage macro:engine _wand_cur\n'),
    ('./data/macro/function/api/wand/internal/unbind_filter.mcfunction', '# macro:api/wand/internal/unbind_filter\n# Write back entries from _wand_unbinds that do not match _wand_filter_tag.\n\nexecute unless data storage macro:engine _wand_unbinds[0] run return 0\n\ndata modify storage macro:engine _wand_cur set from storage macro:engine _wand_unbinds[0]\ndata remove storage macro:engine _wand_unbinds[0]\n\nfunction macro:api/wand/internal/unbind_check with storage macro:engine _wand_cur\n\nfunction macro:api/wand/internal/unbind_filter\ndata remove storage macro:engine _wand_cur\n'),
    ('./data/macro/function/api/wand/internal/unregister_exec.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:api/wand/unregister\n# Removes all wand binds belonging to a specific tag.\n#\n# INPUT:\n#   $(tag) → tag to remove\n# ─────────────────────────────────────────────────────────────────\n\nexecute unless data storage macro:engine wand_binds run return 0\n\ndata modify storage macro:engine _wand_unbinds set from storage macro:engine wand_binds\ndata modify storage macro:engine wand_binds set value []\n$data modify storage macro:engine _wand_filter_tag set value "$(tag)"\nfunction macro:api/wand/internal/unbind_filter\ndata remove storage macro:engine _wand_unbinds\ndata remove storage macro:engine _wand_filter_tag\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/unregister ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"$(tag)","color":"white"},{"text":" removed","color":"#555555"}]\n'),
    ('./data/macro/function/core/tick.mcfunction', '# AME Tick Engine v2 — Entry Point\n# Driven by #minecraft:tick function tag (guaranteed 1/game-tick, no drift).\n#\n# All rate/offset/condition/pause logic is inside the channel dispatcher.\n# Do NOT add any per-system logic here — register a channel instead.\n\n# Guard: no players online → nothing to process\nexecute unless entity @a run return 0\n\n# Guard: engine not initialised\nexecute unless data storage macro:engine global{loaded:1b} run return 0\n\n# Online player count — kept for compatibility\nexecute store result score #online macro.onlinePlayers if entity @a\n\n# Guard: globally paused (macro:core/tick/pause / macro:core/tick/resume)\nexecute if data storage macro:engine tick{paused:1b} run return 0\n\nexecute as @a run function macro:core/tick/dispatch'),
    ('./data/macro/function/core/cmd/exec.mcfunction', '# macro:core/cmd/exec\n# Bridges macro:input cmd → macro:engine tools_trigger → dispatch.\n# Called only when macro:input cmd exists.\n\ndata modify storage macro:engine tools_trigger set from storage macro:input cmd\nfunction macro:debug/tools/trigger/internal/dispatch\ndata remove storage macro:engine tools_trigger\ndata remove storage macro:input cmd\n'),
    ('./data/macro/function/core/cmd/run.mcfunction', '# macro:core/cmd/run\n# Entry point for the command dispatcher.\n# Fires when any player triggers macro_run (via player_systems.mcfunction).\n# Expects macro:input cmd to be set before triggering:\n#   data merge storage macro:input {cmd:{type:"...", data:{...}}}\n#   /trigger macro_run set 1\n#\n# Available types: see macro:debug/tools/trigger/internal/dispatch for full list.\n# Examples:\n#   msg         → data:{player:"Name", message:"..."}\n#   give        → data:{player:"Name", item:"minecraft:diamond", count:1}\n#   gamemode    → data:{player:"Name", mode:"survival"}\n#   tp          → data:{player:"Name", x:0, y:64, z:0}\n#   effect_add  → data:{player:"Name", effect:"minecraft:speed", duration:100, amplifier:1}\n#   score_set   → data:{player:"Name", objective:"obj", value:10}\n#   tag_add     → data:{player:"Name", tag:"myTag"}\n#   xp          → data:{player:"Name", amount:100, type:"points"}\n#   fill        → data:{x1:0,y1:0,z1:0,x2:1,y2:1,z2:1,block:"minecraft:stone"}\n#   setblock    → data:{x:0, y:64, z:0, block:"minecraft:stone"}\n\nexecute if data storage macro:input cmd run function macro:core/cmd/exec\nexecute unless data storage macro:input cmd run tellraw @s [{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd: ","color":"aqua"},{"text":"macro:input cmd not set","color":"red"}]\n'),
    ('./data/macro/function/core/config/delete.mcfunction', '$data remove storage macro:engine config.$(key)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"config/delete ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]\n'),
    ('./data/macro/function/core/config/get.mcfunction', 'data modify storage macro:output result set value ""\n\n$execute if data storage macro:engine config.$(key) run data modify storage macro:output result set from storage macro:engine config.$(key)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"config/get ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/config/has.mcfunction', 'data modify storage macro:output result set value 0b\n$execute if data storage macro:engine config.$(key) run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"config/has ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/config/list.mcfunction', 'tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Config Values ","color":"aqua"},{"text":"━━━━━━━━━━━","color":"#555555"}]\nexecute if data storage macro:engine config run tellraw @a[tag=macro.debug] ["",{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"config","interpret":false,"color":"green"}]\nexecute unless data storage macro:engine config run tellraw @a[tag=macro.debug] ["",{"text":" ","color":"#555555"},{"text":"(no config values set)","color":"gray","italic":true}]\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]'),
    ('./data/macro/function/core/config/reset.mcfunction', 'data remove storage macro:engine config\n'),
    ('./data/macro/function/core/config/score_get.mcfunction', '# macro:core/config/score_get\n# Prints a config value to the caller (admin only, debug use).\n# Usage: $function macro:core/config/score_get {key:"damage"}\nexecute unless entity @s[tag=macro.admin] run return 0\n$tellraw @s ["",{"text":"[Config] ","color":"aqua"},{"text":"#$(key)","color":"white"},{"text":" = ","color":"#555555"},{"score":{"name":"#$(key)","objective":"macro.config"},"color":"green"}]\n'),
    ('./data/macro/function/core/config/score_set.mcfunction', '# macro:core/config/score_set\n# Sets an integer config value on the macro.config scoreboard.\n# Usage: $function macro:core/config/score_set {key:"damage",value:5}\n# Read back: scoreboard players get #damage macro.config\n$scoreboard players set #$(key) macro.config $(value)\n'),
    ('./data/macro/function/core/config/set.mcfunction', '$data modify storage macro:engine config.$(key) set value "$(value)"\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"config/set ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]\n'),
    ('./data/macro/function/core/config/set_default.mcfunction', 'data modify storage macro:output result set value 1b\n\n$execute if data storage macro:engine config.$(key) run data modify storage macro:output result set value 0b\n$execute if data storage macro:engine config.$(key) run return 0\n\n$data modify storage macro:engine config.$(key) set value "$(value)"\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"config/set_default ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/config/set_int.mcfunction', '$execute store result storage macro:engine config.$(key) int 1 run scoreboard players set $cfg_tmp macro.tmp $(value)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"config/set_int ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]\n'),
    ('./data/macro/function/core/cooldown/check.mcfunction', 'data modify storage macro:output result set value 1b\n\n$execute unless data storage macro:engine cooldowns.$(player).$(key) run return 0\n\n$execute store result score $cd_exp macro.tmp run data get storage macro:engine cooldowns.$(player).$(key)\nexecute store result score $cd_now macro.tmp run scoreboard players get $epoch macro.time\n\nexecute if score $cd_now macro.tmp < $cd_exp macro.tmp run data modify storage macro:output result set value 0b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/check ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/cooldown/clear.mcfunction', '$data remove storage macro:engine cooldowns.$(player).$(key)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/clear ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"$(player)","color":"white"},{"text":":","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" cleared","color":"#555555"}]\n'),
    ('./data/macro/function/core/cooldown/clear_all.mcfunction', '$data remove storage macro:engine cooldowns.$(player)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/clear_all ","color":"aqua"},{"text":"✘ ","color":"red"},{"text":"$(player)","color":"white"},{"text":" — all cooldowns cleared","color":"#555555"}]\n'),
    ('./data/macro/function/core/cooldown/detail.mcfunction', 'data merge storage macro:output {active:0b,remaining:0,expires:0}\n\n$execute unless data storage macro:engine cooldowns.$(player).$(key) run return 0\n\n$execute store result score $cdd_exp macro.tmp run data get storage macro:engine cooldowns.$(player).$(key)\nexecute store result storage macro:output expires int 1 run scoreboard players get $cdd_exp macro.tmp\n\nexecute store result score $cdd_now macro.tmp run scoreboard players get $epoch macro.time\n\nexecute if score $cdd_now macro.tmp < $cdd_exp macro.tmp run data modify storage macro:output active set value 1b\n\nscoreboard players operation $cdd_exp macro.tmp -= $cdd_now macro.tmp\nexecute if score $cdd_exp macro.tmp matches 1.. run execute store result storage macro:output remaining int 1 run scoreboard players get $cdd_exp macro.tmp\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/detail ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" active=","color":"#555555"},{"storage":"macro:output","nbt":"active","color":"green"},{"text":" rem=","color":"#555555"},{"storage":"macro:output","nbt":"remaining","color":"green"},{"text":" exp=","color":"#555555"},{"storage":"macro:output","nbt":"expires","color":"green"}]\n'),
    ('./data/macro/function/core/cooldown/extend.mcfunction', 'execute store result score $ce_base macro.tmp run scoreboard players get $epoch macro.time\nscoreboard players operation $ce_exp macro.tmp = $ce_base macro.tmp\n\n$execute if data storage macro:engine cooldowns.$(player).$(key) run execute store result score $ce_exp macro.tmp run data get storage macro:engine cooldowns.$(player).$(key)\n\nexecute if score $ce_exp macro.tmp <= $ce_base macro.tmp run scoreboard players operation $ce_exp macro.tmp = $ce_base macro.tmp\n\n$scoreboard players set $ce_amt macro.tmp $(amount)\nscoreboard players operation $ce_exp macro.tmp += $ce_amt macro.tmp\n\n$execute store result storage macro:engine cooldowns.$(player).$(key) int 1 run scoreboard players get $ce_exp macro.tmp\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/extend ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":":","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" +$(amount)t","color":"green"},{"text":" → exp=","color":"#555555"},{"score":{"name":"$ce_exp","objective":"macro.tmp"},"color":"yellow"}]\n'),
    ('./data/macro/function/core/cooldown/is_ready.mcfunction', '$data modify storage macro:input player set value "$(player)"\n$data modify storage macro:input key set value "$(key)"\nfunction macro:core/cooldown/check with storage macro:input {}\n# check: result=0b → cooldown active. is_ready returns the inverse.\nexecute if data storage macro:output {result:0b} run data modify storage macro:output result set value 1b\nexecute if data storage macro:output {result:1b} run data modify storage macro:output result set value 0b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/is_ready ","color":"aqua"},{"text":"$(player):$(key) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/cooldown/pause.mcfunction', '# macro:core/cooldown/pause\n# Pauses an active cooldown, saving the remaining ticks.\n# Params: player, key\n# Output: macro:output result (remaining ticks saved), 0b if not active\n\ndata modify storage macro:output result set value 0b\n\n$execute unless data storage macro:engine cooldowns.$(player).$(key) run return 0\n\n# Calculate remaining ticks\n$execute store result score $cdp_exp macro.tmp run data get storage macro:engine cooldowns.$(player).$(key)\nexecute store result score $cdp_now macro.tmp run scoreboard players get $epoch macro.time\nscoreboard players operation $cdp_exp macro.tmp -= $cdp_now macro.tmp\n\n# Only pause if actually still active\nexecute unless score $cdp_exp macro.tmp matches 1.. run return 0\n\n# Save remaining ticks to paused storage and clear the live cooldown\n$execute store result storage macro:engine paused_cooldowns.$(player).$(key) int 1 run scoreboard players get $cdp_exp macro.tmp\n$data remove storage macro:engine cooldowns.$(player).$(key)\nexecute store result storage macro:output result int 1 run scoreboard players get $cdp_exp macro.tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/pause ","color":"aqua"},{"text":"⏸ ","color":"yellow"},{"text":"$(player)","color":"white"},{"text":":","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"},{"text":"t remaining","color":"#555555"}]\n'),
    ('./data/macro/function/core/cooldown/remaining.mcfunction', 'data modify storage macro:output result set value 0\n$execute unless data storage macro:engine cooldowns.$(player).$(key) run return 0\n\n$execute store result score $cd_exp macro.tmp run data get storage macro:engine cooldowns.$(player).$(key)\nexecute store result score $cd_now macro.tmp run scoreboard players get $epoch macro.time\n\nscoreboard players operation $cd_exp macro.tmp -= $cd_now macro.tmp\nexecute if score $cd_exp macro.tmp matches 1.. run execute store result storage macro:output result int 1 run scoreboard players get $cd_exp macro.tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/remaining ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/cooldown/reset_all.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/cooldown/reset_all\n# Clears all active cooldowns for a player.\n#  Girdi : $(player) → player name\n# Output: (side effect only)\n#\n# Example:\n# data modify storage macro:input player set value "Steve"\n# function macro:core/cooldown/reset_all with storage macro:input {}\n# ─────────────────────────────────────────────────────────────────\n\n$data remove storage macro:engine cooldowns.$(player)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/reset_all ","color":"aqua"},{"text":"$(player) all cooldowns cleared","color":"yellow"}]\n'),
    ('./data/macro/function/core/cooldown/resume.mcfunction', '# macro:core/cooldown/resume\n# Resumes a previously paused cooldown.\n# Params: player, key\n# Output: macro:output result (new expiry epoch tick), 0b if not paused\n\ndata modify storage macro:output result set value 0b\n\n$execute unless data storage macro:engine paused_cooldowns.$(player).$(key) run return 0\n\n# Reconstruct expiry: now + saved remaining ticks\n$execute store result score $cdr_rem macro.tmp run data get storage macro:engine paused_cooldowns.$(player).$(key)\nexecute store result score $cdr_now macro.tmp run scoreboard players get $epoch macro.time\nscoreboard players operation $cdr_now macro.tmp += $cdr_rem macro.tmp\n\n# Write back to live cooldowns, remove from paused\n$execute store result storage macro:engine cooldowns.$(player).$(key) int 1 run scoreboard players get $cdr_now macro.tmp\n$data remove storage macro:engine paused_cooldowns.$(player).$(key)\nexecute store result storage macro:output result int 1 run scoreboard players get $cdr_now macro.tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/resume ","color":"aqua"},{"text":"▶ ","color":"green"},{"text":"$(player)","color":"white"},{"text":":","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" resumed (","color":"#555555"},{"score":{"name":"$cdr_rem","objective":"macro.tmp"},"color":"yellow"},{"text":"t remaining)","color":"#555555"}]\n'),
    ('./data/macro/function/core/cooldown/set.mcfunction', '$scoreboard players set $cd_dur macro.tmp $(duration)\nexecute store result score $cd_now macro.tmp run scoreboard players get $epoch macro.time\nscoreboard players operation $cd_now macro.tmp += $cd_dur macro.tmp\n$execute store result storage macro:engine cooldowns.$(player).$(key) int 1 run scoreboard players get $cd_now macro.tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cooldown/set ","color":"aqua"},{"text":"→ ","color":"#555555"},{"text":"$(player)","color":"white"},{"text":":","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" for ","color":"#555555"},{"text":"$(duration)","color":"green"},{"text":"t","color":"#555555"}]\n'),
    ('./data/macro/function/core/disable/main.mcfunction', '# macro:disable — Dangerous command (confirmation gate required)\n#\n# Shuts down macroEngine: removes all AME scoreboards, wipes macro:engine\n# and macro:input storage, kills all AME marker entities.\n#\n# CHANGE FROM PREVIOUS BEHAVIOUR\n# --------------------------------\n# This function NO LONGER runs cleanup immediately.\n# It stores the disable intent in macro:engine pending_gate and opens the\n# dangerous-command gate. Cleanup runs only after admin confirms:\n#   /function ame_load:gate/yes\n#\n# To cancel:\n#   /function ame_load:gate/no\n#\n# Auto-cancel fires after 30 seconds if no response.\n#\n# REQUIRES: macro.admin tag on calling entity\n# (check_all → perm_check verifies this before any caller reaches here)\n\ndata modify storage macro:engine pending_gate set value {type:"disable"}\nfunction ame_load:gate/request\n'),
    ('./data/macro/function/core/dispatch/exec.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/dispatch/exec [MACRO]\n# THE ONLY file in AME that executes $function $(func).\n# Do NOT call directly — use #macro:internal/dispatch.\n#\n# INPUT (macro:engine._dispatch): func → fully-qualified function name\n# ─────────────────────────────────────────────────────────────────\n$function $(func)\n'),
    ('./data/macro/function/core/dispatch/run.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/dispatch/run\n# Central function dispatch gateway — called via #macro:internal/dispatch.\n# Reads func from macro:engine._dispatch and calls exec via macro.\n#\n# Override #macro:internal/dispatch in your overlay/pack to inject\n# validation or logging without touching call sites.\n# ─────────────────────────────────────────────────────────────────\nfunction macro:core/dispatch/exec with storage macro:engine _dispatch\n'),
    ('./data/macro/function/core/engine/call/execute_validated.mcfunction', '# ─────────────────────────────────────────────\n# macro:core/engine/call/execute_validated\n# Runs a function that has passed security validation.\n# Called only by macro:debug/tools/utils/input_check.\n#\n# Girdi (macro:output.inputs):\n# func — function name to run (already validated)\n# Veri (macro:input):\n# All parameters to pass to the function\n# ─────────────────────────────────────────────\n\n# Pass validated func name to macro sub-function and run\nfunction macro:core/engine/call/execute_validated/run with storage macro:output inputs\n'),
    ('./data/macro/function/core/engine/call/execute_validated/run.mcfunction', '# ─────────────────────────────────────────────\n# macro:core/engine/call/execute_validated/run\n# Expands and runs the validated function via macro.\n#  Gets $(func) variable from macro:output.inputs storage,\n# uses macro:input storage as the parameter source.\n# ─────────────────────────────────────────────\n\n$function $(func) with storage macro:input {}\n'),
    ('./data/macro/function/core/fallback/check.mcfunction', '# macro:core/fallback/check\n# Returns 1 if a fallback was triggered in the last call, 0 otherwise.\n# Usage:\n#   function macro:core/fallback/clear\n#   function ns:your/action\n#   execute if data storage macro:output fallback{triggered:1b} run function ns:handle_failure\n#   function macro:core/fallback/check   ← or use this for return-based checks\nexecute if data storage macro:output fallback{triggered:1b} run return 1\nreturn 0\n'),
    ('./data/macro/function/core/fallback/clear.mcfunction', '# macro:core/fallback/clear\n# Clears the fallback state from macro:output.\n# Call this before an action chain to get a clean fallback check afterwards.\n# Usage: function macro:core/fallback/clear\ndata remove storage macro:output fallback\n'),
    ('./data/macro/function/core/fallback/entity_missing.mcfunction', '# macro:core/fallback/entity_missing\n# Called when a required entity target was not found.\ndata modify storage macro:input message set value "[Fallback] entity_missing — no valid target found"\ndata modify storage macro:input level set value "WARN"\ndata modify storage macro:input color set value "yellow"\nexecute if score #ame.log_level ame.log_level matches 2.. run function macro:systems/log/add with storage macro:input {}\ndata modify storage macro:output fallback set value {triggered:1b,reason:"entity_missing"}\nreturn 0\n'),
    ('./data/macro/function/core/fallback/generic.mcfunction', '# macro:core/fallback/generic\n# Called when no specific fallback applies.\ndata modify storage macro:input message set value "[Fallback] generic fallback triggered"\ndata modify storage macro:input level set value "WARN"\ndata modify storage macro:input color set value "yellow"\nexecute if score #ame.log_level ame.log_level matches 2.. run function macro:systems/log/add with storage macro:input {}\ndata modify storage macro:output fallback set value {triggered:1b,reason:"generic"}\nreturn 0\n'),
    ('./data/macro/function/core/fallback/invalid_score.mcfunction', '# macro:core/fallback/invalid_score\n# Called when a required scoreboard value is absent or out of range.\ndata modify storage macro:input message set value "[Fallback] invalid_score — score missing or out of range, using default"\ndata modify storage macro:input level set value "WARN"\ndata modify storage macro:input color set value "yellow"\nexecute if score #ame.log_level ame.log_level matches 2.. run function macro:systems/log/add with storage macro:input {}\ndata modify storage macro:output fallback set value {triggered:1b,reason:"invalid_score"}\nreturn 0\n'),
    ('./data/macro/function/core/fallback/no_permission.mcfunction', '# macro:core/fallback/no_permission\n# Called when the executor lacks macro.admin tag.\ndata modify storage macro:input message set value "[Fallback] no_permission — macro.admin tag required"\ndata modify storage macro:input level set value "WARN"\ndata modify storage macro:input color set value "yellow"\nexecute if score #ame.log_level ame.log_level matches 2.. run function macro:systems/log/add with storage macro:input {}\ndata modify storage macro:output fallback set value {triggered:1b,reason:"no_permission"}\nreturn 0\n'),
    ('./data/macro/function/core/fallback/not_loaded.mcfunction', '# macro:core/fallback/not_loaded\n# Called when the engine is not initialized.\ndata modify storage macro:input message set value "[Fallback] not_loaded — macroEngine not initialized, run /function macro:load"\ndata modify storage macro:input level set value "ERROR"\ndata modify storage macro:input color set value "red"\nexecute if score #ame.log_level ame.log_level matches 1.. run function macro:systems/log/add with storage macro:input {}\ndata modify storage macro:output fallback set value {triggered:1b,reason:"not_loaded"}\nreturn 0\n'),
    ('./data/macro/function/core/fallback/storage_missing.mcfunction', '# macro:core/fallback/storage_missing\n# Called when expected NBT storage data is absent.\ndata modify storage macro:input message set value "[Fallback] storage_missing — required NBT key not found"\ndata modify storage macro:input level set value "WARN"\ndata modify storage macro:input color set value "yellow"\nexecute if score #ame.log_level ame.log_level matches 2.. run function macro:systems/log/add with storage macro:input {}\ndata modify storage macro:output fallback set value {triggered:1b,reason:"storage_missing"}\nreturn 0\n'),
