    ('./data/macro/function/core/lib/string/concat.mcfunction', '# macro:core/lib/string/concat\n# Input:  macro:input list   — list of strings to concatenate\n# Output: macro:output string.result — combined string\n# Dep:    StringLib (CMDred)\ndata modify storage stringlib:input concat set from storage macro:input list\nfunction stringlib:util/concat\ndata modify storage macro:output string.result set from storage stringlib:output concat\ndata remove storage stringlib:input concat\ndata remove storage stringlib:output concat\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/concat","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/find.mcfunction', '# macro:core/lib/string/find\n# Input:  macro:input string  — haystack string\n#         macro:input find    — substring to search\n#         macro:input n       — instance count (0=all, +n=first n, -n=last n)\n# Output: macro:output string.result — list of start indices, or [-1] if not found\n# Dep:    StringLib (CMDred)\ndata modify storage stringlib:input find.String set from storage macro:input string\ndata modify storage stringlib:input find.Find set from storage macro:input find\ndata remove storage stringlib:input find.n\ndata modify storage stringlib:input find.n set from storage macro:input n\nfunction stringlib:util/find\ndata modify storage macro:output string.result set from storage stringlib:output find\ndata remove storage stringlib:input find\ndata remove storage stringlib:output find\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/find","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/insert.mcfunction', '# macro:core/lib/string/insert\n# Input:  macro:input string    — original string\n#         macro:input insertion — string to insert\n#         macro:input index     — insertion position (integer)\n# Output: macro:output string.result — resulting string\n# Dep:    StringLib (CMDred)\ndata modify storage stringlib:input insert.String set from storage macro:input string\ndata modify storage stringlib:input insert.Insertion set from storage macro:input insertion\ndata modify storage macro:engine _str_bridge.Index set from storage macro:input index\nfunction macro:core/lib/string/internal/insert_dispatch with storage macro:engine _str_bridge\ndata modify storage macro:output string.result set from storage stringlib:output insert\ndata remove storage stringlib:input insert\ndata remove storage stringlib:output insert\ndata remove storage macro:engine _str_bridge\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/insert","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/replace.mcfunction', '# macro:core/lib/string/replace\n# Input:  macro:input string  — original string\n#         macro:input find    — substring to replace\n#         macro:input replace — replacement string\n#         macro:input n       — instance count (0/unset=all, +n=first n, -n=last n)\n# Output: macro:output string.result — resulting string\n# Dep:    StringLib (CMDred)\ndata modify storage stringlib:input replace.String set from storage macro:input string\ndata modify storage stringlib:input replace.Find set from storage macro:input find\ndata modify storage stringlib:input replace.Replace set from storage macro:input replace\ndata remove storage stringlib:input replace.n\ndata modify storage stringlib:input replace.n set from storage macro:input n\nfunction stringlib:util/replace\ndata modify storage macro:output string.result set from storage stringlib:output replace\ndata remove storage stringlib:input replace\ndata remove storage stringlib:output replace\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/replace","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/split.mcfunction', '# macro:core/lib/string/split\n# Input:  macro:input string      — original string\n#         macro:input separator   — split delimiter (default " ", ""=each char)\n#         macro:input n           — max splits (0/unset=all, +n=first n, -n=last n)\n#         macro:input keep_empty  — 1b to keep empty segments, omit/0b to strip\n# Output: macro:output string.result — list of string segments\n# Dep:    StringLib (CMDred)\ndata modify storage stringlib:input split.String set from storage macro:input string\ndata remove storage stringlib:input split.Separator\ndata modify storage stringlib:input split.Separator set from storage macro:input separator\ndata remove storage stringlib:input split.n\ndata modify storage stringlib:input split.n set from storage macro:input n\ndata remove storage stringlib:input split.KeepEmpty\ndata modify storage stringlib:input split.KeepEmpty set from storage macro:input keep_empty\nfunction stringlib:util/split\ndata modify storage macro:output string.result set from storage stringlib:output split\ndata remove storage stringlib:input split\ndata remove storage stringlib:output split\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/split","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/to_lowercase.mcfunction', '# macro:core/lib/string/to_lowercase\n# Fast variant — covers A-Z only (faster)\n# Input:  macro:input string — string to convert\n# Output: macro:output string.result — lowercase string\n# Dep:    StringLib (CMDred)\ndata modify storage macro:engine _str_bridge.String set from storage macro:input string\nfunction macro:core/lib/string/internal/to_lower_fast_dispatch with storage macro:engine _str_bridge\ndata modify storage macro:output string.result set from storage stringlib:output to_lowercase\ndata remove storage stringlib:output to_lowercase\ndata remove storage macro:engine _str_bridge\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/to_lowercase","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/to_lowercase_full.mcfunction', '# macro:core/lib/string/to_lowercase_full\n# Full variant — covers full Unicode uppercase mapping (slower)\n# Input:  macro:input string — string to convert\n# Output: macro:output string.result — lowercase string\n# Dep:    StringLib (CMDred)\ndata modify storage macro:engine _str_bridge.String set from storage macro:input string\nfunction macro:core/lib/string/internal/to_lower_full_dispatch with storage macro:engine _str_bridge\ndata modify storage macro:output string.result set from storage stringlib:output to_lowercase\ndata remove storage stringlib:output to_lowercase\ndata remove storage macro:engine _str_bridge\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/to_lowercase_full","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/to_number.mcfunction', '# macro:core/lib/string/to_number\n# Input:  macro:input string — numeric string (e.g. "42" or "3.14")\n# Output: macro:output string.result — numeric NBT value\n# Dep:    StringLib (CMDred)\ndata modify storage macro:engine _str_bridge.Input set from storage macro:input string\nfunction macro:core/lib/string/internal/to_number_dispatch with storage macro:engine _str_bridge\ndata modify storage macro:output string.result set from storage stringlib:output to_number\ndata remove storage stringlib:output to_number\ndata remove storage macro:engine _str_bridge\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/to_number","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/to_string.mcfunction', '# macro:core/lib/string/to_string\n# Input:  macro:input value — numeric or any SNBT value to stringify\n# Output: macro:output string.result — string representation\n# Note:   Prefer \'data modify ... set string storage ...\' when possible (cheaper)\n# Dep:    StringLib (CMDred)\ndata modify storage macro:engine _str_bridge.Input set from storage macro:input value\nfunction macro:core/lib/string/internal/to_string_dispatch with storage macro:engine _str_bridge\ndata modify storage macro:output string.result set from storage stringlib:output to_string\ndata remove storage stringlib:output to_string\ndata remove storage macro:engine _str_bridge\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/to_string","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/to_uppercase.mcfunction', '# macro:core/lib/string/to_uppercase\n# Fast variant — covers a-z only (faster)\n# Input:  macro:input string — string to convert\n# Output: macro:output string.result — uppercase string\n# Dep:    StringLib (CMDred)\ndata modify storage macro:engine _str_bridge.String set from storage macro:input string\nfunction macro:core/lib/string/internal/to_upper_fast_dispatch with storage macro:engine _str_bridge\ndata modify storage macro:output string.result set from storage stringlib:output to_uppercase\ndata remove storage stringlib:output to_uppercase\ndata remove storage macro:engine _str_bridge\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/to_uppercase","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/to_uppercase_full.mcfunction', '# macro:core/lib/string/to_uppercase_full\n# Full variant — covers full Unicode lowercase mapping (slower)\n# Input:  macro:input string — string to convert\n# Output: macro:output string.result — uppercase string\n# Dep:    StringLib (CMDred)\ndata modify storage macro:engine _str_bridge.String set from storage macro:input string\nfunction macro:core/lib/string/internal/to_upper_full_dispatch with storage macro:engine _str_bridge\ndata modify storage macro:output string.result set from storage stringlib:output to_uppercase\ndata remove storage stringlib:output to_uppercase\ndata remove storage macro:engine _str_bridge\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/string/to_uppercase_full","color":"aqua"}]\n'),
    ('./data/macro/function/core/lib/string/internal/insert_dispatch.mcfunction', '$function stringlib:util/insert {Index:$(Index)}\n'),
    ('./data/macro/function/core/lib/string/internal/to_lower_fast_dispatch.mcfunction', '$function stringlib:util/to_lowercase/fast {String:"$(String)"}\n'),
    ('./data/macro/function/core/lib/string/internal/to_lower_full_dispatch.mcfunction', '$function stringlib:util/to_lowercase/full {String:"$(String)"}\n'),
    ('./data/macro/function/core/lib/string/internal/to_number_dispatch.mcfunction', '$function stringlib:util/to_number {Input:"$(Input)"}\n'),
    ('./data/macro/function/core/lib/string/internal/to_string_dispatch.mcfunction', '$function stringlib:util/to_string {Input:$(Input)}\n'),
    ('./data/macro/function/core/lib/string/internal/to_upper_fast_dispatch.mcfunction', '$function stringlib:util/to_uppercase/fast {String:"$(String)"}\n'),
    ('./data/macro/function/core/lib/string/internal/to_upper_full_dispatch.mcfunction', '$function stringlib:util/to_uppercase/full {String:"$(String)"}\n'),
    ('./data/macro/function/core/load/warn.mcfunction', 'tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"⚠ ","color":"yellow"},{"text":"Engine not loaded yet. Run ","color":"#555555"},{"text":"/reload","color":"aqua","underlined":true},{"text":" first.","color":"#555555"}]\n'),
    ('./data/macro/function/core/queue/clear.mcfunction', '# macro:core/queue/clear\n# Discards all pending work_queue items immediately.\n# No macro input required.\n#\n# Usage:\n#   function macro:core/queue/clear\n\ndata modify storage macro:engine work_queue set value []\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"queue/clear ","color":"aqua"},{"text":"→ work_queue emptied","color":"#555555"}]\n'),
    ('./data/macro/function/core/queue/flush.mcfunction', '# macro:core/queue/flush\n# Processes ALL remaining work_queue items in a single tick.\n# WARNING: large queues will cause a lag spike. Use only when you know\n#          the queue is small (< ~50 items) or in a controlled context.\n# No macro input required.\n#\n# Usage:\n#   function macro:core/queue/flush\n\nexecute if data storage macro:engine work_queue[0] run function macro:core/queue/internal/flush_loop\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"queue/flush ","color":"aqua"},{"text":"→ done","color":"green"}]\n'),
    ('./data/macro/function/core/queue/push.mcfunction', '# macro:core/queue/push\n# Appends a function call to the rate-limited work queue.\n# The engine will execute it at up to work_queue_rate calls/tick.\n#\n# DIFFERENT from lib/queue_add:\n#   lib/queue_add  → delay-based scheduler (run after N ticks)\n#   queue/push     → throughput limiter   (process heavy lists without lag spikes)\n#\n# Input  (macro:input queue):\n#   fn — fully-qualified function path  e.g. "mypack:do_thing"\n#\n# Usage:\n#   data modify storage macro:input queue.fn set value "mypack:do_thing"\n#   function macro:core/queue/push with storage macro:input queue\n\n$data modify storage macro:engine work_queue append value {fn:"$(fn)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"queue/push ","color":"aqua"},{"text":"→ ","color":"#555555"},{"text":"$(fn)","color":"white"}]\n'),
    ('./data/macro/function/core/queue/push_as.mcfunction', '# macro:core/queue/push_as\n# Appends a function to the work queue, tagged to execute AS a specific player.\n# The player must be online when the item is processed; if offline, it is skipped.\n#\n# Input  (macro:input queue):\n#   fn     — function path          e.g. "mypack:process_player"\n#   player — player name or UUID    e.g. "<player name>"\n#\n# Usage:\n#   data modify storage macro:input queue set value {fn:"mypack:process_player",player:"<player name>"}\n#   function macro:core/queue/push_as with storage macro:input queue\n\n$data modify storage macro:engine work_queue append value {fn:"$(fn)",player:"$(player)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"queue/push_as ","color":"aqua"},{"text":"→ ","color":"#555555"},{"text":"$(fn)","color":"white"},{"text":" as ","color":"#555555"},{"text":"$(player)","color":"#FFAA00"}]\n'),
    ('./data/macro/function/core/queue/set_rate.mcfunction', '# macro:core/queue/set_rate\n# Sets how many work_queue items are processed per tick.\n# Default: 1. Raise for faster throughput; lower to reduce tick cost.\n# A value of 0 pauses processing.\n#\n# Input  (macro:input queue):\n#   rate — integer ≥ 0\n#\n# Usage:\n#   data modify storage macro:input queue.rate set value 4\n#   function macro:core/queue/set_rate with storage macro:input queue\n\n$data modify storage macro:engine work_queue_rate set value $(rate)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"queue/set_rate ","color":"aqua"},{"text":"→ ","color":"#555555"},{"text":"$(rate)","color":"yellow"},{"text":" items/tick","color":"#555555"}]\n'),
    ('./data/macro/function/core/queue/size.mcfunction', '# macro:core/queue/size\n# Writes the current work_queue item count to macro:output queue.size.\n# No macro input required.\n#\n# Output (macro:output queue):\n#   size — int  number of pending items\n#\n# Usage:\n#   function macro:core/queue/size\n#   data get storage macro:output queue.size\n\nexecute store result storage macro:output queue.size int 1 run data get storage macro:engine work_queue\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"queue/size ","color":"aqua"},{"text":"→ ","color":"#555555"},{"storage":"macro:output","nbt":"queue.size","color":"yellow"}]\n'),
    ('./data/macro/function/core/queue/internal/exec_as.mcfunction', '# macro:core/queue/internal/exec_as\n# Runs a queued function as the named player (if online).\n# If the player is offline the item is silently dropped — no retry.\n#\n# Macro input:\n#   fn     — function path to call\n#   player — player name used in selector\n\n$data modify storage macro:engine _dispatch.func set value "$(fn)"\n$execute as $(player) run function #macro:internal/dispatch\n'),
    ('./data/macro/function/core/queue/internal/exec_fn.mcfunction', '# macro:core/queue/internal/exec_fn\n# Runs a queued function in server (non-entity) context.\n# Called with storage macro:engine _wq_job as macro source.\n#\n# Macro input:\n#   fn — function path to call\n\n$data modify storage macro:engine _dispatch.func set value "$(fn)"\nfunction #macro:internal/dispatch\n'),
    ('./data/macro/function/core/queue/internal/exec_next.mcfunction', '# macro:core/queue/internal/exec_next\n# Pops work_queue[0] into _wq_job, removes it from the list,\n# then dispatches to the appropriate runner.\n# player field present → execute as that player (skipped if offline).\n# player field absent  → run in server context.\n\ndata modify storage macro:engine _wq_job set from storage macro:engine work_queue[0]\ndata remove storage macro:engine work_queue[0]\n\nexecute if data storage macro:engine _wq_job.player run function macro:core/queue/internal/exec_as with storage macro:engine _wq_job\nexecute unless data storage macro:engine _wq_job.player run function macro:core/queue/internal/exec_fn with storage macro:engine _wq_job\n\ndata remove storage macro:engine _wq_job\n'),
    ('./data/macro/function/core/queue/internal/flush_loop.mcfunction', '# macro:core/queue/internal/flush_loop\n# Drains the entire work_queue in one call stack (used by queue/flush).\n# Recursion depth = queue size — do NOT call on large queues.\n\nexecute unless data storage macro:engine work_queue[0] run return 0\nfunction macro:core/queue/internal/exec_next\nfunction macro:core/queue/internal/flush_loop\n'),
    ('./data/macro/function/core/queue/internal/tick.mcfunction', '# macro:core/queue/internal/tick\n# Rate-limited work queue dispatcher — called every tick by tick.mcfunction.\n# Reads work_queue_rate and processes up to that many items.\n# Early-exit if queue is empty (zero overhead when idle).\n\nexecute unless data storage macro:engine work_queue[0] run return 0\n\nexecute store result score #wq_rate macro.tmp run data get storage macro:engine work_queue_rate\nexecute if score #wq_rate macro.tmp matches ..0 run return 0\n\nfunction macro:core/queue/internal/tick_loop\n'),
    ('./data/macro/function/core/queue/internal/tick_loop.mcfunction', '# macro:core/queue/internal/tick_loop\n# Recursive loop: processes one item then calls itself until\n# #wq_rate reaches 0 or the queue is empty.\n# Max recursion depth = work_queue_rate (keep ≤ 64 for safety).\n\nexecute unless data storage macro:engine work_queue[0] run return 0\nexecute if score #wq_rate macro.tmp matches ..0 run return 0\n\nscoreboard players remove #wq_rate macro.tmp 1\nfunction macro:core/queue/internal/exec_next\n\nfunction macro:core/queue/internal/tick_loop\n'),
    ('./data/macro/function/core/state/clear.mcfunction', '$data remove storage macro:engine states.$(player)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/clear ","color":"aqua"},{"text":"$(player)","color":"white"}]\n'),
    ('./data/macro/function/core/state/clear_all.mcfunction', 'data remove storage macro:engine states\n'),
    ('./data/macro/function/core/state/get.mcfunction', 'data remove storage macro:output result\n$execute if data storage macro:engine states.$(player) run data modify storage macro:output result set from storage macro:engine states.$(player)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/get ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/state/get_score.mcfunction', '# macro:core/state/get_score\n# Prints the calling player\'s current state score.\n# Usage: /function macro:core/state/get_score\ntellraw @s ["",{"text":"[State] ","color":"aqua"},{"text":"current: ","color":"gray"},{"score":{"name":"@s","objective":"macro.state"},"color":"white","bold":true}]\n'),
    ('./data/macro/function/core/state/is.mcfunction', 'data modify storage macro:output result set value 0b\n$execute if data storage macro:engine states{$(player):"$(state)"} run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/is ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(state)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/state/list.mcfunction', 'tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Player States ","color":"aqua"},{"text":"━━━━━━━━━━","color":"#555555"}]\nexecute if data storage macro:engine states run tellraw @a[tag=macro.debug] ["",{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"states","interpret":false,"color":"white"}]\nexecute unless data storage macro:engine states run tellraw @a[tag=macro.debug] ["",{"text":" ","color":"#555555"},{"text":"(no active states)","color":"gray","italic":true}]\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]\n'),
    ('./data/macro/function/core/state/reset_score.mcfunction', "# macro:core/state/reset_score\n# Resets a player's state to 0 (idle).\n# Usage: /function macro:core/state/reset_score\nscoreboard players set @s macro.state 0\n"),
    ('./data/macro/function/core/state/set.mcfunction', '$data modify storage macro:engine states.$(player) set value "$(state)"\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/set ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(state)","color":"aqua"}]\n'),
    ('./data/macro/function/core/state/set_score.mcfunction', "# macro:core/state/set_score\n# Sets a player's integer state on the macro.state scoreboard.\n# Usage: $function macro:core/state/set_score {value:1}\n# States: 0=idle 1=combat 2=menu (define your own)\n$scoreboard players set @s macro.state $(value)\n"),
    ('./data/macro/function/core/state/toggle.mcfunction', 'scoreboard players set $st_tog macro.tmp 0\n$execute if data storage macro:engine {states:{$(player):"$(on)"}} run scoreboard players set $st_tog macro.tmp 1\n\n$execute if score $st_tog macro.tmp matches 1 run data modify storage macro:engine states.$(player) set value "$(off)"\n$execute if score $st_tog macro.tmp matches 0 run data modify storage macro:engine states.$(player) set value "$(on)"\n\ndata remove storage macro:output result\n$data modify storage macro:output result set from storage macro:engine states.$(player)\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/toggle ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" (","color":"#555555"},{"text":"$(on)","color":"gray"},{"text":"↔","color":"#555555"},{"text":"$(off)","color":"gray"},{"text":") → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/core/tick/admin_systems.mcfunction', 'tag @a[tag=macro.admin] add macro.debug\nscoreboard players enable @a[tag=macro.admin] macro_menu\nscoreboard players enable @a[tag=macro.admin] macro_action\nscoreboard players enable @a[tag=macro.admin] macro_run\nfunction macro:systems/geo/region_watch/internal/tick_scan\n'),
    ('./data/macro/function/core/tick/config.mcfunction', '# AME Tick Channel Defaults\n# ─────────────────────────────────────────────────────────────────────────────\n# This file is the "JSON config" for the tick engine.\n# It is executed ONCE on first world load (and on macro:core/tick/reset_channels).\n# Modify here to change the default channel layout that all new worlds receive.\n#\n# Channel fields\n# ──────────────\n# id (string) unique name — used by all API functions\n# enabled (1b|0b) 1b = runs each applicable tick, 0b = dormant\n# rate (int) fire every N ticks [1=every tick, 20=1/s, 200=10/s]\n# offset (int) phase offset 0..(rate-1)\n# use different offsets per channel to spread CPU load\n# fn (string) function resource location to call\n# condition (string) predicate path; "" means "always fire"\n# e.g. "macro:is_daytime" — only runs during daylight\n#\n# API (available after load)\n# ──────────────────────────\n# function macro:core/tick/channel/enable {id:"..."}\n# function macro:core/tick/channel/disable {id:"..."}\n# function macro:core/tick/channel/set_rate {id:"...",rate:N}\n# function macro:core/tick/channel/set_offset {id:"...",offset:N}\n# function macro:core/tick/channel/set_condition {id:"...",condition:"ns:pred"}\n# function macro:core/tick/channel/register {id:"...",rate:N,offset:N,fn:"ns:path",enabled:1,condition:""}\n# function macro:core/tick/channel/unregister {id:"..."}\n# function macro:core/tick/channel/list\n# function macro:core/tick/pause\n# function macro:core/tick/resume\n# function macro:core/tick/status\n# function macro:core/tick/reset_channels\n# ─────────────────────────────────────────────────────────────────────────────\n\ndata modify storage macro:engine tick.channels set value []\n\n# time_systems — epoch counter; must stay at rate:1 offset:0\ndata modify storage macro:engine tick.channels append value {id:"time_systems",enabled:1b,rate:1,offset:0,fn:"macro:core/tick/time_systems",condition:""}\n\n# player_systems — per-player state polling; every tick\ndata modify storage macro:engine tick.channels append value {id:"player_systems",enabled:1b,rate:1,offset:0,fn:"macro:core/tick/player_systems",condition:""}\n\n# queue_systems — scheduled task queue; every tick\ndata modify storage macro:engine tick.channels append value {id:"queue_systems",enabled:1b,rate:1,offset:0,fn:"macro:core/tick/queue_systems",condition:""}\n\n# hud_systems — HUD refresh; every 2 ticks, offset 1 (fires on odd ticks, avoiding collision with rate-1 channels)\ndata modify storage macro:engine tick.channels append value {id:"hud_systems",enabled:1b,rate:2,offset:1,fn:"macro:core/tick/hud_systems",condition:""}\n\n# admin_systems — admin tooling; every 4 ticks, offset 2\ndata modify storage macro:engine tick.channels append value {id:"admin_systems",enabled:1b,rate:4,offset:2,fn:"macro:core/tick/admin_systems",condition:"macro:is_creative"}'),
    ('./data/macro/function/core/tick/disabled.mcfunction', ''),
    ('./data/macro/function/core/tick/dispatch.mcfunction', '# AME Tick — Channel Dispatcher\n# Increments the internal tick counter then iterates all channels.\n\nscoreboard players add #tick_ctr macro.tick 1\ndata modify storage macro:tick_work i set value 0\nfunction macro:core/tick/dispatch/step with storage macro:tick_work'),
    ('./data/macro/function/core/tick/hud_systems.mcfunction', 'execute if data storage macro:engine pb_obj run scoreboard players operation $pb_mod macro.tmp = $epoch macro.time\nexecute if data storage macro:engine pb_obj run scoreboard players operation $pb_mod macro.tmp %= $pb_four macro.tmp\nexecute if data storage macro:engine pb_obj run execute if score $pb_mod macro.tmp matches 0 run execute as @a run function macro:systems/string/progress_bar_self with storage macro:engine {}\n'),
    ('./data/macro/function/core/tick/init_channels.mcfunction', "# Called during every load — only writes defaults if channels don't exist yet.\n# This preserves any runtime customisations made via the channel API.\n# To reset to file defaults: function macro:core/tick/reset_channels\nexecute unless data storage macro:engine tick.channels run function macro:core/tick/config"),
    ('./data/macro/function/core/tick/pause.mcfunction', '# macro:core/tick/pause — Suspend all tick channels until macro:core/tick/resume\ndata modify storage macro:engine tick.paused set value 1b\ntellraw @s [{"text":"[AME] ","color":"gold"},{"text":"Tick engine paused.","color":"red"}]'),
    ('./data/macro/function/core/tick/player_systems.mcfunction', 'execute as @a run function macro:core/lib/tick_guard_clear\n\nexecute as @a[scores={macro_menu=1..}] run function macro:menu\nscoreboard players set @a[scores={macro_menu=1..}] macro_menu 0\nscoreboard players enable @a[scores={macro_menu=-1..}] macro_menu\n\nexecute as @a[scores={macro_run=1..}] run function #macro:admin/run\nscoreboard players set @a[scores={macro_run=1..}] macro_run 0\nscoreboard players enable @a[scores={macro_run=-1..}] macro_run\n\nexecute as @a[scores={macro_action=1..}] run function macro:api/trigger/internal/dispatch\n\nfunction macro:api/interaction/internal/tick_scan\n\nfunction macro:api/perm/trigger/internal/tick_start\n\nfunction macro:api/wand/internal/tick_scan\n\nfunction macro:systems/hook/internal/tick_scan\n# Event bus — on_tick\nfunction #macro:events/on_tick\n'),
    ('./data/macro/function/core/tick/queue_systems.mcfunction', 'function macro:core/lib/process_queue\n'),
    ('./data/macro/function/core/tick/reset_channels.mcfunction', '# macro:core/tick/reset_channels — Overwrite channel storage with config file defaults\n# WARNING: this discards ALL runtime API changes (enable/disable/set_rate/etc.)\nfunction macro:core/tick/config\ntellraw @s [{"text":"[AME] ","color":"gold"},{"text":"Tick channels reset to defaults.","color":"green"}]'),
    ('./data/macro/function/core/tick/resume.mcfunction', '# macro:core/tick/resume — Resume tick engine\ndata remove storage macro:engine tick.paused\ntellraw @s [{"text":"[AME] ","color":"gold"},{"text":"Tick engine resumed.","color":"green"}]'),
    ('./data/macro/function/core/tick/status.mcfunction', '# macro:core/tick/status — Show tick engine diagnostics\ntellraw @s [{"text":"","extra":[{"text":"══ AME Tick Engine v2 ══","color":"gold","bold":true}]}]\ntellraw @s [{"text":" Counter ","color":"gray"},{"score":{"name":"#tick_ctr","objective":"macro.tick"},"color":"aqua"}]\ntellraw @s [{"text":" Paused ","color":"gray"},{"storage":"macro:engine","nbt":"tick.paused","color":"red"}]\ntellraw @s [{"text":" Channels","color":"gray"}]\ntellraw @s {"storage":"macro:engine","nbt":"tick.channels","color":"yellow"}'),
    ('./data/macro/function/core/tick/time_systems.mcfunction', 'scoreboard players add $epoch macro.time 1\nscoreboard players add $tick macro.tmp 1\n\nscoreboard players set $pq_depth macro.tmp 0\n'),
    ('./data/macro/function/core/tick/channel/disable.mcfunction', '# macro:core/tick/channel/disable — Disable a tick channel by ID\n# Usage: function macro:core/tick/channel/disable {id:"channel_id"}\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {enabled:0b}'),
    ('./data/macro/function/core/tick/channel/enable.mcfunction', '# macro:core/tick/channel/enable — Enable a tick channel by ID\n# Usage: function macro:core/tick/channel/enable {id:"channel_id"}\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {enabled:1b}'),
    ('./data/macro/function/core/tick/channel/list.mcfunction', '# macro:core/tick/channel/list — Print all registered tick channels\ntellraw @s {"storage":"macro:engine","nbt":"tick.channels","color":"yellow"}'),
    ('./data/macro/function/core/tick/channel/register.mcfunction', '# macro:core/tick/channel/register — Register or replace a tick channel\n# Usage:\n# function macro:core/tick/channel/register {id:"my_sys",rate:20,offset:0,fn:"my_ns:tick/my_system",enabled:1,condition:""}\n#\n# Fields:\n# id (string) — unique channel identifier\n# enabled (0|1) — 1 = active, 0 = paused; stored as byte internally\n# rate (int) — fire every N ticks (1 = every tick, 20 = 1/s, 1200 = 1/min)\n# offset (int) — phase shift 0..(rate-1); spread channels to avoid lag spikes\n# fn (string) — function resource location to execute\n# condition (string) — predicate path, or "" to always fire regardless of world state\n\n# Remove any existing channel with same ID (idempotent)\n$data remove storage macro:engine tick.channels[{id:"$(id)"}]\n\n# Append new channel definition\n$data modify storage macro:engine tick.channels append value {id:"$(id)",enabled:$(enabled)b,rate:$(rate),offset:$(offset),fn:"$(fn)",condition:"$(condition)"}'),
    ('./data/macro/function/core/tick/channel/set_condition.mcfunction', '# macro:core/tick/channel/set_condition — Set or clear condition predicate\n# Usage: function macro:core/tick/channel/set_condition {id:"channel_id",condition:"ns:pred"}\n# function macro:core/tick/channel/set_condition {id:"channel_id",condition:""} ← always-run\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {condition:"$(condition)"}'),
    ('./data/macro/function/core/tick/channel/set_offset.mcfunction', '# macro:core/tick/channel/set_offset — Change phase offset (0 to rate-1)\n# Usage: function macro:core/tick/channel/set_offset {id:"channel_id",offset:5}\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {offset:$(offset)}'),
    ('./data/macro/function/core/tick/channel/set_rate.mcfunction', '# macro:core/tick/channel/set_rate — Change execution rate (every N ticks, min 1)\n# Usage: function macro:core/tick/channel/set_rate {id:"channel_id",rate:20}\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {rate:$(rate)}'),
    ('./data/macro/function/core/tick/channel/unregister.mcfunction', '# macro:core/tick/channel/unregister — Remove a tick channel by ID\n# Usage: function macro:core/tick/channel/unregister {id:"channel_id"}\n$data remove storage macro:engine tick.channels[{id:"$(id)"}]'),
    ('./data/macro/function/core/tick/dispatch/channel.mcfunction', '# AME Tick — Channel Loader [MACRO]\n# Copies channels[i] into work storage, skips if disabled.\n# Input: $(i) — channel index\n\n$data modify storage macro:tick_work channel set from storage macro:engine tick.channels[$(i)]\nexecute unless data storage macro:tick_work channel{enabled:1b} run return 0\nfunction macro:core/tick/dispatch/rate_check with storage macro:tick_work channel'),
    ('./data/macro/function/core/tick/dispatch/exec.mcfunction', '# AME Tick — Channel Execute [MACRO]\n# Calls fn directly if condition is empty, otherwise checks predicate first.\n# Input: $(fn), $(condition)\n#\n# condition:"" → always run (no predicate check)\n# condition:"macro:is_daytime" → only run when predicate passes\n\n$data modify storage macro:engine _dispatch.func set value "$(fn)"\nexecute if data storage macro:tick_work channel{condition:""} run function #macro:internal/dispatch\n'),
    ('./data/macro/function/core/tick/dispatch/exec2.mcfunction', '# AME Tick — Channel Execute [MACRO]\n# Calls fn directly if condition is empty, otherwise checks predicate first.\n# Input: $(fn), $(condition)\n#\n# condition:"" → always run (no predicate check)\n# condition:"macro:is_daytime" → only run when predicate passes\n\nexecute if data storage macro:tick_work channel{condition:""} run return 0\n\n$data modify storage macro:engine _dispatch.func set value "$(fn)"\n$execute as @a[limit=1] at @s if predicate $(condition) run function #macro:internal/dispatch\n'),
    ('./data/macro/function/core/tick/dispatch/rate_check.mcfunction', "# AME Tick — Rate/Offset Check [MACRO]\n# Fires when (#tick_ctr - offset) % rate == 0.\n# Input: $(rate), $(offset), $(fn), $(condition)\n#\n# rate:1 = every tick | rate:20 = every second | rate:200 = every 10s\n# offset: phase shift, spreads channels so they don't all run on the same tick\n\n$scoreboard players set #rate macro.tick $(rate)\n$scoreboard players set #offset macro.tick $(offset)\n\n# Compute modular position\nscoreboard players operation #check macro.tick = #tick_ctr macro.tick\nscoreboard players operation #check macro.tick -= #offset macro.tick\nscoreboard players operation #check macro.tick %= #rate macro.tick\n\n# Fix negative remainder (possible when tick_ctr < offset at world start)\nexecute if score #check macro.tick matches ..-1 run scoreboard players operation #check macro.tick += #rate macro.tick\n\n# Not this tick → skip\nexecute unless score #check macro.tick matches 0 run return 0\n\n# Passed → execute channel function\nfunction macro:core/tick/dispatch/exec with storage macro:tick_work channel\nfunction macro:core/tick/dispatch/exec2 with storage macro:tick_work channel"),
    ('./data/macro/function/core/tick/dispatch/step.mcfunction', '# AME Tick — Dispatch Step [MACRO]\n# Recursive iterator over tick.channels[].\n# Terminates automatically when index exceeds array length.\n# Input: $(i) — current channel array index\n\n# Termination: channel[i] absent → stop\n$execute unless data storage macro:engine tick.channels[$(i)] run return 0\n\n# Process this channel\n$function macro:core/tick/dispatch/channel {i:$(i)}\n\n# Advance: $(i)+1 → write back → recurse\n$scoreboard players set #ch_next macro.tick $(i)\nscoreboard players add #ch_next macro.tick 1\nexecute store result storage macro:tick_work i int 1 run scoreboard players get #ch_next macro.tick\nfunction macro:core/tick/dispatch/step with storage macro:tick_work'),
    ('./data/macro/function/debug/dump_cooldowns.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:debug/dump_cooldowns\n# Dumps all active cooldown records to screen.\n# Usage: /function macro:debug/dump_cooldowns\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Cooldown Dump ","color":"aqua"},{"text":"━━━━━━━━━━━━━━━━━━","color":"#555555"}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"engine.cooldowns","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"cooldowns","color":"yellow","italic":false}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"epoch now: ","color":"gray"},{"score":{"name":"$epoch","objective":"macro.time"},"color":"aqua"}]\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]'),
    ('./data/macro/function/debug/dump_events.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:debug/dump_events\n# Lists all registered event handlers.\n# Usage: /function macro:debug/dump_events\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Event Registry ","color":"aqua"},{"text":"━━━━━━━━━━━━━━━━","color":"#555555"}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"engine.events","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"events","color":"light_purple","italic":false}]\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]'),
    ('./data/macro/function/debug/dump_players.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:debug/dump_players\n# Shows all player variables (player vars), PIDs and their states.\n# Usage: /function macro:debug/dump_players\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Player State Dump ","color":"aqua"},{"text":"━━━━━━━━━━━━━","color":"#555555"}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"players ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"players","color":"green","italic":false}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"pids ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"player_pids","color":"aqua","italic":false}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"perms ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"permissions","color":"yellow","italic":false}]\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]'),
    ('./data/macro/function/debug/dump_schedules.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:debug/dump_schedules\n# Shows active schedules and the queue.\n# Usage: /function macro:debug/dump_schedules\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Schedule / Queue Dump ","color":"aqua"},{"text":"━━━━━━━","color":"#555555"}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"schedules","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"schedules","color":"gold","italic":false}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"queue ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"queue","color":"gold","italic":false}]\ntellraw @s ["",{"text":" ","color":"#555555"},{"text":"throttle ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"throttle","color":"gray","italic":false}]\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]'),
    ('./data/macro/function/debug/example_events.mcfunction', 'tellraw @a[tag=macro.debug] {"text":"[DEBUG] Event system test starting...","color":"yellow"}\n\ndata modify storage macro:input event set value "on_join"\ndata modify storage macro:input func set value "macro:debug/internal/on_join_handler"\nfunction macro:events/register with storage macro:input {}\n\ndata modify storage macro:input event set value "on_kill"\ndata modify storage macro:input func set value "macro:debug/internal/on_kill_handler"\nfunction macro:events/register with storage macro:input {}\n\ndata remove storage macro:engine event_context\ndata modify storage macro:engine event_context.player set value "TestPlayer"\ndata modify storage macro:engine event_context.reason set value "debug_test"\n\ndata modify storage macro:input event set value "on_join"\nfunction macro:events/fire with storage macro:input {}\ndata remove storage macro:input event\n\ntellraw @a[tag=macro.debug] {"text":"[DEBUG] example_events completed.","color":"green"}'),
    ('./data/macro/function/debug/tools/trigger.mcfunction', '$function macro:debug/tools/trigger/execute {type:"$(type)",data:$(data)}'),
    ('./data/macro/function/debug/tools/admin/add.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$execute if entity @s[tag=macro.admin] run tag @a[nane=$(target),limit=1] add macro.admin\n$tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✔ ","color":"green"},{"text":"$(NAME)","color":"white"},{"text":" added as admin.","color":"green"}]\n'),
    ('./data/macro/function/debug/tools/admin/list.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Admin List ","color":"aqua"},{"text":"━━━━━━━━━━━━━━","color":"#555555"}]\nexecute if entity @a[tag=macro.admin] run tellraw @s ["",{"text":" ◈ ","color":"#00AAAA"},{"selector":"@a[tag=macro.admin]","color":"white"}]\nexecute unless entity @a[tag=macro.admin] run tellraw @s ["",{"text":" ","color":"#555555"},{"text":"(no admins)","color":"gray","italic":true}]\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]\n'),
    ('./data/macro/function/debug/tools/admin/remove.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return run tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$execute if entity @s[tag=macro.admin] run tag @a[nane=$(target),limit=1] remove macro.admin\n$tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✔ ","color":"green"},{"text":"$(NAME)","color":"white"},{"text":" removed from admins.","color":"green"}]\n'),
    ('./data/macro/function/debug/tools/trigger/execute.mcfunction', '# macro:debug/tools/trigger — single-call dispatch layer (EC-style).\n# Does not require EventCore; uses AME\'s own macro:api/cmd/* functions.\n#\n# Usage:\n# function macro:debug/tools/trigger {type:"<type>", data:{...}}\n# function macro:debug/tools/trigger {type:"<type>", data:{...}, config:{silent:1}}\n#\n# config:{silent:1} → suppress debug tellraw.\n\ndata modify storage macro:engine tools_trigger.data.uuid set from entity @s UUID\n\n$data modify storage macro:engine tools_trigger.type set value "$(type)"\n$data modify storage macro:engine tools_trigger.data set value $(data)\n\n# Execute action\nfunction macro:debug/tools/trigger/internal/dispatch\n\n# Debug message\n$execute if data storage macro:engine tools_trigger.config{silent:1} run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"tools/trigger/execute ","color":"aqua"},{"text":"► ","color":"yellow"},{"text":"$(type)","color":"white"}]\nexecute if data storage macro:engine tools_trigger.config{silent:0} run function macro:core/tick/disabled\n\n# Remove \'macro:engine tools_trigger\' storage\ndata remove storage macro:engine tools_trigger'),
