    ('./data/macro/function/player/add_to_var.mcfunction', '$execute store result score $pvar macro.tmp run data get storage macro:engine players.$(player).$(key)\n$scoreboard players set $pamount macro.tmp $(amount)\nscoreboard players operation $pvar macro.tmp += $pamount macro.tmp\n$execute store result storage macro:engine players.$(player).$(key) int 1 run scoreboard players get $pvar macro.tmp\nexecute store result storage macro:output result int 1 run scoreboard players get $pvar macro.tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/add_to_var ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]'),
    ('./data/macro/function/player/clamp_var.mcfunction', '$execute store result score $cv macro.tmp run data get storage macro:engine players.$(player).$(key)\n$scoreboard players set $cv_mn macro.tmp $(min)\n$scoreboard players set $cv_mx macro.tmp $(max)\nexecute if score $cv macro.tmp < $cv_mn macro.tmp run scoreboard players operation $cv macro.tmp = $cv_mn macro.tmp\nexecute if score $cv macro.tmp > $cv_mx macro.tmp run scoreboard players operation $cv macro.tmp = $cv_mx macro.tmp\n$execute store result storage macro:engine players.$(player).$(key) int 1 run scoreboard players get $cv macro.tmp\nexecute store result storage macro:output result int 1 run scoreboard players get $cv macro.tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/clamp_var ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]'),
