    ('./data/macro/function/player/decrement.mcfunction', '$execute store result score $pvar macro.tmp run data get storage macro:engine players.$(player).$(key)\nscoreboard players remove $pvar macro.tmp 1\n$execute store result storage macro:engine players.$(player).$(key) int 1 run scoreboard players get $pvar macro.tmp\nexecute store result storage macro:output result int 1 run scoreboard players get $pvar macro.tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/decrement ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]'),
