    ('./data/macro/function/player/get_air.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:player/get_air\n# Returns the current air supply of the named player.\n# Air ranges from 0 (drowning) to 300 (full) in ticks.\n#\n# INPUT : $(player) → player name\n# OUTPUT: macro:output result → air ticks (int, 0–300)\n#         macro:output found  → 1b if player online, 0b otherwise\n#\n# EXAMPLE:\n#   function macro:player/get_air {player:"Steve"}\n#   → macro:output result = 300\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output found set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] store result storage macro:output result int 1 run data get entity @s Air\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/get_air ","color":"aqua"},{"text":"$(player) → air=","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./data/macro/function/player/get_armor.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:player/get_armor\n# Returns the armor point value of the named player.\n# Armor is read from the generic.armor attribute base value.\n# Also returns armor toughness.\n#\n# INPUT : $(player) → player name\n# OUTPUT: macro:output result → armor points (int)\n# macro:output toughness → armor toughness (int, scaled x1000)\n# macro:output found → 1b if player exists, 0b otherwise\n#\n# EXAMPLE:\n# function macro:player/get_armor {player:"Steve"}\n# data get storage macro:output result\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output found set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] store result storage macro:output result int 1 run data get entity @s Attributes[{Name:"minecraft:armor"}].Base\n$execute as @a[name=$(player),limit=1] store result storage macro:output toughness int 1000 run data get entity @s Attributes[{Name:"minecraft:armor_toughness"}].Base\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/get_armor ","color":"aqua"},{"text":"$(player) → armor=","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"},{"text":" toughness=","color":"gray"},{"storage":"macro:output","nbt":"toughness","color":"green"}]'),
    ('./data/macro/function/player/get_dimension.mcfunction', 'data remove storage macro:output result\n$data modify storage macro:output result set from entity @a[name=$(player),limit=1] Dimension\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/get_dimension ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]'),
    ('./data/macro/function/player/get_food.mcfunction', 'data modify storage macro:output found set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] store result storage macro:output food int 1 run data get entity @s FoodLevel\n$execute as @a[name=$(player),limit=1] store result storage macro:output saturation int 1000 run data get entity @s FoodSaturationLevel\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/get_food ","color":"aqua"},{"text":"$(player) → food=","color":"gray"},{"storage":"macro:output","nbt":"food","color":"green"},{"text":" sat=","color":"gray"},{"storage":"macro:output","nbt":"saturation","color":"green"}]'),
    ('./data/macro/function/player/get_gamemode.mcfunction', '# macro:player/get_gamemode [MACRO]\n# Returns the gamemode of a named player as an integer.\n#\n# INPUT:  $(player) — player name\n# OUTPUT: macro:output result — 0=survival, 1=creative, 2=adventure, 3=spectator\n# macro:output name — "survival" | "creative" | "adventure" | "spectator"\n# macro:output found — 1b if player exists, 0b otherwise\n#\n# EXAMPLE:\n# function macro:player/get_gamemode {player:"Steve"}\n# data get storage macro:output name\n\ndata modify storage macro:output found set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n\n$execute if entity @a[name=$(player),gamemode=survival,limit=1] run data modify storage macro:output result set value 0\n$execute if entity @a[name=$(player),gamemode=creative,limit=1] run data modify storage macro:output result set value 1\n$execute if entity @a[name=$(player),gamemode=adventure,limit=1] run data modify storage macro:output result set value 2\n$execute if entity @a[name=$(player),gamemode=spectator,limit=1] run data modify storage macro:output result set value 3\n\n$execute if entity @a[name=$(player),gamemode=survival,limit=1] run data modify storage macro:output name set value "survival"\n$execute if entity @a[name=$(player),gamemode=creative,limit=1] run data modify storage macro:output name set value "creative"\n$execute if entity @a[name=$(player),gamemode=adventure,limit=1] run data modify storage macro:output name set value "adventure"\n$execute if entity @a[name=$(player),gamemode=spectator,limit=1] run data modify storage macro:output name set value "spectator"\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/get_gamemode ","color":"aqua"},{"text":"$(player) → ","color":"gray"},{"storage":"macro:output","nbt":"name","color":"green"}]'),
    ('./data/macro/function/player/get_health.mcfunction', 'data modify storage macro:output found set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] store result storage macro:output result int 1 run data get entity @s Health\n$execute as @a[name=$(player),limit=1] store result storage macro:output max int 1 run data get entity @s Attributes[{Name:"minecraft:max_health"}].Base\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/get_health ","color":"aqua"},{"text":"$(player) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"},{"text":"/","color":"#555555"},{"storage":"macro:output","nbt":"max","color":"yellow"}]'),
    ('./data/macro/function/player/get_name.mcfunction', 'data remove storage macro:names temp\n\nsetblock 0 300 0 black_shulker_box replace\n\nloot insert 0 300 0 loot macro:player/head\n\ndata modify storage macro:names temp.NAME set from block 0 300 0 Items[0].components."minecraft:profile".name\n\ndata modify storage macro:names temp.UUID insert 0 from entity @s UUID[0]\ndata modify storage macro:names temp.UUID insert 1 from entity @s UUID[1]\ndata modify storage macro:names temp.UUID insert 2 from entity @s UUID[2]\ndata modify storage macro:names temp.UUID insert 3 from entity @s UUID[3]\n\nsetblock 0 300 0 air replace'),
    ('./data/macro/function/player/get_online_count.mcfunction', 'scoreboard players set $poc macro.tmp 0\nexecute as @a run scoreboard players add $poc macro.tmp 1\nexecute store result storage macro:output result int 1 run scoreboard players get $poc macro.tmp'),
    ('./data/macro/function/player/get_pos.mcfunction', 'data modify storage macro:output found set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] at @s store result storage macro:output x int 1 run data get entity @s Pos[0]\n$execute as @a[name=$(player),limit=1] at @s store result storage macro:output y int 1 run data get entity @s Pos[1]\n$execute as @a[name=$(player),limit=1] at @s store result storage macro:output z int 1 run data get entity @s Pos[2]\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/get_pos ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"x=","color":"gray"},{"storage":"macro:output","nbt":"x","color":"green"},{"text":" y=","color":"gray"},{"storage":"macro:output","nbt":"y","color":"green"},{"text":" z=","color":"gray"},{"storage":"macro:output","nbt":"z","color":"green"}]'),
