    ('./data/macro/function/systems/hook/internal/on_jump.mcfunction', '# macro:systems/hook/internal/on_jump\n# Bridge: #player_action:v1/jumped → #macro:events/on_jump\n# Executor: @s = jumping player\nfunction #macro:events/on_jump\n'),
    ('./data/macro/function/systems/hook/internal/on_killed_by_arrow.mcfunction', '# macro:systems/hook/internal/on_killed_by_arrow\n# @s = player who triggered the event\ndata modify storage macro:engine _hook_fire_tmp set value {event:"killed_by_arrow"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
