    ('./data/macro/function/systems/hook/internal/on_open_gui.mcfunction', '# macro:systems/hook/internal/on_open_gui\n# Bridge: #player_action:v1/open_gui → #macro:events/on_open_gui\n# Executor: @s = player who opened a GUI block\nfunction #macro:events/on_open_gui\n'),
    ('./data/macro/function/systems/hook/internal/on_player_death.mcfunction', '# macro:systems/hook/internal/on_player_death\n# @s = the triggering player\ndata modify storage macro:engine _hook_fire_tmp set value {event:"player_death"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n\n# Event bus\nfunction #macro:events/on_death\n'),
    ('./data/macro/function/systems/hook/internal/on_player_join.mcfunction', '# macro:systems/hook/internal/on_player_join\n# @s = the triggering player\ndata modify storage macro:engine _hook_fire_tmp set value {event:"player_join"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n\n# Event bus\nfunction #macro:events/on_join\n\n# Initialize player data and assign macro.pid\n# get_name populates macro:names temp.NAME; init_from_name relays it to player/init\nfunction macro:player/get_name\nfunction macro:player/internal/init_from_name with storage macro:names temp\n'),
    ('./data/macro/function/systems/hook/internal/on_player_respawn.mcfunction', '# macro:systems/hook/internal/on_player_respawn\n# @s = the triggering player\ndata modify storage macro:engine _hook_fire_tmp set value {event:"player_respawn"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n\n# Event bus\nfunction #macro:events/on_respawn\n'),
    ('./data/macro/function/systems/hook/internal/on_rc.mcfunction', 'function #macro:events/on_rc'),
    ('./data/macro/function/systems/hook/internal/on_sneak_start.mcfunction', '# macro:systems/hook/internal/on_sneak_start\n# @s = player who triggered the event\ndata modify storage macro:engine _hook_fire_tmp set value {event:"sneak_start"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
    ('./data/macro/function/systems/hook/internal/on_sneak_stop.mcfunction', '# macro:systems/hook/internal/on_sneak_stop\n# @s = player who triggered the event\ndata modify storage macro:engine _hook_fire_tmp set value {event:"sneak_stop"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
    ('./data/macro/function/systems/hook/internal/on_sprint_start.mcfunction', '# macro:systems/hook/internal/on_sprint_start\n# @s = player who triggered the event\ndata modify storage macro:engine _hook_fire_tmp set value {event:"sprint_start"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
    ('./data/macro/function/systems/hook/internal/on_sprint_stop.mcfunction', '# macro:systems/hook/internal/on_sprint_stop\n# @s = player who triggered the event\ndata modify storage macro:engine _hook_fire_tmp set value {event:"sprint_stop"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
    ('./data/macro/function/systems/hook/internal/on_target_hit.mcfunction', '# macro:systems/hook/internal/on_target_hit\ndata modify storage macro:engine _hook_fire_tmp set value {event:"target_hit"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
    ('./data/macro/function/systems/hook/internal/on_trade.mcfunction', '# macro:systems/hook/internal/on_trade\n# @s = the triggering player\ndata modify storage macro:engine _hook_fire_tmp set value {event:"trade"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
    ('./data/macro/function/systems/hook/internal/on_using_item.mcfunction', '# macro:systems/hook/internal/on_using_item\n# @s = player who triggered the event\ndata modify storage macro:engine _hook_fire_tmp set value {event:"using_item"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
    ('./data/macro/function/systems/hook/internal/run_cmd.mcfunction', '# macro:systems/hook/internal/run_cmd [MACRO]\n# INPUT: $(cmd)\n# @s = the triggering player\nexecute if score #ame.log_level ame.log_level matches 4.. run tellraw @a[tag=macro.debug] ["",{"text":"[Hook] ","color":"aqua"},{"selector":"@s","color":"gold"},{"text":" cmd executed","color":"#555555"}]\n$$(cmd)\n'),
    ('./data/macro/function/systems/hook/internal/tick_scan.mcfunction', "# macro:systems/hook/internal/tick_scan\n# Her tick'te hook event'lerini tespit eder.\n# Runs only if hook_binds is non-empty.\n\nexecute unless data storage macro:engine hook_binds[0] run return 0\n\n# player_join — delegated to #player_action:v1/joined (fired by player_action when player_action.join >= 1)\n# Only score management remains here to prevent double-fire\nexecute as @a run scoreboard players set @s macro.hook_online 1\n\n# player_death — delegated to #player_action:v1/died (fired by player_action when player_action.death >= 1)\n# Only score reset remains here to prevent double-fire\nexecute as @a[scores={macro.hook_deaths=1..}] run scoreboard players set @s macro.hook_deaths 0\n\n# player_respawn — was dead (dead flag set) but alive again\nexecute as @a[tag=macro.hook_dead,nbt={DeathTime:0s}] run function macro:systems/hook/internal/on_player_respawn\nexecute as @a[tag=macro.hook_dead,nbt={DeathTime:0s}] run tag @s remove macro.hook_dead\nexecute as @a[nbt={DeathTime:1s}] run tag @s add macro.hook_dead\n\n# level_up — XP level increase\nexecute as @a run function macro:systems/hook/internal/check_level_up\n\n# block_place — advancement-based, placed_blocks score increase\nexecute as @a[scores={macro.hook_placed=1..}] run function macro:systems/hook/internal/on_block_place\nexecute as @a[scores={macro.hook_placed=1..}] run scoreboard players set @s macro.hook_placed 0\n\n# block_break — statistic-based (no advancement trigger in 1.20.3–26.1+)\nexecute as @a run function macro:systems/hook/internal/check_block_break\n\n# item_use — advancement-based, score increase\nexecute as @a[scores={macro.hook_item_used=1..}] run function macro:systems/hook/internal/on_item_use\nexecute as @a[scores={macro.hook_item_used=1..}] run scoreboard players set @s macro.hook_item_used 0\n\n\n# entity_kill — advancement-based, score increase\nexecute as @a[scores={macro.hook_entity_killed=1..}] run function macro:systems/hook/internal/on_entity_kill\nexecute as @a[scores={macro.hook_entity_killed=1..}] run scoreboard players set @s macro.hook_entity_killed 0\n\n# using_item — item_durability_changed advancement-based\nexecute as @a[scores={macro.hook_using_item=1..}] run function macro:systems/hook/internal/on_using_item\nexecute as @a[scores={macro.hook_using_item=1..}] run scoreboard players set @s macro.hook_using_item 0\n\n# killed_by_arrow — entity_killed_player + killing_blow:arrow advancement-based\nexecute as @a[scores={macro.hook_killed_by_arrow=1..}] run function macro:systems/hook/internal/on_killed_by_arrow\nexecute as @a[scores={macro.hook_killed_by_arrow=1..}] run scoreboard players set @s macro.hook_killed_by_arrow 0\n\n# hero_of_the_village — raid victory advancement-based\nexecute as @a[scores={macro.hook_hero_of_the_village=1..}] run function macro:systems/hook/internal/on_hero_of_the_village\nexecute as @a[scores={macro.hook_hero_of_the_village=1..}] run scoreboard players set @s macro.hook_hero_of_the_village 0\n\n# sneak_start / sneak_stop — predicate-based\nexecute as @a[scores={macro.hook_sneak=..0},predicate=macro:is_sneaking] run function macro:systems/hook/internal/on_sneak_start\nexecute as @a[scores={macro.hook_sneak=1},predicate=!macro:is_sneaking] run function macro:systems/hook/internal/on_sneak_stop\nexecute as @a[predicate=macro:is_sneaking] run scoreboard players set @s macro.hook_sneak 1\nexecute as @a[predicate=!macro:is_sneaking] run scoreboard players set @s macro.hook_sneak 0\n\n# sprint_start / sprint_stop — predicate-based\nexecute as @a[scores={macro.hook_sprint=..0},predicate=macro:is_sprinting] run function macro:systems/hook/internal/on_sprint_start\nexecute as @a[scores={macro.hook_sprint=1},predicate=!macro:is_sprinting] run function macro:systems/hook/internal/on_sprint_stop\nexecute as @a[predicate=macro:is_sprinting] run scoreboard players set @s macro.hook_sprint 1\nexecute as @a[predicate=!macro:is_sprinting] run scoreboard players set @s macro.hook_sprint 0\n\n# elytra_start / elytra_stop — predicate-based\nexecute as @a[scores={macro.hook_elytra=..0},predicate=macro:is_gliding] run function macro:systems/hook/internal/on_elytra_start\nexecute as @a[scores={macro.hook_elytra=1},predicate=!macro:is_gliding] run function macro:systems/hook/internal/on_elytra_stop\nexecute as @a[predicate=macro:is_gliding] run scoreboard players set @s macro.hook_elytra 1\nexecute as @a[predicate=!macro:is_gliding] run scoreboard players set @s macro.hook_elytra 0\n\n\nexecute as @a[scores={macro.hook_dim_changed=1..}] run function macro:systems/hook/internal/on_dimension_change\nexecute as @a[scores={macro.hook_dim_changed=1..}] run scoreboard players set @s macro.hook_dim_changed 0\n\nexecute as @a[scores={macro.hook_traded=1..}] run function macro:systems/hook/internal/on_trade\nexecute as @a[scores={macro.hook_traded=1..}] run scoreboard players set @s macro.hook_traded 0\n\n# jumped — delegated to #player_action:v1/jumped (fired by player_action when player_action.jump >= 1)\n# Only score reset remains here to prevent double-fire\nexecute as @a[scores={macro.hook_jump=1..}] run scoreboard players reset @s macro.hook_jump\n\n# open_chest — minecraft.custom:minecraft.open_chest stat\nexecute as @a[scores={macro.hook_open_chest=1..}] run function macro:systems/hook/internal/on_open_chest\nexecute as @a[scores={macro.hook_open_chest=1..}] run scoreboard players reset @s macro.hook_open_chest\n\n# drop_item — minecraft.custom:minecraft.drop stat\nexecute as @a[scores={macro.hook_drop=1..}] run function macro:systems/hook/internal/on_drop\nexecute as @a[scores={macro.hook_drop=1..}] run scoreboard players reset @s macro.hook_drop\n\n# target_hit — minecraft.custom:minecraft.target_hit stat\nexecute as @a[scores={macro.hook_target_hit=1..}] run function macro:systems/hook/internal/on_target_hit\nexecute as @a[scores={macro.hook_target_hit=1..}] run scoreboard players reset @s macro.hook_target_hit\n\n# eat — consume_item advancement-based\nexecute as @a[scores={macro.hook_eat=1..}] run function macro:systems/hook/internal/on_eat_fire\nexecute as @a[scores={macro.hook_eat=1..}] run scoreboard players set @s macro.hook_eat 0\n\n# fish_caught — fishing_rod_hooked advancement-based\nexecute as @a[scores={macro.hook_fish=1..}] run function macro:systems/hook/internal/on_fish_fire\nexecute as @a[scores={macro.hook_fish=1..}] run scoreboard players set @s macro.hook_fish 0\n"),
    ('./data/macro/function/systems/hook/internal/unbind_check.mcfunction', '# macro:systems/hook/internal/unbind_check [MACRO]\n# INPUT: $(event) — event field of the current bind\n# If it does not match _hook_filter_event, put back into hook_binds.\n\n$execute unless data storage macro:engine {_hook_filter_event:"$(event)"} run data modify storage macro:engine hook_binds append from storage macro:engine _hook_unbinds[0]\n'),
    ('./data/macro/function/systems/hook/internal/unbind_exec.mcfunction', '# macro:systems/hook/internal/unbind_exec [MACRO]\n# INPUT: $(event)\n# Filters all binds belonging to $(event) from hook_binds.\n\ndata modify storage macro:engine _hook_unbinds set from storage macro:engine hook_binds\ndata modify storage macro:engine hook_binds set value []\n$data modify storage macro:engine _hook_filter_event set value "$(event)"\nfunction macro:systems/hook/internal/unbind_filter\n\ndata remove storage macro:engine _hook_unbinds\ndata remove storage macro:engine _hook_filter_event\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"hook/unbind ","color":"aqua"},{"text":"$(event)","color":"yellow"},{"text":" removed","color":"#555555"}]\n'),
    ('./data/macro/function/systems/hook/internal/unbind_filter.mcfunction', '# macro:systems/hook/internal/unbind_filter\n# _hook_unbinds listesini iterate eder.\n# Copies back binds that do not match _hook_filter_event to hook_binds.\n\nexecute unless data storage macro:engine _hook_unbinds[0] run return 0\n\ndata modify storage macro:engine _hook_unbinds[0] set from storage macro:engine _hook_unbinds[0]\n\nfunction macro:systems/hook/internal/unbind_check with storage macro:engine _hook_unbinds[0]\n\ndata remove storage macro:engine _hook_unbinds[0]\n\nfunction macro:systems/hook/internal/unbind_filter\n'),
    ('./data/macro/function/systems/hook/raycast/found.mcfunction', '# Block found!\n# Increment hook.placed scoreboard\nscoreboard players add @s macro.hook_placed 1\n\n# Write to hook event storage (other systems can listen)\n# Save block coordinates (via marker summon from positioned context)\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.hook_block_pos"]}\nexecute store result storage macro:hook placed.x int 1 run data get entity @e[type=minecraft:marker,tag=macro.hook_block_pos,limit=1] Pos[0]\nexecute store result storage macro:hook placed.y int 1 run data get entity @e[type=minecraft:marker,tag=macro.hook_block_pos,limit=1] Pos[1]\nexecute store result storage macro:hook placed.z int 1 run data get entity @e[type=minecraft:marker,tag=macro.hook_block_pos,limit=1] Pos[2]\nkill @e[type=minecraft:marker,tag=macro.hook_block_pos,limit=1]\n\n# Record timestamp (from macro.time scoreboard)\nexecute store result storage macro:hook placed.tick int 1 run scoreboard players get #time macro.time\n\n# Get player UUID and name via macroEngine modules\nexecute as @s run function macro:systems/uuid/from_entity\ndata modify storage macro:hook placed.uuid set from storage macro:input value\n\nexecute as @s run function macro:player/get_name\ndata modify storage macro:hook placed.name set from storage macro:names temp.NAME\ndata modify storage macro:hook placed.uuid_array set from storage macro:names temp.UUID\n\n# Set hook event flag\ndata modify storage macro:hook placed.active set value 1b\n\n# Hook event sistemine "placed_block" event\'i fire et\ndata modify storage macro:engine _hook_fire_tmp set value {event:"placed_block"}\nexecute as @s run function macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n\n# Legacy event system support (if present)\nexecute if score #m_hook macro.Flags matches 1.. run function macro:events/fire {id:"hook.placed"}\n\n# Cleanup: reset counter\nscoreboard players reset @s macro.tmp\n'),
    ('./data/macro/function/systems/hook/raycast/loop.mcfunction', '# Raycast loop\n# Check if there is a non-air block at the current position\n\n# Non-air block found → call found function\nexecute unless block ~ ~ ~ #minecraft:air run return run function macro:systems/hook/raycast/found\n\n# Still air → continue\n# Increment counter\nscoreboard players add @s macro.tmp 1\n\n# Stop if max distance reached (50 steps = 5 blocks)\nexecute if score @s macro.tmp matches 50.. run return 0\n\n# Advance position by 0.1 blocks and try again\nexecute positioned ^ ^ ^0.1 run function macro:systems/hook/raycast/loop\n'),
    ('./data/macro/function/systems/hook/raycast/start.mcfunction', '# Raycast start\n# Reset distance counter (max 50 steps = 5 blocks)\nscoreboard players set @s macro.tmp 0\n\n# Start loop\nfunction macro:systems/hook/raycast/loop\n'),
    ('./data/macro/function/systems/log/add.mcfunction', '# macro:systems/log/add (internal)\n# Called by error/warn/info/debug — do not call directly.\n# Appends to the 30-entry ring buffer in macro:engine log_display.\nexecute unless data storage macro:engine log_display run data modify storage macro:engine log_display set value []\n\n$data modify storage macro:engine log_display append value {text:"[$(level)] $(message)",color:"$(color)"}\n\nscoreboard players add #ame.log_count macro.tmp 1\nexecute if score #ame.log_count macro.tmp matches 31.. run data remove storage macro:engine log_display[0]\nexecute if score #ame.log_count macro.tmp matches 31.. run scoreboard players remove #ame.log_count macro.tmp 1\n'),
    ('./data/macro/function/systems/log/clear.mcfunction', '# macro:systems/log/clear\n# Usage: /function macro:systems/log/clear\n# Clears the log buffer.\nexecute unless entity @s[tag=macro.admin] run return 0\ndata remove storage macro:engine log_display\nscoreboard players set #ame.log_count macro.tmp 0\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"Log buffer cleared.","color":"gray"}]\n'),
    ('./data/macro/function/systems/log/debug.mcfunction', '# macro:systems/log/debug\n# Usage: $function macro:systems/log/debug {message:"[System] Trace detail"}\n# Level: 4 — only shown when debug mode active\n$data modify storage macro:input message set value "$(message)"\ndata modify storage macro:input level set value "DEBUG"\ndata modify storage macro:input color set value "dark_gray"\nexecute if score #ame.log_level ame.log_level matches 4.. run function macro:systems/log/add with storage macro:input {}\n'),
    ('./data/macro/function/systems/log/error.mcfunction', '# macro:systems/log/error\n# Usage: $function macro:systems/log/error {message:"[System] Something failed"}\n# Level: 1 — always shown unless log is off\n$data modify storage macro:input message set value "$(message)"\ndata modify storage macro:input level set value "ERROR"\ndata modify storage macro:input color set value "red"\nexecute if score #ame.log_level ame.log_level matches 1.. run function macro:systems/log/add with storage macro:input {}\n'),
    ('./data/macro/function/systems/log/get_level.mcfunction', '# macro:systems/log/get_level\n# Usage: /function macro:systems/log/get_level\n# Shows the current log level.\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"Log level: ","color":"gray"},{"score":{"name":"#ame.log_level","objective":"ame.log_level"},"color":"white","bold":true},{"text":"  (0=off 1=error 2=warn 3=info 4=debug)","color":"#555555"}]\n'),
    ('./data/macro/function/systems/log/info.mcfunction', '# macro:systems/log/info\n# Usage: $function macro:systems/log/info {message:"[System] Something happened"}\n# Level: 3\n$data modify storage macro:input message set value "$(message)"\ndata modify storage macro:input level set value "INFO"\ndata modify storage macro:input color set value "gray"\nexecute if score #ame.log_level ame.log_level matches 3.. run function macro:systems/log/add with storage macro:input {}\n'),
    ('./data/macro/function/systems/log/set_level.mcfunction', '# macro:systems/log/set_level\n# Usage: $function macro:systems/log/set_level {level:3}\n# Sets the active log level:\n#   0 = off\n#   1 = error only\n#   2 = warn + error\n#   3 = info + warn + error  (default)\n#   4 = debug (all)\nexecute unless entity @s[tag=macro.admin] run return 0\n$scoreboard players set #ame.log_level ame.log_level $(level)\n$tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"Log level set to ","color":"gray"},{"text":"$(level)","color":"white","bold":true}]\n'),
    ('./data/macro/function/systems/log/show.mcfunction', '# macro:systems/log/show\n# Usage: /function macro:systems/log/show\n# Prints the log buffer to the calling player.\n# Requires: macro.admin tag\nexecute unless entity @s[tag=macro.admin] run return 0\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Log Buffer ","color":"aqua"},{"text":"(level: ","color":"#555555"},{"score":{"name":"#ame.log_level","objective":"ame.log_level"},"color":"white"},{"text":")","color":"#555555"},{"text":"━━━━━━━━━━━━━","color":"#555555"}]\nexecute unless data storage macro:engine log_display[0] run tellraw @s ["",{"text":"  ","color":"#555555"},{"text":"(empty)","color":"gray","italic":true}]\nexecute unless data storage macro:engine log_display[0] run return 0\n\nfunction macro:core/lib/input_push\ndata modify storage macro:engine _felist_input set from storage macro:engine log_display\ndata modify storage macro:input func set value "macro:systems/log/internal/print_entry"\nfunction macro:core/lib/for_each_list with storage macro:input {}\nfunction macro:core/lib/input_pop\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]\n'),
    ('./data/macro/function/systems/log/warn.mcfunction', '# macro:systems/log/warn\n# Usage: $function macro:systems/log/warn {message:"[System] Something suspicious"}\n# Level: 2\n$data modify storage macro:input message set value "$(message)"\ndata modify storage macro:input level set value "WARN"\ndata modify storage macro:input color set value "yellow"\nexecute if score #ame.log_level ame.log_level matches 2.. run function macro:systems/log/add with storage macro:input {}\n'),
