    ('./data/player_action/function/v1.7/enumerate.mcfunction', '\nscoreboard players add #player_action.major load.status 0\nscoreboard players add #player_action.minor load.status 0\n\nexecute if score #player_action.major load.status matches ..0 run scoreboard players set #player_action.minor load.status 7\nexecute if score #player_action.major load.status matches ..0 run scoreboard players set #player_action.major load.status 1\nexecute if score #player_action.major load.status matches 1 if score #player_action.minor load.status matches ..7 run scoreboard players set #player_action.minor load.status 7\n'),
    ('./data/player_action/function/v1.7/init.mcfunction', '\nschedule function player_action:v1.7/tick 5t\nschedule function player_action:v1.7/player/click_detection/tick_entities 100t\ndata merge storage player_action:temp {list:[], obj:{}, var:""}\n\n# dummy\nscoreboard objectives add player_action.data dummy\n\nscoreboard objectives add player_action.uuid.0 dummy\nscoreboard objectives add player_action.uuid.1 dummy\nscoreboard objectives add player_action.uuid.2 dummy\nscoreboard objectives add player_action.uuid.3 dummy\n\nscoreboard objectives add player_action.x dummy\nscoreboard objectives add player_action.y dummy\nscoreboard objectives add player_action.z dummy\n\n# movement\nscoreboard objectives add player_action.aviate minecraft.custom:minecraft.aviate_one_cm\nscoreboard objectives add player_action.climb minecraft.custom:minecraft.climb_one_cm\nscoreboard objectives add player_action.fall minecraft.custom:minecraft.fall_one_cm\nscoreboard objectives add player_action.fly minecraft.custom:minecraft.fly_one_cm\nscoreboard objectives add player_action.walk minecraft.custom:minecraft.walk_one_cm\nscoreboard objectives add player_action.jump minecraft.custom:minecraft.jump\n\n# other interactions\nscoreboard objectives add player_action.death minecraft.custom:minecraft.deaths\nscoreboard objectives add player_action.join minecraft.custom:minecraft.leave_game\nscoreboard objectives add player_action.enchant minecraft.custom:minecraft.enchant_item\nscoreboard objectives add player_action.use_coas minecraft.used:minecraft.carrot_on_a_stick\nscoreboard objectives add player_action.use_wfoas minecraft.used:minecraft.warped_fungus_on_a_stick\n'),
    ('./data/player_action/function/v1.7/resolve.mcfunction', '\nexecute if predicate player_action:v1.7/is_correct_version run function player_action:v1.7/init\n'),
    ('./data/player_action/function/v1.7/tick.mcfunction', '\nschedule function player_action:v1.7/tick 1t\n\nexecute as @a at @s run function player_action:v1.7/player/tick\n'),
    ('./data/player_action/function/v1.7/player/is_moving.mcfunction', '\n# cache position\ndata modify storage player_action:temp list set from entity @s Pos\n\n# calc difference\nexecute store result score #x player_action.data run data get storage player_action:temp list[0] 70\nscoreboard players operation #temp player_action.data = #x player_action.data\nscoreboard players operation #temp player_action.data -= @s player_action.x\nexecute unless score #temp player_action.data matches 0 run tag @s add player_action.moving\n\nexecute store result score #y player_action.data run data get storage player_action:temp list[1] 70\nscoreboard players operation #temp player_action.data = #y player_action.data\nscoreboard players operation #temp player_action.data -= @s player_action.y\nexecute unless score #temp player_action.data matches 0 run tag @s add player_action.moving\n\nexecute store result score #z player_action.data run data get storage player_action:temp list[2] 70\nscoreboard players operation #temp player_action.data = #z player_action.data\nscoreboard players operation #temp player_action.data -= @s player_action.z\nexecute unless score #temp player_action.data matches 0 run tag @s add player_action.moving\n\n# save score\nscoreboard players operation @s player_action.x = #x player_action.data\nscoreboard players operation @s player_action.y = #y player_action.data\nscoreboard players operation @s player_action.z = #z player_action.data\n'),
    ('./data/player_action/function/v1.7/player/process_data.mcfunction', '\nexecute if score @s player_action.fly matches 1.. run tag @s add player_action.flying\nexecute if score @s player_action.walk matches 1.. run tag @s add player_action.walking\nexecute if score @s player_action.fall matches 1.. run tag @s add player_action.falling\nexecute if score @s player_action.climb matches 1.. run tag @s add player_action.climbing\nexecute if score @s player_action.aviate matches 1.. run tag @s add player_action.elyra_flying\n\nexecute if predicate player_action:v1/swimming run tag @s add player_action.swimming\nexecute if predicate player_action:v1/sneaking run tag @s add player_action.sneaking\nexecute if predicate player_action:v1/sprinting run tag @s add player_action.sprinting\nexecute if predicate player_action:v1/riding_pig run tag @s add player_action.riding_pig\nexecute if predicate player_action:v1/riding_boat run tag @s add player_action.riding_boat\nexecute if predicate player_action:v1/riding_mule run tag @s add player_action.riding_mule\nexecute if predicate player_action:v1/riding_llama run tag @s add player_action.riding_llama\nexecute if predicate player_action:v1/riding_horse run tag @s add player_action.riding_horse\nexecute if predicate player_action:v1/riding_donkey run tag @s add player_action.riding_donkey\nexecute if predicate player_action:v1/riding_strider run tag @s add player_action.riding_strider\nexecute if predicate player_action:v1/riding_minecart run tag @s add player_action.riding_minecart\n\nexecute if score @s player_action.death matches 1.. run function #player_action:v1/died\nexecute if score @s player_action.enchant matches 1.. run function #player_action:v1/enchanted\nexecute if score @s player_action.jump matches 1.. run function #player_action:v1/jumped\nexecute if score @s player_action.use_coas matches 1.. run function #player_action:v1/right_click\nexecute if score @s player_action.use_wfoas matches 1.. run function #player_action:v1/right_click\n\nexecute if score @s player_action.join matches 1.. run function #player_action:v1/joined\nexecute unless score @s player_action.join matches 0.. run function #player_action:v1/joined\nexecute unless score @s player_action.join matches 0.. run scoreboard players add @s player_action.join 0\n'),
    ('./data/player_action/function/v1.7/player/remove_tags.mcfunction', '\ntag @s remove player_action.moving\ntag @s remove player_action.flying\ntag @s remove player_action.walking\ntag @s remove player_action.falling\ntag @s remove player_action.climbing\ntag @s remove player_action.elyra_flying\ntag @s remove player_action.swimming\ntag @s remove player_action.sneaking\ntag @s remove player_action.sprinting\ntag @s remove player_action.riding_pig\ntag @s remove player_action.riding_boat\ntag @s remove player_action.riding_mule\ntag @s remove player_action.riding_llama\ntag @s remove player_action.riding_horse\ntag @s remove player_action.riding_donkey\ntag @s remove player_action.riding_strider\ntag @s remove player_action.riding_minecart\n'),
    ('./data/player_action/function/v1.7/player/reset_scores.mcfunction', '\nscoreboard players set @s player_action.fly 0\nscoreboard players set @s player_action.walk 0\nscoreboard players set @s player_action.fall 0\nscoreboard players set @s player_action.climb 0\nscoreboard players set @s player_action.aviate 0\nscoreboard players set @s player_action.death 0\nscoreboard players set @s player_action.enchant 0\nscoreboard players set @s player_action.jump 0\nscoreboard players set @s player_action.use_coas 0\nscoreboard players set @s player_action.use_wfoas 0\nscoreboard players set @s player_action.join 0\n'),
    ('./data/player_action/function/v1.7/player/set_uuid.mcfunction', '\nexecute store result score @s player_action.uuid.0 run data get entity @s UUID[0]\nexecute store result score @s player_action.uuid.1 run data get entity @s UUID[1]\nexecute store result score @s player_action.uuid.2 run data get entity @s UUID[2]\nexecute store result score @s player_action.uuid.3 run data get entity @s UUID[3]\n'),
    ('./data/player_action/function/v1.7/player/tick.mcfunction', '\nfunction player_action:v1.7/player/remove_tags\n\nexecute unless score @s player_action.uuid.0 matches -2147483648.. run function player_action:v1.7/player/set_uuid\nfunction player_action:v1.7/player/is_moving\nfunction player_action:v1.7/player/process_data\nfunction player_action:v1.7/player/click_detection/tick\n\nfunction player_action:v1.7/player/reset_scores\n\nfunction #player_action:v1/tick\n'),
    ('./data/player_action/function/v1.7/player/click_detection/attack_click_entity.mcfunction', '\nadvancement revoke @s only player_action:v1/attack_click_entity\nfunction #player_action:v1/left_click\n'),
    ('./data/player_action/function/v1.7/player/click_detection/end.mcfunction', '\n# copy uuid\nscoreboard players operation #uuid.0 player_action.data = @s player_action.uuid.0\nscoreboard players operation #uuid.1 player_action.data = @s player_action.uuid.1\nscoreboard players operation #uuid.2 player_action.data = @s player_action.uuid.2\nscoreboard players operation #uuid.3 player_action.data = @s player_action.uuid.3\n\n# destroy entities\nexecute as @e[type=minecraft:interaction,tag=player_action.click_entity,predicate=player_action:v1/equals_uuid] run tp @s ~ -300 ~\nexecute as @e[type=minecraft:interaction,tag=player_action.click_entity,predicate=player_action:v1/equals_uuid] run kill @s\n\n# remove tag\ntag @s remove player_action.click_detection\n'),
    ('./data/player_action/function/v1.7/player/click_detection/interact_click_entity.mcfunction', '\nadvancement revoke @s only player_action:v1/interact_click_entity\nfunction #player_action:v1/right_click\n'),
    ('./data/player_action/function/v1.7/player/click_detection/process.mcfunction', '\n# copy uuid\nscoreboard players operation #uuid.0 player_action.data = @s player_action.uuid.0\nscoreboard players operation #uuid.1 player_action.data = @s player_action.uuid.1\nscoreboard players operation #uuid.2 player_action.data = @s player_action.uuid.2\nscoreboard players operation #uuid.3 player_action.data = @s player_action.uuid.3\n\n# start detection\nexecute if entity @s[tag=!player_action.click_detection] run function player_action:v1.7/player/click_detection/start\n\n# teleport villager\nexecute if entity @s[tag=!player_action.moving] as @e[type=minecraft:interaction,tag=player_action.click_entity,predicate=player_action:v1/equals_uuid] run tp @s ~ ~0.75 ~\nexecute if entity @s[tag=player_action.moving] as @e[type=minecraft:interaction,tag=player_action.click_entity,predicate=player_action:v1/equals_uuid] positioned ~ ~0.75 ~ run tp @s ^ ^ ^1.5\n'),
    ('./data/player_action/function/v1.7/player/click_detection/start.mcfunction', '\ntag @s add player_action.click_detection\nsummon minecraft:interaction ~ ~ ~ {Tags:["player_action.click_entity","player_action.new","smithed.entity","smithed.strict"]}\nexecute as @e[type=minecraft:interaction,tag=player_action.new] at @s run function player_action:v1.7/player/click_detection/start_2\n'),
    ('./data/player_action/function/v1.7/player/click_detection/start_2.mcfunction', '\nscoreboard players operation @s player_action.uuid.0 = #uuid.0 player_action.data\nscoreboard players operation @s player_action.uuid.1 = #uuid.1 player_action.data\nscoreboard players operation @s player_action.uuid.2 = #uuid.2 player_action.data\nscoreboard players operation @s player_action.uuid.3 = #uuid.3 player_action.data\n\ntag @s remove player_action.new\n'),
    ('./data/player_action/function/v1.7/player/click_detection/tick.mcfunction', '\nexecute store result score #temp player_action.data if items entity @s weapon.mainhand *[minecraft:custom_data~{player_action:{click_detection:1b}}]\n\nexecute if score #temp player_action.data matches 0 if entity @s[tag=player_action.click_detection] run function player_action:v1.7/player/click_detection/end\nexecute if score #temp player_action.data matches 1 run function player_action:v1.7/player/click_detection/process\n'),
    ('./data/player_action/function/v1.7/player/click_detection/tick_entities.mcfunction', '\nschedule function player_action:v1.7/player/click_detection/tick_entities 100t\nexecute as @e[type=minecraft:interaction,tag=player_action.click_entity] at @s run function player_action:v1.7/player/click_detection/tick_entities_2\n'),
    ('./data/player_action/function/v1.7/player/click_detection/tick_entities_2.mcfunction', '\nexecute store result score #temp player_action.data if entity @p[distance=..10,tag=player_action.click_detection]\nexecute if score #temp player_action.data matches 0 run tp @s ~ -300 ~\nexecute if score #temp player_action.data matches 0 run kill @s\n'),
    ('./data/player_action/function/v1.7/player/interact/interact_anvil.mcfunction', '\nadvancement revoke @s only player_action:v1/interact_anvil\nfunction #player_action:v1/interact_anvil\n'),
