    ('./data/player_action/predicate/v1/equals_uuid.json', '[\n  {\n    "condition": "minecraft:value_check",\n    "value": {\n      "type": "minecraft:score",\n      "target": "this",\n      "score": "player_action.uuid.0"\n    },\n    "range": {\n      "min": {\n        "type": "minecraft:score",\n        "target": {\n          "type": "minecraft:fixed",\n          "name": "#uuid.0"\n        },\n        "score": "player_action.data"\n      },\n      "max": {\n        "type": "minecraft:score",\n        "target": {\n          "type": "minecraft:fixed",\n          "name": "#uuid.0"\n        },\n        "score": "player_action.data"\n      }\n    }\n  },\n  {\n    "condition": "minecraft:value_check",\n    "value": {\n      "type": "minecraft:score",\n      "target": "this",\n      "score": "player_action.uuid.1"\n    },\n    "range": {\n      "min": {\n        "type": "minecraft:score",\n        "target": {\n          "type": "minecraft:fixed",\n          "name": "#uuid.1"\n        },\n        "score": "player_action.data"\n      },\n      "max": {\n        "type": "minecraft:score",\n        "target": {\n          "type": "minecraft:fixed",\n          "name": "#uuid.1"\n        },\n        "score": "player_action.data"\n      }\n    }\n  },\n  {\n    "condition": "minecraft:value_check",\n    "value": {\n      "type": "minecraft:score",\n      "target": "this",\n      "score": "player_action.uuid.2"\n    },\n    "range": {\n      "min": {\n        "type": "minecraft:score",\n        "target": {\n          "type": "minecraft:fixed",\n          "name": "#uuid.2"\n        },\n        "score": "player_action.data"\n      },\n      "max": {\n        "type": "minecraft:score",\n        "target": {\n          "type": "minecraft:fixed",\n          "name": "#uuid.2"\n        },\n        "score": "player_action.data"\n      }\n    }\n  },\n  {\n    "condition": "minecraft:value_check",\n    "value": {\n      "type": "minecraft:score",\n      "target": "this",\n      "score": "player_action.uuid.3"\n    },\n    "range": {\n      "min": {\n        "type": "minecraft:score",\n        "target": {\n          "type": "minecraft:fixed",\n          "name": "#uuid.3"\n        },\n        "score": "player_action.data"\n      },\n      "max": {\n        "type": "minecraft:score",\n        "target": {\n          "type": "minecraft:fixed",\n          "name": "#uuid.3"\n        },\n        "score": "player_action.data"\n      }\n    }\n  }\n]'),
