    ('./data/stringlib/function/zprivate/load.mcfunction', '# Init\nscoreboard objectives add StringLib dummy\nexecute unless score #StringLib.Init StringLib matches 1 run function stringlib:zprivate/init\n\n# Tellraw\nexecute if score #StringLib.ShowLoadMessage StringLib matches 1 run tellraw @a ["﹌ ",{"text":"StringLib >> ","color":"#99EAD6"},{"text":"Made by CMDred","hover_event":{"action":"show_text","value":[{"text":"YouTube: ","color":"dark_aqua"},{"text":"CMDred","color":"white"}]}},"\\n﹌ ",{"text":"StringLib >> ","color":"#99EAD6"},"Get the latest updates: ",{"text":"Modrinth","color":"#5491F7","hover_event":{"action":"show_text","value":["Open page"]}},", ",{"text":"GitHub","color":"#5491F7","hover_event":{"action":"show_text","value":["Open page"]}}]\n'),
    ('./data/stringlib/function/zprivate/concat/combine_large.mcfunction', "# Combine up to 100 strings at once (Size=100 adds 100 to the current result, so it's 101 afterwards)\n$function stringlib:zprivate/concat/s/$(Size)\n\n# Next loop\nexecute if score #StringLib.ConcatsLeft StringLib matches 1 run return 0\nscoreboard players remove #StringLib.ConcatsLeft StringLib 1\nexecute if score #StringLib.ConcatsLeft StringLib matches 1 store result storage stringlib:temp data.Size byte 1 run scoreboard players get #StringLib.StringsTotal StringLib\nexecute if score #StringLib.ConcatsLeft StringLib matches 2.. run data modify storage stringlib:temp data.Size set value 100b\nfunction stringlib:zprivate/concat/combine_large with storage stringlib:temp data\n"),
