    ('./data/stringlib/function/zprivate/split/fail.mcfunction', '# Reset temporary storage & return fail if no separator was found\ndata modify storage stringlib:input find set from storage stringlib:temp data2.PrevInput\ndata modify storage stringlib:output find set from storage stringlib:temp data2.PrevOutput\nexecute unless data storage stringlib:temp data2.PrevInput run data remove storage stringlib:input find\nexecute unless data storage stringlib:temp data2.PrevOutput run data remove storage stringlib:output find\ndata remove storage stringlib:temp data2\ndata remove storage stringlib:temp data\n\ndata modify storage stringlib:output split append from storage stringlib:input split.String\n\nreturn fail\n'),
    ('./data/stringlib/function/zprivate/split/last_segment.mcfunction', '# Append the segment after the last separator instance\n$data modify storage stringlib:output split append string storage stringlib:input split.String $(Min)\n'),
    ('./data/stringlib/function/zprivate/split/main.mcfunction', '# Loop through each index of the separators to split off the part before it\n$data modify storage stringlib:output split append string storage stringlib:input split.String $(Min) $(Max)\nexecute if score #StringLib.KeepEmpty StringLib matches 0 store result score #StringLib.FindLength StringLib run data get storage stringlib:output split[-1]\nexecute if score #StringLib.KeepEmpty StringLib matches 0 if score #StringLib.FindLength StringLib matches 0 run data remove storage stringlib:output split[-1]\n\nexecute if score #StringLib.SplitsLeft StringLib matches 1 run return 0\n\n# Setup next loop\nscoreboard players remove #StringLib.SplitsLeft StringLib 1\ndata remove storage stringlib:output find[0]\n\nexecute store result storage stringlib:temp data.Min int 1 run scoreboard players operation #StringLib.Max StringLib += #StringLib.SeparatorLength StringLib\nexecute store result storage stringlib:temp data.Max int 1 store result score #StringLib.Max StringLib run data get storage stringlib:output find[0]\n\nfunction stringlib:zprivate/split/main with storage stringlib:temp data\n'),
    ('./data/stringlib/function/zprivate/split/setup.mcfunction', '# Reverse stringlib:output split for negative-n direction splits.\n# Forward splits (n >= 0) are already in correct order — no-op.\nexecute if score #StringLib.FindAmount StringLib matches 0.. run return 0\n\n# reversed/main appended segments right-to-left; reverse the list back.\ndata modify storage stringlib:temp setup_buf set value []\nfunction stringlib:zprivate/split/setup_step\ndata modify storage stringlib:output split set from storage stringlib:temp setup_buf\ndata remove storage stringlib:temp setup_buf\n'),
    ('./data/stringlib/function/zprivate/split/setup_step.mcfunction', 'execute unless data storage stringlib:output split[] run return 0\ndata modify storage stringlib:temp setup_buf prepend from storage stringlib:output split[0]\ndata remove storage stringlib:output split[0]\nfunction stringlib:zprivate/split/setup_step\n'),
    ('./data/stringlib/function/zprivate/split/reversed/main.mcfunction', '# Loop through each index of the separators to split off the part before it\n$data modify storage stringlib:output split append string storage stringlib:input split.String $(Min) $(Max)\nexecute if score #StringLib.KeepEmpty StringLib matches 0 store result score #StringLib.FindLength StringLib run data get storage stringlib:output split[-1]\nexecute if score #StringLib.KeepEmpty StringLib matches 0 if score #StringLib.FindLength StringLib matches 0 run data remove storage stringlib:output split[-1]\n\nexecute if score #StringLib.SplitsLeft StringLib matches 1 run return 0\n\n# Setup next loop\nscoreboard players remove #StringLib.SplitsLeft StringLib 1\ndata remove storage stringlib:output find[-1]\n\nexecute store result storage stringlib:temp data.Min int 1 run scoreboard players operation #StringLib.Max StringLib += #StringLib.SeparatorLength StringLib\nexecute store result storage stringlib:temp data.Max int 1 store result score #StringLib.Max StringLib run data get storage stringlib:output find[-1]\n\nfunction stringlib:zprivate/split/reversed/main with storage stringlib:temp data\n'),
    ('./data/stringlib/function/zprivate/split/split_chars/main.mcfunction', '# Split off the first character and append it to the output\ndata modify storage stringlib:output split append string storage stringlib:temp data.String 0 1\n\n# Setup next loop\nexecute if score #StringLib.CharsLeft StringLib matches 1 run return 0\nscoreboard players remove #StringLib.CharsLeft StringLib 1\ndata modify storage stringlib:temp data.String set string storage stringlib:temp data.String 1\n\nfunction stringlib:zprivate/split/split_chars/main\n'),
    ('./data/stringlib/function/zprivate/split/split_chars/setup.mcfunction', '# IDEA: Do the same thing as with concat, so hardcode it for multiples of 100 chars. NEEDS TO WORK WITH NEGATIVE n AS WELL. BENCHMARK WHEN IT STARTS TO BE FASTER\n\n# Split each character off\ndata modify storage stringlib:temp data.String set from storage stringlib:input split.String\nexecute store result score #StringLib.CharsLeft StringLib run data get storage stringlib:input split.n\nexecute if score #StringLib.CharsLeft StringLib matches 0 run scoreboard players operation #StringLib.CharsLeft StringLib = #StringLib.CharsTotal StringLib\nexecute if score #StringLib.CharsLeft StringLib matches 0.. if score #StringLib.CharsLeft StringLib > #StringLib.CharsTotal StringLib run scoreboard players operation #StringLib.CharsLeft StringLib = #StringLib.CharsTotal StringLib\nexecute if score #StringLib.CharsLeft StringLib matches ..-1 run scoreboard players operation #StringLib.CharsTotal StringLib *= #StringLib.c-1 StringLib\nexecute if score #StringLib.CharsLeft StringLib matches ..-1 if score #StringLib.CharsLeft StringLib < #StringLib.CharsTotal StringLib run scoreboard players operation #StringLib.CharsLeft StringLib = #StringLib.CharsTotal StringLib\n\nexecute if score #StringLib.CharsLeft StringLib matches 0.. run function stringlib:zprivate/split/split_chars/main\nexecute if score #StringLib.CharsLeft StringLib matches ..-1 run function stringlib:zprivate/split/split_chars/reversed/main\n\n# Append the part after it (if CharsLeft was less than CharsTotal at the start). NEEDS TO WORK WITH NEGATIVE n AS WELL\nexecute store result score #StringLib.CharsTotal StringLib run data get storage stringlib:temp data.String\nexecute if score #StringLib.CharsTotal StringLib matches 2.. if score #StringLib.CharsLeft StringLib matches 1 run data modify storage stringlib:output split append string storage stringlib:temp data.String 1\nexecute if score #StringLib.CharsTotal StringLib matches 2.. if score #StringLib.CharsLeft StringLib matches -1 run data modify storage stringlib:output split prepend string storage stringlib:temp data.String 0 -1\n\n# Reset\ndata remove storage stringlib:temp data\n\n# Return value\nreturn run execute if data storage stringlib:output split[]\n'),
    ('./data/stringlib/function/zprivate/split/split_chars/reversed/main.mcfunction', '# Split off the first character and append it to the output\ndata modify storage stringlib:output split prepend string storage stringlib:temp data.String -1\n\n# Setup next loop\nexecute if score #StringLib.CharsLeft StringLib matches -1 run return 0\nscoreboard players add #StringLib.CharsLeft StringLib 1\ndata modify storage stringlib:temp data.String set string storage stringlib:temp data.String 0 -1\n\nfunction stringlib:zprivate/split/split_chars/reversed/main\n'),
    ('./data/stringlib/function/zprivate/to_lowercase/main_fast.mcfunction', '# Convert current character to uppercase (& handle a character having 2 possible outputs)\ndata remove storage stringlib:temp data.List\n$data modify storage stringlib:temp data.List append from storage stringlib:zprivate data.CharMap.Fast[{u:"$(Char)"}].l\ndata modify storage stringlib:temp data.CharList append from storage stringlib:temp data.List[0]\nexecute unless data storage stringlib:temp data.List run data modify storage stringlib:temp data.CharList append from storage stringlib:temp data.Char\n\n# Next loop\nexecute if score #StringLib.CharsLeft StringLib matches 1 run return 0\nscoreboard players remove #StringLib.CharsLeft StringLib 1\ndata modify storage stringlib:temp data.Input set string storage stringlib:temp data.Input 1\ndata modify storage stringlib:temp data.Char set string storage stringlib:temp data.Input 0 1\nfunction stringlib:zprivate/to_lowercase/main_fast with storage stringlib:temp data\n'),
    ('./data/stringlib/function/zprivate/to_lowercase/main_full.mcfunction', '# Convert current character to uppercase (& handle a character having 2 possible outputs)\ndata remove storage stringlib:temp data.List\n$data modify storage stringlib:temp data.List append from storage stringlib:zprivate data.CharMap.Full[{u:"$(Char)"}].l\ndata modify storage stringlib:temp data.CharList append from storage stringlib:temp data.List[0]\nexecute unless data storage stringlib:temp data.List run data modify storage stringlib:temp data.CharList append from storage stringlib:temp data.Char\n\n# Next loop\nexecute if score #StringLib.CharsLeft StringLib matches 1 run return 0\nscoreboard players remove #StringLib.CharsLeft StringLib 1\ndata modify storage stringlib:temp data.Input set string storage stringlib:temp data.Input 1\ndata modify storage stringlib:temp data.Char set string storage stringlib:temp data.Input 0 1\nfunction stringlib:zprivate/to_lowercase/main_full with storage stringlib:temp data\n'),
    ('./data/stringlib/function/zprivate/to_uppercase/main_fast.mcfunction', '# Convert current character to uppercase (& handle a character having 2 possible outputs)\ndata remove storage stringlib:temp data.List\n$data modify storage stringlib:temp data.List append from storage stringlib:zprivate data.CharMap.Fast[{l:"$(Char)"}].u\ndata modify storage stringlib:temp data.CharList append from storage stringlib:temp data.List[0]\nexecute unless data storage stringlib:temp data.List run data modify storage stringlib:temp data.CharList append from storage stringlib:temp data.Char\n\n# Next loop\nexecute if score #StringLib.CharsLeft StringLib matches 1 run return 0\nscoreboard players remove #StringLib.CharsLeft StringLib 1\ndata modify storage stringlib:temp data.Input set string storage stringlib:temp data.Input 1\ndata modify storage stringlib:temp data.Char set string storage stringlib:temp data.Input 0 1\nfunction stringlib:zprivate/to_uppercase/main_fast with storage stringlib:temp data\n'),
    ('./data/stringlib/function/zprivate/to_uppercase/main_full.mcfunction', '# Convert current character to uppercase (& handle a character having 2 possible outputs)\ndata remove storage stringlib:temp data.List\n$data modify storage stringlib:temp data.List append from storage stringlib:zprivate data.CharMap.Full[{l:"$(Char)"}].u\ndata modify storage stringlib:temp data.CharList append from storage stringlib:temp data.List[0]\nexecute unless data storage stringlib:temp data.List run data modify storage stringlib:temp data.CharList append from storage stringlib:temp data.Char\n\n# Next loop\nexecute if score #StringLib.CharsLeft StringLib matches 1 run return 0\nscoreboard players remove #StringLib.CharsLeft StringLib 1\ndata modify storage stringlib:temp data.Input set string storage stringlib:temp data.Input 1\ndata modify storage stringlib:temp data.Char set string storage stringlib:temp data.Input 0 1\nfunction stringlib:zprivate/to_uppercase/main_full with storage stringlib:temp data\n'),
    ('./_pre_1_21_4/data/ame_load/function/load/post_load.mcfunction', '# Stage 4 — post_load: schedule #macro:init after AME finishes loading\n# ame_load:load/all is scheduled at t+16 (from Stage 0 in ame_load:_).\n# Firing #macro:init at t+20 gives 4 ticks of margin after AME is fully ready.\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.stage4"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run say Scheduling #macro:init (t+20)...\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run schedule function #macro:init 20t replace\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run kill @s\n'),
    ('./_pre_1_21_4/data/load/function/_private/init.mcfunction', '# Reset scoreboards so packs can set values accurate for current load.\nscoreboard objectives add load.status dummy\nscoreboard players reset * load.status\n'),
    ('./_pre_1_21_4/data/load/tags/function/load.json', '{\n    "values": [\n        "macro:load",\n        "#player_action:load"\n    ]\n}'),
    ('./_pre_1_21_4/data/load/tags/function/post_load.json', '{\n    "values": [\n        "ame_load:load/post_load"\n    ]\n}\n'),
    ('./_pre_1_21_4/data/load/tags/function/pre_load.json', '{\n    "values": [\n        "#macro:init/pre_load"\n    ]\n}'),
    ('./_pre_1_21_4/data/load/tags/function/_private/init.json', '{\n    "values": [\n        "load:_private/init"\n    ]\n}\n'),
    ('./_pre_1_21_4/data/load/tags/function/_private/load.json', '{\n    "values": [\n        "#load:_private/init",\n        {"id": "#load:pre_load", "required": false},\n        {"id": "#load:load", "required": false},\n        {"id": "#load:post_load", "required": false}\n    ]\n}\n'),
    ('./_pre_1_21_4/data/macro/item_modifier/hide_tooltip.json', '{\n  "function": "minecraft:set_components",\n  "components": {\n    "minecraft:hide_tooltip": {}\n  }\n}'),
    ('./_pre_1_21_4/data/minecraft/tags/function/load.json', '{\n    "values": [\n        "#load:_private/load"\n    ]\n}\n'),
    ('./_pre_1_21_4/data/stringlib/function/uninstall.mcfunction', '# Check if it\'s installed\nscoreboard objectives add StringLib.Uninstall dummy\nexecute if score #StringLib.Init StringLib matches 1 run scoreboard players set #StringLib.Init StringLib.Uninstall 1\nexecute unless score #StringLib.Init StringLib.Uninstall matches 1 run tellraw @a ["﹌ ",{text:"StringLib >> ",color:"#99EAD6"},{text:"⚠ Could not remove StringLib.\\nIs it installed?",color:"red"}]\nexecute unless score #StringLib.Init StringLib.Uninstall matches 1 run return run scoreboard objectives remove StringLib.Uninstall\nscoreboard objectives remove StringLib.Uninstall\n\n# Tellraw\ntellraw @s ["﹌ ",{text:"StringLib >> ",color:"#99EAD6"},"Uninstalled StringLib (v0.2.0)"]\n\n# Remove scoreboards & data storages\nscoreboard objectives remove StringLib\n\nscoreboard players reset #StringLib.Init\nscoreboard players reset #StringLib.ShowLoadMessage\nscoreboard players reset #StringLib.c-1\nscoreboard players reset #StringLib.c100\nscoreboard players reset #StringLib.StringsTotal\nscoreboard players reset #StringLib.CharsLeft\nscoreboard players reset #StringLib.CharsTotal\nscoreboard players reset #StringLib.ConcatsLeft\nscoreboard players reset #StringLib.SuccessCheck\nscoreboard players reset #StringLib.FindLength\nscoreboard players reset #StringLib.FindAmount\nscoreboard players reset #StringLib.KeepEmpty\nscoreboard players reset #StringLib.SeparatorLength\nscoreboard players reset #StringLib.Max\nscoreboard players reset #StringLib.SplitsLeft\nscoreboard players reset #StringLib.Index\nscoreboard players reset #StringLib.FoundNothing\nscoreboard players reset #StringLib.ReturnValue\nscoreboard players reset #StringLib.CheckString.CharsLeft\nscoreboard players reset #StringLib.CheckString.IsFindLength\n\ndata remove storage stringlib:zprivate data\ndata remove storage stringlib:input concat\ndata remove storage stringlib:input find\ndata remove storage stringlib:input replace\ndata remove storage stringlib:input insert\ndata remove storage stringlib:input split\ndata remove storage stringlib:output concat\ndata remove storage stringlib:output to_lowercase\ndata remove storage stringlib:output to_uppercase\ndata remove storage stringlib:output to_number\ndata remove storage stringlib:output to_string\ndata remove storage stringlib:output find\ndata remove storage stringlib:output replace\ndata remove storage stringlib:output insert\ndata remove storage stringlib:output split'),
    ('./_pre_1_21_4/data/stringlib/function/debug/toggle_load_message.mcfunction', '# Toggle the load message\nscoreboard players add #StringLib.ShowLoadMessage StringLib 1\nexecute unless score #StringLib.ShowLoadMessage StringLib matches 1 run scoreboard players set #StringLib.ShowLoadMessage StringLib 0\n\n# Tellraw\nexecute if score #StringLib.ShowLoadMessage StringLib matches 0 run tellraw @s ["﹌ ",{text:"StringLib >> ",color:"#99EAD6"},"Disabled the load message"]\nexecute if score #StringLib.ShowLoadMessage StringLib matches 1 run tellraw @s ["﹌ ",{text:"StringLib >> ",color:"#99EAD6"},"Enabled the load message"]'),
