    ('./_pre_1_21_4/data/stringlib/function/zprivate/load.mcfunction', '# Init\nscoreboard objectives add StringLib dummy\nexecute unless score #StringLib.Init StringLib matches 1 run function stringlib:zprivate/init\n\n# Tellraw\nexecute if score #StringLib.ShowLoadMessage StringLib matches 1 run tellraw @a ["﹌ ",{text:"StringLib >> ",color:"#99EAD6"},{text:"Made by CMDred",hover_event:{action:"show_text",value:[{text:"YouTube: ",color:"dark_aqua"},{text:"CMDred",color:"white"}]}},"\\n﹌ ",{text:"StringLib >> ",color:"#99EAD6"},"Get the latest updates: ",{text:"Modrinth",color:"#5491F7",hover_event:{action:"show_text",value:["Open page"]}},", ",{text:"GitHub",color:"#5491F7",hover_event:{action:"show_text",value:["Open page"]}}]'),
    ('./compat_1_21_4/data/ame_load/function/load/post_load.mcfunction', '# Stage 4 — post_load: schedule #macro:init after AME finishes loading\n# ame_load:load/all is scheduled at t+16 (from Stage 0 in ame_load:_).\n# Firing #macro:init at t+20 gives 4 ticks of margin after AME is fully ready.\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.stage4"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run say Scheduling #macro:init (t+20)...\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run schedule function #macro:init 20t replace\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run kill @s\n'),
    ('./compat_1_21_4/data/ame_load/function/load/internal/finalize.mcfunction', 'execute if score #ame.pre ame.pre_version matches 1.. run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"aqua","bold":true},{"text":"ready · ame.pre_version → ","color":"#555555"},{"score":{"name":"#ame.major","objective":"ame.pre_version"},"color":"yellow"},{"text":".","color":"#555555"},{"score":{"name":"#ame.minor","objective":"ame.pre_version"},"color":"yellow"},{"text":".","color":"#555555"},{"score":{"name":"#ame.patch","objective":"ame.pre_version"},"color":"yellow"},{"text":"-pre","color":"#ff8800"},{"score":{"name":"#ame.pre","objective":"ame.pre_version"},"color":"#ff8800"}]\nexecute if score #ame.pre ame.pre_version matches ..0 run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"aqua","bold":true},{"text":"ready · ame.pre_version → ","color":"#555555"},{"score":{"name":"#ame.major","objective":"ame.pre_version"},"color":"yellow"},{"text":".","color":"#555555"},{"score":{"name":"#ame.minor","objective":"ame.pre_version"},"color":"yellow"},{"text":".","color":"#555555"},{"score":{"name":"#ame.patch","objective":"ame.pre_version"},"color":"yellow"}]\n\ndata modify storage macro:input message set value "✅ All modules initialized. Engine ready."\ndata modify storage macro:input level set value "AME"\ndata modify storage macro:input color set value "green"\nfunction macro:systems/log/add with storage macro:input {}\ndata remove storage macro:input message\ndata remove storage macro:input level\ndata remove storage macro:input color'),
    ('./compat_1_21_4/data/ame_load/function/load/internal/version_warn.mcfunction', 'tellraw @a ["",{"text":"❌ ","color":"red"},{"text":"[AME] ","color":"aqua","bold":true},{"text":"Version conflict! ","color":"red","bold":true},{"text":"Expected ","color":"gray"},{"text":"v4.0.2","color":"yellow","bold":true},{"text":" — stored scores do not match.","color":"gray"}]\ntellraw @a ["",{"text":" ↳ ","color":"#555555"},{"text":"Run ","color":"gray"},{"text":"/reload","color":"white","underlined":true},{"text":" to reinitialize AME.","color":"gray"}]\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME/DEBUG] ","color":"aqua"},{"text":"ame.pre_version → ","color":"#555555"},{"text":"major=","color":"gray"},{"score":{"name":"#ame.major","objective":"ame.pre_version"},"color":"yellow"},{"text":" minor=","color":"gray"},{"score":{"name":"#ame.minor","objective":"ame.pre_version"},"color":"yellow"},{"text":" patch=","color":"gray"},{"score":{"name":"#ame.patch","objective":"ame.pre_version"},"color":"yellow"},{"text":" pre=","color":"gray"},{"score":{"name":"#ame.pre","objective":"ame.pre_version"},"color":"yellow"},{"text":" (expected: 4 0 2 pre=0)","color":"red"}]\n\ndata modify storage macro:input message set value "❌ Version mismatch — expected v4.0.2. Load aborted."\nfunction macro:systems/log/warn with storage macro:input {}\ndata remove storage macro:input message'),
    ('./compat_1_21_4/data/load/function/_private/init.mcfunction', '# Reset scoreboards so packs can set values accurate for current load.\nscoreboard objectives add load.status dummy\nscoreboard players reset * load.status\n'),
    ('./compat_1_21_4/data/load/tags/function/load.json', '{\n    "values": [\n        "macro:load",\n        "#player_action:load"\n    ]\n}'),
    ('./compat_1_21_4/data/load/tags/function/post_load.json', '{\n    "values": [\n        "ame_load:load/post_load"\n    ]\n}\n'),
    ('./compat_1_21_4/data/load/tags/function/pre_load.json', '{\n    "values": [\n        "#macro:init/pre_load"\n    ]\n}'),
    ('./compat_1_21_4/data/load/tags/function/_private/init.json', '{\n    "values": [\n        "load:_private/init"\n    ]\n}\n'),
    ('./compat_1_21_4/data/load/tags/function/_private/load.json', '{\n    "values": [\n        "#load:_private/init",\n        {"id": "#load:pre_load", "required": false},\n        {"id": "#load:load", "required": false},\n        {"id": "#load:post_load", "required": false}\n    ]\n}\n'),
    ('./compat_1_21_4/data/macro/function/disable.mcfunction', 'playsound minecraft:block.note_block.pling master @s ~ ~ ~ 4 2\n\nfunction macro:core/disable/main\n\ntellraw @s [{"text":"To restart:"}," ",{"text":"Reload Dataa!","color":"aqua","bold":true,"italic":false}]'),
    ('./compat_1_21_4/data/macro/function/reset_all.mcfunction', 'function macro:core/disable/main\n\nfunction macro:systems/hook/unbind_all\nfunction macro:api/trigger/unbind_all\nfunction macro:api/wand/unregister_all\ndata remove storage macro:engine interaction_binds\ndata remove storage macro:engine fibers\ndata remove storage macro:engine perm_triggers\ndata remove storage macro:engine perm_trigger_names\ndata remove storage macro:engine log_display\ndata remove storage macro:engine schedules\ndata remove storage macro:engine global.tick\ndata remove storage macro:engine global.epoch\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"Engine disabled. ","color":"red"},{"text":"Restart → ","color":"#555555"},{"text":"[Click here]","color":"aqua","bold":true,"underlined":true,"hoverEvent":{"action":"show_text","contents":"/function macro:load"}}]'),
    ('./compat_1_21_4/data/macro/function/tick.mcfunction', 'execute unless entity @a run return 0\nexecute unless data storage macro:engine global{loaded:1b} run return 0\n\nexecute if score #m_time macro.Flags matches 1 run function macro:core/tick/time_systems\nexecute if score #m_time macro.Flags matches 0 run function macro:core/tick/disabled\n\nexecute if score #m_queue macro.Flags matches 1 run function macro:core/tick/queue_systems\nexecute if score #m_queue macro.Flags matches 0 run function macro:core/tick/disabled\n\nexecute if score #m_player macro.Flags matches 1 run function macro:core/tick/player_systems\nexecute if score #m_player macro.Flags matches 0 run function macro:core/tick/disabled\n\nexecute if score #m_hud macro.Flags matches 1 run function macro:core/tick/hud_systems\nexecute if score #m_hud macro.Flags matches 0 run function macro:core/tick/disabled\n\nexecute if score #m_admin macro.Flags matches 1 run function macro:core/tick/admin_systems\nexecute if score #m_admin macro.Flags matches 0 run function macro:core/tick/disabled'),
    ('./compat_1_21_4/data/macro/function/version.mcfunction', '# ─────────────────────────────────────────────\n# macro:version\n# Shows AME version info to the calling player.\n# Usage: /function macro:version\n# ─────────────────────────────────────────────\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Version Info ","color":"aqua"},{"text":"━━━━━━━━━━━━━━","color":"#555555"}]\n\ntellraw @s ["",{"text":" ◈ ","color":"#00AAAA"},{"text":"Advanced Macro Engine","color":"white","bold":true}]\n\nexecute if score #ame.pre ame.pre_version matches 1.. run tellraw @s ["",{"text":" ┃ ","color":"#555555"},{"text":"Version ","color":"gray"},{"text":"v","color":"#ffaa00"},{"score":{"name":"#ame.major","objective":"ame.pre_version"},"color":"#ffaa00","bold":true},{"text":".","color":"#ffaa00"},{"score":{"name":"#ame.minor","objective":"ame.pre_version"},"color":"#ffaa00","bold":true},{"text":".","color":"#ffaa00"},{"score":{"name":"#ame.patch","objective":"ame.pre_version"},"color":"#ffaa00","bold":true},{"text":"-pre","color":"#ff8800"},{"score":{"name":"#ame.pre","objective":"ame.pre_version"},"color":"#ff8800","bold":true}]\nexecute if score #ame.pre ame.pre_version matches ..0 run tellraw @s ["",{"text":" ┃ ","color":"#555555"},{"text":"Version ","color":"gray"},{"text":"v","color":"#ffaa00"},{"score":{"name":"#ame.major","objective":"ame.pre_version"},"color":"#ffaa00","bold":true},{"text":".","color":"#ffaa00"},{"score":{"name":"#ame.minor","objective":"ame.pre_version"},"color":"#ffaa00","bold":true},{"text":".","color":"#ffaa00"},{"score":{"name":"#ame.patch","objective":"ame.pre_version"},"color":"#ffaa00","bold":true}]\n\ntellraw @s ["",{"text":" ┃ ","color":"#555555"},{"text":"MC ","color":"gray"},{"text":"1.20.3–26.1+","color":"#e3ff57"},{"text":" (pack_format 26–101.1)","color":"#555555"}]\ntellraw @s ["",{"text":" ┃ ","color":"#555555"},{"text":"Author ","color":"gray"},{"text":"Legends11","color":"#00ff33"},{"text":" / ","color":"#555555"},{"text":"runtoolkit","color":"aqua","underlined":true}]\n\ntellraw @s ["",{"text":" ┃ ","color":"#555555"},{"text":"Source ","color":"gray"},{"text":"github.com/runtoolkit/macroEngine-dp","color":"#5555ff","underlined":true}]\n# Check if loaded\nexecute if score #ame.ver_set ame.pre_version matches 1 run tellraw @s ["",{"text":" ┃ ","color":"#555555"},{"text":"Status ","color":"gray"},{"text":"● loaded","color":"green"}]\nexecute unless score #ame.ver_set ame.pre_version matches 1 run tellraw @s ["",{"text":" ┃ ","color":"#555555"},{"text":"Status ","color":"gray"},{"text":"✖ not initialized","color":"red"}]\n\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]'),
    ('./compat_1_21_4/data/macro/function/api/dialog/notify_admins.mcfunction', '# Ensure this runs only for a valid player with an open dialog\nexecute unless entity @s[tag=macro.dialog_opened] run return 0\n\n# Notify all admins that a dialog has been opened\ntellraw @a[tag=macro.admin] ["",{"text":"[Dialog] ","color":"gold"},{"selector":"@s","color":"yellow"},{"text":" opened a dialog.","color":"white"}]\n'),
    ('./compat_1_21_4/data/macro/function/api/dialog/open.mcfunction', 'execute unless data storage macro:engine dialog.DIALOG run return 0\n\nscoreboard players set @s macro.dialog_load -1\ntag @s remove macro.dialog_closed\ntag @s remove macro.dialog_opened\ntag @s add macro.dialog_opened\n\ntellraw @s ["",{"text":"[AME] ","color":"aqua","bold":true},{"text":"Dialog: ","color":"gray"},{"nbt":"dialog.DIALOG","storage":"macro:engine","color":"yellow"},{"text":" — ","color":"#555555"},{"text":"[Load]","color":"green","bold":true,"underlined":true,"hoverEvent":{"action":"show_text","value":{"text":"Upgrade to 1.21.6+ for native dialog support","color":"gray"}}}]\n\nfunction macro:api/dialog/notify_admins\n\nreturn 1\n'),
    ('./compat_1_21_4/data/macro/function/api/wand/give.mcfunction', '# macro:api/wand/give [compat_1_21_4 overlay — pack_format 48–61]\n# 1.21.4 and below: item_name uses legacy \' string syntax.\n#\n# INPUT: $(player), $(tag), $(name)\n\n$give @a[name=$(player),limit=1] minecraft:carrot_on_a_stick[minecraft:custom_data={wand:"$(tag)"},minecraft:item_name=\'"$(name)"\',minecraft:enchantment_glint_override=true]\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/give ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(tag)","color":"aqua"}]\n'),
    ('./compat_1_21_4/data/macro/function/api/wand/give_custom.mcfunction', '# macro:api/wand/give_custom [compat_1_21_4 overlay — pack_format 48–61]\n# 1.21.4 and below: item_name uses legacy \' string syntax.\n#\n# INPUT: $(player), $(item), $(tag), $(name), $(count)\n\n$give @a[name=$(player),limit=1] $(item)[minecraft:custom_data={wand:"$(tag)"},minecraft:item_name=\'"$(name)"\',minecraft:enchantment_glint_override=true] $(count)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"wand/give_custom ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(item)","color":"aqua"},{"text":" [$(tag)]","color":"#555555"}]\n'),
    ('./compat_1_21_4/data/macro/function/core/load/warn.mcfunction', 'execute if data storage macro:engine global{loaded:1b} run return 0\n\nexecute unless entity @a run return run function macro:load\n\ntellraw @a {"text":"⚠ Warning: Bu dunya deneysel ozellikler iceriyor. You can load it with /function macro:load.","color":"yellow"}\n'),
    ('./compat_1_21_4/data/macro/function/systems/string/hover_text.mcfunction', '$tellraw $(target) {"text":"$(text)","color":"$(color)","hoverEvent":{"action":"show_text","value":{"text":"$(hover)","color":"$(hover_color)"}}}\n'),
    ('./compat_1_21_4/data/macro/function/systems/string/tag_badge.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/string/tag_badge [compat_1_21_4]\n# Sends a styled [TAG] badge with optional hover text.\n#  Input : $(target)     → selector\n#          $(tag)        → badge label (e.g. "ADMIN", "VIP")\n#          $(color)      → badge color (e.g. "red", "gold")\n#          $(hover)      → hover tooltip text\n#\n# compat_1_21_4: uses hoverEvent (camelCase) instead of hover_event\n# ─────────────────────────────────────────────────────────────────\n\n$tellraw $(target) ["",{"text":"[","color":"#555555","bold":false},{"text":"$(tag)","color":"$(color)","bold":true,"hoverEvent":{"action":"show_text","value":{"text":"$(hover)","color":"gray","italic":true}}},{"text":"]","color":"#555555","bold":false}]\n'),
    ('./compat_1_21_4/data/macro/function/systems/string/tooltip_item.mcfunction', '$tellraw $(target) {"text":"$(text)","color":"$(color)","hoverEvent":{"action":"show_item","value":{"id":"$(item)","count":1}}}\n'),
    ('./compat_1_21_4/data/macro/item_modifier/hide_tooltip.json', '{\n  "function": "minecraft:set_components",\n  "components": {\n    "minecraft:hide_tooltip": {}\n  }\n}'),
    ('./compat_1_21_4/data/minecraft/tags/function/load.json', '{\n    "values": [\n        "#load:_private/load"\n    ]\n}\n'),
    ('./compat_1_21_4/data/stringlib/function/uninstall.mcfunction', '# Check if it\'s installed\nscoreboard objectives add StringLib.Uninstall dummy\nexecute if score #StringLib.Init StringLib matches 1 run scoreboard players set #StringLib.Init StringLib.Uninstall 1\nexecute unless score #StringLib.Init StringLib.Uninstall matches 1 run tellraw @a ["﹌ ",{"text":"StringLib >> ","color":"#99EAD6"},{"text":"⚠ Could not remove StringLib.\\nIs it installed?","color":"red"}]\nexecute unless score #StringLib.Init StringLib.Uninstall matches 1 run return run scoreboard objectives remove StringLib.Uninstall\nscoreboard objectives remove StringLib.Uninstall\n\n# Tellraw\ntellraw @s ["﹌ ",{"text":"StringLib >> ","color":"#99EAD6"},"Uninstalled StringLib (v0.2.0)"]\n\n# Remove scoreboards & data storages\nscoreboard objectives remove StringLib\n\nscoreboard players reset #StringLib.Init\nscoreboard players reset #StringLib.ShowLoadMessage\nscoreboard players reset #StringLib.c-1\nscoreboard players reset #StringLib.c100\nscoreboard players reset #StringLib.StringsTotal\nscoreboard players reset #StringLib.CharsLeft\nscoreboard players reset #StringLib.CharsTotal\nscoreboard players reset #StringLib.ConcatsLeft\nscoreboard players reset #StringLib.SuccessCheck\nscoreboard players reset #StringLib.FindLength\nscoreboard players reset #StringLib.FindAmount\nscoreboard players reset #StringLib.KeepEmpty\nscoreboard players reset #StringLib.SeparatorLength\nscoreboard players reset #StringLib.Max\nscoreboard players reset #StringLib.SplitsLeft\nscoreboard players reset #StringLib.Index\nscoreboard players reset #StringLib.FoundNothing\nscoreboard players reset #StringLib.ReturnValue\nscoreboard players reset #StringLib.CheckString.CharsLeft\nscoreboard players reset #StringLib.CheckString.IsFindLength\n\ndata remove storage stringlib:zprivate data\ndata remove storage stringlib:input concat\ndata remove storage stringlib:input find\ndata remove storage stringlib:input replace\ndata remove storage stringlib:input insert\ndata remove storage stringlib:input split\ndata remove storage stringlib:output concat\ndata remove storage stringlib:output to_lowercase\ndata remove storage stringlib:output to_uppercase\ndata remove storage stringlib:output to_number\ndata remove storage stringlib:output to_string\ndata remove storage stringlib:output find\ndata remove storage stringlib:output replace\ndata remove storage stringlib:output insert\ndata remove storage stringlib:output split'),
