    ('./1_20_3/data/macro/functions/api/cmd/weather.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\n$weather $(type) $(duration)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/weather ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(type)","color":"aqua"}]}\n'),
    ('./1_20_3/data/macro/functions/api/cmd/whitelist.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\nexecute unless entity @s[type=minecraft:player] run return 0\nexecute unless dimension minecraft:overworld run return 0\nexecute unless entity @s[gamemode=creative] run return 0\n\n# ─────────────────────────────────────────────────────────────────\n# SANDBOX GUARD — sandbox modunda tehlikeli komutlar engellenir.\n# Aktif:  /data modify storage macro:engine sandbox set value 1b\n# Pasif:  /data modify storage macro:engine sandbox set value 0b\n# ─────────────────────────────────────────────────────────────────\nexecute if data storage macro:engine {sandbox:1b} run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"SANDBOX — cmd/whitelist engellendi.","color":"red"}]\nexecute if data storage macro:engine {sandbox:1b} run return 0\nexecute unless data storage macro:engine {sandbox:1b} run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"TIP ","color":"yellow","bold":true},{"text":"Sandbox modu önerilir → ","color":"gray"},{"text":"/data modify storage macro:engine sandbox set value 1b","color":"aqua"}]\n$whitelist $(action) $(player)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/whitelist ","color":"aqua"},{"text":"$(action) $(player)","color":"white"}]}\n'),
    ('./1_20_3/data/macro/functions/api/cmd/xp_add.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\n$execute as @a[name=$(player),limit=1] run xp add @s $(amount) $(type)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/xp_add ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(type)","color":"aqua"}]}\n'),
    ('./1_20_3/data/macro/functions/api/cmd/xp_get.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\n$execute store result storage macro:output result int 1 run xp query @a[name=$(player),limit=1] $(type)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/xp_get ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(type)","color":"aqua"}]}\n'),
    ('./1_20_3/data/macro/functions/api/cmd/xp_set.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\n$execute as @a[name=$(player),limit=1] run xp set @s $(amount) $(type)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/xp_set ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(type)","color":"aqua"}]}\n'),
    ('./1_20_3/data/macro/functions/api/cmd/internal/sandbox_blocked.mcfunction', '# macro:api/cmd/internal/sandbox_blocked [1.20.3 overlay]\n# Called by cmd/ files when macro:engine {sandbox:1b} is set.\n# Reads macro:engine _sandbox_cmd (set by the caller before this call).\n# Passes the entire macro:engine storage as macro input so that\n# sandbox_blocked_macro can read $(_sandbox_cmd) directly.\n#\n# test_block server logging (added in 25w03a / 1.21.5) is NOT available\n# on this version — only the in-game log buffer is used.\nfunction macro:api/cmd/internal/sandbox_blocked_macro with storage macro:engine {}\n'),
    ('./1_20_3/data/macro/functions/api/cmd/internal/sandbox_blocked_macro.mcfunction', '# macro:api/cmd/internal/sandbox_blocked_macro [1.20.3 overlay]\n# INPUT: $(_sandbox_cmd) — read from macro:engine storage via `with storage macro:engine {}`\n# Appends a WARN entry to the log buffer and notifies debug admins.\n# Do NOT call directly — use macro:api/cmd/internal/sandbox_blocked.\n$data modify storage macro:input message set value "[SANDBOX] cmd/$(_sandbox_cmd) blocked"\ndata modify storage macro:input level set value "WARN"\ndata modify storage macro:input color set value "yellow"\nexecute if score #ame.log_level ame.log_level matches 2.. run function macro:systems/log/add with storage macro:input {}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"SANDBOX ","color":"red","bold":true},{"text":"cmd/$(_sandbox_cmd) blocked","color":"red"}]\ndata remove storage macro:input message\ndata remove storage macro:input level\ndata remove storage macro:input color\n'),
    ('./1_20_3/data/macro/functions/api/cmd/other/action_run.mcfunction', '$execute as @a[name=$(player),limit=1] at @s run function macro:api/cmd/$(type) $(arguments)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/other/action_run ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(type)","color":"aqua"}]}\n'),
    ('./1_20_3/data/macro/functions/api/cmd/other/multi_cmd.mcfunction', 'execute unless entity @s[tag=macro.admin] run return 0\n\n$data modify storage macro:engine _mcmd_queue set value $(commands)\ndata modify storage macro:engine _mcmd_options set value {error_mode:"continue",profile:0b,spread:0}\n\nexecute at @s run function macro:api/cmd/other/multi_cmd/run\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/other/multi_cmd ","color":"aqua"},{"text":"▶ executing batch","color":"#555555"}]}\n'),
    ('./1_20_3/data/macro/functions/api/cmd/other/multi_cmd_adv.mcfunction', '$data merge storage macro:input {list:$(list),options:$(options)}\n\nfunction macro:api/cmd/other/multi_cmd/advanced/run_with_options'),
