    ('./1_20_3/data/macro/functions/api/title/actionbar.mcfunction', '# macro:api/title/actionbar — Raw JSON actionbar display [MACRO]\n# Displays a full JSON component string in the actionbar of a named player.\n# Unlike cmd/actionbar (text + color only), this accepts any serialized component\n# including gradients, translate, score, selector, and nbt text sources.\n#\n# Input (macro args):\n#   player — player name selector string (e.g. "Steve")\n#   json   — serialized JSON component string\n#\n# Output → none\n#\n# Usage:\n#   function macro:api/title/actionbar {player:"Steve",json:\'{"text":"HP: 20/20","color":"red"}\'}\n#   function macro:api/title/actionbar {player:"Steve",\\\n#     json:\'[{"text":"Kills: "},{"score":{"name":"@s","objective":"kills"},"color":"gold"}]\'}\n\nexecute unless function macro:debug/tools/utils/check_all run return 0\n\n$title @a[name=$(player),limit=1] actionbar $(json)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"title/actionbar ","color":"aqua"},{"text":"$(player)","color":"white"}]\n'),
    ('./1_20_3/data/macro/functions/api/title/broadcast.mcfunction', '# macro:api/title/broadcast — Broadcast title + subtitle + times to all players [MACRO]\n# Sends a complete title display (timing + title + subtitle) to every online player.\n# Unlike cmd/title_all which only sends a plain title to @a with no subtitle or\n# timing control, this sets times and subtitle in the same atomic call.\n#\n# Input (macro args):\n#   title     — title text\n#   subtitle  — subtitle text\n#   color     — title color    (e.g. "red", "#RRGGBB")\n#   sub_color — subtitle color (e.g. "yellow", "#RRGGBB")\n#   fade_in   — ticks to fade in  (e.g. 20)\n#   stay      — ticks to stay     (e.g. 100)\n#   fade_out  — ticks to fade out (e.g. 20)\n#\n# Output → none\n#\n# Usage:\n#   function macro:api/title/broadcast {title:"Server restart in 5 min",\\\n#     subtitle:"Save your progress!",color:"red",sub_color:"yellow",\\\n#     fade_in:20,stay:100,fade_out:20}\n\nexecute unless function macro:debug/tools/utils/check_all run return 0\n\n$title @a times $(fade_in) $(stay) $(fade_out)\n$title @a title {"text":"$(title)","color":"$(color)"}\n$title @a subtitle {"text":"$(subtitle)","color":"$(sub_color)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"title/broadcast ","color":"aqua"},{"text":"@a ","color":"gray"},{"text":"→ ","color":"#555555"},{"text":"$(title)","color":"$(color)"},{"text":" / ","color":"#555555"},{"text":"$(subtitle)","color":"$(sub_color)"}]\n'),
    ('./1_20_3/data/macro/functions/api/title/show.mcfunction', '# macro:api/title/show — Atomic title display [MACRO]\n# Sets display timing then shows title + subtitle for one player in a single call.\n# Unlike calling cmd/title_times + cmd/title + cmd/subtitle separately,\n# this guarantees consistent timing for the title/subtitle pair.\n#\n# Input (macro args):\n#   player    — player name selector string (e.g. "Steve")\n#   title     — title text\n#   subtitle  — subtitle text\n#   color     — title color    (e.g. "gold", "#RRGGBB")\n#   sub_color — subtitle color (e.g. "gray", "#RRGGBB")\n#   fade_in   — ticks to fade in  (e.g. 10)\n#   stay      — ticks to stay     (e.g. 60)\n#   fade_out  — ticks to fade out (e.g. 10)\n#\n# Output → none\n#\n# Usage:\n#   function macro:api/title/show {player:"Steve",title:"Hello",subtitle:"welcome back",\\\n#     color:"gold",sub_color:"gray",fade_in:10,stay:60,fade_out:10}\n\nexecute unless function macro:debug/tools/utils/check_all run return 0\n\n$title @a[name=$(player),limit=1] times $(fade_in) $(stay) $(fade_out)\n$title @a[name=$(player),limit=1] title {"text":"$(title)","color":"$(color)"}\n$title @a[name=$(player),limit=1] subtitle {"text":"$(subtitle)","color":"$(sub_color)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"title/show ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(title)","color":"$(color)"},{"text":" / ","color":"#555555"},{"text":"$(subtitle)","color":"$(sub_color)"}]\n'),
    ('./1_20_3/data/macro/functions/api/title/show_raw.mcfunction', '# macro:api/title/show_raw — Atomic title display with raw JSON [MACRO]\n# Like title/show but accepts full serialized JSON component strings,\n# allowing gradients, translate, score, selector, and nbt text sources.\n#\n# Input (macro args):\n#   player        — player name selector string (e.g. "Steve")\n#   title_json    — serialized JSON component for title    (must be a valid JSON text component)\n#   subtitle_json — serialized JSON component for subtitle (must be a valid JSON text component)\n#   fade_in       — ticks to fade in\n#   stay          — ticks to stay\n#   fade_out      — ticks to fade out\n#\n# Output → none\n#\n# Usage:\n#   function macro:api/title/show_raw {player:"Steve",\\\n#     title_json:\'{"text":"Hello","color":"gold","bold":true}\',\\\n#     subtitle_json:\'[{"text":"Welcome "},{"score":{"name":"@s","objective":"kills"}}]\',\\\n#     fade_in:10,stay:70,fade_out:20}\n\nexecute unless function macro:debug/tools/utils/check_all run return 0\n\n$title @a[name=$(player),limit=1] times $(fade_in) $(stay) $(fade_out)\n$title @a[name=$(player),limit=1] title $(title_json)\n$title @a[name=$(player),limit=1] subtitle $(subtitle_json)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"title/show_raw ","color":"aqua"},{"text":"$(player)","color":"white"}]\n'),
