    ('./1_20_3/data/macro/functions/core/lib/once_per_player.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/once_per_player\n# Runs the function once per player for the given key.\n# Will not run again until the session is reset.\n#  Input : $(func)   → function to run\n#           $(key)    → unique key (e.g. "tutorial_intro")\n#           $(player) → player name\n# Output: macro:output ran → 1b (ran) / 0b (already done)\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output ran set value 0b\n\n$execute if data storage macro:engine once_per_player.$(player).$(key) run return 0\n\ndata modify storage macro:output ran set value 1b\n$data modify storage macro:engine once_per_player.$(player).$(key) set value 1b\n\n$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/once_per_player ","color":"aqua"},{"text":"$(player):$(key) ","color":"white"},{"text":"✔ ran for the first time","color":"green"}]\n'),
    ('./1_20_3/data/macro/functions/core/lib/once_per_player_reset.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/once_per_player_reset\n# Deletes the once_per_player record — function can run again.\n#  Girdi : $(player), $(key)\n# ─────────────────────────────────────────────────────────────────\n\n$data remove storage macro:engine once_per_player.$(player).$(key)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/once_per_player_reset ","color":"aqua"},{"text":"$(player):$(key) reset","color":"yellow"}]}\n'),
    ('./1_20_3/data/macro/functions/core/lib/process_queue.mcfunction', 'scoreboard players add $pq_depth macro.tmp 1\nexecute if score $pq_depth macro.tmp matches 257.. run return 0\n\nexecute unless data storage macro:engine queue[0] run return 0\n\nexecute store result score $qdel macro.tmp run data get storage macro:engine queue[0].delay\n\nscoreboard players remove $qdel macro.tmp 1\nexecute store result storage macro:engine queue[0].delay int 1 run scoreboard players get $qdel macro.tmp\n\nexecute if score $qdel macro.tmp matches ..0 run function macro:core/lib/internal/queue_fire\nexecute if score $qdel macro.tmp matches ..0 run function macro:core/lib/process_queue\n'),
