    ('./1_20_3/data/macro/functions/systems/hook/internal/on_eat.mcfunction', '# macro:systems/hook/internal/on_eat\n# @s = yiyen oyuncu\nscoreboard players add @s macro.hook_eat 1\nadvancement revoke @s only macro:systems/hook/eat_food\n'),
