    ('./1_20_5/data/ame_load/functions/_.mcfunction', '# Stage 0 Load\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.stage0"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.stage0,limit=1] run say Loading macroEngine...\nexecute as @e[type=minecraft:marker,tag=macro.stage0,limit=1] run schedule function ame_load:load/all 16t replace\nexecute as @e[type=minecraft:marker,tag=macro.stage0,limit=1] run kill @s'),
    ('./1_20_5/data/ame_load/functions/gate/no.mcfunction', '# ame_load:gate/no\n# Cancel the pending dangerous command.\n#\n# Does NOT execute the pending action. Clears pending_gate from storage.\n# Idempotent — safe to call multiple times.\n#\n# ALSO CALLED BY: ame_load:gate/timeout (auto-cancel after 30 seconds)\n\n# Guard: nothing pending\nexecute unless score #pending ame.gate matches 1 run return 0\n\n# Close the gate window\nscoreboard players set #pending ame.gate 0\nscoreboard players set #confirmed ame.gate 0\n\n# Cancel the still-pending timeout if admin called /no explicitly\nschedule clear ame_load:gate/timeout\n\n# Announce cancellation via marker\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.gate_no"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.gate_no,limit=1] run say [AME GATE] Dangerous command CANCELLED. Action was NOT executed.\nexecute as @e[type=minecraft:marker,tag=macro.gate_no,limit=1] run kill @s\n\n# Discard pending context\ndata remove storage macro:engine pending_gate\nscoreboard players reset #pending ame.gate\nscoreboard players reset #confirmed ame.gate\nscoreboard objectives remove ame.gate'),
    ('./1_20_5/data/ame_load/functions/gate/request.mcfunction', '# ame_load:gate/request\n# Generic dangerous-command confirmation gate — request side.\n#\n# CALLER PROTOCOL\n# ---------------\n# Before calling this function, the caller MUST write a pending_gate\n# compound to macro:engine storage describing the action to confirm:\n#\n#   data modify storage macro:engine pending_gate set value {type:"ban", player:"...", reason:"..."}\n#   function ame_load:gate/request\n#\n# This function then:\n#   1. Opens the ame.gate scoreboard window\n#   2. Broadcasts confirmation instructions via marker say\n#   3. Schedules a 30-second auto-cancel\n#\n# CONFIRMING:  /function ame_load:gate/yes\n# CANCELLING:  /function ame_load:gate/no\n#\n# If another gate is already pending, this call is silently dropped to\n# prevent multiple dangerous commands from racing in multiplayer.\n\n# Drop silently if a gate is already open (multiplayer safety)\nscoreboard objectives add ame.gate dummy\nexecute if score #pending ame.gate matches 1 run return 0\n\n# Open the gate window\nscoreboard players set #pending ame.gate 0\nscoreboard players set #confirmed ame.gate 0\nscoreboard players set #pending ame.gate 1\n\n# Broadcast via marker (server-startup safe, no player context needed)\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.gate_req"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.gate_req,limit=1] run say [AME GATE] Dangerous command pending — awaiting confirmation.\nexecute as @e[type=minecraft:marker,tag=macro.gate_req,limit=1] run say [AME GATE] CONFIRM:  /function ame_load:gate/yes\nexecute as @e[type=minecraft:marker,tag=macro.gate_req,limit=1] run say [AME GATE] CANCEL:   /function ame_load:gate/no\nexecute as @e[type=minecraft:marker,tag=macro.gate_req,limit=1] run say [AME GATE] Auto-cancel fires in 30 seconds.\nexecute as @e[type=minecraft:marker,tag=macro.gate_req,limit=1] run kill @s\n\n# Schedule 30-second auto-cancel for dangerous commands\nschedule function ame_load:gate/timeout 30s replace\n'),
    ('./1_20_5/data/ame_load/functions/gate/timeout.mcfunction', '# ame_load:gate/timeout\n# Fires 30 seconds after ame_load:gate/request if no admin response.\n#\n# Delegates to ame_load:gate/no which is idempotent — if the gate was\n# already closed by an explicit /yes or /no, the #pending guard in\n# gate/no returns 0 and nothing happens.\n\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.gtimeout"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.gtimeout,limit=1] run say [AME GATE] Dangerous command timeout (30s) — auto-cancelling.\nexecute as @e[type=minecraft:marker,tag=macro.gtimeout,limit=1] run kill @s\n\nexecute if score #pending ame.gate matches 1 run function ame_load:gate/no\n'),
    ('./1_20_5/data/ame_load/functions/gate/yes.mcfunction', '# ame_load:gate/yes\n# Execute the pending dangerous command after admin confirmation.\n#\n# Reads the pending_gate compound from macro:engine storage and dispatches\n# to the correct executor based on the \'type\' field.\n#\n# SUPPORTED TYPES\n# ---------------\n#   "ban"     → ame_load:gate/exec/ban       (macro: player, reason)\n#   "ban_ip"  → ame_load:gate/exec/ban_ip    (macro: player, reason)\n#   "disable" → ame_load:gate/exec/disable   (no macro params)\n#\n# Adding new types: write an executor in ame_load:gate/exec/, then add\n# an \'execute if data\' dispatch line here.\n\n# Guard: no gate open\nexecute unless score #pending ame.gate matches 1 run return 0\n\n# Guard: already confirmed (double-call protection)\nexecute if score #confirmed ame.gate matches 1 run return 0\n\n# Mark confirmed, close window\nscoreboard players set #confirmed ame.gate 1\nscoreboard players set #pending ame.gate 0\n\n# Cancel the 30-second timeout\nschedule clear ame_load:gate/timeout\n\n# Announce execution via marker\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.gate_exec"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.gate_exec,limit=1] run say [AME GATE] Dangerous command CONFIRMED. Executing...\nexecute as @e[type=minecraft:marker,tag=macro.gate_exec,limit=1] run kill @s\n\n# --- DISPATCH ---\n# Each executor reads its own fields from macro:engine pending_gate via macro.\n# The \'with storage\' pattern passes pending_gate fields as $(macro) parameters.\n\n# ban: requires {type:"ban", player:"...", reason:"..."}\nexecute if data storage macro:engine pending_gate{type:"ban"} run function ame_load:gate/exec/ban with storage macro:engine pending_gate\n\n# ban_ip: requires {type:"ban_ip", player:"...", reason:"..."}\nexecute if data storage macro:engine pending_gate{type:"ban_ip"} run function ame_load:gate/exec/ban_ip with storage macro:engine pending_gate\n\n# disable: requires {type:"disable"} (no extra fields)\nexecute if data storage macro:engine pending_gate{type:"disable"} run function ame_load:gate/exec/disable\n\n# --- CLEANUP ---\ndata remove storage macro:engine pending_gate\nscoreboard players reset #pending ame.gate\nscoreboard players reset #confirmed ame.gate\nscoreboard objectives remove ame.gate\n'),
    ('./1_20_5/data/ame_load/functions/gate/exec/ban.mcfunction', '# ame_load:gate/exec/ban\n# Executor for confirmed ban command.\n# Called by ame_load:gate/yes via: function ... with storage macro:engine pending_gate\n#\n# Macro fields required in macro:engine pending_gate:\n#   player  — target player name or UUID\n#   reason  — ban reason string\n#\n# MACRO LINE RULES: every $ line must contain at least one $(key).\n# No $ lines without $(key) — Minecraft crashes on that.\n\n$ban $(player) $(reason)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/ban ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" — reason: ","color":"gray"},{"text":"$(reason)","color":"yellow"}]\n'),
    ('./1_20_5/data/ame_load/functions/gate/exec/ban_ip.mcfunction', '# ame_load:gate/exec/ban_ip\n# Executor for confirmed ban-ip command.\n# Called by ame_load:gate/yes via: function ... with storage macro:engine pending_gate\n#\n# Macro fields required in macro:engine pending_gate:\n#   player  — target player name or UUID (resolves to IP)\n#   reason  — ban reason string\n\n$ban-ip $(player) $(reason)\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"cmd/ban_ip ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" — reason: ","color":"gray"},{"text":"$(reason)","color":"yellow"}]\n'),
    ('./1_20_5/data/ame_load/functions/gate/exec/disable.mcfunction', '# ame_load:gate/exec/disable\n# Executor for confirmed engine disable.\n# Called by ame_load:gate/yes when pending_gate{type:"disable"}.\n#\n# Runs the full cleanup pipeline then announces shutdown via marker.\n# No macro parameters needed.\n\nfunction ame_load:load/internal/cleanup\n\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.gate_disable"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.gate_disable,limit=1] run say [AME] Engine DISABLED. All scoreboards and storage removed.\nexecute as @e[type=minecraft:marker,tag=macro.gate_disable,limit=1] run say [AME] To reinitialize: /reload  or  /function ame_load:_\nexecute as @e[type=minecraft:marker,tag=macro.gate_disable,limit=1] run kill @s\n'),
    ('./1_20_5/data/ame_load/functions/load/all.mcfunction', '# Load — entry point called from minecraft:load tag via macro:load\nforceload add -30000000 1600\n\n# Stage 1 debug\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.stage1"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.stage1,limit=1] run say Starting macroEngine...\nexecute as @e[type=minecraft:marker,tag=macro.stage1,limit=1] run kill @s\n\nexecute unless function ame_load:load/internal/validate run return 0\n\ndata modify storage macro:input level set value "A.M.E."\ndata modify storage macro:input message set value "Starting..."\ndata modify storage macro:input color set value "aqua"\nfunction macro:systems/log/add with storage macro:input {}\n\n# Stage 2 debug\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.stage2"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.stage2,limit=1] run say Loading scoreboards...\nexecute as @e[type=minecraft:marker,tag=macro.stage2,limit=1] run kill @s\nfunction ame_load:load/scoreboards\n\n# Stage 3 debug\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.stage3"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.stage3,limit=1] run say Loading storages...\nexecute as @e[type=minecraft:marker,tag=macro.stage3,limit=1] run kill @s\nfunction ame_load:load/storages\n\nfunction ame_load:load/other\n\ndata modify storage macro:engine global.loaded set value 1b\n\nfunction ame_load:load/internal/version_set\n\n# Lantern Load integration — set pack version in load.status\n# Format: (major * 10000) + (minor * 100) + patch\n# Example: v2.2.6 = 20206\nexecute store result score #version_calc macro.tmp run scoreboard players get #ame.major ame.pre_version\nscoreboard players operation #version_calc macro.tmp *= #10000 macro.tmp\nexecute store result score #temp macro.tmp run scoreboard players get #ame.minor ame.pre_version\nscoreboard players operation #temp macro.tmp *= #100 macro.tmp\nscoreboard players operation #version_calc macro.tmp += #temp macro.tmp\nscoreboard players operation #version_calc macro.tmp += #ame.patch ame.pre_version\nscoreboard players operation #macroEngine load.status = #version_calc macro.tmp\n\nexecute if score #ame.pre ame.pre_version matches 1.. run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"Loaded. ","color":"green"},[{"text":"v","color":"aqua"},{"score":{"name":"#ame.major","objective":"ame.pre_version"},"color":"aqua","bold":true},{"text":".","color":"aqua"},{"score":{"name":"#ame.minor","objective":"ame.pre_version"},"color":"aqua","bold":true},{"text":".","color":"aqua"},{"score":{"name":"#ame.patch","objective":"ame.pre_version"},"color":"aqua","bold":true},{"text":"-pre","color":"#ff8800"},{"score":{"name":"#ame.pre","objective":"ame.pre_version"},"color":"#ff8800","bold":true}]]\nexecute if score #ame.pre ame.pre_version matches ..0 run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"Loaded. ","color":"green"},[{"text":"v","color":"aqua"},{"score":{"name":"#ame.major","objective":"ame.pre_version"},"color":"aqua","bold":true},{"text":".","color":"aqua"},{"score":{"name":"#ame.minor","objective":"ame.pre_version"},"color":"aqua","bold":true},{"text":".","color":"aqua"},{"score":{"name":"#ame.patch","objective":"ame.pre_version"},"color":"aqua","bold":true}]]\n\ndata modify storage macro:input level set value "Advanced Macro Engine"\ndata modify storage macro:input message set value "Loaded."\ndata modify storage macro:input color set value "green"\nfunction macro:systems/log/add with storage macro:input {}\n\nfunction ame_load:load/internal/finalize'),
    ('./1_20_5/data/ame_load/functions/load/confirm.mcfunction', "# ame_load:load/confirm\n# AME Load Confirmation Gate — Stage 0 dispatcher\n# Execution context: minecraft:marker (spawned by ame_load:_)\n#\n# PURPOSE\n# -------\n# The minecraft:load tag fires on /reload AND on server/world open.\n# If macro:engine storage already holds live data from a previous session\n# (permission maps, flag tables, wand binds, etc.), overwriting it\n# immediately causes nondeterministic state and silent data loss.\n#\n# This function sets a scoreboard-based pending flag, broadcasts the\n# confirmation instructions to the server log via marker say (immune to\n# the server-startup tellraw / clickEvent rendering bug), and schedules\n# an automatic cancel after 5 minutes.\n#\n# NOTHING in macro:engine storage is touched here.\n# Storage writes happen only after ame_load:load/yes is called.\n#\n# FLOW\n# ----\n#   ame_load:_ (stage0)\n#     └─ ame_load:load/confirm   ← this file (runs as marker)\n#         ├─ broadcasts instructions\n#         └─ schedules ame_load:timeout (5m)\n#\n#   Admin: /function ame_load:load/yes\n#     └─ ame_load:load/all → full init pipeline\n#\n#   Admin: /function ame_load:load/no\n#     └─ abort — storage untouched\n#\n#   5 minutes elapse with no response:\n#     └─ ame_load:timeout → ame_load:load/no (auto-abort)\n\n# Create load-gate tracking objective\n# Safe to call even if objective already exists (add is idempotent)\nscoreboard objectives add ame.load dummy\n\n# Reset any stale state from a previous incomplete gate cycle\nscoreboard players set #pending ame.load 0\nscoreboard players set #confirmed ame.load 0\nscoreboard players set #cancelled ame.load 0\n\n# Open the gate window\nscoreboard players set #pending ame.load 1\n\n# Broadcast via marker say — works at server start, no clickEvent, no players required\nsay [AME GATE] ========================================\nsay [AME GATE] macroEngine load is PENDING.\nsay [AME GATE] Storage has NOT been modified yet.\nsay [AME GATE] ----------------------------------------\nsay [AME GATE] CONFIRM:  /function ame_load:load/yes\nsay [AME GATE] CANCEL:   /function ame_load:load/no\nsay [AME GATE] ----------------------------------------\nsay [AME GATE] Auto-cancel fires in 5 minutes if no response.\nsay [AME GATE] ========================================\n\n# Schedule 5-minute auto-cancel\n# 'replace' ensures repeated /reload does not stack multiple timeout schedules\nschedule function ame_load:timeout 300s replace\n\n# ─────────────────────────────────────────────────────────────────\n# SANDBOX MODE — auto-confirm\n# Enable:  /data modify storage macro:engine sandbox set value 1b\n# Disable: /data modify storage macro:engine sandbox set value 0b\n# Storage persists across reloads — set once, active until cleared.\n# NOTE: schedule is cleared inside load/yes. Do NOT remove ame.load\n#       objective here — load/yes guard checks #pending ame.load == 1.\n# ─────────────────────────────────────────────────────────────────\nexecute if data storage macro:engine {sandbox:1b} run say [AME GATE] SANDBOX MODE — auto-confirming load.\nexecute if data storage macro:engine {sandbox:1b} run function ame_load:load/yes\nexecute if data storage macro:engine {sandbox:1b} run return 0\n"),
    ('./1_20_5/data/ame_load/functions/load/no.mcfunction', '# ame_load:load/no\n# Admin cancelled (or timeout fired) — AME load is ABORTED.\n#\n# macro:engine storage is NOT touched at any point.\n# The engine remains uninitialized and fully inert.\n#\n# IDEMPOTENT — safe to call multiple times.\n# The #pending guard ensures this is a no-op if no gate is open.\n#\n# ALSO CALLED BY: ame_load:timeout (auto-cancel after 5 minutes)\n#\n# TO RETRY: run /reload  OR  /function ame_load:_\n# (calling ame_load:_ directly re-runs stage0 without a full /reload)\n\n# Guard: nothing pending\nexecute unless score #pending ame.load matches 1 run return 0\n\n# Close the gate window\nscoreboard players set #cancelled ame.load 1\nscoreboard players set #pending ame.load 0\nscoreboard players set #confirmed ame.load 0\n\n# If admin called /no explicitly, cancel the still-pending timeout\nschedule clear ame_load:timeout\n\n# Announce cancellation via marker (works with zero players online)\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.gate_no"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.gate_no,limit=1] run say [AME GATE] ========================================\nexecute as @e[type=minecraft:marker,tag=macro.gate_no,limit=1] run say [AME GATE] Load CANCELLED. macro:engine storage was NOT modified.\nexecute as @e[type=minecraft:marker,tag=macro.gate_no,limit=1] run say [AME GATE] Engine is NOT running.\nexecute as @e[type=minecraft:marker,tag=macro.gate_no,limit=1] run say [AME GATE] To retry: /reload  or  /function ame_load:_\nexecute as @e[type=minecraft:marker,tag=macro.gate_no,limit=1] run say [AME GATE] ========================================\nexecute as @e[type=minecraft:marker,tag=macro.gate_no,limit=1] run kill @s\n\n# Tear down gate objective\nscoreboard players reset #pending ame.load\nscoreboard players reset #cancelled ame.load\nscoreboard players reset #confirmed ame.load\nscoreboard objectives remove ame.load\n'),
    ('./1_20_5/data/ame_load/functions/load/other.mcfunction', 'forceload add 0 0\n\ndata modify storage macro:input func set value "macro:core/lib/sync_tick"\ndata modify storage macro:input interval set value 20\ndata modify storage macro:input key set value "sync_tick"\nfunction macro:core/lib/schedule with storage macro:input {}\ndata remove storage macro:input func\ndata remove storage macro:input interval\ndata remove storage macro:input key\n\nscoreboard players enable @a[tag=macro.admin] macro_menu\nscoreboard players enable @a[tag=macro.admin] macro_run\nscoreboard players enable @a[tag=macro.admin] macro_action\n\n# Initialize tick channel config on first world load\nfunction macro:core/tick/init_channels\n'),
    ('./1_20_5/data/ame_load/functions/load/post_load.mcfunction', '# Stage 4 — post_load: schedule #macro:init after AME finishes loading\n# ame_load:load/all is scheduled at t+16 (from Stage 0 in ame_load:_).\n# Firing #macro:init at t+20 gives 4 ticks of margin after AME is fully ready.\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.stage4"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run say Scheduling #macro:init (t+20)...\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run schedule function #macro:init 20t replace\nexecute as @e[type=minecraft:marker,tag=macro.stage4,limit=1] run kill @s\n'),
    ('./1_20_5/data/ame_load/functions/load/scoreboards.mcfunction', 'scoreboard objectives add macro.tmp dummy\nscoreboard objectives add macro.time dummy\nscoreboard objectives add macro_menu trigger\nscoreboard objectives add macro_run trigger\nscoreboard objectives add macro_action trigger\nscoreboard objectives add macro.dialog_load dummy\nscoreboard objectives add macro.tick_guard dummy\nscoreboard objectives add health health {"text":"❤","color":"red"}\nscoreboard objectives add ame.pre_version dummy\nscoreboard objectives add macro.pid dummy\n\n# Wand module — carrot_on_a_stick right-click tracker\nscoreboard objectives add macro.rightClick minecraft.used:minecraft.carrot_on_a_stick\n\n# Hook module scoreboards\nscoreboard objectives add macro.hook_online dummy\n# BUGFIX: existing players should not re-trigger as new joins after reload\nscoreboard players set @a macro.hook_online 1\nscoreboard objectives add macro.hook_deaths deathCount\n# NOTE: placed_blocks is not a general statistic — must be used as dummy\nscoreboard objectives add macro.hook_placed dummy\nscoreboard objectives add macro.hook_lvl dummy\nscoreboard objectives add macro.hook_lvl_new dummy\nscoreboard objectives add macro.hook_sneak dummy\nscoreboard objectives add macro.hook_sprint dummy\nscoreboard objectives add macro.hook_elytra dummy\n# block_break — item_durability_changed advancement-based\nscoreboard objectives add macro.hook_tool_used dummy\n# item_use, entity_kill advancement-based\nscoreboard objectives add macro.hook_item_used dummy\nscoreboard objectives add macro.hook_entity_killed dummy\n# using_item, killed_by_arrow, hero_of_the_village\nscoreboard objectives add macro.hook_using_item dummy\nscoreboard objectives add macro.hook_killed_by_arrow dummy\nscoreboard objectives add macro.hook_hero_of_the_village dummy\n# geo/region_watch — no scoreboard needed for enter/leave tracking (uses entity tags)\n# hook/dimension_change — changed_dimension advancement-based\nscoreboard objectives add macro.hook_dim_changed dummy\n# hook/trade — villager_trade advancement-based\nscoreboard objectives add macro.hook_traded dummy\n\n# Tick channel dispatch\nscoreboard objectives add macro.tick dummy\nscoreboard objectives add macro.Flags dummy\n\n# Player stat hooks\nscoreboard objectives add macro.hook_jump minecraft.custom:minecraft.jump\nscoreboard objectives add macro.hook_open_chest minecraft.custom:minecraft.open_chest\nscoreboard objectives add macro.hook_drop minecraft.custom:minecraft.drop\nscoreboard objectives add macro.hook_target_hit minecraft.custom:minecraft.target_hit\n\n# eat / fish_caught — advancement-based (1.20.5+)\nscoreboard objectives add macro.hook_eat dummy\nscoreboard objectives add macro.hook_fish dummy\n\n# Lantern Load integration — pack version tracking\nscoreboard objectives add load.status dummy\n\n# Version calculation constants (for Lantern Load integration)\nscoreboard players set #10000 macro.tmp 10000\nscoreboard players set #100 macro.tmp 100\n'),
    ('./1_20_5/data/ame_load/functions/load/storages.mcfunction', 'execute unless score $epoch macro.time matches -2147483648..2147483647 run scoreboard players set $epoch macro.time 0\nscoreboard players set $tick macro.tmp 0\n\nscoreboard players set $pq_depth macro.tmp 0\n\nscoreboard players set $pb_four macro.tmp 1\n\nexecute unless data storage macro:engine throttle run data modify storage macro:engine throttle set value {}\n\nexecute unless data storage macro:engine flags run data modify storage macro:engine flags set value {}\nexecute unless data storage macro:engine states run data modify storage macro:engine states set value {}\n\nexecute unless data storage macro:engine permissions run data modify storage macro:engine permissions set value {}\n\nexecute unless data storage macro:engine perm_triggers run data modify storage macro:engine perm_triggers set value {}\nexecute unless data storage macro:engine perm_trigger_names run data modify storage macro:engine perm_trigger_names set value []\n\nexecute unless data storage macro:engine trigger_binds run data modify storage macro:engine trigger_binds set value []\n\nexecute unless data storage macro:engine interaction_binds run data modify storage macro:engine interaction_binds set value {attack:[], use:[]}\n\nexecute unless data storage macro:engine player_pids run data modify storage macro:engine player_pids set value {}\nexecute unless data storage macro:engine _pid_seq run data modify storage macro:engine _pid_seq set value 0\n\n# UUID module init\nfunction macro:systems/uuid/internal/init\n\n# once_per_player module init\nexecute unless data storage macro:engine once_per_player run data modify storage macro:engine once_per_player set value {}\n\n# Wand module init\nexecute unless data storage macro:engine wand_binds run data modify storage macro:engine wand_binds set value []\n\n# Hook module init\nexecute unless data storage macro:engine hook_binds run data modify storage macro:engine hook_binds set value []\n\n# lib/fiber module init\nexecute unless data storage macro:engine fibers run data modify storage macro:engine fibers set value {}\ndata remove storage macro:engine fibers._pending\n\n# geo/region_watch module init\n# Watches are cleared on reload — must re-register on each load\ndata remove storage macro:engine region_watches\ndata modify storage macro:engine region_watches set value []\n\n# lib/batch module init\n# Incomplete batches are cleared on reload\ndata remove storage macro:engine batches\ndata modify storage macro:engine batches set value {}\n'),
    ('./1_20_5/data/ame_load/functions/load/yes.mcfunction', '# ame_load:load/yes\n# Admin confirmed AME load. Triggers the full initialization pipeline.\n#\n# GUARDS\n# ------\n#   - Gate must be open (#pending ame.load == 1)\n#   - Already-confirmed calls are no-ops (idempotent)\n#   - If called with no gate pending, silently returns 0\n#\n# WHAT HAPPENS\n# ------------\n#   1. Mark confirmed, close the pending window\n#   2. Cancel the 5-minute timeout schedule\n#   3. Tear down the ame.load objective (not needed after this point)\n#   4. Schedule ame_load:load/all at t+1 (clean tick boundary)\n#\n# The 1-tick delay lets the scoreboard objective removal settle before\n# ame_load:load/scoreboards runs and recreates its own objectives.\n\n# Guard: no gate open\nexecute unless score #pending ame.load matches 1 run return 0\n\n# Guard: already confirmed (double-call protection)\nexecute if score #confirmed ame.load matches 1 run return 0\n\n# Mark confirmed — close window\nscoreboard players set #confirmed ame.load 1\nscoreboard players set #pending ame.load 0\n\n# Cancel auto-cancel timeout\nschedule clear ame_load:timeout\n\n# Announce via marker (safe on all MC versions, no player context needed)\nsummon minecraft:marker ~ ~ ~ {Tags:["macro.gate_yes"],CustomName:\'{"text":"AME"}\'}\nexecute as @e[type=minecraft:marker,tag=macro.gate_yes,limit=1] run say [AME GATE] Load CONFIRMED by operator. Initializing macroEngine...\nexecute as @e[type=minecraft:marker,tag=macro.gate_yes,limit=1] run kill @s\n\n# Tear down gate scoreboard before load pipeline touches scoreboards\nscoreboard players reset #pending ame.load\nscoreboard players reset #confirmed ame.load\nscoreboard players reset #cancelled ame.load\nscoreboard objectives remove ame.load\n\n# Fire the actual load pipeline\n# 1-tick delay gives scoreboard removal a clean tick boundary before\n# ame_load:load/scoreboards recreates its objectives\nschedule function ame_load:load/all 1t replace'),
    ('./1_20_5/data/ame_load/functions/load/internal/cleanup.mcfunction', 'schedule clear macro:core/lib/sync_tick\n\nforceload remove -30000000 1600\nforceload remove 0 0\n\nscoreboard players reset @a macro_menu\nscoreboard players reset @a macro_run\n\nscoreboard players reset $tick macro.tmp\nscoreboard players reset $pq_depth macro.tmp\n# $epoch intentionally preserved — cooldown expiry times depend on it\n\ndata remove storage macro:engine queue\ndata remove storage macro:engine events\ndata remove storage macro:engine event_context\ndata remove storage macro:engine _event_tmp\ndata remove storage macro:engine cooldowns\ndata remove storage macro:engine throttle\ndata remove storage macro:engine players\ndata remove storage macro:engine flags\ndata remove storage macro:engine states\ndata remove storage macro:engine schedules\ndata remove storage macro:engine _input_stack\ndata remove storage macro:engine _repeat\ndata remove storage macro:engine _rng_state\ndata remove storage macro:engine _felist_input\ndata remove storage macro:engine _felist_state\ndata remove storage macro:engine _felist_current\ndata remove storage macro:engine _felist_i\ndata remove storage macro:engine log_display\nscoreboard players reset #ame.log_count macro.tmp\ndata remove storage macro:engine trigger_binds\ndata remove storage macro:engine _tc_binds\ndata remove storage macro:engine _tc_current\ndata remove storage macro:engine _tc_unbind\ndata remove storage macro:engine _tc_uval\ndata remove storage macro:engine interaction_binds\ndata remove storage macro:engine _ia_iter\ndata remove storage macro:engine _ia_cur\ndata remove storage macro:engine _ia_ubinds\ndata remove storage macro:engine _ia_ufilter\ndata remove storage macro:engine _ia_ucur\ndata remove storage macro:engine teams\ndata remove storage macro:engine global\ndata remove storage macro:output result\n\n# rate_limit module cleanup\ndata remove storage macro:engine rate_limit\n\nscoreboard objectives remove macro.tmp\nscoreboard objectives remove macro.time\nscoreboard objectives remove macro_menu\nscoreboard objectives remove macro_run\nscoreboard objectives remove macro_action\nscoreboard objectives remove macro.tick_guard\nscoreboard objectives remove macro.dialog_load\nscoreboard objectives remove health\nscoreboard objectives remove ame.pre_version\n\nscoreboard objectives remove macro.Flags\nscoreboard objectives remove macro.hook_eat\nscoreboard objectives remove macro.hook_fish\nscoreboard objectives remove macro.state\n\ntag @a remove macro.dialog_opened\ntag @a remove macro.dialog_closed\nadvancement revoke @a from macro:hidden/root\n\nscoreboard objectives remove macro.pid\nscoreboard objectives remove macro.rightClick\ndata remove storage macro:engine wand_binds\ndata remove storage macro:engine _wand_iter\ndata remove storage macro:engine _wand_current\ndata remove storage macro:engine _wand_unbinds\ndata remove storage macro:engine _wand_filter_tag\ndata remove storage macro:engine _wand_cur\ndata remove storage macro:engine player_pids\ndata remove storage macro:engine _pid_seq\n\n# Hook module cleanup\nscoreboard objectives remove macro.hook_online\nscoreboard objectives remove macro.hook_deaths\nscoreboard objectives remove macro.hook_placed\nscoreboard objectives remove macro.hook_lvl\nscoreboard objectives remove macro.hook_lvl_new\nscoreboard objectives remove macro.hook_sneak\nscoreboard objectives remove macro.hook_sprint\nscoreboard objectives remove macro.hook_elytra\ntag @a remove macro.hook_dead\ntag @a remove macro.hook_sneaking\ntag @a remove macro.hook_sprinting\ntag @a remove macro.hook_gliding\nscoreboard objectives remove macro.hook_tool_used\nscoreboard objectives remove macro.hook_item_used\nscoreboard objectives remove macro.hook_entity_killed\nscoreboard objectives remove macro.hook_using_item\nscoreboard objectives remove macro.hook_killed_by_arrow\nscoreboard objectives remove macro.hook_hero_of_the_village\ndata remove storage macro:engine hook_binds\ndata remove storage macro:engine _hook_iter\ndata remove storage macro:engine _hook_ctx\ndata remove storage macro:engine _hook_fire_event\ndata remove storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_unbinds\ndata remove storage macro:engine _hook_filter_event\n\n# Fiber module cleanup\ndata remove storage macro:engine fibers\n\n# Region watch cleanup\ndata remove storage macro:engine region_watches\n\n# Batch module cleanup\ndata remove storage macro:engine batches\n\n# Once-per-player cleanup\ndata remove storage macro:engine once_per_player\n\n# UUID cache cleanup\ndata remove storage macro:engine _uuid_cache\n'),
