    ('./1_20_5/data/ame_load/functions/load/internal/version_warn.mcfunction', 'tellraw @a ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Version conflict! ","color":"red","bold":true},{"text":"Expected ","color":"#555555"},{"text":"v4.0.5-pre1","color":"aqua","bold":true},{"text":" — stored scores do not match.","color":"#555555"}]\ntellraw @a ["",{"text":" ","color":"#555555"},{"text":"→ Run ","color":"gray"},{"text":"/reload","color":"aqua","underlined":true,"hoverEvent":{"action":"show_text","value":"Reload Dat"}},{"text":" to reinitialize AME.","color":"gray"}]\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"DEBUG ","color":"aqua"},{"text":"ame.pre_version scores → ","color":"#555555"},{"text":"major=","color":"gray"},{"score":{"name":"#ame.major","objective":"ame.pre_version"},"color":"yellow"},{"text":" minor=","color":"gray"},{"score":{"name":"#ame.minor","objective":"ame.pre_version"},"color":"yellow"},{"text":" patch=","color":"gray"},{"score":{"name":"#ame.patch","objective":"ame.pre_version"},"color":"yellow"},{"text":" pre=","color":"gray"},{"score":{"name":"#ame.pre","objective":"ame.pre_version"},"color":"yellow"},{"text":" (expected: 4 0 4 pre=0)","color":"red"}]\n\ndata modify storage macro:input message set value "✘ Version mismatch — expected v4.0.5-pre1. Load aborted."\nfunction macro:systems/log/warn with storage macro:input {}\ndata remove storage macro:input message'),
