    ('./1_20_5/data/macro/functions/core/lib/repeat_n.mcfunction', '$scoreboard players set $rn_n macro.tmp $(n)\nscoreboard players set $rn_i macro.tmp 0\n\nexecute if score $rn_n macro.tmp matches ..0 run return 0\n\n$data modify storage macro:engine _rn_func set value "$(func)"\nfunction macro:core/lib/internal/repeat_n_loop\ndata remove storage macro:engine _rn_func\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/repeat_n ","color":"aqua"},{"text":"$(func) × $(n)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule.mcfunction', '$execute if data storage macro:engine schedules.$(key) run data remove storage macro:engine schedules.$(key)\n\n$data modify storage macro:engine schedules.$(key).func set value "$(func)"\n$data modify storage macro:engine schedules.$(key).interval set value $(interval)\n$data modify storage macro:engine queue append value {func:"$(func)", delay:$(interval)}\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/schedule ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_as.mcfunction', '$execute if data storage macro:engine schedules.$(key) run data remove storage macro:engine schedules.$(key)\n\n$data modify storage macro:engine schedules.$(key).func set value "$(func)"\n$data modify storage macro:engine schedules.$(key).interval set value $(interval)\n$data modify storage macro:engine schedules.$(key).player set value "$(player)"\n$data modify storage macro:engine queue append value {func:"$(func)", delay:$(interval), player:"$(player)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/schedule_as ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" as $(player)","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_cancel.mcfunction', '$data remove storage macro:engine schedules.$(key)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/schedule_cancel ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_cmd.mcfunction', '# ─────────────────────────────────────────────\n# macro:core/lib/schedule_cmd\n# Repeating command scheduler at a fixed interval.\n#\n# Girdi (macro:input):\n# key — scheduler name (unique identifier)\n# cmd — raw command to run on each trigger\n# interval — repeat interval in ticks\n# ─────────────────────────────────────────────\n\n$execute if data storage macro:engine schedules.$(key) run data remove storage macro:engine schedules.$(key)\n\n$data modify storage macro:engine schedules.$(key).cmd set value "$(cmd)"\n$data modify storage macro:engine schedules.$(key).interval set value $(interval)\n$data modify storage macro:engine queue append value {cmd:"$(cmd)", delay:$(interval)}\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/schedule_cmd ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" ($(interval)t)","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_cmd_as.mcfunction', '$execute if data storage macro:engine schedules.$(key) run data remove storage macro:engine schedules.$(key)\n\n$data modify storage macro:engine schedules.$(key).cmd set value "$(cmd)"\n$data modify storage macro:engine schedules.$(key).interval set value $(interval)\n$data modify storage macro:engine schedules.$(key).player set value "$(player)"\n$data modify storage macro:engine queue append value {cmd:"$(cmd)", delay:$(interval), player:"$(player)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/schedule_cmd_as ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" as $(player)","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_if.mcfunction', 'function macro:core/lib/queue_add with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_if_cmd.mcfunction', 'function macro:core/lib/queue_add_cmd with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_list.mcfunction', 'tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Active Schedules ","color":"aqua"},{"text":"━━━━━━━━━","color":"#555555"}]}\nexecute if data storage macro:engine schedules run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"schedules","interpret":false,"color":"gold"}]}\nexecute unless data storage macro:engine schedules run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"(no active schedules)","color":"gray","italic":true}]}\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_renew.mcfunction', '$execute unless data storage macro:engine schedules.$(key) run return 0\n$data modify storage macro:engine _sched_tmp set from storage macro:engine schedules.$(key)\nexecute if data storage macro:engine _sched_tmp.func if data storage macro:engine _sched_tmp.player run function macro:core/lib/internal/schedule_requeue_as with storage macro:engine _sched_tmp\nexecute if data storage macro:engine _sched_tmp.func unless data storage macro:engine _sched_tmp.player run function macro:core/lib/internal/schedule_requeue with storage macro:engine _sched_tmp\nexecute if data storage macro:engine _sched_tmp.cmd if data storage macro:engine _sched_tmp.player run function macro:core/lib/internal/schedule_requeue_cmd_as with storage macro:engine _sched_tmp\nexecute if data storage macro:engine _sched_tmp.cmd unless data storage macro:engine _sched_tmp.player run function macro:core/lib/internal/schedule_requeue_cmd with storage macro:engine _sched_tmp\ndata remove storage macro:engine _sched_tmp\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/schedule_renew ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/core/lib/schedule_reset.mcfunction', '$execute unless data storage macro:engine schedules.$(key) run return 0\n\n$data modify storage macro:engine _sreset set from storage macro:engine schedules.$(key)\n$data modify storage macro:engine _sreset.key set value "$(key)"\n\n$data remove storage macro:engine schedules.$(key)\n\nexecute if data storage macro:engine _sreset.func if data storage macro:engine _sreset.player run function macro:core/lib/internal/schedule_reset_do_as with storage macro:engine _sreset\nexecute if data storage macro:engine _sreset.func unless data storage macro:engine _sreset.player run function macro:core/lib/internal/schedule_reset_do with storage macro:engine _sreset\nexecute if data storage macro:engine _sreset.cmd if data storage macro:engine _sreset.player run function macro:core/lib/internal/schedule_reset_do_cmd_as with storage macro:engine _sreset\nexecute if data storage macro:engine _sreset.cmd unless data storage macro:engine _sreset.player run function macro:core/lib/internal/schedule_reset_do_cmd with storage macro:engine _sreset\ndata remove storage macro:engine _sreset\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/schedule_reset ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/core/lib/sync_tick.mcfunction', 'execute store result storage macro:engine global.tick int 1 run scoreboard players get $tick macro.tmp\nexecute store result storage macro:engine global.epoch int 1 run scoreboard players get $epoch macro.time\nscoreboard players set $tick macro.tmp 0\n'),
    ('./1_20_5/data/macro/functions/core/lib/throttle.mcfunction', 'scoreboard players set $thr_go macro.tmp 1\n\n$execute if data storage macro:engine throttle.$(key) run execute store result score $thr_exp macro.tmp run data get storage macro:engine throttle.$(key)\nexecute store result score $thr_now macro.tmp run scoreboard players get $epoch macro.time\n$execute if data storage macro:engine throttle.$(key) run execute if score $thr_now macro.tmp < $thr_exp macro.tmp run scoreboard players set $thr_go macro.tmp 0\n\n$execute if score $thr_go macro.tmp matches 0 run execute as @a[tag=macro.debug] run tellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/throttle ","color":"aqua"},{"text":"SKIP ","color":"#FF5555"},{"text":"$(key)","color":"aqua"},{"text":" — throttled, skipped","color":"#555555"}]}\nexecute if score $thr_go macro.tmp matches 0 run return 0\n\n$scoreboard players set $thr_int macro.tmp $(interval)\nscoreboard players operation $thr_now macro.tmp += $thr_int macro.tmp\n$execute store result storage macro:engine throttle.$(key) int 1 run scoreboard players get $thr_now macro.tmp\n\nfunction macro:core/lib/queue_add with storage macro:input {}\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/throttle ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/tick_guard.mcfunction', 'execute if score @s macro.tick_guard = $epoch macro.time run return 0\n\nscoreboard players operation @s macro.tick_guard = $epoch macro.time\n\nreturn 1\n'),
    ('./1_20_5/data/macro/functions/core/lib/tick_guard_clear.mcfunction', 'scoreboard players set @s macro.tick_guard -1\n'),
    ('./1_20_5/data/macro/functions/core/lib/ticks_to_time.mcfunction', '$scoreboard players set $ttt_t macro.tmp $(ticks)\n\nexecute if score $ttt_t macro.tmp matches ..-1 run scoreboard players set $ttt_t macro.tmp 0\n\nscoreboard players operation $ttt_r macro.tmp = $ttt_t macro.tmp\nscoreboard players set $ttt_20 macro.tmp 20\nscoreboard players operation $ttt_r macro.tmp %= $ttt_20 macro.tmp\nexecute store result storage macro:output ticks int 1 run scoreboard players get $ttt_r macro.tmp\n\nscoreboard players operation $ttt_t macro.tmp /= $ttt_20 macro.tmp\n\nscoreboard players operation $ttt_r macro.tmp = $ttt_t macro.tmp\nscoreboard players set $ttt_60 macro.tmp 60\nscoreboard players operation $ttt_r macro.tmp %= $ttt_60 macro.tmp\nexecute store result storage macro:output seconds int 1 run scoreboard players get $ttt_r macro.tmp\n\nscoreboard players operation $ttt_t macro.tmp /= $ttt_60 macro.tmp\n\nscoreboard players operation $ttt_r macro.tmp = $ttt_t macro.tmp\nscoreboard players operation $ttt_r macro.tmp %= $ttt_60 macro.tmp\nexecute store result storage macro:output minutes int 1 run scoreboard players get $ttt_r macro.tmp\n\nscoreboard players operation $ttt_t macro.tmp /= $ttt_60 macro.tmp\nexecute store result storage macro:output hours int 1 run scoreboard players get $ttt_t macro.tmp\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/ticks_to_time ","color":"aqua"},{"text":"($(ticks)t)","color":"gray"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"hours","color":"green"},{"text":"h ","color":"gray"},{"storage":"macro:output","nbt":"minutes","color":"green"},{"text":"m ","color":"gray"},{"storage":"macro:output","nbt":"seconds","color":"green"},{"text":"s ","color":"gray"},{"storage":"macro:output","nbt":"ticks","color":"green"},{"text":"t","color":"gray"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/wait.mcfunction', 'function macro:core/lib/queue_add with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/wait_as.mcfunction', '$data modify storage macro:engine queue append value {func:"$(func)", delay:$(delay), player:"$(player)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/wait_as ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"},{"text":" ($(delay)t) as $(player)","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/core/lib/wait_cmd.mcfunction', 'function macro:core/lib/queue_add_cmd with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/wait_cmd_as.mcfunction', '$data modify storage macro:engine queue append value {cmd:"$(cmd)", delay:$(delay), player:"$(player)"}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/wait_cmd_as ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(cmd)","color":"aqua"},{"text":" ($(delay)t) as $(player)","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/add.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/batch/add\n# Adds a job to the batch queue.\n#\n# INPUT (storage macro:input):\n# id → batch id\n# func → function to run (opsiyonel)\n# cmd → command to run (optional, used if no func)\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/batch/internal/add_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/begin.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/batch/begin\n# Starts a new batch or clears an existing one.\n#\n# INPUT (storage macro:input):\n# id → batch id\n# spread_over → how many ticks to spread over (default: 1)\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/batch/internal/begin_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/cancel.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/batch/cancel\n# Cancels a batch that has not been flushed.\n# Items already flushed and queued cannot be cancelled\n# (pulling from process_queue is not supported — AME design constraint).\n#\n# INPUT (storage macro:input):\n# id → batch id\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/batch/internal/cancel_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/flush.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/batch/flush\n# Splits batch jobs across spread_over ticks and adds them to process_queue.\n# Jobs per tick: ceil(items / spread_over).\n# Batch record is deleted after flush.\n#\n# INPUT (storage macro:input):\n# id → batch id\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/batch/internal/flush_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/add_cmd.mcfunction', '# macro:core/lib/batch/internal/add_cmd [MACRO]\n# INPUT: $(id), $(cmd)\n# Called with cmd field guaranteed.\n\n$data modify storage macro:engine batches.$(id).items append value {cmd:"$(cmd)"}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/add_exec.mcfunction', '# macro:core/lib/batch/internal/add_exec [MACRO]\n# INPUT: $(id)\n# func or cmd field existence is checked outside the macro,\n# then the relevant append_func / append_cmd is called — prevents undefined $(func/cmd).\n\n$execute unless data storage macro:engine batches.$(id) run return 0\n\nexecute if data storage macro:input func run function macro:core/lib/batch/internal/add_func with storage macro:input\nexecute if data storage macro:input cmd run function macro:core/lib/batch/internal/add_cmd with storage macro:input\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/add_func.mcfunction', '# macro:core/lib/batch/internal/add_func [MACRO]\n# INPUT: $(id), $(func)\n# Called with func field guaranteed.\n\n$data modify storage macro:engine batches.$(id).items append value {func:"$(func)"}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/begin_exec.mcfunction', '# macro:core/lib/batch/internal/begin_exec [MACRO]\n# INPUT: $(id), $(spread_over)\n\n$data modify storage macro:engine batches.$(id) set value {items:[],spread_over:$(spread_over),flushed:0b}\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/batch/begin ","color":"aqua"},{"text":"$(id)","color":"white"},{"text":" spread_over=$(spread_over)t","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/cancel_exec.mcfunction', '# macro:core/lib/batch/internal/cancel_exec [MACRO]\n# INPUT: $(id)\n\n$execute unless data storage macro:engine batches.$(id) run return 0\n$data remove storage macro:engine batches.$(id)\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/batch/cancel ","color":"aqua"},{"text":"$(id)","color":"white"},{"text":" — cancelled","color":"#FF5555"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/flush_exec.mcfunction', '# macro:core/lib/batch/internal/flush_exec [MACRO]\n# INPUT: $(id)\n# For each item, delay = floor(idx * spread_over / total) is computed.\n# Item\'lar tek tek process_queue\'ya eklenir — slice storage gerekmez.\n\n$execute unless data storage macro:engine batches.$(id) run return 0\n\n# Load total and spread_over values to score\n$execute store result score $bfl_total macro.tmp run data get storage macro:engine batches.$(id).items\n$execute store result score $bfl_spread macro.tmp run data get storage macro:engine batches.$(id).spread_over\nexecute if score $bfl_spread macro.tmp matches ..0 run scoreboard players set $bfl_spread macro.tmp 1\nexecute if score $bfl_total macro.tmp matches 0 run return 0\n\n# Iteration counter\nscoreboard players set $bfl_idx macro.tmp 0\n\n# Copy items to working storage\n$data modify storage macro:engine _bfl_items set from storage macro:engine batches.$(id).items\n$data modify storage macro:engine _bfl_id set value "$(id)"\n\nfunction macro:core/lib/batch/internal/flush_loop\n\ndata remove storage macro:engine _bfl_items\ndata remove storage macro:engine _bfl_id\nscoreboard players reset $bfl_idx macro.tmp\nscoreboard players reset $bfl_total macro.tmp\nscoreboard players reset $bfl_spread macro.tmp\n\n$data remove storage macro:engine batches.$(id)\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/batch/flush ","color":"aqua"},{"text":"$(id)","color":"white"},{"text":" — queued","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/flush_loop.mcfunction', '# macro:core/lib/batch/internal/flush_loop\n# Consumes _bfl_items. For each item:\n# delay = floor($bfl_idx * $bfl_spread / $bfl_total)\n# computed and added to the queue.\n# func or cmd presence is checked with execute if data.\n\nexecute unless data storage macro:engine _bfl_items[0] run return 0\n\n# delay = floor(idx * spread / total)\nscoreboard players operation $bfl_delay macro.tmp = $bfl_idx macro.tmp\nscoreboard players operation $bfl_delay macro.tmp *= $bfl_spread macro.tmp\nscoreboard players operation $bfl_delay macro.tmp /= $bfl_total macro.tmp\n\n# Move item to temporary storage\ndata modify storage macro:engine _bfl_cur set from storage macro:engine _bfl_items[0]\ndata remove storage macro:engine _bfl_items[0]\n\n# Write delay to item, then queue by func/cmd\nexecute store result storage macro:engine _bfl_cur.delay int 1 run scoreboard players get $bfl_delay macro.tmp\n\nexecute if data storage macro:engine _bfl_cur.func run function macro:core/lib/batch/internal/flush_queue_func with storage macro:engine _bfl_cur\nexecute unless data storage macro:engine _bfl_cur.func run execute if data storage macro:engine _bfl_cur.cmd run function macro:core/lib/batch/internal/flush_queue_cmd with storage macro:engine _bfl_cur\n\ndata remove storage macro:engine _bfl_cur\nscoreboard players add $bfl_idx macro.tmp 1\n\nfunction macro:core/lib/batch/internal/flush_loop'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/flush_queue_cmd.mcfunction', '# macro:core/lib/batch/internal/flush_queue_cmd [MACRO]\n# INPUT: $(cmd), $(delay) — from _bfl_cur; cmd field guaranteed.\n\n$data modify storage macro:engine queue append value {cmd:"$(cmd)", delay:$(delay)}\n'),
    ('./1_20_5/data/macro/functions/core/lib/batch/internal/flush_queue_func.mcfunction', '# macro:core/lib/batch/internal/flush_queue_func [MACRO]\n# INPUT: $(func), $(delay) — _bfl_cur\'dan; func field guaranteed.\n\n$data modify storage macro:engine queue append value {func:"$(func)", delay:$(delay)}\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/is_alive.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/fiber/is_alive\n# Checks whether a fiber is active.\n#\n# INPUT (storage macro:input):\n# id → fiber id\n#\n# OUTPUT (storage macro:output):\n# result → 1b (active) | 0b (dead or never started)\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/fiber/internal/is_alive_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/kill.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/fiber/kill\n# Stops a fiber. Pending resumes in the queue will not run.\n#\n# INPUT (storage macro:input):\n# id → fiber id\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/fiber/internal/kill_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/resume.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/fiber/resume\n# Resumes a fiber immediately (no delay).\n# Used to trigger a fiber step externally without yield.\n#\n# INPUT (storage macro:input):\n# id → fiber id\n# func → function to run\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/fiber/internal/resume_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/spawn.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/fiber/spawn\n# Starts a new fiber and immediately runs its first step.\n# If spawned with the same id, the existing fiber is replaced.\n#\n# INPUT (storage macro:input):\n# id → fiber id (unique string)\n# func → function name to start\n#\n# EXAMPLE:\n# data modify storage macro:input id set value "boss_intro"\n# data modify storage macro:input func set value "mypack:boss/step_0"\n# function macro:core/lib/fiber/spawn\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/fiber/internal/spawn_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/yield.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:core/lib/fiber/yield\n# Exits a fiber step and queues the next step.\n# Checks if the fiber is dead — no resume after kill.\n#\n# INPUT (storage macro:input):\n# id → fiber id\n# resume → function name of the next step\n# delay → how many ticks to wait before resuming (default: 1)\n#\n# CALL SITE: called at the end of a fiber step function.\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:core/lib/fiber/internal/yield_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/internal/is_alive_exec.mcfunction', '# macro:core/lib/fiber/internal/is_alive_exec [MACRO]\n# INPUT: $(id)\n\ndata modify storage macro:output result set value 0b\n$execute if data storage macro:engine fibers.$(id){alive:1b} run data modify storage macro:output result set value 1b\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/fiber/is_alive ","color":"aqua"},{"text":"$(id)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/internal/kill_exec.mcfunction', '# macro:core/lib/fiber/internal/kill_exec [MACRO]\n# INPUT: $(id)\n\n$execute unless data storage macro:engine fibers.$(id) run return 0\n\n$data remove storage macro:engine fibers.$(id).alive\n$data remove storage macro:engine fibers.$(id).resume\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/fiber/kill ","color":"aqua"},{"text":"[killed] ","color":"#FF5555"},{"text":"$(id)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/internal/resume_dispatch.mcfunction', '# macro:core/lib/fiber/internal/resume_dispatch\n# Called by process_queue.\n# Pops _pending[0], checks fiber alive status, runs the function.\n\nexecute unless data storage macro:engine fibers._pending[0] run return 0\n\ndata modify storage macro:engine _fib_cur set from storage macro:engine fibers._pending[0]\ndata remove storage macro:engine fibers._pending[0]\n\nfunction macro:core/lib/fiber/internal/resume_exec with storage macro:engine _fib_cur\ndata remove storage macro:engine _fib_cur'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/internal/resume_exec.mcfunction', '# macro:core/lib/fiber/internal/resume_exec [MACRO]\n# INPUT: $(id), $(func)\n# Fed from _fib_cur.\n\n# Is the fiber still alive?\n$execute unless data storage macro:engine fibers.$(id){alive:1b} run return 0\n\n# Run via central dispatch\n$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/fiber/resume ","color":"aqua"},{"text":"[run] ","color":"green"},{"text":"$(id)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/internal/spawn_exec.mcfunction', '# macro:core/lib/fiber/internal/spawn_exec [MACRO]\n# INPUT: $(id), $(func)\n\n# Delete if same id exists\n$data remove storage macro:engine fibers.$(id)\n\n# Create fiber record\n$data modify storage macro:engine fibers.$(id) set value {alive:1b}\n\n# Run first step via central dispatch\n$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/fiber/spawn ","color":"aqua"},{"text":"[start] ","color":"green"},{"text":"$(id)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/core/lib/fiber/internal/yield_exec.mcfunction', '# macro:core/lib/fiber/internal/yield_exec [MACRO]\n# INPUT: $(id), $(resume), $(delay)\n\n# Do not continue if fiber is dead\n$execute unless data storage macro:engine fibers.$(id){alive:1b} run return 0\n\n# Write resume point to fiber record (readable by is_alive/resume)\n$data modify storage macro:engine fibers.$(id).resume set value "$(resume)"\n\n# Add this fiber\'s resume request to the _pending queue.\n# resume_dispatch consumes _pending[0] each call → yield/dispatch match 1:1.\n$data modify storage macro:engine fibers._pending append value {id:"$(id)", func:"$(resume)"}\n\n# Add dispatch entry to process_queue — runs after delay ticks\n$data modify storage macro:engine queue append value {func:"macro:core/lib/fiber/internal/resume_dispatch", delay:$(delay)}\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/fiber/yield ","color":"aqua"},{"text":"$(id)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(resume)","color":"aqua"},{"text":" in $(delay)t","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/for_each_list_call.mcfunction', '$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/for_each_list_step.mcfunction', 'execute unless data storage macro:engine _felist_input[0] run execute as @a[tag=macro.debug] run tellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/for_each_list ","color":"aqua"},{"text":"DONE ","color":"green"},{"text":"list exhausted, loop ended","color":"#555555"}]}\nexecute unless data storage macro:engine _felist_input[0] run return 0\n\ndata modify storage macro:engine _felist_current set from storage macro:engine _felist_input[0]\nexecute store result storage macro:engine _felist_i int 1 run scoreboard players get $felist_i macro.tmp\n\nfunction macro:core/lib/internal/for_each_list_call with storage macro:engine _felist_state\n\ndata remove storage macro:engine _felist_input[0]\nscoreboard players add $felist_i macro.tmp 1\n\nfunction macro:core/lib/internal/for_each_list_step\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/queue_fire.mcfunction', 'execute if data storage macro:engine queue[0].func if data storage macro:engine queue[0].player run function macro:core/lib/internal/queue_run_func_as with storage macro:engine queue[0]\nexecute if data storage macro:engine queue[0].func unless data storage macro:engine queue[0].player run function macro:core/lib/internal/queue_run_func with storage macro:engine queue[0]\nexecute if data storage macro:engine queue[0].cmd if data storage macro:engine queue[0].player run function macro:core/lib/internal/queue_run_cmd_as with storage macro:engine queue[0]\nexecute if data storage macro:engine queue[0].cmd unless data storage macro:engine queue[0].player run function macro:core/lib/internal/queue_run_cmd with storage macro:engine queue[0]\ndata remove storage macro:engine queue[0]\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/queue_run_cmd.mcfunction', 'tellraw @a[tag=macro.admin] [{"selector":"@s","color":"gold"},{"text":" - command executed","color":"yellow"}]\n\n$$(cmd)\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/queue_run_cmd_as.mcfunction', '$execute as $(player) at @s run $(cmd)\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/queue_run_func.mcfunction', '$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/queue_run_func_as.mcfunction', '$data modify storage macro:engine _dispatch.func set value "$(func)"\n$execute as $(player) at @s run function #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/repeat_call.mcfunction', '$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/repeat_n_call.mcfunction', '$data modify storage macro:engine _dispatch.func set value "$(_rn_func)"\nfunction #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/repeat_n_loop.mcfunction', 'execute if score $rn_i macro.tmp >= $rn_n macro.tmp run return 0\n\nexecute store result score $repeat_i macro.tmp run scoreboard players get $rn_i macro.tmp\nfunction macro:core/lib/internal/repeat_n_call with storage macro:engine {}\nscoreboard players add $rn_i macro.tmp 1\nfunction macro:core/lib/internal/repeat_n_loop\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/repeat_run.mcfunction', 'execute store result score $rep_r macro.tmp run data get storage macro:engine _repeat.remaining\nexecute if score $rep_r macro.tmp matches ..0 run execute as @a[tag=macro.debug] run tellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"lib/repeat ","color":"aqua"},{"text":"DONE ","color":"green"},{"text":"all iterations completed","color":"#555555"}]}\nexecute if score $rep_r macro.tmp matches ..0 run return 0\n\nfunction macro:core/lib/internal/repeat_call with storage macro:engine _repeat\n\nscoreboard players remove $rep_r macro.tmp 1\nexecute store result storage macro:engine _repeat.remaining int 1 run scoreboard players get $rep_r macro.tmp\nexecute store result score $rep_i macro.tmp run data get storage macro:engine _repeat.i\nscoreboard players add $rep_i macro.tmp 1\nexecute store result storage macro:engine _repeat.i int 1 run scoreboard players get $rep_i macro.tmp\n\nfunction macro:core/lib/internal/repeat_run\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/schedule_requeue.mcfunction', '$data modify storage macro:engine queue append value {func:"$(func)", delay:$(interval)}\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/schedule_requeue_as.mcfunction', '$data modify storage macro:engine queue append value {func:"$(func)", delay:$(interval), player:"$(player)"}\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/schedule_requeue_cmd.mcfunction', '$data modify storage macro:engine queue append value {cmd:"$(cmd)", delay:$(interval)}\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/schedule_requeue_cmd_as.mcfunction', '$data modify storage macro:engine queue append value {cmd:"$(cmd)", delay:$(interval), player:"$(player)"}\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/schedule_reset_do.mcfunction', '$data modify storage macro:engine schedules.$(key).func set value "$(func)"\n$data modify storage macro:engine schedules.$(key).interval set value $(interval)\n$data modify storage macro:engine queue append value {func:"$(func)", delay:$(interval)}\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/schedule_reset_do_as.mcfunction', '$data modify storage macro:engine schedules.$(key).func set value "$(func)"\n$data modify storage macro:engine schedules.$(key).interval set value $(interval)\n$data modify storage macro:engine schedules.$(key).player set value "$(player)"\n$data modify storage macro:engine queue append value {func:"$(func)", delay:$(interval), player:"$(player)"}\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/schedule_reset_do_cmd.mcfunction', '$data modify storage macro:engine schedules.$(key).cmd set value "$(cmd)"\n$data modify storage macro:engine schedules.$(key).interval set value $(interval)\n$data modify storage macro:engine queue append value {cmd:"$(cmd)", delay:$(interval)}\n'),
    ('./1_20_5/data/macro/functions/core/lib/internal/schedule_reset_do_cmd_as.mcfunction', '$data modify storage macro:engine schedules.$(key).cmd set value "$(cmd)"\n$data modify storage macro:engine schedules.$(key).interval set value $(interval)\n$data modify storage macro:engine schedules.$(key).player set value "$(player)"\n$data modify storage macro:engine queue append value {cmd:"$(cmd)", delay:$(interval), player:"$(player)"}\n'),
    ('./1_20_5/data/macro/functions/core/load/warn.mcfunction', 'tellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"⚠ ","color":"yellow"},{"text":"Engine not loaded yet. Run ","color":"#555555"},{"text":"/reload","color":"aqua","underlined":true},{"text":" first.","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/core/state/clear.mcfunction', '$data remove storage macro:engine states.$(player)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/clear ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/core/state/clear_all.mcfunction', 'data remove storage macro:engine states\n'),
    ('./1_20_5/data/macro/functions/core/state/get.mcfunction', 'data remove storage macro:output result\n$execute if data storage macro:engine states.$(player) run data modify storage macro:output result set from storage macro:engine states.$(player)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/get ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/core/state/is.mcfunction', 'data modify storage macro:output result set value 0b\n$execute if data storage macro:engine states{$(player):"$(state)"} run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/is ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(state)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/core/state/list.mcfunction', 'tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Player States ","color":"aqua"},{"text":"━━━━━━━━━━","color":"#555555"}]}\nexecute if data storage macro:engine states run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"states","interpret":false,"color":"white"}]}\nexecute unless data storage macro:engine states run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"(no active states)","color":"gray","italic":true}]}\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/core/state/set.mcfunction', '$data modify storage macro:engine states.$(player) set value "$(state)"\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/set ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(state)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/core/state/toggle.mcfunction', 'scoreboard players set $st_tog macro.tmp 0\n$execute if data storage macro:engine {states:{$(player):"$(on)"}} run scoreboard players set $st_tog macro.tmp 1\n\n$execute if score $st_tog macro.tmp matches 1 run data modify storage macro:engine states.$(player) set value "$(off)"\n$execute if score $st_tog macro.tmp matches 0 run data modify storage macro:engine states.$(player) set value "$(on)"\n\ndata remove storage macro:output result\n$data modify storage macro:output result set from storage macro:engine states.$(player)\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"state/toggle ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" (","color":"#555555"},{"text":"$(on)","color":"gray"},{"text":"↔","color":"#555555"},{"text":"$(off)","color":"gray"},{"text":") → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/core/tick/admin_systems.mcfunction', 'tag @a[tag=macro.admin] add macro.debug\nscoreboard players enable @a[tag=macro.admin] macro_menu\nscoreboard players enable @a[tag=macro.admin] macro_action\nscoreboard players enable @a[tag=macro.admin] macro_run\n'),
    ('./1_20_5/data/macro/functions/core/tick/config.mcfunction', '# AME Tick Channel Defaults\n# ─────────────────────────────────────────────────────────────────────────────\n# This file is the "JSON config" for the tick engine.\n# It is executed ONCE on first world load (and on macro:core/tick/reset_channels).\n# Modify here to change the default channel layout that all new worlds receive.\n#\n# Channel fields\n# ──────────────\n# id (string) unique name — used by all API functions\n# enabled (1b|0b) 1b = runs each applicable tick, 0b = dormant\n# rate (int) fire every N ticks [1=every tick, 20=1/s, 200=10/s]\n# offset (int) phase offset 0..(rate-1)\n# use different offsets per channel to spread CPU load\n# fn (string) function resource location to call\n# condition (string) predicate path; "" means "always fire"\n# e.g. "macro:is_daytime" — only runs during daylight\n#\n# API (available after load)\n# ──────────────────────────\n# function macro:core/tick/channel/enable {id:"..."}\n# function macro:core/tick/channel/disable {id:"..."}\n# function macro:core/tick/channel/set_rate {id:"...",rate:N}\n# function macro:core/tick/channel/set_offset {id:"...",offset:N}\n# function macro:core/tick/channel/set_condition {id:"...",condition:"ns:pred"}\n# function macro:core/tick/channel/register {id:"...",rate:N,offset:N,fn:"ns:path",enabled:1,condition:""}\n# function macro:core/tick/channel/unregister {id:"..."}\n# function macro:core/tick/channel/list\n# function macro:core/tick/pause\n# function macro:core/tick/resume\n# function macro:core/tick/status\n# function macro:core/tick/reset_channels\n# ─────────────────────────────────────────────────────────────────────────────\n\ndata modify storage macro:engine tick.channels set value []\n\n# time_systems — epoch counter; must stay at rate:1 offset:0\ndata modify storage macro:engine tick.channels append value {id:"time_systems",enabled:1b,rate:1,offset:0,fn:"macro:core/tick/time_systems",condition:""}\n\n# player_systems — per-player state polling; every tick\ndata modify storage macro:engine tick.channels append value {id:"player_systems",enabled:1b,rate:1,offset:0,fn:"macro:core/tick/player_systems",condition:""}\n\n# queue_systems — scheduled task queue; every tick\ndata modify storage macro:engine tick.channels append value {id:"queue_systems",enabled:1b,rate:1,offset:0,fn:"macro:core/tick/queue_systems",condition:""}\n\n# hud_systems — HUD refresh; every 2 ticks, offset 1 (fires on odd ticks, avoiding collision with rate-1 channels)\ndata modify storage macro:engine tick.channels append value {id:"hud_systems",enabled:1b,rate:2,offset:1,fn:"macro:core/tick/hud_systems",condition:""}\n\n# admin_systems — admin tooling; every 4 ticks, offset 2\ndata modify storage macro:engine tick.channels append value {id:"admin_systems",enabled:1b,rate:4,offset:2,fn:"macro:core/tick/admin_systems",condition:""}\n\ndata modify storage macro:engine tick.channels append value {id:"main_systems",enabled:1b,rate:4,offset:2,fn:"macro:tick",condition:""}'),
    ('./1_20_5/data/macro/functions/core/tick/disabled.mcfunction', ''),
    ('./1_20_5/data/macro/functions/core/tick/dispatch.mcfunction', '# AME Tick — Channel Dispatcher\n# Increments the internal tick counter then iterates all channels.\n\nscoreboard players add #tick_ctr macro.tick 1\ndata modify storage macro:tick_work i set value 0\nfunction macro:core/tick/dispatch/step with storage macro:tick_work'),
    ('./1_20_5/data/macro/functions/core/tick/hud_systems.mcfunction', 'execute if data storage macro:engine pb_obj run scoreboard players operation $pb_mod macro.tmp = $epoch macro.time\nexecute if data storage macro:engine pb_obj run scoreboard players operation $pb_mod macro.tmp %= $pb_four macro.tmp\nexecute if data storage macro:engine pb_obj run execute if score $pb_mod macro.tmp matches 0 run execute as @a run function macro:systems/string/progress_bar_self with storage macro:engine {}\n'),
    ('./1_20_5/data/macro/functions/core/tick/init_channels.mcfunction', "# Called during every load — only writes defaults if channels don't exist yet.\n# This preserves any runtime customisations made via the channel API.\n# To reset to file defaults: function macro:core/tick/reset_channels\nexecute unless data storage macro:engine tick.channels run function macro:core/tick/config"),
    ('./1_20_5/data/macro/functions/core/tick/pause.mcfunction', '# macro:core/tick/pause — Suspend all tick channels until macro:core/tick/resume\ndata modify storage macro:engine tick.paused set value 1b\ntellraw @s [{"text":"[AME] ","color":"gold"},{"text":"Tick engine paused.","color":"red"}]'),
    ('./1_20_5/data/macro/functions/core/tick/player_systems.mcfunction', 'execute as @a run function macro:core/lib/tick_guard_clear\n\nexecute as @a[scores={macro_menu=1..}] run function macro:menu\nscoreboard players set @a[scores={macro_menu=1..}] macro_menu 0\nscoreboard players enable @a[scores={macro_menu=-1..}] macro_menu\n\nexecute as @a[scores={macro_run=1..}] run function #macro:admin/run\nscoreboard players set @a[scores={macro_run=1..}] macro_run 0\nscoreboard players enable @a[scores={macro_run=-1..}] macro_run\n\nexecute as @a[scores={macro_action=1..}] run function macro:api/trigger/internal/dispatch\n\nfunction macro:api/interaction/internal/tick_scan\n\nfunction macro:api/perm/trigger/internal/tick_start\n\nfunction macro:api/wand/internal/tick_scan\n\nfunction macro:systems/hook/internal/tick_scan\n\nfunction macro:systems/geo/region_watch/internal/tick_scan\n# Event bus — on_tick\nfunction #macro:events/on_tick\n'),
    ('./1_20_5/data/macro/functions/core/tick/queue_systems.mcfunction', 'function macro:core/lib/process_queue\n'),
    ('./1_20_5/data/macro/functions/core/tick/reset_channels.mcfunction', '# macro:core/tick/reset_channels — Overwrite channel storage with config file defaults\n# WARNING: this discards ALL runtime API changes (enable/disable/set_rate/etc.)\nfunction macro:core/tick/config\ntellraw @s [{"text":"[AME] ","color":"gold"},{"text":"Tick channels reset to defaults.","color":"green"}]'),
    ('./1_20_5/data/macro/functions/core/tick/resume.mcfunction', '# macro:core/tick/resume — Resume tick engine\ndata remove storage macro:engine tick.paused\ntellraw @s [{"text":"[AME] ","color":"gold"},{"text":"Tick engine resumed.","color":"green"}]'),
    ('./1_20_5/data/macro/functions/core/tick/status.mcfunction', '# macro:core/tick/status — Show tick engine diagnostics\ntellraw @s [{"text":"","extra":[{"text":"══ AME Tick Engine v2 ══","color":"gold","bold":true}]}]\ntellraw @s [{"text":" Counter ","color":"gray"},{"score":{"name":"#tick_ctr","objective":"macro.tick"},"color":"aqua"}]\ntellraw @s [{"text":" Paused ","color":"gray"},{"storage":"macro:engine","nbt":"tick.paused","color":"red"}]\ntellraw @s [{"text":" Channels","color":"gray"}]\ntellraw @s {"storage":"macro:engine","nbt":"tick.channels","color":"yellow"}'),
    ('./1_20_5/data/macro/functions/core/tick/time_systems.mcfunction', 'scoreboard players add $epoch macro.time 1\nscoreboard players add $tick macro.tmp 1\n\nscoreboard players set $pq_depth macro.tmp 0\n'),
    ('./1_20_5/data/macro/functions/core/tick/channel/disable.mcfunction', '# macro:core/tick/channel/disable — Disable a tick channel by ID\n# Usage: function macro:core/tick/channel/disable {id:"channel_id"}\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {enabled:0b}'),
    ('./1_20_5/data/macro/functions/core/tick/channel/enable.mcfunction', '# macro:core/tick/channel/enable — Enable a tick channel by ID\n# Usage: function macro:core/tick/channel/enable {id:"channel_id"}\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {enabled:1b}'),
    ('./1_20_5/data/macro/functions/core/tick/channel/list.mcfunction', '# macro:core/tick/channel/list — Print all registered tick channels\ntellraw @s {"storage":"macro:engine","nbt":"tick.channels","color":"yellow"}'),
    ('./1_20_5/data/macro/functions/core/tick/channel/register.mcfunction', '# macro:core/tick/channel/register — Register or replace a tick channel\n# Usage:\n# function macro:core/tick/channel/register {id:"my_sys",rate:20,offset:0,fn:"my_ns:tick/my_system",enabled:1,condition:""}\n#\n# Fields:\n# id (string) — unique channel identifier\n# enabled (0|1) — 1 = active, 0 = paused; stored as byte internally\n# rate (int) — fire every N ticks (1 = every tick, 20 = 1/s, 1200 = 1/min)\n# offset (int) — phase shift 0..(rate-1); spread channels to avoid lag spikes\n# fn (string) — function resource location to execute\n# condition (string) — predicate path, or "" to always fire regardless of world state\n\n# Remove any existing channel with same ID (idempotent)\n$data remove storage macro:engine tick.channels[{id:"$(id)"}]\n\n# Append new channel definition\n$data modify storage macro:engine tick.channels append value {id:"$(id)",enabled:$(enabled)b,rate:$(rate),offset:$(offset),fn:"$(fn)",condition:"$(condition)"}'),
    ('./1_20_5/data/macro/functions/core/tick/channel/set_condition.mcfunction', '# macro:core/tick/channel/set_condition — Set or clear condition predicate\n# Usage: function macro:core/tick/channel/set_condition {id:"channel_id",condition:"ns:pred"}\n# function macro:core/tick/channel/set_condition {id:"channel_id",condition:""} ← always-run\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {condition:"$(condition)"}'),
    ('./1_20_5/data/macro/functions/core/tick/channel/set_offset.mcfunction', '# macro:core/tick/channel/set_offset — Change phase offset (0 to rate-1)\n# Usage: function macro:core/tick/channel/set_offset {id:"channel_id",offset:5}\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {offset:$(offset)}'),
    ('./1_20_5/data/macro/functions/core/tick/channel/set_rate.mcfunction', '# macro:core/tick/channel/set_rate — Change execution rate (every N ticks, min 1)\n# Usage: function macro:core/tick/channel/set_rate {id:"channel_id",rate:20}\n$data modify storage macro:engine tick.channels[{id:"$(id)"}] merge value {rate:$(rate)}'),
    ('./1_20_5/data/macro/functions/core/tick/channel/unregister.mcfunction', '# macro:core/tick/channel/unregister — Remove a tick channel by ID\n# Usage: function macro:core/tick/channel/unregister {id:"channel_id"}\n$data remove storage macro:engine tick.channels[{id:"$(id)"}]'),
    ('./1_20_5/data/macro/functions/core/tick/dispatch/channel.mcfunction', '# AME Tick — Channel Loader [MACRO]\n# Copies channels[i] into work storage, skips if disabled.\n# Input: $(i) — channel index\n\n$data modify storage macro:tick_work channel set from storage macro:engine tick.channels[$(i)]\nexecute unless data storage macro:tick_work channel{enabled:1b} run return 0\nfunction macro:core/tick/dispatch/rate_check with storage macro:tick_work channel'),
    ('./1_20_5/data/macro/functions/core/tick/dispatch/exec.mcfunction', '# AME Tick — Channel Execute [MACRO]\n# Calls fn directly if condition is empty, otherwise checks predicate first.\n# Input: $(fn), $(condition)\n#\n# condition:"" → always run (no predicate check)\n# condition:"macro:is_daytime" → only run when predicate passes\n\n$data modify storage macro:engine _dispatch.func set value "$(fn)"\nexecute if data storage macro:tick_work channel{condition:""} run function #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/core/tick/dispatch/exec2.mcfunction', '# AME Tick — Channel Execute [MACRO]\n# Calls fn directly if condition is empty, otherwise checks predicate first.\n# Input: $(fn), $(condition)\n#\n# condition:"" → always run (no predicate check)\n# condition:"macro:is_daytime" → only run when predicate passes\n\nexecute if data storage macro:tick_work channel{condition:""} run return 0\n\n$data modify storage macro:engine _dispatch.func set value "$(fn)"\n$execute as @a[limit=1] at @s if predicate $(condition) run function #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/core/tick/dispatch/rate_check.mcfunction', "# AME Tick — Rate/Offset Check [MACRO]\n# Fires when (#tick_ctr - offset) % rate == 0.\n# Input: $(rate), $(offset), $(fn), $(condition)\n#\n# rate:1 = every tick | rate:20 = every second | rate:200 = every 10s\n# offset: phase shift, spreads channels so they don't all run on the same tick\n\n$scoreboard players set #rate macro.tick $(rate)\n$scoreboard players set #offset macro.tick $(offset)\n\n# Compute modular position\nscoreboard players operation #check macro.tick = #tick_ctr macro.tick\nscoreboard players operation #check macro.tick -= #offset macro.tick\nscoreboard players operation #check macro.tick %= #rate macro.tick\n\n# Fix negative remainder (possible when tick_ctr < offset at world start)\nexecute if score #check macro.tick matches ..-1 run scoreboard players operation #check macro.tick += #rate macro.tick\n\n# Not this tick → skip\nexecute unless score #check macro.tick matches 0 run return 0\n\n# Passed → execute channel function\nfunction macro:core/tick/dispatch/exec with storage macro:tick_work channel\nfunction macro:core/tick/dispatch/exec2 with storage macro:tick_work channel"),
    ('./1_20_5/data/macro/functions/core/tick/dispatch/step.mcfunction', '# AME Tick — Dispatch Step [MACRO]\n# Recursive iterator over tick.channels[].\n# Terminates automatically when index exceeds array length.\n# Input: $(i) — current channel array index\n\n# Termination: channel[i] absent → stop\n$execute unless data storage macro:engine tick.channels[$(i)] run return 0\n\n# Process this channel\n$function macro:core/tick/dispatch/channel {i:$(i)}\n\n# Advance: $(i)+1 → write back → recurse\n$scoreboard players set #ch_next macro.tick $(i)\nscoreboard players add #ch_next macro.tick 1\nexecute store result storage macro:tick_work i int 1 run scoreboard players get #ch_next macro.tick\nfunction macro:core/tick/dispatch/step with storage macro:tick_work'),
    ('./1_20_5/data/macro/functions/debug/dump_cooldowns.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:debug/dump_cooldowns\n# Dumps all active cooldown records to screen.\n# Usage: /function macro:debug/dump_cooldowns\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Cooldown Dump ","color":"aqua"},{"text":"━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"engine.cooldowns","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"cooldowns","color":"yellow","italic":false}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"epoch now: ","color":"gray"},{"score":{"name":"$epoch","objective":"macro.time"},"color":"aqua"}]}\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/debug/dump_events.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:debug/dump_events\n# Lists all registered event handlers.\n# Usage: /function macro:debug/dump_events\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Event Registry ","color":"aqua"},{"text":"━━━━━━━━━━━━━━━━","color":"#555555"}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"engine.events","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"events","color":"light_purple","italic":false}]}\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/debug/dump_players.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:debug/dump_players\n# Shows all player variables (player vars), PIDs and their states.\n# Usage: /function macro:debug/dump_players\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Player State Dump ","color":"aqua"},{"text":"━━━━━━━━━━━━━","color":"#555555"}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"players ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"players","color":"green","italic":false}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"pids ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"player_pids","color":"aqua","italic":false}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"perms ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"permissions","color":"yellow","italic":false}]}\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/debug/dump_schedules.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:debug/dump_schedules\n# Shows active schedules and the queue.\n# Usage: /function macro:debug/dump_schedules\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Schedule / Queue Dump ","color":"aqua"},{"text":"━━━━━━━","color":"#555555"}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"schedules","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"schedules","color":"gold","italic":false}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"queue ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"queue","color":"gold","italic":false}]}\ntellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"throttle ","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:engine","nbt":"throttle","color":"gray","italic":false}]}\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/debug/example_events.mcfunction', 'tellraw @a[tag=macro.debug] {"text":"[DEBUG] Event system test starting...","color":"yellow"}\n\ndata modify storage macro:input event set value "on_join"\ndata modify storage macro:input func set value "macro:debug/internal/on_join_handler"\nfunction macro:events/register with storage macro:input {}\n\ndata modify storage macro:input event set value "on_kill"\ndata modify storage macro:input func set value "macro:debug/internal/on_kill_handler"\nfunction macro:events/register with storage macro:input {}\n\ndata remove storage macro:engine event_context\ndata modify storage macro:engine event_context.player set value "TestPlayer"\ndata modify storage macro:engine event_context.reason set value "debug_test"\n\ndata modify storage macro:input event set value "on_join"\nfunction macro:events/fire with storage macro:input {}\ndata remove storage macro:input event\n\ntellraw @a[tag=macro.debug] {"text":"[DEBUG] example_events completed.","color":"green"}\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger.mcfunction', '# macro:debug/tools/trigger — single-call dispatch layer (EC-style).\n# Does not require EventCore; uses AME\'s own macro:api/cmd/* functions.\n#\n# Usage:\n# function macro:debug/tools/trigger {type:"<type>", data:{...}}\n# function macro:debug/tools/trigger {type:"<type>", data:{...}, config:{silent:1}}\n#\n# config:{silent:1} → suppress debug tellraw.\n\n$data modify storage macro:engine tools_trigger.type  set value "$(type)"\n$data modify storage macro:engine tools_trigger.data  set value $(data)\n$execute unless data storage macro:engine tools_trigger.config{silent:1} run tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"tools/trigger ","color":"aqua"},{"text":"► ","color":"yellow"},{"text":"$(type)","color":"white"}]\n\nfunction macro:debug/tools/trigger/internal/dispatch\n\ndata remove storage macro:engine tools_trigger\n'),
    ('./1_20_5/data/macro/functions/debug/tools/admin/add.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return run tellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]}\n\n$execute if entity @s[tag=macro.admin] run tag @a[nane=$(target),limit=1] add macro.admin\n$tellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✔ ","color":"green"},{"text":"$(NAME)","color":"white"},{"text":" added as admin.","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/debug/tools/admin/list.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return 0\n\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Admin List ","color":"aqua"},{"text":"━━━━━━━━━━━━━━","color":"#555555"}]}\nexecute if entity @a[tag=macro.admin] run tellraw @s {"text":"","extra":[{"text":" ◈ ","color":"#00AAAA"},{"selector":"@a[tag=macro.admin]","color":"white"}]}\nexecute unless entity @a[tag=macro.admin] run tellraw @s {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"(no admins)","color":"gray","italic":true}]}\ntellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/debug/tools/admin/remove.mcfunction', 'execute unless function macro:debug/tools/utils/check_all run return run tellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]}\n\n$execute if entity @s[tag=macro.admin] run tag @a[nane=$(target),limit=1] remove macro.admin\n$tellraw @s {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✔ ","color":"green"},{"text":"$(NAME)","color":"white"},{"text":" removed from admins.","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/bind.mcfunction', '# Admin-protected trigger/bind. Wraps macro:api/trigger/bind.\n# Usage: {value:1, func:"ns:path"}\nexecute unless function macro:debug/tools/utils/check_all run return run \\\n tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$function macro:api/trigger/bind {value:$(value), func:"$(func)"}\n$tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✔ ","color":"green"},{"text":"trigger/bind ","color":"aqua"},{"text":"$(value)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/bind_cmd.mcfunction', '# Admin-protected trigger/bind_cmd.\n# Usage: {value:1, cmd:"say hello"}\nexecute unless function macro:debug/tools/utils/check_all run return run \\\n tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$function macro:api/trigger/bind_cmd {value:$(value), cmd:"$(cmd)"}\n$tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✔ ","color":"green"},{"text":"trigger/bind_cmd ","color":"aqua"},{"text":"$(value)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(cmd)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/disable.mcfunction', '# Admin-protected trigger/disable.\n# Usage: {player:"Name"}\nexecute unless function macro:debug/tools/utils/check_all run return run \\\n tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$function macro:api/trigger/disable {player:"$(player)"}\n$tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"· ","color":"#555555"},{"text":"trigger/disable ","color":"aqua"},{"text":"$(player)","color":"white"}]\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/enable.mcfunction', '# Admin-protected trigger/enable.\n# Usage: {player:"Name"}\nexecute unless function macro:debug/tools/utils/check_all run return run \\\n tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$function macro:api/trigger/enable {player:"$(player)"}\n$tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✔ ","color":"green"},{"text":"trigger/enable ","color":"aqua"},{"text":"$(player)","color":"white"}]\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/list.mcfunction', '# Admin-protected trigger/list. Takes no arguments.\nexecute unless function macro:debug/tools/utils/check_all run return run \\\n tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\nfunction macro:api/trigger/list\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/unbind.mcfunction', '# Admin-protected trigger/unbind.\n# Usage: {value:1}\nexecute unless function macro:debug/tools/utils/check_all run return run \\\n tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\n$function macro:api/trigger/unbind {value:$(value)}\n$tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"trigger/unbind ","color":"aqua"},{"text":"value=","color":"#555555"},{"text":"$(value)","color":"white"},{"text":" removed","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/unbind_all.mcfunction', '# Admin-protected trigger/unbind_all. Takes no arguments.\nexecute unless function macro:debug/tools/utils/check_all run return run \\\n tellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"✘ ","color":"red"},{"text":"Permission denied.","color":"red"}]\n\nfunction macro:api/trigger/unbind_all\ntellraw @s ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"⚠ ","color":"yellow"},{"text":"trigger/unbind_all ","color":"aqua"},{"text":"all binds cleared","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/internal/dispatch.mcfunction', '# macro:debug/tools/trigger/internal/dispatch\n# Calls macro:api/cmd/* based on tools_trigger.type.\n# All calls use "with storage macro:engine tools_trigger.data".\n\n# ── Message ──────────────────────────────────────────────────────────────────\n# type:"msg" → data:{player:"Name", message:"..."}\nexecute if data storage macro:engine tools_trigger{type:"msg"} run function macro:api/cmd/msg with storage macro:engine tools_trigger.data\n\n# type:"title" → data:{player:"Name", text:"...", color:"gold"}\nexecute if data storage macro:engine tools_trigger{type:"title"} run function macro:api/cmd/title with storage macro:engine tools_trigger.data\n\n# type:"subtitle" → data:{player:"Name", text:"...", color:"white"}\nexecute if data storage macro:engine tools_trigger{type:"subtitle"} run function macro:api/cmd/subtitle with storage macro:engine tools_trigger.data\n\n# type:"actionbar" → data:{player:"Name", text:"...", color:"aqua"}\nexecute if data storage macro:engine tools_trigger{type:"actionbar"} run function macro:api/cmd/actionbar with storage macro:engine tools_trigger.data\n\n# type:"title_times"→ data:{player:"Name", in:10, stay:70, out:20}\nexecute if data storage macro:engine tools_trigger{type:"title_times"} run function macro:api/cmd/title_times with storage macro:engine tools_trigger.data\n\n# type:"title_clear"→ data:{player:"Name"}\nexecute if data storage macro:engine tools_trigger{type:"title_clear"} run function macro:api/cmd/title_clear with storage macro:engine tools_trigger.data\n\n# type:"title_reset"→ data:{player:"Name"}\nexecute if data storage macro:engine tools_trigger{type:"title_reset"} run function macro:api/cmd/title_reset with storage macro:engine tools_trigger.data\n\n# ── Sound & Particles ──────────────────────────────────────────────────────\n# type:"sound" → data:{player:"Name", sound:"minecraft:...", volume:1, pitch:1}\nexecute if data storage macro:engine tools_trigger{type:"sound"} run function macro:api/cmd/sound with storage macro:engine tools_trigger.data\n\n# ── Efekt ─────────────────────────────────────────────────────────────────\n# type:"effect_add" → data:{player:"Name", effect:"minecraft:speed", duration:100, amplifier:1}\nexecute if data storage macro:engine tools_trigger{type:"effect_add"} run function macro:api/cmd/effect_give with storage macro:engine tools_trigger.data\n\n# type:"effect_clear"→ data:{player:"Name"}\nexecute if data storage macro:engine tools_trigger{type:"effect_clear"} run function macro:api/cmd/effect_clear with storage macro:engine tools_trigger.data\n\n# ── Item ──────────────────────────────────────────────────────────────────\n# type:"give" → data:{player:"Name", item:"minecraft:diamond", count:1}\nexecute if data storage macro:engine tools_trigger{type:"give"} run function macro:api/cmd/give with storage macro:engine tools_trigger.data\n\n# ── XP ────────────────────────────────────────────────────────────────────\n# type:"xp" → data:{player:"Name", amount:100, type:"points"} (type: points|levels)\nexecute if data storage macro:engine tools_trigger{type:"xp"} run function macro:api/cmd/xp_add with storage macro:engine tools_trigger.data\n\n# ── Oyuncu ────────────────────────────────────────────────────────────────\n# type:"gamemode" → data:{player:"Name", mode:"survival"}\nexecute if data storage macro:engine tools_trigger{type:"gamemode"} run function macro:api/cmd/gamemode with storage macro:engine tools_trigger.data\n\n# type:"kick" → data:{player:"Name"}\nexecute if data storage macro:engine tools_trigger{type:"kick"} run function macro:api/cmd/kick with storage macro:engine tools_trigger.data\n\n# type:"tp" → data:{player:"Name", x:0, y:64, z:0}\nexecute if data storage macro:engine tools_trigger{type:"tp"} run function macro:api/cmd/tp_to_coords with storage macro:engine tools_trigger.data\n\n# ── Scoreboard ────────────────────────────────────────────────────────────\n# type:"score_set" → data:{player:"Name", objective:"obj", value:10}\nexecute if data storage macro:engine tools_trigger{type:"score_set"} run function macro:api/cmd/scoreboard_set with storage macro:engine tools_trigger.data\n\n# type:"score_add" → data:{player:"Name", objective:"obj", amount:5}\nexecute if data storage macro:engine tools_trigger{type:"score_add"} run function macro:api/cmd/scoreboard_add with storage macro:engine tools_trigger.data\n\n# ── Tag ───────────────────────────────────────────────────────────────────\n# type:"tag_add" → data:{player:"Name", tag:"myTag"}\nexecute if data storage macro:engine tools_trigger{type:"tag_add"} run function macro:api/cmd/tag_add with storage macro:engine tools_trigger.data\n\n# type:"tag_remove" → data:{player:"Name", tag:"myTag"}\nexecute if data storage macro:engine tools_trigger{type:"tag_remove"} run function macro:api/cmd/tag_remove with storage macro:engine tools_trigger.data\n\n# ── World ─────────────────────────────────────────────────────────────────\n# type:"fill" → data:{x1:..,y1:..,z1:..,x2:..,y2:..,z2:..,block:"minecraft:stone"}\nexecute if data storage macro:engine tools_trigger{type:"fill"} run function macro:api/cmd/fill with storage macro:engine tools_trigger.data\n\n# type:"setblock" → data:{x:..,y:..,z:..,block:"minecraft:stone"}\nexecute if data storage macro:engine tools_trigger{type:"setblock"} run function macro:api/cmd/setblock with storage macro:engine tools_trigger.data\n\n# ── Fonksiyon & Komut ─────────────────────────────────────────────────────\n# NOTE: delay / schedule_cancel intentionally excluded here.\n# The schedule command runs at op-level; allowing arbitrary function scheduling.\n# Use macro:core/lib/schedule directly and explicitly if needed.\n# type:"func" → data:{ns:"namespace", path:"func/path"}\nexecute if data storage macro:engine tools_trigger{type:"func"} run function macro:debug/tools/trigger/internal/exec_func with storage macro:engine tools_trigger.data\n\n# type:"cmd" → data:{cmd:"say hello"}\nexecute if data storage macro:engine tools_trigger{type:"cmd"} run function macro:debug/tools/trigger/internal/exec_cmd with storage macro:engine tools_trigger.data\n'),
    ('./1_20_5/data/macro/functions/debug/tools/trigger/internal/exec_cmd.mcfunction', '# type:"cmd" → {cmd:"say hello"}\n# Security: only executors with the macro.admin tag may run this.\nexecute unless entity @s[tag=macro.admin] run return 0\ntellraw @a[tag=macro.admin] [{"selector":"@s","color":"gold"},{"text":" - command executed","color":"yellow"}]\n\n$$(cmd)\n'),
