    ('./1_20_5/data/macro/functions/player/init.mcfunction', '$execute unless data storage macro:engine players.$(player) run data modify storage macro:engine players.$(player) set value {}\n$execute unless data storage macro:engine players.$(player).coins run data modify storage macro:engine players.$(player).coins set value 0\n$execute unless data storage macro:engine players.$(player).level run data modify storage macro:engine players.$(player).level set value 1\n$execute unless data storage macro:engine players.$(player).xp run data modify storage macro:engine players.$(player).xp set value 0\n$data modify storage macro:engine players.$(player).online set value 1b\n$execute unless data storage macro:engine players.$(player).first_join_tick run execute store result storage macro:engine players.$(player).first_join_tick int 1 run scoreboard players get $epoch macro.time\n$execute store result storage macro:engine players.$(player).last_join_tick int 1 run scoreboard players get $epoch macro.time\n$execute unless data storage macro:engine player_pids.$(player) run function macro:player/internal/assign_pid with storage macro:input {}\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/init ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/player/is_burning.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:player/is_burning\n# Checks whether a named player is currently on fire.\n# Uses the macro:is_burning predicate (entity_flags).\n#\n# INPUT : $(player) → player name\n# OUTPUT: macro:output result → 1b if burning, 0b otherwise\n# macro:output found → 1b if player online, 0b otherwise\n#\n# EXAMPLE:\n# function macro:player/is_burning {player:"Steve"}\n# → macro:output result = 1b\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output found set value 0b\ndata modify storage macro:output result set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] if predicate macro:is_burning run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/is_burning ","color":"aqua"},{"text":"$(player) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./1_20_5/data/macro/functions/player/is_flying.mcfunction', '# macro:player/is_flying\n# Checks whether the named player is currently flying (creative/spectator flight or elytra).\n# Params: player\n# Output: macro:output result = 1b (flying) or 0b (not flying / not found)\n# macro:output found = 1b if player exists online, else 0b\n\ndata modify storage macro:output result set value 0b\ndata modify storage macro:output found set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] if data entity @s {abilities:{flying:1b}} run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/is_flying ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
