    ('./1_20_5/data/macro/functions/player/is_sneaking.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:player/is_sneaking\n# Checks whether a named player is currently sneaking.\n# Uses the macro:is_sneaking predicate (entity_flags).\n#\n# INPUT : $(player) → player name\n# OUTPUT: macro:output result → 1b if sneaking, 0b otherwise\n# macro:output found → 1b if player online, 0b otherwise\n#\n# EXAMPLE:\n# function macro:player/is_sneaking {player:"Steve"}\n# → macro:output result = 1b\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output found set value 0b\ndata modify storage macro:output result set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] if predicate macro:is_sneaking run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/is_sneaking ","color":"aqua"},{"text":"$(player) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./1_20_5/data/macro/functions/player/is_sprinting.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:player/is_sprinting\n# Checks whether a named player is currently sprinting.\n# Uses the macro:is_sprinting predicate (entity_flags).\n#\n# INPUT : $(player) → player name\n# OUTPUT: macro:output result → 1b if sprinting, 0b otherwise\n# macro:output found → 1b if player online, 0b otherwise\n#\n# EXAMPLE:\n# function macro:player/is_sprinting {player:"Steve"}\n# → macro:output result = 1b\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output found set value 0b\ndata modify storage macro:output result set value 0b\n\n$execute unless entity @a[name=$(player),limit=1] run return 0\n\ndata modify storage macro:output found set value 1b\n$execute as @a[name=$(player),limit=1] if predicate macro:is_sprinting run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/is_sprinting ","color":"aqua"},{"text":"$(player) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./1_20_5/data/macro/functions/player/list_vars.mcfunction', '$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Player: ","color":"aqua"},{"text":"$(player)","color":"white","bold":true},{"text":" ━━━━━━━━━━━━━━","color":"#555555"}]}\n$execute if data storage macro:engine players.$(player) run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" vars ","color":"#555555"},{"storage":"macro:engine","nbt":"players.$(player)","interpret":false,"color":"yellow"}]}\n$execute unless data storage macro:engine players.$(player) run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" vars ","color":"#555555"},{"text":"(no data)","color":"gray","italic":true}]}\n$execute if data storage macro:engine cooldowns.$(player) run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" cooldowns ","color":"#555555"},{"storage":"macro:engine","nbt":"cooldowns.$(player)","interpret":false,"color":"aqua"}]}\n$execute unless data storage macro:engine cooldowns.$(player) run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" cooldowns ","color":"#555555"},{"text":"(none active)","color":"gray","italic":true}]}\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/player/online_check.mcfunction', 'data modify storage macro:output result set value 0b\n$execute if entity @a[name=$(player),limit=1] run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/online_check ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/player/reset.mcfunction', '$data remove storage macro:engine players.$(player)\n$data remove storage macro:engine cooldowns.$(player)\n$advancement revoke @a[name=$(player),limit=1] from macro:hidden/root\nfunction macro:player/init with storage macro:input {}\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/reset ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/player/run_cmd_as_uuid_macro.mcfunction', '$execute as @a[nbt={UUID:$(uuid)}] run $(cmd)\n'),
    ('./1_20_5/data/macro/functions/player/run_func_as_uuid_macro.mcfunction', '$execute as @a[nbt={UUID:$(uuid)}] run function $(func)\n'),
    ('./1_20_5/data/macro/functions/player/set_var.mcfunction', '$data modify storage macro:engine players.$(player).$(key) set value $(value)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/set_var ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/swap_var.mcfunction', '$data modify storage macro:engine _swap.tmp set from storage macro:engine players.$(player_a).$(key)\n$data modify storage macro:engine players.$(player_a).$(key) set from storage macro:engine players.$(player_b).$(key)\n$data modify storage macro:engine players.$(player_b).$(key) set from storage macro:engine _swap.tmp\ndata remove storage macro:engine _swap\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/swap_var ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/transfer_var.mcfunction', '$execute store result score $tr_f macro.tmp run data get storage macro:engine players.$(from).$(key)\n$scoreboard players set $tr_a macro.tmp $(amount)\nscoreboard players operation $tr_f macro.tmp -= $tr_a macro.tmp\n$execute store result storage macro:engine players.$(from).$(key) int 1 run scoreboard players get $tr_f macro.tmp\n\n$execute store result score $tr_t macro.tmp run data get storage macro:engine players.$(to).$(key)\nscoreboard players operation $tr_t macro.tmp += $tr_a macro.tmp\n$execute store result storage macro:engine players.$(to).$(key) int 1 run scoreboard players get $tr_t macro.tmp\n\nexecute store result storage macro:output result int 1 run scoreboard players get $tr_t macro.tmp\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/transfer_var ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/player/internal/assign_pid.mcfunction', 'execute store result score $next_pid macro.tmp run data get storage macro:engine _pid_seq\n\nscoreboard players add $next_pid macro.tmp 1\n\n$execute store result storage macro:engine player_pids.$(player) int 1 run scoreboard players get $next_pid macro.tmp\n$scoreboard players operation @a[name=$(player),limit=1] macro.pid = $next_pid macro.tmp\n\nexecute store result storage macro:engine _pid_seq int 1 run scoreboard players get $next_pid macro.tmp\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"player/internal/assign_pid ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → pid=","color":"#555555"},{"score":{"name":"$next_pid","objective":"macro.tmp"},"color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/player/internal/init_from_name.mcfunction', '# macro:player/internal/init_from_name [MACRO]\n# Relay: storage macro:names temp {NAME:"<player>"} → macro:player/init\n# Called by on_player_join after macro:player/get_name populates macro:names temp.\n# Bridges the NAME key to the player key expected by player/init.\n\n$data modify storage macro:engine _pid_init_tmp set value {player:"$(NAME)"}\nfunction macro:player/init with storage macro:engine _pid_init_tmp\ndata remove storage macro:engine _pid_init_tmp\n'),
    ('./1_20_5/data/macro/functions/player/internal/init_online.mcfunction', '# macro:player/internal/init_online\n# @s = online player\n# Called once per online player during load to ensure pid is assigned.\n\nfunction macro:player/get_name\nfunction macro:player/internal/init_from_name with storage macro:names temp\n'),
    ('./1_20_5/data/macro/functions/player/internal/stamp_join.mcfunction', '$execute store result storage macro:engine players.$(player).joined_tick int 1 run scoreboard players get $epoch macro.time\n'),
    ('./1_20_5/data/macro/functions/player/inv/chest_minecart_if_item.mcfunction', '# macro:player/inv/chest_minecart_if_item [1.20.5+]\n$execute as @a at @s if items entity @e[type=minecraft:chest_minecart,distance=..2,limit=1,tag=$(tag)] container.$(slot) *[minecraft:custom_data~{wand:"$(customData)"}] run $(invoke)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"inv/chest_minecart_if_item ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(tag)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/inv/chest_minecart_unless_item.mcfunction', '# macro:player/inv/chest_minecart_unless_item [1.20.5+]\n$execute as @a at @s unless items entity @e[type=minecraft:chest_minecart,distance=..2,limit=1,tag=$(tag)] container.$(slot) *[minecraft:custom_data~{wand:"$(customData)"}] run $(invoke)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"inv/chest_minecart_unless_item ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(tag)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/inv/clear_custom.mcfunction', '# macro:player/inv/clear_custom [1.20.5+]\n$execute as @a[name=$(player),limit=1] run clear @s minecraft:carrot_on_a_stick[minecraft:custom_data={wand:"$(customData)"}] $(count)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"inv/clear_custom ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/player/inv/count_item.mcfunction', '# macro:player/inv/count_item [1.20.5+]\nscoreboard players set $inv_cnt macro.tmp 0\n$execute as @a[name=$(player),limit=1] run execute store result score $inv_cnt macro.tmp run clear @s minecraft:carrot_on_a_stick[minecraft:custom_data={wand:"$(customData)"}] 0\nexecute store result storage macro:output count int 1 run scoreboard players get $inv_cnt macro.tmp\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"inv/count_item ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/player/inv/cursor_item.mcfunction', "# macro:player/inv/cursor_item [1.20.5+]\n# Detect click by checking if the item exists in that slot (component syntax)\n$execute unless items entity @e[type=chest_minecart,tag=$(id),limit=1,sort=nearest,distance=..3] container.$(slot) $(item)[minecraft:custom_data~$(data)] run $(invoke)\n\n# Optional: Restore the item in the slot after click (prevents item disappearing)\n$item replace entity @e[type=chest_minecart,tag=$(id),limit=1,sort=nearest] container.$(slot) with $(item)[minecraft:custom_data=$(data)] $(count)\n\n# Clear the item from player's cursor\n$clear @s $(item)[minecraft:custom_data=$(data)] $(count)\n"),
    ('./1_20_5/data/macro/functions/player/inv/offhand_item.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:player/inv/offhand_item\n# Runs a command/function for each player in @a whose offhand\n# matches the given item id and custom data.\n# Mirrors the pattern of macro:player/inv/selected_item (mainhand).\n#\n# INPUT : $(item)       → item id (e.g. "minecraft:shield")\n#         $(customData) → custom_data compound to match (e.g. "{my_tag:1b}")\n#         $(invoke)     → command to run as the matching player\n#\n# EXAMPLE:\n# function macro:player/inv/offhand_item {item:"minecraft:shield",customData:"{my_tag:1b}",invoke:"function mypack:on_shield"}\n# ─────────────────────────────────────────────────────────────────\n\n$execute as @a at @s if items entity @s weapon.offhand $(item)[minecraft:custom_data=$(customData)] run $(invoke)\n'),
    ('./1_20_5/data/macro/functions/player/inv/player_if_item.mcfunction', '# macro:player/inv/player_if_item [1.20.5+]\n$execute as @a[name=$(player),limit=1] at @s if items entity @s container.* *[minecraft:custom_data~{wand:"$(customData)"}] run $(invoke)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"inv/player_if_item ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/player/inv/player_slot_if_item.mcfunction', '# macro:player/inv/player_slot_if_item [1.20.5+]\n# Checks the whole inventory (slot-specific routing via execute if items).\n$execute as @a[name=$(player),limit=1] at @s if items entity @s container.* *[minecraft:custom_data~{wand:"$(customData)"}] run $(invoke)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"inv/player_slot_if_item ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/player/inv/player_unless_item.mcfunction', '# macro:player/inv/player_unless_item [1.20.5+]\n$execute as @a[name=$(player),limit=1] at @s unless items entity @s container.* *[minecraft:custom_data~{wand:"$(customData)"}] run $(invoke)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"inv/player_unless_item ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/player/inv/selected_item.mcfunction', '# macro:player/inv/selected_item [1.20.5+]\n$execute as @a at @s if items entity @s weapon.mainhand *[minecraft:custom_data~{wand:"$(customData)"}] run $(invoke)\n'),
    ('./1_20_5/data/macro/functions/player/inv/transfer_item.mcfunction', '$execute as @a[name=$(player),limit=1] at @s run item replace entity @s weapon.mainhand from entity @e[type=minecraft:chest_minecart,distance=..2,limit=1,tag=$(tag)] container.$(slot)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"inv/transfer_item ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(tag)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/team/add.mcfunction', '$team join $(team) $(player)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"team/add ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(team)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/team/count.mcfunction', 'scoreboard players set $team_cnt macro.tmp 0\n$execute as @a[team=$(team)] run scoreboard players add $team_cnt macro.tmp 1\nexecute store result storage macro:output result int 1 run scoreboard players get $team_cnt macro.tmp\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"team/count ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(team)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/player/team/create.mcfunction', '$team add $(team)\n$data modify storage macro:engine teams.$(team) set value {color:"white",friendly_fire:"true",see_friendly_invisibles:"false"}\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"team/create ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(team)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/team/delete.mcfunction', '$team remove $(team)\n$data remove storage macro:engine teams.$(team)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"team/delete ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(team)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/team/has.mcfunction', 'data modify storage macro:output result set value 0b\n$execute if entity @a[name=$(player),team=$(team)] run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"team/has ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(team)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/player/team/list.mcfunction', 'tellraw @a[tag=macro.debug] {"text":"[Team] -- Registered Teams --","color":"aqua"}\ntellraw @a[tag=macro.debug] {"nbt":"teams","storage":"macro:engine","interpret":false,"color":"white"}\ntellraw @a[tag=macro.debug] {"text":"[Team] ---------------------","color":"aqua"}\n'),
    ('./1_20_5/data/macro/functions/player/team/remove.mcfunction', '$team leave $(player)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"team/remove ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/player/team/set_color.mcfunction', '$team modify $(team) color $(color)\n$data modify storage macro:engine teams.$(team).color set value "$(color)"\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"team/set_color ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(team)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/player/team/set_friendly_fire.mcfunction', '$team modify $(team) friendlyFire $(value)\n$data modify storage macro:engine teams.$(team).friendly_fire set value "$(value)"\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"team/set_friendly_fire ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(team)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/flag/any.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/flag/any\n# Checks whether ANY of two flags is set.\n# Returns 1b if at least one of key_a or key_b is set, 0b otherwise.\n# For three or more flags, chain calls or use flag/get on each.\n#\n# INPUT : $(key_a) → first flag key\n#         $(key_b) → second flag key\n# OUTPUT: macro:output result → 1b if either flag set, 0b if neither\n# macro:output result_a → 1b if key_a set, 0b otherwise\n# macro:output result_b → 1b if key_b set, 0b otherwise\n#\n# EXAMPLE:\n# function macro:systems/flag/any {key_a:"pvp_enabled",key_b:"war_active"}\n# → macro:output result = 1b (if either is set)\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output result_a set value 0b\ndata modify storage macro:output result_b set value 0b\ndata modify storage macro:output result set value 0b\n\nscoreboard players set #fany_a macro.tmp 0\nscoreboard players set #fany_b macro.tmp 0\n\n$execute if data storage macro:engine flags.$(key_a) run scoreboard players set #fany_a macro.tmp 1\n$execute if data storage macro:engine flags.$(key_b) run scoreboard players set #fany_b macro.tmp 1\n\nexecute if score #fany_a macro.tmp matches 1 run data modify storage macro:output result_a set value 1b\nexecute if score #fany_b macro.tmp matches 1 run data modify storage macro:output result_b set value 1b\n\nscoreboard players operation #fany_a macro.tmp += #fany_b macro.tmp\nexecute if score #fany_a macro.tmp matches 1.. run data modify storage macro:output result set value 1b\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"flag/any ","color":"aqua"},{"text":"$(key_a)|$(key_b) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./1_20_5/data/macro/functions/systems/flag/copy.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/flag/copy\n# Copies a flag value from one key to another.\n# If the source flag is set, the destination is set.\n# If the source flag is absent, the destination is removed.\n#  Input : $(from) → source flag key\n#          $(to)   → destination flag key\n# Output: macro:output result → 1b if copied (flag was set), 0b if cleared\n#\n# Example:\n# data modify storage macro:input from set value "feature_a"\n# data modify storage macro:input to set value "feature_a_backup"\n# function macro:systems/flag/copy with storage macro:input {}\n# ─────────────────────────────────────────────────────────────────\n\n# Default: clear destination\ndata modify storage macro:output result set value 0b\n\n$execute if data storage macro:engine flags.$(from) run data modify storage macro:engine flags.$(to) set value 1b\n$execute if data storage macro:engine flags.$(from) run data modify storage macro:output result set value 1b\n$execute unless data storage macro:engine flags.$(from) run data remove storage macro:engine flags.$(to)\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"flag/copy ","color":"aqua"},{"text":"$(from) → $(to) ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/flag/get.mcfunction', 'data modify storage macro:output result set value 0b\n$execute if data storage macro:engine flags.$(key) run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"flag/get ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/flag/get_or_default.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/flag/get_or_default\n# Returns 1b if the flag is set, otherwise stores the given default.\n#  Input : $(key)     → flag key\n#          $(default) → value to store if flag is absent (0b or 1b)\n#  Output: macro:output result → 1b if set, $(default) if absent\n#\n# Example:\n# data modify storage macro:input key set value "my_feature"\n# data modify storage macro:input default set value 0b\n# function macro:systems/flag/get_or_default with storage macro:input {}\n# # macro:output result = 0b (if flag not set)\n# ─────────────────────────────────────────────────────────────────\n\n$data modify storage macro:output result set value $(default)\n$execute if data storage macro:engine flags.$(key) run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"flag/get_or_default ","color":"aqua"},{"text":"$(key) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/flag/list.mcfunction', 'tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Global Flags ","color":"aqua"},{"text":"━━━━━━━━━━━","color":"#555555"}]}\nexecute if data storage macro:engine flags run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"flags","interpret":false,"color":"white"}]}\nexecute unless data storage macro:engine flags run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"(no active flags)","color":"gray","italic":true}]}\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/flag/list_systems.mcfunction', '# macro:systems/flag/list_systems — List all tick channels with their current config\ntellraw @s [{"text":"[AME] Tick Channels","color":"gold","bold":true}]\ntellraw @s {"storage":"macro:engine","nbt":"tick.channels","color":"yellow"}'),
    ('./1_20_5/data/macro/functions/systems/flag/set.mcfunction', '$data modify storage macro:engine flags.$(key) set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"flag/set ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/flag/set_if.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/flag/set_if\n# Sets a flag only when a scoreboard condition is met.\n# Condition: score of $(score_holder) in $(objective) must match $(matches).\n# Uses scoreboard matches syntax (e.g. "1", "1..5", "..0", "2..").\n#\n# INPUT : $(key)          → flag key\n#         $(score_holder) → scoreboard entity/fake-player name\n#         $(objective)    → scoreboard objective\n#         $(matches)      → match range string (e.g. "1..")\n# OUTPUT: macro:output result → 1b if flag was set, 0b if condition not met\n#\n# EXAMPLE:\n# function macro:systems/flag/set_if {key:"night_mode",score_holder:"$time",objective:"macro.tmp",matches:"..12000"}\n# ─────────────────────────────────────────────────────────────────\n\ndata modify storage macro:output result set value 0b\n$execute if score $(score_holder) $(objective) matches $(matches) run data modify storage macro:engine flags.$(key) set value 1b\n$execute if score $(score_holder) $(objective) matches $(matches) run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"flag/set_if ","color":"aqua"},{"text":"$(key) if $(score_holder) $(objective) matches $(matches) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./1_20_5/data/macro/functions/systems/flag/toggle.mcfunction', 'scoreboard players set $ftgl macro.tmp 0\n$execute if data storage macro:engine flags.$(key) run scoreboard players set $ftgl macro.tmp 1\n\n$execute if score $ftgl macro.tmp matches 1 run data remove storage macro:engine flags.$(key)\nexecute if score $ftgl macro.tmp matches 1 run data modify storage macro:output result set value 0b\n\n$execute if score $ftgl macro.tmp matches 0 run data modify storage macro:engine flags.$(key) set value 1b\nexecute if score $ftgl macro.tmp matches 0 run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"flag/toggle ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/flag/toggle_system.mcfunction', '# macro:systems/flag/toggle_system — Toggle a built-in tick channel on/off\n# Usage: function macro:systems/flag/toggle_system {system:"time"}\n# Valid systems: time | queue | player | hud | admin\n# Delegates to macro:core/tick/channel/enable|disable internally.\n\n$data modify storage macro:tick_work _ftgl set from storage macro:engine tick.channels[{id:"$(system)_systems"}]\nfunction macro:systems/flag/toggle_system/exec with storage macro:tick_work _ftgl'),
    ('./1_20_5/data/macro/functions/systems/flag/unset.mcfunction', '$data remove storage macro:engine flags.$(key)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"flag/unset ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(key)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/flag/toggle_system/exec.mcfunction', '# [MACRO] Internal exec for flag/toggle_system\n$execute if data storage macro:tick_work _ftgl{enabled:1b} run function macro:core/tick/channel/disable {id:"$(id)"}\n$execute if data storage macro:tick_work _ftgl{enabled:0b} run function macro:core/tick/channel/enable {id:"$(id)"}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/as_nearby_player.mcfunction', '$data modify storage macro:engine _dispatch.func set value "$(func)"\n$execute as @a[distance=..$(distance),limit=1,sort=nearest] at @s run function #macro:internal/dispatch\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"geo/as_nearby_player ","color":"aqua"},{"text":" → ","color":"#555555"},{"text":"$(func)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/systems/geo/in_region.mcfunction', 'data modify storage macro:output result set value 0b\n\n$scoreboard players set $rgn_x macro.tmp $(x)\n$scoreboard players set $rgn_y macro.tmp $(y)\n$scoreboard players set $rgn_z macro.tmp $(z)\n$scoreboard players set $rgn_x1 macro.tmp $(x1)\n$scoreboard players set $rgn_y1 macro.tmp $(y1)\n$scoreboard players set $rgn_z1 macro.tmp $(z1)\n$scoreboard players set $rgn_x2 macro.tmp $(x2)\n$scoreboard players set $rgn_y2 macro.tmp $(y2)\n$scoreboard players set $rgn_z2 macro.tmp $(z2)\n\n# min/max normalization\nexecute if score $rgn_x1 macro.tmp > $rgn_x2 macro.tmp run scoreboard players operation $rgn_t macro.tmp = $rgn_x1 macro.tmp\nexecute if score $rgn_x1 macro.tmp > $rgn_x2 macro.tmp run scoreboard players operation $rgn_x1 macro.tmp = $rgn_x2 macro.tmp\nexecute if score $rgn_t macro.tmp > $rgn_x2 macro.tmp run scoreboard players operation $rgn_x2 macro.tmp = $rgn_t macro.tmp\n\nexecute if score $rgn_y1 macro.tmp > $rgn_y2 macro.tmp run scoreboard players operation $rgn_t macro.tmp = $rgn_y1 macro.tmp\nexecute if score $rgn_y1 macro.tmp > $rgn_y2 macro.tmp run scoreboard players operation $rgn_y1 macro.tmp = $rgn_y2 macro.tmp\nexecute if score $rgn_t macro.tmp > $rgn_y2 macro.tmp run scoreboard players operation $rgn_y2 macro.tmp = $rgn_t macro.tmp\n\nexecute if score $rgn_z1 macro.tmp > $rgn_z2 macro.tmp run scoreboard players operation $rgn_t macro.tmp = $rgn_z1 macro.tmp\nexecute if score $rgn_z1 macro.tmp > $rgn_z2 macro.tmp run scoreboard players operation $rgn_z1 macro.tmp = $rgn_z2 macro.tmp\nexecute if score $rgn_t macro.tmp > $rgn_z2 macro.tmp run scoreboard players operation $rgn_z2 macro.tmp = $rgn_t macro.tmp\n\nexecute if score $rgn_x macro.tmp < $rgn_x1 macro.tmp run return 0\nexecute if score $rgn_x macro.tmp > $rgn_x2 macro.tmp run return 0\nexecute if score $rgn_y macro.tmp < $rgn_y1 macro.tmp run return 0\nexecute if score $rgn_y macro.tmp > $rgn_y2 macro.tmp run return 0\nexecute if score $rgn_z macro.tmp < $rgn_z1 macro.tmp run return 0\nexecute if score $rgn_z macro.tmp > $rgn_z2 macro.tmp run return 0\n\ndata modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"geo/in_region ","color":"aqua"},{"text":"($(x),$(y),$(z)) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/in_region_unless.mcfunction', '$execute as @a[name=$(player),limit=1] unless entity @s[x=$(x),y=$(y),z=$(z),dx=$(dx),dy=$(dy),dz=$(dz)] run $(invoke)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"geo/in_region_unless ","color":"aqua"},{"text":"$(player)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/in_sphere.mcfunction', 'data modify storage macro:output result set value 0b\n\n$scoreboard players set $sph_dx macro.tmp $(x)\n$scoreboard players set $sph_cx macro.tmp $(cx)\nscoreboard players operation $sph_dx macro.tmp -= $sph_cx macro.tmp\n\n$scoreboard players set $sph_dy macro.tmp $(y)\n$scoreboard players set $sph_cy macro.tmp $(cy)\nscoreboard players operation $sph_dy macro.tmp -= $sph_cy macro.tmp\n\n$scoreboard players set $sph_dz macro.tmp $(z)\n$scoreboard players set $sph_cz macro.tmp $(cz)\nscoreboard players operation $sph_dz macro.tmp -= $sph_cz macro.tmp\n\n# Overflow prevention (max 26754 per axis)\nexecute if score $sph_dx macro.tmp matches 26755.. run scoreboard players set $sph_dx macro.tmp 26754\nexecute if score $sph_dx macro.tmp matches ..-26755 run scoreboard players set $sph_dx macro.tmp -26754\nexecute if score $sph_dy macro.tmp matches 26755.. run scoreboard players set $sph_dy macro.tmp 26754\nexecute if score $sph_dy macro.tmp matches ..-26755 run scoreboard players set $sph_dy macro.tmp -26754\nexecute if score $sph_dz macro.tmp matches 26755.. run scoreboard players set $sph_dz macro.tmp 26754\nexecute if score $sph_dz macro.tmp matches ..-26755 run scoreboard players set $sph_dz macro.tmp -26754\n\nscoreboard players operation $sph_dx macro.tmp *= $sph_dx macro.tmp\nscoreboard players operation $sph_dy macro.tmp *= $sph_dy macro.tmp\nscoreboard players operation $sph_dz macro.tmp *= $sph_dz macro.tmp\n\nscoreboard players operation $sph_dsq macro.tmp = $sph_dx macro.tmp\nscoreboard players operation $sph_dsq macro.tmp += $sph_dy macro.tmp\nscoreboard players operation $sph_dsq macro.tmp += $sph_dz macro.tmp\nexecute store result storage macro:output dist_sq int 1 run scoreboard players get $sph_dsq macro.tmp\n\n$scoreboard players set $sph_r macro.tmp $(r)\nscoreboard players operation $sph_r macro.tmp *= $sph_r macro.tmp\n\nexecute if score $sph_dsq macro.tmp <= $sph_r macro.tmp run data modify storage macro:output result set value 1b\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"geo/in_sphere ","color":"aqua"},{"text":"r=$(r) dsq=","color":"gray"},{"score":{"name":"$sph_dsq","objective":"macro.tmp"},"color":"yellow"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/near_entity.mcfunction', '$execute as @a[name=$(player),limit=1] at @s if entity @e[type=$(type),tag=$(tag),distance=..$(distance),limit=1] run $(invoke)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"geo/near_entity ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(type)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/near_entity_unless.mcfunction', '$execute as @a[name=$(player),limit=1] at @s unless entity @e[type=$(type),tag=$(tag),distance=..$(distance),limit=1] run $(invoke)\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"geo/near_entity_unless ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(type)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/list.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/geo/region_watch/list\n# Shows all registered regions to debug players.\n# ─────────────────────────────────────────────────────────────────\n\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Region Watches ━━━━━━━━━━━━━━","color":"aqua"}]}\nexecute if data storage macro:engine region_watches run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"region_watches","interpret":false,"color":"yellow"}]}\nexecute unless data storage macro:engine region_watches run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" (no regions registered)","color":"gray","italic":true}]}\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/register.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/geo/region_watch/register\n# Defines a persistent region. Player position is checked every tick;\n# on_enter fires when a player enters, on_leave when they leave.\n# Depends on the hook/internal/tick_scan loop.\n#\n# INPUT (storage macro:input):\n# id → region id (unique string)\n# x1, y1, z1, x2, y2, z2 → corner coordinates (integer)\n# on_enter → (optional) entry function — as the triggering player\n# on_leave → (optional) leave function — as the triggering player\n# on_enter_cmd → (optional) entry command\n# on_leave_cmd → (optional) leave command\n#\n# EXAMPLE:\n# data modify storage macro:input id set value "spawn_safe"\n# data modify storage macro:input x1 set value 0\n# data modify storage macro:input y1 set value 60\n# data modify storage macro:input z1 set value 0\n# data modify storage macro:input x2 set value 100\n# data modify storage macro:input y2 set value 120\n# data modify storage macro:input z2 set value 100\n# data modify storage macro:input on_enter set value "mypack:zones/safe_enter"\n# data modify storage macro:input on_leave set value "mypack:zones/safe_leave"\n# function macro:systems/geo/region_watch/register\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/geo/region_watch/internal/register_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/unregister.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/geo/region_watch/unregister\n# Deletes a registered region. Player state scores are not cleared\n# (automatically skipped in the next tick_scan loop).\n#\n# INPUT (storage macro:input):\n# id → region id\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/geo/region_watch/internal/unregister_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/check_region.mcfunction', '# macro:systems/geo/region_watch/internal/check_region [MACRO]\n# INPUT (from _rw_cur): $(id), $(x1), $(y1), $(z1), $(x2), $(y2), $(z2)\n# @s = kontrol edilen oyuncu\n# Player coordinates: macro:engine _rw_player.{x,y,z}\n\n# --- AABB test: return early if outside any axis ---\nexecute store result score $rwx macro.tmp run data get storage macro:engine _rw_player.x\nexecute store result score $rwy macro.tmp run data get storage macro:engine _rw_player.y\nexecute store result score $rwz macro.tmp run data get storage macro:engine _rw_player.z\n\n$scoreboard players set $rwx1 macro.tmp $(x1)\n$scoreboard players set $rwy1 macro.tmp $(y1)\n$scoreboard players set $rwz1 macro.tmp $(z1)\n$scoreboard players set $rwx2 macro.tmp $(x2)\n$scoreboard players set $rwy2 macro.tmp $(y2)\n$scoreboard players set $rwz2 macro.tmp $(z2)\n\n# min/max normalize\nexecute if score $rwx1 macro.tmp > $rwx2 macro.tmp run scoreboard players operation $rwt macro.tmp = $rwx1 macro.tmp\nexecute if score $rwx1 macro.tmp > $rwx2 macro.tmp run scoreboard players operation $rwx1 macro.tmp = $rwx2 macro.tmp\nexecute if score $rwt macro.tmp > $rwx2 macro.tmp run scoreboard players operation $rwx2 macro.tmp = $rwt macro.tmp\nexecute if score $rwy1 macro.tmp > $rwy2 macro.tmp run scoreboard players operation $rwt macro.tmp = $rwy1 macro.tmp\nexecute if score $rwy1 macro.tmp > $rwy2 macro.tmp run scoreboard players operation $rwy1 macro.tmp = $rwy2 macro.tmp\nexecute if score $rwt macro.tmp > $rwy2 macro.tmp run scoreboard players operation $rwy2 macro.tmp = $rwt macro.tmp\nexecute if score $rwz1 macro.tmp > $rwz2 macro.tmp run scoreboard players operation $rwt macro.tmp = $rwz1 macro.tmp\nexecute if score $rwz1 macro.tmp > $rwz2 macro.tmp run scoreboard players operation $rwz1 macro.tmp = $rwz2 macro.tmp\nexecute if score $rwt macro.tmp > $rwz2 macro.tmp run scoreboard players operation $rwz2 macro.tmp = $rwt macro.tmp\n\n# Inside AABB? 1=inside, 0=outside\nscoreboard players set $rw_inside macro.tmp 1\nexecute if score $rwx macro.tmp < $rwx1 macro.tmp run scoreboard players set $rw_inside macro.tmp 0\nexecute if score $rwx macro.tmp > $rwx2 macro.tmp run scoreboard players set $rw_inside macro.tmp 0\nexecute if score $rwy macro.tmp < $rwy1 macro.tmp run scoreboard players set $rw_inside macro.tmp 0\nexecute if score $rwy macro.tmp > $rwy2 macro.tmp run scoreboard players set $rw_inside macro.tmp 0\nexecute if score $rwz macro.tmp < $rwz1 macro.tmp run scoreboard players set $rw_inside macro.tmp 0\nexecute if score $rwz macro.tmp > $rwz2 macro.tmp run scoreboard players set $rw_inside macro.tmp 0\n\n# --- State transition ---\n# Was inside and still inside → do nothing\n$execute if score $rw_inside macro.tmp matches 1 run execute if entity @s[tag=rw.$(id)] run return 0\n# Was outside and still outside → do nothing\n$execute if score $rw_inside macro.tmp matches 0 run execute unless entity @s[tag=rw.$(id)] run return 0\n\n# --- on_enter: was outside, now inside ---\n$execute if score $rw_inside macro.tmp matches 1 run tag @s add rw.$(id)\n# DOT NOTATION: _rw_cur.on_enter (space-separated subpath is invalid)\nexecute if score $rw_inside macro.tmp matches 1 run execute if data storage macro:engine _rw_cur.on_enter run function macro:systems/geo/region_watch/internal/fire_enter with storage macro:engine _rw_cur\nexecute if score $rw_inside macro.tmp matches 1 run execute if data storage macro:engine _rw_cur.on_enter_cmd run function macro:systems/geo/region_watch/internal/fire_enter_cmd with storage macro:engine _rw_cur\nexecute if score $rw_inside macro.tmp matches 1 run return 0\n\n# --- on_leave: was inside, now outside ---\n$tag @s remove rw.$(id)\nexecute if data storage macro:engine _rw_cur.on_leave run function macro:systems/geo/region_watch/internal/fire_leave with storage macro:engine _rw_cur\nexecute if data storage macro:engine _rw_cur.on_leave_cmd run function macro:systems/geo/region_watch/internal/fire_leave_cmd with storage macro:engine _rw_cur\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/fire_enter.mcfunction', '# macro:systems/geo/region_watch/internal/fire_enter [MACRO]\n# INPUT: $(on_enter) — from _rw_cur; called ONLY when on_enter field exists.\n# @s = player entering the region\n\n$data modify storage macro:engine _dispatch.func set value "$(on_enter)"\nfunction #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/fire_enter_cmd.mcfunction', '# macro:systems/geo/region_watch/internal/fire_enter_cmd [MACRO]\n# INPUT: $(on_enter_cmd) — from _rw_cur; called ONLY when on_enter_cmd field exists.\n# @s = player entering the region\n\n$$(on_enter_cmd)\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/fire_leave.mcfunction', '# macro:systems/geo/region_watch/internal/fire_leave [MACRO]\n# INPUT: $(on_leave) — from _rw_cur; called ONLY when on_leave field exists.\n# @s = player leaving the region\n\n$data modify storage macro:engine _dispatch.func set value "$(on_leave)"\nfunction #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/fire_leave_cmd.mcfunction', '# macro:systems/geo/region_watch/internal/fire_leave_cmd [MACRO]\n# INPUT: $(on_leave_cmd) — from _rw_cur; called ONLY when on_leave_cmd field exists.\n# @s = player leaving the region\n\n$$(on_leave_cmd)\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/player_scan.mcfunction', '# macro:systems/geo/region_watch/internal/player_scan\n# @s = kontrol edilecek oyuncu\n# Reads coordinates to storage, then iterates all regions.\n\ndata modify storage macro:engine _rw_iter set from storage macro:engine region_watches\n\n# Write player coordinates to _rw_player (int truncation, consistent with geo module)\nexecute store result storage macro:engine _rw_player.x int 1 run data get entity @s Pos[0]\nexecute store result storage macro:engine _rw_player.y int 1 run data get entity @s Pos[1]\nexecute store result storage macro:engine _rw_player.z int 1 run data get entity @s Pos[2]\n\nfunction macro:systems/geo/region_watch/internal/region_loop\n\ndata remove storage macro:engine _rw_iter\ndata remove storage macro:engine _rw_player\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/region_loop.mcfunction', '# macro:systems/geo/region_watch/internal/region_loop\n# @s = kontrol edilen oyuncu\n# Consumes _rw_iter list, calls check_region for each region.\n\nexecute unless data storage macro:engine _rw_iter[0] run return 0\n\ndata modify storage macro:engine _rw_cur set from storage macro:engine _rw_iter[0]\ndata remove storage macro:engine _rw_iter[0]\n\nfunction macro:systems/geo/region_watch/internal/check_region with storage macro:engine _rw_cur\n\nfunction macro:systems/geo/region_watch/internal/region_loop\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/register_exec.mcfunction', '# macro:systems/geo/region_watch/internal/register_exec [MACRO]\n# INPUT: $(id), $(x1), $(y1), $(z1), $(x2), $(y2), $(z2)\n#        $(on_enter), $(on_leave) — opsiyonel func\n#        $(on_enter_cmd), $(on_leave_cmd) — opsiyonel cmd\n#\n# region_watches stored as list: [{id,x1,...,on_enter,...}, ...]\n# If same id exists, filter it out first, then append.\n\n# Varsa sil (unregister_filter pattern)\ndata modify storage macro:engine _rw_unbind_id set from storage macro:input id\ndata modify storage macro:engine _rw_new set value []\ndata modify storage macro:engine _rw_src set from storage macro:engine region_watches\nfunction macro:systems/geo/region_watch/internal/unregister_filter\ndata modify storage macro:engine region_watches set from storage macro:engine _rw_new\ndata remove storage macro:engine _rw_new\ndata remove storage macro:engine _rw_src\ndata remove storage macro:engine _rw_unbind_id\n\n# Create new record and append\n$data modify storage macro:engine region_watches append value {id:"$(id)",x1:$(x1),y1:$(y1),z1:$(z1),x2:$(x2),y2:$(y2),z2:$(z2)}\n\n# on_enter / on_leave func — last appended element [-1]\nexecute if data storage macro:input on_enter run data modify storage macro:engine region_watches[-1].on_enter set from storage macro:input on_enter\nexecute if data storage macro:input on_leave run data modify storage macro:engine region_watches[-1].on_leave set from storage macro:input on_leave\n\n# on_enter_cmd / on_leave_cmd\nexecute if data storage macro:input on_enter_cmd run data modify storage macro:engine region_watches[-1].on_enter_cmd set from storage macro:input on_enter_cmd\nexecute if data storage macro:input on_leave_cmd run data modify storage macro:engine region_watches[-1].on_leave_cmd set from storage macro:input on_leave_cmd\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"geo/region_watch/register ","color":"aqua"},{"text":"$(id)","color":"white"},{"text":" ($(x1),$(y1),$(z1))→($(x2),$(y2),$(z2))","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/tick_scan.mcfunction', '# macro:systems/geo/region_watch/internal/tick_scan\n# Called from hook/internal/tick_scan (requires patch).\n# If region_watches is non-empty, checks all regions for each player.\n\nexecute unless data storage macro:engine region_watches run return 0\n\ndata modify storage macro:engine _rw_watch_list set from storage macro:engine region_watches\nexecute as @a run function macro:systems/geo/region_watch/internal/player_scan\ndata remove storage macro:engine _rw_watch_list\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/unregister_check.mcfunction', '# macro:systems/geo/region_watch/internal/unregister_check [MACRO]\n# INPUT: $(id) — _rw_cur\'dan beslenir\n# If id does not match, add to _rw_new (keep).\n\n$execute unless data storage macro:engine {_rw_unbind_id:"$(id)"} run data modify storage macro:engine _rw_new append from storage macro:engine _rw_cur\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/unregister_exec.mcfunction', '# macro:systems/geo/region_watch/internal/unregister_exec [MACRO]\n# INPUT: $(id)\n# region_watches in list format — always run filter,\n# if id not found, list remains unchanged.\n\nexecute unless data storage macro:engine region_watches run return 0\n\ndata modify storage macro:engine _rw_unbind_id set from storage macro:input id\ndata modify storage macro:engine _rw_new set value []\ndata modify storage macro:engine _rw_src set from storage macro:engine region_watches\nfunction macro:systems/geo/region_watch/internal/unregister_filter\ndata modify storage macro:engine region_watches set from storage macro:engine _rw_new\ndata remove storage macro:engine _rw_new\ndata remove storage macro:engine _rw_src\ndata remove storage macro:engine _rw_unbind_id\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"geo/region_watch/unregister ","color":"aqua"},{"text":"$(id)","color":"white"},{"text":" removed","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/geo/region_watch/internal/unregister_filter.mcfunction', '# macro:systems/geo/region_watch/internal/unregister_filter\n# Iterates _rw_src list.\n# Copies entries whose id does not match _rw_unbind_id to _rw_new.\n\nexecute unless data storage macro:engine _rw_src[0] run return 0\n\ndata modify storage macro:engine _rw_cur set from storage macro:engine _rw_src[0]\ndata remove storage macro:engine _rw_src[0]\n\nfunction macro:systems/geo/region_watch/internal/unregister_check with storage macro:engine _rw_cur\n\nfunction macro:systems/geo/region_watch/internal/unregister_filter'),
    ('./1_20_5/data/macro/functions/systems/hook/bind.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/hook/bind\n# Binds a function or command to a specific event.\n# Multiple binds can be added to the same event.\n#\n# INPUT (storage macro:input):\n# event → event name: "player_join" | "player_death" | "player_respawn"\n# "level_up" | "block_place" | "block_break" | "item_use"\n# func → (optional) function to run — as the triggering player\n# cmd → (optional) command to run — used if func is absent\n#\n# EXAMPLE:\n# data modify storage macro:input event set value "player_death"\n# data modify storage macro:input func set value "mypack:on_death"\n# function macro:systems/hook/bind\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/hook/internal/bind_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/hook/list.mcfunction', '# macro:systems/hook/list\n# Shows all registered hook binds to macro.debug players.\n\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━ Hook Binds ","color":"aqua"},{"text":"━━━━━━━━━━━━━━━━","color":"#555555"}]}\nexecute unless data storage macro:engine hook_binds[0] run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"text":"(no hook binds)","color":"gray","italic":true}]}\nexecute if data storage macro:engine hook_binds[0] run tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":" ","color":"#555555"},{"storage":"macro:engine","nbt":"hook_binds","interpret":false,"color":"yellow"}]}\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_advancement_fire.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/hook/on_advancement_fire\n# Called from the user\'s own advancement reward function.\n# Fires an event in "advancement:<id>" format.\n#\n# INPUT (storage macro:input):\n# advancement → advancement ID (e.g. "story/mine_stone")\n#\n# KULLANIM:\n# 1) Define a function as the reward in your advancement JSON:\n# "rewards": {"function": "mypack:advancements/mine_stone"}\n#\n# 2) Inside that function:\n# data modify storage macro:input advancement set value "story/mine_stone"\n# function macro:systems/hook/on_advancement_fire\n#\n# 3) Hook bind:\n# data modify storage macro:input event set value "advancement:story/mine_stone"\n# data modify storage macro:input func set value "mypack:on_first_mine"\n# function macro:systems/hook/bind\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/hook/internal/on_advancement_fire with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_break_block.mcfunction', '# macro:systems/hook/on_break_block\n# Reward: break_block advancement (item_durability_changed, delta max -1)\n# Feeds both break_block and using_item hooks.\nadvancement revoke @s only macro:systems/hook/break_block\nscoreboard players add @s macro.hook_tool_used 1\nscoreboard players add @s macro.hook_using_item 1\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_dimension_change.mcfunction', '# macro:systems/hook/on_dimension_change\n# Advancement reward: runs when changed_dimension triggers.\n# @s = player who changed dimension\n\nadvancement revoke @s only macro:systems/hook/dimension_change\nscoreboard players add @s macro.hook_dim_changed 1\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_drop.mcfunction', '# macro:systems/hook/on_drop\n# Binds a function or command to the "drop_item" event.\n#\n# INPUT (storage macro:input):\n#   func → function to run when a player drops an item\n#   cmd  → command to run when a player drops an item (used if func is absent)\n#\n# USAGE:\n#   data modify storage macro:input func set value "mypack:on_drop"\n#   function macro:systems/hook/on_drop\n#   -- or --\n#   data modify storage macro:input cmd set value "say An item was dropped"\n#   function macro:systems/hook/on_drop\ndata modify storage macro:input event set value "drop_item"\nfunction macro:systems/hook/bind\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_eat.mcfunction', '# macro:systems/hook/on_eat\n# Binds a function or command to the "eat" event.\n#\n# INPUT (storage macro:input):\n#   func → function to run when a player eats\n#   cmd  → command to run when a player eats (used if func is absent)\ndata modify storage macro:input event set value "eat"\nfunction macro:systems/hook/bind\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_entity_kill.mcfunction', '# macro:systems/hook/on_entity_kill\n# Reward: entity_kill advancement (player_killed_entity trigger)\nadvancement revoke @s only macro:systems/hook/entity_kill\nscoreboard players add @s macro.hook_entity_killed 1\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_fish_caught.mcfunction', '# macro:systems/hook/on_fish_caught\n# Binds a function or command to the "fish_caught" event.\n#\n# INPUT (storage macro:input):\n#   func → function to run when a player catches a fish\n#   cmd  → command to run (used if func is absent)\ndata modify storage macro:input event set value "fish_caught"\nfunction macro:systems/hook/bind\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_hero_of_the_village.mcfunction', '# macro:systems/hook/on_hero_of_the_village\n# Reward: hero_of_the_village advancement (raid victory)\nadvancement revoke @s only macro:systems/hook/hero_of_the_village\nscoreboard players add @s macro.hook_hero_of_the_village 1\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_interact_anvil.mcfunction', '# macro:systems/hook/on_interact_anvil\n# Advancement reward: runs when player interacts with an anvil\nadvancement revoke @s only macro:systems/hook/interact_anvil\nfunction macro:systems/hook/internal/on_interact_anvil\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_interact_shulker_box.mcfunction', '# macro:systems/hook/on_interact_shulker_box\n# Advancement reward: runs when player opens a shulker box\nadvancement revoke @s only macro:systems/hook/interact_shulker_box\nfunction macro:systems/hook/internal/on_interact_shulker_box\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_item_use.mcfunction', '# macro:systems/hook/on_item_use\n# Reward: item_use advancement (using_item trigger)\nadvancement revoke @s only macro:systems/hook/item_use\nscoreboard players add @s macro.hook_item_used 1\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_jump.mcfunction', '# macro:systems/hook/on_jump\n# Binds a function or command to the "jumped" event.\n#\n# INPUT (storage macro:input):\n#   func → function to run when a player jumps\n#   cmd  → command to run when a player jumps (used if func is absent)\n#\n# USAGE:\n#   data modify storage macro:input func set value "mypack:on_jump"\n#   function macro:systems/hook/on_jump\n#   -- or --\n#   data modify storage macro:input cmd set value "say A player jumped"\n#   function macro:systems/hook/on_jump\ndata modify storage macro:input event set value "jumped"\nfunction macro:systems/hook/bind\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_killed_by_arrow.mcfunction', '# macro:systems/hook/on_killed_by_arrow\n# Reward: killed_by_arrow advancement (entity_killed_player + killing_blow arrow)\nadvancement revoke @s only macro:systems/hook/killed_by_arrow\nscoreboard players add @s macro.hook_killed_by_arrow 1\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_open_chest.mcfunction', '# macro:systems/hook/on_open_chest\n# Binds a function or command to the "open_chest" event.\n#\n# INPUT (storage macro:input):\n#   func → function to run when a player opens a chest\n#   cmd  → command to run when a player opens a chest (used if func is absent)\n#\n# USAGE:\n#   data modify storage macro:input func set value "mypack:on_open_chest"\n#   function macro:systems/hook/on_open_chest\n#   -- or --\n#   data modify storage macro:input cmd set value "say A chest was opened"\n#   function macro:systems/hook/on_open_chest\ndata modify storage macro:input event set value "open_chest"\nfunction macro:systems/hook/bind\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_placed_block.mcfunction', "# Advancement reward: runs when placed_block triggers\n# Find the newly placed block in the direction the player is looking\n\n# Revoke advancement (so it can trigger again)\nadvancement revoke @s only macro:systems/hook/placed_block\n\n# Start raycast: begin from player's eyes\nexecute as @s at @s anchored eyes run function macro:systems/hook/raycast/start\n"),
    ('./1_20_5/data/macro/functions/systems/hook/on_player_death.mcfunction', '# macro:systems/hook/on_player_death\n# Reward: player_death advancement (entity_killed_player trigger)\n# @s = dying player\nadvancement revoke @s only macro:systems/hook/player_death\ndata modify storage macro:engine _hook_fire_tmp set value {event:"player_death"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_target_hit.mcfunction', '# macro:systems/hook/on_target_hit\n# Binds a function or command to the "target_hit" event.\n#\n# INPUT (storage macro:input):\n#   func → function to run when a player hits a target block\n#   cmd  → command to run when a player hits a target block (used if func is absent)\n#\n# USAGE:\n#   data modify storage macro:input func set value "mypack:on_target_hit"\n#   function macro:systems/hook/on_target_hit\n#   -- or --\n#   data modify storage macro:input cmd set value "say Target hit"\n#   function macro:systems/hook/on_target_hit\ndata modify storage macro:input event set value "target_hit"\nfunction macro:systems/hook/bind\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_trade.mcfunction', '# macro:systems/hook/on_trade\n# Advancement reward: runs when villager_trade triggers.\n# @s = takas yapan oyuncu\n\nadvancement revoke @s only macro:systems/hook/trade\nscoreboard players add @s macro.hook_traded 1\n'),
    ('./1_20_5/data/macro/functions/systems/hook/on_using_item.mcfunction', '# macro:systems/hook/on_using_item\n# Called by tick_scan when macro.hook_using_item >= 1.\n# Score is set by on_break_block (shared advancement).\n'),
    ('./1_20_5/data/macro/functions/systems/hook/unbind.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/hook/unbind\n# Removes all binds belonging to a specific event.\n#\n# INPUT (storage macro:input):\n# event → event name\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/hook/internal/unbind_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/hook/unbind_all.mcfunction', '# macro:systems/hook/unbind_all\n# Clears all hook binds.\n\ndata modify storage macro:engine hook_binds set value []\n\ntellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"hook/unbind_all ","color":"aqua"},{"text":"⚠ all hook binds cleared","color":"yellow"}]\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/bind_exec.mcfunction', '# macro:systems/hook/internal/bind_exec [MACRO]\n# INPUT: $(event) — required\n# macro:input.func OR macro:input.cmd — one must exist\n#\n# Two-step: append a base compound with just event, then set func or cmd from storage.\n# This avoids requiring both $(func) and $(cmd) to be present simultaneously.\n\n$data modify storage macro:engine hook_binds append value {event:"$(event)"}\nexecute if data storage macro:input func run data modify storage macro:engine hook_binds[-1].func set from storage macro:input func\nexecute unless data storage macro:input func run data modify storage macro:engine hook_binds[-1].cmd set from storage macro:input cmd\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"hook/bind ","color":"aqua"},{"text":"$(event)","color":"yellow"},{"text":" → ","color":"#555555"},{"text":"$(event)","color":"white"}]\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/check_bind.mcfunction', '# macro:systems/hook/internal/check_bind [MACRO]\n# INPUT: $(event) - event field of the bind in _hook_ctx\n# If it matches _hook_fire_event, run func or cmd.\n# @s = tetikleyen oyuncu\n\n$execute if data storage macro:engine {_hook_fire_event:"$(event)"} if data storage macro:engine _hook_ctx.func run function macro:systems/hook/internal/exec with storage macro:engine _hook_ctx\n$execute if data storage macro:engine {_hook_fire_event:"$(event)"} unless data storage macro:engine _hook_ctx.func run function macro:systems/hook/internal/run_cmd with storage macro:engine _hook_ctx\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/check_block_break.mcfunction', '# macro:systems/hook/internal/check_block_break\n# @s = player being checked\n#\n# METHOD:\n# item_durability_changed advancement -> macro.hook_tool_used score increments.\n# tick_scan calls this per player; fires on_block_break if score >= 1.\n#\n# KNOWN LIMITATION:\n# Hand-breaking (cobweb, snow, leaves) is not detectable in 1.20.3–26.1+\n# via advancement triggers. Tool-based breaking only.\n# Mob hits also trigger item_durability_changed (sword, axe, etc.).\nexecute unless score @s macro.hook_tool_used matches 1.. run return 0\nfunction macro:systems/hook/internal/on_block_break\nscoreboard players set @s macro.hook_tool_used 0\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/check_level_up.mcfunction', 'execute store result score $hlvl_cur macro.tmp run data get entity @s XpLevel\nexecute if score @s macro.hook_lvl < $hlvl_cur macro.tmp run scoreboard players operation @s macro.hook_lvl_new = $hlvl_cur macro.tmp\nexecute if score @s macro.hook_lvl < $hlvl_cur macro.tmp run function macro:systems/hook/internal/on_level_up\nexecute store result score @s macro.hook_lvl run scoreboard players get $hlvl_cur macro.tmp\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/dispatch.mcfunction', '# macro:systems/hook/internal/dispatch\n# Iterates _hook_iter list, runs matching events.\n\nexecute unless data storage macro:engine _hook_iter[0] run return 0\n\ndata modify storage macro:engine _hook_ctx set from storage macro:engine _hook_iter[0]\ndata remove storage macro:engine _hook_iter[0]\n\nfunction macro:systems/hook/internal/check_bind with storage macro:engine _hook_ctx\n\nfunction macro:systems/hook/internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/exec.mcfunction', '# macro:systems/hook/internal/exec [MACRO]\n# INPUT: $(func) — guaranteed present (check_bind ensures func exists)\n# @s = tetikleyen oyuncu\n\n$data modify storage macro:engine _dispatch.func set value "$(func)"\nfunction #macro:internal/dispatch\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/fire.mcfunction', '# macro:systems/hook/internal/fire [MACRO]\n# INPUT: $(event) — event name to fire\n# @s = tetikleyen oyuncu\n# Copies hook_binds list and dispatches it.\n\n$data modify storage macro:engine _hook_fire_event set value "$(event)"\ndata modify storage macro:engine _hook_iter set from storage macro:engine hook_binds\n\nexecute if data storage macro:engine _hook_iter run function macro:systems/hook/internal/dispatch\n\ndata remove storage macro:engine _hook_iter\ndata remove storage macro:engine _hook_fire_event\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/on_advancement_fire.mcfunction', '# macro:systems/hook/internal/on_advancement_fire [MACRO]\n# INPUT: $(advancement)\n# @s = player who earned the advancement\n\n$data modify storage macro:engine _hook_fire_tmp set value {event:"advancement:$(advancement)"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"hook/on_advancement_fire ","color":"aqua"},{"text":"advancement:$(advancement)","color":"yellow"}]\n'),
    ('./1_20_5/data/macro/functions/systems/hook/internal/on_block_break.mcfunction', '# macro:systems/hook/internal/on_block_break\n# @s = player who triggered the event\ndata modify storage macro:engine _hook_fire_tmp set value {event:"block_break"}\nfunction macro:systems/hook/internal/fire with storage macro:engine _hook_fire_tmp\ndata remove storage macro:engine _hook_fire_tmp\n'),
