    ('./1_20_5/data/macro/functions/systems/math/distance2d.mcfunction', '$scoreboard players set $d2d_x1 macro.tmp $(x1)\n$scoreboard players set $d2d_z1 macro.tmp $(z1)\n$scoreboard players set $d2d_x2 macro.tmp $(x2)\n$scoreboard players set $d2d_z2 macro.tmp $(z2)\n\nscoreboard players operation $d2d_dx macro.tmp = $d2d_x2 macro.tmp\nscoreboard players operation $d2d_dx macro.tmp -= $d2d_x1 macro.tmp\n\nscoreboard players operation $d2d_dz macro.tmp = $d2d_z2 macro.tmp\nscoreboard players operation $d2d_dz macro.tmp -= $d2d_z1 macro.tmp\n\n# Overflow prevention: 2 * 32767² = 2,147,354,578 ≤ INT_MAX (2,147,483,647)\nexecute if score $d2d_dx macro.tmp matches 32768.. run scoreboard players set $d2d_dx macro.tmp 32767\nexecute if score $d2d_dx macro.tmp matches ..-32768 run scoreboard players set $d2d_dx macro.tmp -32767\nexecute if score $d2d_dz macro.tmp matches 32768.. run scoreboard players set $d2d_dz macro.tmp 32767\nexecute if score $d2d_dz macro.tmp matches ..-32768 run scoreboard players set $d2d_dz macro.tmp -32767\n\nscoreboard players operation $d2d_dx macro.tmp *= $d2d_dx macro.tmp\nscoreboard players operation $d2d_dz macro.tmp *= $d2d_dz macro.tmp\nscoreboard players operation $d2d_sq macro.tmp = $d2d_dx macro.tmp\nscoreboard players operation $d2d_sq macro.tmp += $d2d_dz macro.tmp\n\nexecute if score $d2d_sq macro.tmp matches 0 run data modify storage macro:output result set value 0\nexecute if score $d2d_sq macro.tmp matches 0 run return 0\n\nscoreboard players operation $sqrt_n macro.tmp = $d2d_sq macro.tmp\nscoreboard players set $sqrt_lo macro.tmp 0\nscoreboard players operation $sqrt_hi macro.tmp = $sqrt_n macro.tmp\nexecute if score $sqrt_hi macro.tmp matches 46342.. run scoreboard players set $sqrt_hi macro.tmp 46341\nscoreboard players set $sqrt_itr macro.tmp 16\nfunction macro:systems/math/internal/sqrt_step\n\nexecute store result storage macro:output result int 1 run scoreboard players get $sqrt_lo macro.tmp\n'),
    ('./1_20_5/data/macro/functions/systems/math/distance3d.mcfunction', '$scoreboard players set $d3d_x1 macro.tmp $(x1)\n$scoreboard players set $d3d_y1 macro.tmp $(y1)\n$scoreboard players set $d3d_z1 macro.tmp $(z1)\n$scoreboard players set $d3d_x2 macro.tmp $(x2)\n$scoreboard players set $d3d_y2 macro.tmp $(y2)\n$scoreboard players set $d3d_z2 macro.tmp $(z2)\n\nscoreboard players operation $d3d_dx macro.tmp = $d3d_x2 macro.tmp\nscoreboard players operation $d3d_dx macro.tmp -= $d3d_x1 macro.tmp\n\nscoreboard players operation $d3d_dy macro.tmp = $d3d_y2 macro.tmp\nscoreboard players operation $d3d_dy macro.tmp -= $d3d_y1 macro.tmp\n\nscoreboard players operation $d3d_dz macro.tmp = $d3d_z2 macro.tmp\nscoreboard players operation $d3d_dz macro.tmp -= $d3d_z1 macro.tmp\n\n# Overflow prevention: 3 * 26754² = 2,147,329,548 ≤ INT_MAX (2,147,483,647)\nexecute if score $d3d_dx macro.tmp matches 26755.. run scoreboard players set $d3d_dx macro.tmp 26754\nexecute if score $d3d_dx macro.tmp matches ..-26755 run scoreboard players set $d3d_dx macro.tmp -26754\nexecute if score $d3d_dy macro.tmp matches 26755.. run scoreboard players set $d3d_dy macro.tmp 26754\nexecute if score $d3d_dy macro.tmp matches ..-26755 run scoreboard players set $d3d_dy macro.tmp -26754\nexecute if score $d3d_dz macro.tmp matches 26755.. run scoreboard players set $d3d_dz macro.tmp 26754\nexecute if score $d3d_dz macro.tmp matches ..-26755 run scoreboard players set $d3d_dz macro.tmp -26754\n\nscoreboard players operation $d3d_dx macro.tmp *= $d3d_dx macro.tmp\nscoreboard players operation $d3d_dy macro.tmp *= $d3d_dy macro.tmp\nscoreboard players operation $d3d_dz macro.tmp *= $d3d_dz macro.tmp\nscoreboard players operation $d3d_sq macro.tmp = $d3d_dx macro.tmp\nscoreboard players operation $d3d_sq macro.tmp += $d3d_dy macro.tmp\nscoreboard players operation $d3d_sq macro.tmp += $d3d_dz macro.tmp\n\nexecute if score $d3d_sq macro.tmp matches 0 run data modify storage macro:output result set value 0\nexecute if score $d3d_sq macro.tmp matches 0 run return 0\n\nscoreboard players operation $sqrt_n macro.tmp = $d3d_sq macro.tmp\nscoreboard players set $sqrt_lo macro.tmp 0\nscoreboard players operation $sqrt_hi macro.tmp = $sqrt_n macro.tmp\nexecute if score $sqrt_hi macro.tmp matches 46342.. run scoreboard players set $sqrt_hi macro.tmp 46341\nscoreboard players set $sqrt_itr macro.tmp 16\nfunction macro:systems/math/internal/sqrt_step\n\nexecute store result storage macro:output result int 1 run scoreboard players get $sqrt_lo macro.tmp\n'),
    ('./1_20_5/data/macro/functions/systems/math/divmod.mcfunction', '$scoreboard players set $dvm_v macro.tmp $(value)\n$scoreboard players set $dvm_d macro.tmp $(divisor)\n\nexecute if score $dvm_d macro.tmp matches ..0 run data modify storage macro:output quotient set value 0\nexecute if score $dvm_d macro.tmp matches ..0 run data modify storage macro:output remainder set value 0\nexecute if score $dvm_d macro.tmp matches ..0 run return 0\n\nscoreboard players operation $dvm_q macro.tmp = $dvm_v macro.tmp\nscoreboard players operation $dvm_q macro.tmp /= $dvm_d macro.tmp\nexecute store result storage macro:output quotient int 1 run scoreboard players get $dvm_q macro.tmp\n\nscoreboard players operation $dvm_v macro.tmp %= $dvm_d macro.tmp\nexecute if score $dvm_v macro.tmp matches ..-1 run scoreboard players operation $dvm_v macro.tmp += $dvm_d macro.tmp\nexecute store result storage macro:output remainder int 1 run scoreboard players get $dvm_v macro.tmp\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/divmod ","color":"aqua"},{"text":"($(value)/$(divisor))","color":"gray"},{"text":" → ","color":"#555555"},{"text":"q=","color":"gray"},{"storage":"macro:output","nbt":"quotient","color":"green"},{"text":" r=","color":"gray"},{"storage":"macro:output","nbt":"remainder","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/math/factorial.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/math/factorial\n# Computes n! for integer n in range 0–12.\n# Values outside this range are clamped:\n# n < 0 → result = 0 (undefined)\n# n > 12 → result = 0 (would overflow INT32)\n#\n#  Input : $(n) → non-negative integer\n# Output: macro:output result → n!\n#\n# Lookup table approach — avoids recursion overhead and is safe\n# against scoreboard overflow (12! = 479001600 < 2147483647).\n#\n# Example:\n# function macro:systems/math/factorial {n:5}\n# # macro:output result = 120\n# function macro:systems/math/factorial {n:0}\n# # macro:output result = 1\n# ─────────────────────────────────────────────────────────────────\n\n$scoreboard players set $fact_n macro.tmp $(n)\n\n# Out-of-range guard\nexecute if score $fact_n macro.tmp matches ..-1 run data modify storage macro:output result set value 0\nexecute if score $fact_n macro.tmp matches ..-1 run return 0\nexecute if score $fact_n macro.tmp matches 13.. run data modify storage macro:output result set value 0\nexecute if score $fact_n macro.tmp matches 13.. run return 0\n\n# Lookup table 0! – 12!\nexecute if score $fact_n macro.tmp matches 0 run data modify storage macro:output result set value 1\nexecute if score $fact_n macro.tmp matches 1 run data modify storage macro:output result set value 1\nexecute if score $fact_n macro.tmp matches 2 run data modify storage macro:output result set value 2\nexecute if score $fact_n macro.tmp matches 3 run data modify storage macro:output result set value 6\nexecute if score $fact_n macro.tmp matches 4 run data modify storage macro:output result set value 24\nexecute if score $fact_n macro.tmp matches 5 run data modify storage macro:output result set value 120\nexecute if score $fact_n macro.tmp matches 6 run data modify storage macro:output result set value 720\nexecute if score $fact_n macro.tmp matches 7 run data modify storage macro:output result set value 5040\nexecute if score $fact_n macro.tmp matches 8 run data modify storage macro:output result set value 40320\nexecute if score $fact_n macro.tmp matches 9 run data modify storage macro:output result set value 362880\nexecute if score $fact_n macro.tmp matches 10 run data modify storage macro:output result set value 3628800\nexecute if score $fact_n macro.tmp matches 11 run data modify storage macro:output result set value 39916800\nexecute if score $fact_n macro.tmp matches 12 run data modify storage macro:output result set value 479001600\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/factorial ","color":"aqua"},{"text":"$(n)! = ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./1_20_5/data/macro/functions/systems/math/gcd.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/math/gcd\n# Computes GCD using the Euclidean algorithm.\n#  Input : $(a), $(b)          → integers (may be negative)\n# Output: macro:output result → GCD(|a|, |b|)\n#\n# Example:\n# data modify storage macro:input a set value 48\n# data modify storage macro:input b set value 18\n# function macro:systems/math/gcd with storage macro:input {}\n# # macro:output result = 6\n# ─────────────────────────────────────────────────────────────────\n\n$scoreboard players set $gcd_a macro.tmp $(a)\n$scoreboard players set $gcd_b macro.tmp $(b)\n\n# Take absolute value\nscoreboard players set $gcd_neg macro.tmp -1\nexecute if score $gcd_a macro.tmp matches ..-1 run scoreboard players operation $gcd_a macro.tmp *= $gcd_neg macro.tmp\nexecute if score $gcd_b macro.tmp matches ..-1 run scoreboard players operation $gcd_b macro.tmp *= $gcd_neg macro.tmp\n\n# b=0 → result is a\nexecute if score $gcd_b macro.tmp matches 0 run execute store result storage macro:output result int 1 run scoreboard players get $gcd_a macro.tmp\nexecute if score $gcd_b macro.tmp matches 0 run return 0\n\n# Euclidean loop (inner function)\nfunction macro:systems/math/internal/gcd_loop\n\nexecute store result storage macro:output result int 1 run scoreboard players get $gcd_a macro.tmp\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/gcd ","color":"aqua"},{"text":"($(a),$(b)) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/math/is_between.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/math/is_between\n# Checks if value is in the inclusive range [min, max].\n#  Input : $(value), $(min), $(max)\n# Output: macro:output result → 1b (true) or 0b (false)\n#\n# Example:\n# data modify storage macro:input value set value 15\n# data modify storage macro:input min set value 10\n# data modify storage macro:input max set value 20\n# function macro:systems/math/is_between with storage macro:input {}\n# # macro:output result = 1b\n# ─────────────────────────────────────────────────────────────────\n\n$scoreboard players set $ib_v macro.tmp $(value)\n$scoreboard players set $ib_lo macro.tmp $(min)\n$scoreboard players set $ib_hi macro.tmp $(max)\n\ndata modify storage macro:output result set value 0b\n\nexecute if score $ib_v macro.tmp >= $ib_lo macro.tmp run execute if score $ib_v macro.tmp <= $ib_hi macro.tmp run data modify storage macro:output result set value 1b\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/is_between ","color":"aqua"},{"text":"$(value) in [$(min),$(max)] → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/math/lcm.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/math/lcm\n# EKOK (LCM) hesaplar: lcm(a,b) = |a*b| / gcd(a,b)\n#  Input : $(a), $(b)          → integers\n# Output: macro:output result → LCM(a, b)\n# NOTE : Overflow risk — result may exceed INT_MAX for large inputs.\n#\n# Example:\n# data modify storage macro:input a set value 12\n# data modify storage macro:input b set value 8\n# function macro:systems/math/lcm with storage macro:input {}\n# # macro:output result = 24\n# ─────────────────────────────────────────────────────────────────\n\n$scoreboard players set $lcm_a macro.tmp $(a)\n$scoreboard players set $lcm_b macro.tmp $(b)\n\n# Zero check\nexecute if score $lcm_a macro.tmp matches 0 run data modify storage macro:output result set value 0\nexecute if score $lcm_a macro.tmp matches 0 run return 0\nexecute if score $lcm_b macro.tmp matches 0 run data modify storage macro:output result set value 0\nexecute if score $lcm_b macro.tmp matches 0 run return 0\n\n# Absolute value\nscoreboard players set $lcm_neg macro.tmp -1\nexecute if score $lcm_a macro.tmp matches ..-1 run scoreboard players operation $lcm_a macro.tmp *= $lcm_neg macro.tmp\nexecute if score $lcm_b macro.tmp matches ..-1 run scoreboard players operation $lcm_b macro.tmp *= $lcm_neg macro.tmp\n\n# Compute GCD (lcm_a, lcm_b share gcd_a, gcd_b variables)\nscoreboard players operation $gcd_a macro.tmp = $lcm_a macro.tmp\nscoreboard players operation $gcd_b macro.tmp = $lcm_b macro.tmp\nfunction macro:systems/math/internal/gcd_loop\n\n# lcm = (a / gcd) * b (divide first to prevent overflow)\nscoreboard players operation $lcm_a macro.tmp /= $gcd_a macro.tmp\nscoreboard players operation $lcm_a macro.tmp *= $lcm_b macro.tmp\n\nexecute store result storage macro:output result int 1 run scoreboard players get $lcm_a macro.tmp\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/lcm ","color":"aqua"},{"text":"($(a),$(b)) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/math/lerp.mcfunction', '$scoreboard players set $lerp_a macro.tmp $(a)\n$scoreboard players set $lerp_b macro.tmp $(b)\n$scoreboard players set $lerp_t macro.tmp $(t)\n\nscoreboard players operation $lerp_r macro.tmp = $lerp_b macro.tmp\nscoreboard players operation $lerp_r macro.tmp -= $lerp_a macro.tmp\n\nscoreboard players operation $lerp_r macro.tmp *= $lerp_t macro.tmp\nscoreboard players set $lerp_100 macro.tmp 100\nscoreboard players operation $lerp_r macro.tmp /= $lerp_100 macro.tmp\nscoreboard players operation $lerp_r macro.tmp += $lerp_a macro.tmp\n\nexecute store result storage macro:output result int 1 run scoreboard players get $lerp_r macro.tmp\n'),
    ('./1_20_5/data/macro/functions/systems/math/lerp_clamped.mcfunction', '$scoreboard players set $lc_a macro.tmp $(a)\n$scoreboard players set $lc_b macro.tmp $(b)\n$scoreboard players set $lc_t macro.tmp $(t)\n\nexecute if score $lc_t macro.tmp matches ..-1 run scoreboard players set $lc_t macro.tmp 0\nscoreboard players set $lc_100 macro.tmp 100\nexecute if score $lc_t macro.tmp > $lc_100 macro.tmp run scoreboard players operation $lc_t macro.tmp = $lc_100 macro.tmp\n\nscoreboard players operation $lc_r macro.tmp = $lc_b macro.tmp\nscoreboard players operation $lc_r macro.tmp -= $lc_a macro.tmp\n\nscoreboard players operation $lc_r macro.tmp *= $lc_t macro.tmp\nscoreboard players operation $lc_r macro.tmp /= $lc_100 macro.tmp\nscoreboard players operation $lc_r macro.tmp += $lc_a macro.tmp\n\nexecute store result storage macro:output result int 1 run scoreboard players get $lc_r macro.tmp\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/lerp_clamped ","color":"aqua"},{"text":"a=","color":"#555555"},{"text":"$(a)","color":"white"},{"text":" b=","color":"#555555"},{"text":"$(b)","color":"white"},{"text":" t=","color":"#555555"},{"text":"$(t)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/math/log2.mcfunction', '$scoreboard players set $lg2_v macro.tmp $(value)\n\nexecute if score $lg2_v macro.tmp matches ..0 run data modify storage macro:output result set value -1\nexecute if score $lg2_v macro.tmp matches ..0 run return 0\n\nscoreboard players set $lg2_r macro.tmp 0\nscoreboard players set $lg2_2 macro.tmp 2\n\nfunction macro:systems/math/internal/log2_loop\n\nexecute store result storage macro:output result int 1 run scoreboard players get $lg2_r macro.tmp\n'),
    ('./1_20_5/data/macro/functions/systems/math/map.mcfunction', '$scoreboard players set $map_v macro.tmp $(value)\n$scoreboard players set $map_imin macro.tmp $(in_min)\n$scoreboard players set $map_imax macro.tmp $(in_max)\n$scoreboard players set $map_omin macro.tmp $(out_min)\n$scoreboard players set $map_omax macro.tmp $(out_max)\n\nscoreboard players operation $map_ir macro.tmp = $map_imax macro.tmp\nscoreboard players operation $map_ir macro.tmp -= $map_imin macro.tmp\n\nexecute if score $map_ir macro.tmp matches 0 run execute store result storage macro:output result int 1 run scoreboard players get $map_omin macro.tmp\nexecute if score $map_ir macro.tmp matches 0 run return 0\n\nscoreboard players operation $map_or macro.tmp = $map_omax macro.tmp\nscoreboard players operation $map_or macro.tmp -= $map_omin macro.tmp\n\nscoreboard players operation $map_off macro.tmp = $map_v macro.tmp\nscoreboard players operation $map_off macro.tmp -= $map_imin macro.tmp\n\nscoreboard players operation $map_off macro.tmp *= $map_or macro.tmp\nscoreboard players operation $map_off macro.tmp /= $map_ir macro.tmp\nscoreboard players operation $map_off macro.tmp += $map_omin macro.tmp\n\nexecute store result storage macro:output result int 1 run scoreboard players get $map_off macro.tmp\n'),
