    ('./1_20_5/data/macro/functions/systems/math/vec/internal/dot_exec.mcfunction', '# macro:systems/math/vec/internal/dot_exec [MACRO]\n# INPUT: $(ax), $(ay), $(az), $(bx), $(by), $(bz)\n\n$scoreboard players set $vdax macro.tmp $(ax)\n$scoreboard players set $vdbx macro.tmp $(bx)\nscoreboard players operation $vdax macro.tmp *= $vdbx macro.tmp\n\n$scoreboard players set $vday macro.tmp $(ay)\n$scoreboard players set $vdby macro.tmp $(by)\nscoreboard players operation $vday macro.tmp *= $vdby macro.tmp\n\n$scoreboard players set $vdaz macro.tmp $(az)\n$scoreboard players set $vdbz macro.tmp $(bz)\nscoreboard players operation $vdaz macro.tmp *= $vdbz macro.tmp\n\nscoreboard players operation $vdax macro.tmp += $vday macro.tmp\nscoreboard players operation $vdax macro.tmp += $vdaz macro.tmp\n\nexecute store result storage macro:output result int 1 run scoreboard players get $vdax macro.tmp\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/vec/dot ","color":"aqua"},{"text":"($(ax),$(ay),$(az))·($(bx),$(by),$(bz)) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"yellow"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/math/vec/internal/normalize_exec.mcfunction', '# macro:systems/math/vec/internal/normalize_exec [MACRO]\n# INPUT: $(x), $(y), $(z)\n# Compute length via math/distance3d, then ×1000 / length\n# RULE: Lines without $(var) must NOT have a $ prefix.\n\nfunction macro:core/lib/input_push\n\ndata modify storage macro:input x1 set value 0\ndata modify storage macro:input y1 set value 0\ndata modify storage macro:input z1 set value 0\n$data modify storage macro:input x2 set value $(x)\n$data modify storage macro:input y2 set value $(y)\n$data modify storage macro:input z2 set value $(z)\nfunction macro:systems/math/distance3d with storage macro:input {}\n\nfunction macro:core/lib/input_pop\n\nexecute store result score $vnlen macro.tmp run data get storage macro:output result\n\nexecute if score $vnlen macro.tmp matches 0 run data modify storage macro:output x set value 0\nexecute if score $vnlen macro.tmp matches 0 run data modify storage macro:output y set value 0\nexecute if score $vnlen macro.tmp matches 0 run data modify storage macro:output z set value 0\nexecute if score $vnlen macro.tmp matches 0 run data modify storage macro:output length set value 0\nexecute if score $vnlen macro.tmp matches 0 run return 0\n\nexecute store result storage macro:output length int 1 run scoreboard players get $vnlen macro.tmp\n\n$scoreboard players set $vnx macro.tmp $(x)\nscoreboard players set $vn1000 macro.tmp 1000\nscoreboard players operation $vnx macro.tmp *= $vn1000 macro.tmp\nscoreboard players operation $vnx macro.tmp /= $vnlen macro.tmp\nexecute store result storage macro:output x int 1 run scoreboard players get $vnx macro.tmp\n\n$scoreboard players set $vny macro.tmp $(y)\nscoreboard players operation $vny macro.tmp *= $vn1000 macro.tmp\nscoreboard players operation $vny macro.tmp /= $vnlen macro.tmp\nexecute store result storage macro:output y int 1 run scoreboard players get $vny macro.tmp\n\n$scoreboard players set $vnz macro.tmp $(z)\nscoreboard players operation $vnz macro.tmp *= $vn1000 macro.tmp\nscoreboard players operation $vnz macro.tmp /= $vnlen macro.tmp\nexecute store result storage macro:output z int 1 run scoreboard players get $vnz macro.tmp\n\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/vec/normalize ","color":"aqua"},{"text":"len=","color":"gray"},{"storage":"macro:output","nbt":"length","color":"yellow"},{"text":" → ","color":"gray"},{"storage":"macro:output","nbt":"x","color":"yellow"},{"text":",","color":"gray"},{"storage":"macro:output","nbt":"y","color":"yellow"},{"text":",","color":"gray"},{"storage":"macro:output","nbt":"z","color":"yellow"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/math/vec/internal/sub_exec.mcfunction', '# macro:systems/math/vec/internal/sub_exec [MACRO]\n# INPUT: $(ax), $(ay), $(az), $(bx), $(by), $(bz)\n\n$scoreboard players set $vx macro.tmp $(ax)\n$scoreboard players set $vy macro.tmp $(ay)\n$scoreboard players set $vz macro.tmp $(az)\n$scoreboard players remove $vx macro.tmp $(bx)\n$scoreboard players remove $vy macro.tmp $(by)\n$scoreboard players remove $vz macro.tmp $(bz)\n\nexecute store result storage macro:output x int 1 run scoreboard players get $vx macro.tmp\nexecute store result storage macro:output y int 1 run scoreboard players get $vy macro.tmp\nexecute store result storage macro:output z int 1 run scoreboard players get $vz macro.tmp\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"math/vec/sub ","color":"aqua"},{"text":"($(ax),$(ay),$(az))-($(bx),$(by),$(bz)) → ","color":"gray"},{"storage":"macro:output","nbt":"x","color":"yellow"},{"text":",","color":"gray"},{"storage":"macro:output","nbt":"y","color":"yellow"},{"text":",","color":"gray"},{"storage":"macro:output","nbt":"z","color":"yellow"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/append.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/append\n# Appends an element from another storage path to a list in storage.\n#\n# INPUT (storage macro:input):\n# dst_storage → hedef storage\n# dst_path → hedef list path\n# src_storage → kaynak storage\n# src_path → path of the value to append\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/append_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/clear.mcfunction', "# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/clear\n# Storage'dan belirli path'i siler.\n#\n# INPUT (storage macro:input):\n# storage → storage namespace\n# path → silinecek path\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/clear_exec with storage macro:input {}\n"),
    ('./1_20_5/data/macro/functions/systems/nbt/copy.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/copy\n# Copies a path between two storages or within the same storage.\n#\n# INPUT (storage macro:input):\n# src_storage → source storage namespace (e.g. "macro:engine")\n# src_path → source NBT path (e.g. "players.Steve")\n# dst_storage → hedef storage namespace\n# dst_path → hedef NBT path\n#\n# EXAMPLE:\n# data modify storage macro:input src_storage set value "macro:engine"\n# data modify storage macro:input src_path set value "players.Steve"\n# data modify storage macro:input dst_storage set value "mypack:data"\n# data modify storage macro:input dst_path set value "backup.Steve"\n# function macro:systems/nbt/copy\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/copy_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/count.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/count\n# Returns the element count of a list in storage.\n#\n# INPUT (storage macro:input):\n# storage → storage namespace\n# path → list path\n#\n# OUTPUT: macro:output result (int)\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/count_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/exists.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/exists\n# Checks whether a specific path exists in storage.\n#\n# INPUT (storage macro:input):\n# storage → storage namespace\n# path → kontrol edilecek path\n#\n# OUTPUT: macro:output result → 1b (var) veya 0b (yok)\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/exists_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/first.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/first\n# Copies the first element [0] of a list at src_path into dst_path.\n# If the list is empty or path does not exist, does nothing (silent fail).\n#\n# INPUT (storage macro:input):\n# src_storage → source storage namespace\n# src_path → list path (element [0] will be read)\n# dst_storage → destination storage namespace\n# dst_path → destination path to write into\n#\n# EXAMPLE:\n# data modify storage macro:input src_storage set value "macro:engine"\n# data modify storage macro:input src_path set value "event_queue"\n# data modify storage macro:input dst_storage set value "macro:output"\n# data modify storage macro:input dst_path set value "result"\n# function macro:systems/nbt/first\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/first_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/merge.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/merge\n# Merges a compound from src_storage:src_path into dst_storage:dst_path.\n# Equivalent to: data modify <dst> merge from <src>\n# Existing keys in dst are overwritten by src values; missing keys added.\n#\n# INPUT (storage macro:input):\n# src_storage → source storage namespace (e.g. "macro:engine")\n# src_path → source compound path\n# dst_storage → destination storage namespace\n# dst_path → destination compound path\n#\n# EXAMPLE:\n# data modify storage macro:input src_storage set value "macro:engine"\n# data modify storage macro:input src_path set value "players.Steve"\n# data modify storage macro:input dst_storage set value "mypack:data"\n# data modify storage macro:input dst_path set value "backup.Steve"\n# function macro:systems/nbt/merge\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/merge_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/move.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/move\n# Moves a path within the same storage (copy + delete).\n#\n# INPUT (storage macro:input):\n# storage → storage namespace\n# from_path → kaynak path\n# to_path → hedef path\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/move_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/pop.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/pop\n# Copies the first element of a list to macro:output result and removes it.\n#\n# INPUT (storage macro:input):\n# storage → storage namespace\n# path → list path\n#\n# OUTPUT: macro:output result (popped element)\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/pop_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/swap.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/nbt/swap\n# Swaps the values of two paths within the same storage.\n#\n# INPUT (storage macro:input):\n# storage → storage namespace\n# path_a → birinci path\n# path_b → ikinci path\n# ─────────────────────────────────────────────────────────────────\n\nfunction macro:systems/nbt/internal/swap_exec with storage macro:input {}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/append_exec.mcfunction', '# macro:systems/nbt/internal/append_exec [MACRO]\n# INPUT: $(dst_storage), $(dst_path), $(src_storage), $(src_path)\n\n$data modify storage $(dst_storage) $(dst_path) append from storage $(src_storage) $(src_path)\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/append ","color":"aqua"},{"text":"$(src_storage):$(src_path)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(dst_storage):$(dst_path)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/clear_exec.mcfunction', '# macro:systems/nbt/internal/clear_exec [MACRO]\n# INPUT: $(storage), $(path)\n\n$data remove storage $(storage) $(path)\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/clear ","color":"aqua"},{"text":"$(storage):$(path)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/copy_exec.mcfunction', '# macro:systems/nbt/internal/copy_exec [MACRO]\n# INPUT: $(src_storage), $(src_path), $(dst_storage), $(dst_path)\n\n$data modify storage $(dst_storage) $(dst_path) set from storage $(src_storage) $(src_path)\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/copy ","color":"aqua"},{"text":"$(src_storage):$(src_path)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(dst_storage):$(dst_path)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/count_exec.mcfunction', '# macro:systems/nbt/internal/count_exec [MACRO]\n# INPUT: $(storage), $(path)\n\nscoreboard players set $nbt_count macro.tmp 0\n$execute store result score $nbt_count macro.tmp run data get storage $(storage) $(path)\n\nexecute store result storage macro:output result int 1 run scoreboard players get $nbt_count macro.tmp\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/count ","color":"aqua"},{"text":"$(storage):$(path)","color":"white"},{"text":" → ","color":"#555555"},{"score":{"name":"$nbt_count","objective":"macro.tmp"},"color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/exists_exec.mcfunction', '# macro:systems/nbt/internal/exists_exec [MACRO]\n# INPUT: $(storage), $(path)\n\ndata modify storage macro:output result set value 0b\n$execute if data storage $(storage) $(path) run data modify storage macro:output result set value 1b\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/exists ","color":"aqua"},{"text":"$(storage):$(path)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/first_exec.mcfunction', '# macro:systems/nbt/internal/first_exec [MACRO]\n# INPUT: $(src_storage), $(src_path), $(dst_storage), $(dst_path)\n\n$data modify storage $(dst_storage) $(dst_path) set from storage $(src_storage) $(src_path)[0]\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/first ","color":"aqua"},{"text":"$(src_storage):$(src_path)[0]","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(dst_storage):$(dst_path)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/merge_exec.mcfunction', '# macro:systems/nbt/internal/merge_exec [MACRO]\n# INPUT: $(src_storage), $(src_path), $(dst_storage), $(dst_path)\n\n$data modify storage $(dst_storage) $(dst_path) merge from storage $(src_storage) $(src_path)\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/merge ","color":"aqua"},{"text":"$(src_storage):$(src_path)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(dst_storage):$(dst_path)","color":"aqua"}]\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/move_exec.mcfunction', '# macro:systems/nbt/internal/move_exec [MACRO]\n# INPUT: $(storage), $(from_path), $(to_path)\n\n$data modify storage $(storage) $(to_path) set from storage $(storage) $(from_path)\n$data remove storage $(storage) $(from_path)\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/move ","color":"aqua"},{"text":"$(from_path)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(to_path)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/pop_exec.mcfunction', '# macro:systems/nbt/internal/pop_exec [MACRO]\n# INPUT: $(storage), $(path)\n\n$execute if data storage $(storage) $(path)[0] run data modify storage macro:output result set from storage $(storage) $(path)[0]\n$execute if data storage $(storage) $(path)[0] run data remove storage $(storage) $(path)[0]\n$execute unless data storage $(storage) $(path)[0] run data modify storage macro:output result set value 0b\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/pop ","color":"aqua"},{"text":"$(storage):$(path)","color":"white"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/nbt/internal/swap_exec.mcfunction', '# macro:systems/nbt/internal/swap_exec [MACRO]\n# INPUT: $(storage), $(path_a), $(path_b)\n\n$data modify storage macro:engine _nbt_swap set from storage $(storage) $(path_a)\n$data modify storage $(storage) $(path_a) set from storage $(storage) $(path_b)\n$data modify storage $(storage) $(path_b) set from storage macro:engine _nbt_swap\ndata remove storage macro:engine _nbt_swap\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"nbt/swap ","color":"aqua"},{"text":"$(path_a)","color":"white"},{"text":" ↔ ","color":"#555555"},{"text":"$(path_b)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/check.mcfunction', '# macro:systems/rate_limit/check — Sliding window check + consume [MACRO]\n#\n# The core API call. Checks whether the key is under its configured limit\n# for the current sliding window, then records this hit.\n#\n# Output → macro:output result\n# 1b = ALLOWED (hit was recorded, call may proceed)\n# 0b = DENIED (limit reached, hit NOT recorded)\n#\n# Usage:\n# function macro:systems/rate_limit/check {key:"global:my_event"}\n# execute if data storage macro:output {result:1b} run function my_ns:do_thing\n#\n# For per-player (build key in caller):\n#   $function macro:systems/rate_limit/check {key:"player:shop:$(player)"}\n#\n# Rule must be pre-registered via macro:systems/rate_limit/config.\n# If no rule exists for the key → ALLOWED (fail-open; log warning).\n\ndata modify storage macro:output result set value 1b\n\n# Guard: rule must exist — try auto-create from player template first\n# Key format "player:<tpl>:<name>" → tpl is the second segment\n# We attempt player_ensure unconditionally; it exits early if not a player key or no template\n$data modify storage macro:rl_work ensure_key set value "$(key)"\nfunction macro:systems/rate_limit/internal/player_check with storage macro:rl_work\n\n$execute unless data storage macro:engine rate_limit.rules.$(key) run function macro:systems/rate_limit/internal/no_rule\n$execute unless data storage macro:engine rate_limit.rules.$(key) run return 0\n\n# Copy rule into work storage with key context\n$data modify storage macro:rl_work rule set from storage macro:engine rate_limit.rules.$(key)\n$data modify storage macro:rl_work rule.key set value "$(key)"\n\n# Run the sliding window evaluation\nfunction macro:systems/rate_limit/internal/evaluate with storage macro:rl_work rule\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/config.mcfunction', '# macro:systems/rate_limit/config — Register or update a rate limit rule [MACRO]\n#\n# Creates or replaces a sliding window rule for any key.\n# Rules survive reloads because they live in macro:engine storage.\n#\n# Usage:\n# function macro:systems/rate_limit/config {key:"global:my_event",limit:5,window:100}\n# function macro:systems/rate_limit/config {key:"player:Steve:shop",limit:3,window:600}\n# function macro:systems/rate_limit/config {key:"channel:admin_systems",limit:10,window:20}\n#\n# Fields:\n# key (string) — unique rule identifier; convention:\n# "global:<name>" → server-wide shared bucket\n#                     "player:<name>:<player>" → per-player bucket (use $(player))\n# "channel:<id>" → tick-channel guard\n# limit (int) — max number of hits allowed inside the window\n# window (int) — sliding window width in ticks (20 = 1 second)\n#\n# Removing a rule: function macro:systems/rate_limit/delete {key:"..."}\n# Listing rules: function macro:systems/rate_limit/list\n\n$data modify storage macro:engine rate_limit.rules.$(key) set value {limit:$(limit),window:$(window),hits:[]}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"rate_limit/config ","color":"aqua"},{"text":"→ ","color":"#555555"},{"text":"$(key)","color":"white"},{"text":" limit=","color":"#555555"},{"text":"$(limit)","color":"green"},{"text":" window=","color":"#555555"},{"text":"$(window)","color":"green"},{"text":"t","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/channel/check.mcfunction', '# macro:systems/rate_limit/channel/check — Per-channel rate guard [MACRO]\n#\n# Prevents a tick channel\'s function from running too frequently even if\n# the channel itself fires every tick. Place at the TOP of the channel function.\n#\n# Usage (inside your channel function):\n# function macro:systems/rate_limit/channel/check {id:"my_channel"}\n# execute if data storage macro:output {result:0b} run return 0\n# # ... rest of channel logic\n#\n# Rule must be registered via:\n# function macro:systems/rate_limit/channel/config {id:"my_channel",limit:5,window:20}\n#\n# Output → macro:output result 1b=ALLOWED 0b=DENIED\n\n$function macro:systems/rate_limit/check {key:"channel:$(id)"}\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/global/check.mcfunction', '# macro:systems/rate_limit/global/check — Global sliding window check [MACRO]\n#\n# Convenience wrapper for global (server-wide) rate limits.\n# All players share the same bucket under this key.\n#\n# Usage:\n# function macro:systems/rate_limit/global/check {key:"boss_spawn"}\n#\n# Rule must be registered via:\n# function macro:systems/rate_limit/global/config {key:"boss_spawn",limit:1,window:24000}\n#\n# Output → macro:output result 1b=ALLOWED 0b=DENIED\n\n$function macro:systems/rate_limit/check {key:"global:$(key)"}\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/global/config.mcfunction', '# macro:systems/rate_limit/global/config — Register a global (server-wide) rate limit [MACRO]\n#\n# Usage:\n# function macro:systems/rate_limit/global/config {key:"boss_spawn",limit:1,window:24000}\n#\n# Equivalent to:\n# function macro:systems/rate_limit/config {key:"global:boss_spawn",limit:1,window:24000}\n\n$function macro:systems/rate_limit/config {key:"global:$(key)",limit:$(limit),window:$(window)}\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/internal/evaluate.mcfunction', '# macro:systems/rate_limit/internal/evaluate — Sliding window core [MACRO]\n# Input: $(key), $(limit), $(window), $(hits) (array, not used directly here)\n#\n# Algorithm:\n# 1. Get current epoch tick\n# 2. Compute window start = epoch - window + 1\n# 3. Prune hits older than window start → stored as macro:engine rate_limit.rules.<key>.hits\n# 4. Count remaining hits\n# 5. If count < limit → record new hit, return ALLOWED\n# 6. Else → return DENIED (do NOT record hit)\n\n# Step 1: capture current epoch + compute window boundary\nexecute store result score $rl_now macro.tmp run scoreboard players get $epoch macro.time\n$scoreboard players set $rl_win macro.tmp $(window)\nscoreboard players operation $rl_start macro.tmp = $rl_now macro.tmp\nscoreboard players operation $rl_start macro.tmp -= $rl_win macro.tmp\nscoreboard players add $rl_start macro.tmp 1\n\n# Step 2: write boundary into work storage for the pruner macro\nexecute store result storage macro:rl_work prune_before int 1 run scoreboard players get $rl_start macro.tmp\n\n# Step 3: prune expired hits (hits[i].t < prune_before)\n# We do this by rebuilding the hits list via internal/prune\n$data modify storage macro:rl_work rule_key set value "$(key)"\nfunction macro:systems/rate_limit/internal/prune with storage macro:rl_work\n\n# Step 4: count surviving hits\n$execute store result score $rl_count macro.tmp run data get storage macro:engine rate_limit.rules.$(key).hits\n\n# Step 5: compare against limit\n$scoreboard players set $rl_limit macro.tmp $(limit)\n\n# DENIED path — limit reached\nexecute if score $rl_count macro.tmp >= $rl_limit macro.tmp run data modify storage macro:output result set value 0b\nexecute if score $rl_count macro.tmp >= $rl_limit macro.tmp run return 0\n\n# ALLOWED path — append new hit timestamp\nexecute store result storage macro:rl_work new_hit.t int 1 run scoreboard players get $rl_now macro.tmp\n$data modify storage macro:engine rate_limit.rules.$(key).hits append from storage macro:rl_work new_hit\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"rate_limit ","color":"aqua"},{"text":"ALLOW ","color":"#55FF55"},{"text":"$(key)","color":"white"},{"text":" (","color":"#555555"},{"score":{"name":"$rl_count","objective":"macro.tmp"},"color":"green"},{"text":"+1/","color":"#555555"},{"text":"$(limit)","color":"green"},{"text":")","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/internal/no_rule.mcfunction', '# macro:systems/rate_limit/internal/no_rule — Warn when check called on unregistered key [MACRO]\n# Input: $(key)\n# Fail-open: result stays 1b (ALLOWED) so callers aren\'t broken by missing config.\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"rate_limit/check ","color":"aqua"},{"text":"WARN ","color":"#FFAA00"},{"text":"no rule for key: ","color":"#555555"},{"text":"$(key)","color":"#FF5555"},{"text":" — fail-open","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/internal/player_check.mcfunction', '# macro:systems/rate_limit/internal/player_check — Auto-ensure player bucket if needed [MACRO]\n# Input: $(ensure_key) — the full compound key from check\n#\n# Only acts when:\n# 1. Key starts with "player:" (checked via NBT string prefix match workaround)\n# 2. No rule exists yet for that key\n# 3. A player_template exists for the base key portion\n#\n# Since we can\'t do string operations in mcfunction, we use a two-pass approach:\n# player/check wrapper sets both $(key) and $(tpl) explicitly, so\n# this file is only reached from the generic check path.\n# In that case, just check if rule exists and exit if it does.\n\n$execute if data storage macro:engine rate_limit.rules.$(ensure_key) run return 0\n\n# Rule absent. If this looks like a player key the wrapper already pre-seeded it.\n# Nothing more to do here — no_rule path handles the rest.\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/internal/player_ensure.mcfunction', '# macro:systems/rate_limit/internal/player_ensure — Auto-create player bucket from template [MACRO]\n# Called by check when rule key "player:<key>:<player>" doesn\'t exist yet.\n# Reads the template registered via rate_limit/player/config and creates the bucket.\n# Input: $(key) = full compound key e.g. "player:shop:Steve"\n#        $(tpl) = template key e.g. "shop"\n\n$execute unless data storage macro:engine rate_limit.player_templates.$(tpl) run return 0\n$data modify storage macro:engine rate_limit.rules.$(key) set from storage macro:engine rate_limit.player_templates.$(tpl)\n$data modify storage macro:engine rate_limit.rules.$(key).hits set value []\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"rate_limit ","color":"aqua"},{"text":"INIT ","color":"#55FFFF"},{"text":"bucket for ","color":"#555555"},{"text":"$(key)","color":"white"}]\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/internal/prune.mcfunction', '# macro:systems/rate_limit/internal/prune — Remove hits outside the sliding window [MACRO]\n# Input: $(rule_key), macro:rl_work.prune_before (int, from evaluate)\n#\n# Strategy: iterate hits array from index 0 upward.\n# Hits are appended in chronological order, so hits[0] is always the oldest.\n# We remove from the front until hits[0].t >= prune_before (or array empty).\n# This is O(expired_count) — optimal for a FIFO sliding window.\n\n$execute unless data storage macro:engine rate_limit.rules.$(rule_key).hits[0] run return 0\n\n# Read oldest hit timestamp\n$execute store result score $rl_oldest macro.tmp run data get storage macro:engine rate_limit.rules.$(rule_key).hits[0].t\n\n# If oldest hit is still inside window → nothing left to prune\nexecute if score $rl_oldest macro.tmp >= $rl_start macro.tmp run return 0\n\n# Oldest hit is expired → remove it and recurse\n$data remove storage macro:engine rate_limit.rules.$(rule_key).hits[0]\nfunction macro:systems/rate_limit/internal/prune with storage macro:rl_work\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/player/check.mcfunction', '# macro:systems/rate_limit/player/check — Per-player sliding window check [MACRO]\n#\n# Builds the compound key "player:<key>:<player>" and ensures the bucket exists.\n# If no bucket exists yet for this player, auto-creates from the player_template.\n#\n# Usage:\n#   $function macro:systems/rate_limit/player/check {key:"shop",player:"$(player)"}\n#\n# Rule template must be registered via:\n# function macro:systems/rate_limit/player/config {key:"shop",limit:3,window:600}\n#\n# Output → macro:output result 1b=ALLOWED 0b=DENIED\n\n# Auto-seed: if bucket for this player+key doesn\'t exist, create from template\n$execute unless data storage macro:engine "rate_limit.rules.player:$(key):$(player)" run function macro:systems/rate_limit/player/internal/ensure {tpl:"$(key)",full:"player:$(key):$(player)"}\n\n# Delegate to generic check with full compound key\n$function macro:systems/rate_limit/check {key:"player:$(key):$(player)"}\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/player/config.mcfunction', '# macro:systems/rate_limit/player/config — Register per-player rate limit rule [MACRO]\n#\n# Creates one template rule. The player bucket key is "player:<key>:<player>".\n# This function registers the TEMPLATE rule used for ALL players under this key.\n# Individual player buckets are auto-created on first check.\n#\n# Usage:\n# function macro:systems/rate_limit/player/config {key:"shop",limit:3,window:600}\n#\n# This allows: $function macro:systems/rate_limit/player/check {key:"shop",player:"$(player)"}\n#\n# Note: each player gets their own independent sliding window bucket.\n# To register a SHARED (global) rule use macro:systems/rate_limit/config directly.\n\n# Store template rule — concrete player buckets inherit limit+window on first hit\n$data modify storage macro:engine rate_limit.player_templates.$(key) set value {limit:$(limit),window:$(window)}\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"rate_limit/player/config ","color":"aqua"},{"text":"→ ","color":"#555555"},{"text":"player:$(key):<player>","color":"white"},{"text":" limit=","color":"#555555"},{"text":"$(limit)","color":"green"},{"text":" window=","color":"#555555"},{"text":"$(window)","color":"green"},{"text":"t","color":"#555555"}]\n'),
    ('./1_20_5/data/macro/functions/systems/rate_limit/player/internal/ensure.mcfunction', '# macro:systems/rate_limit/player/internal/ensure — Seed player bucket from template [MACRO]\n# Input: $(tpl), $(full)\n# Called only when bucket doesn\'t exist yet for this player.\n\n$execute unless data storage macro:engine rate_limit.player_templates.$(tpl) run return 0\n$data modify storage macro:engine "rate_limit.rules.$(full)" set from storage macro:engine rate_limit.player_templates.$(tpl)\n$data modify storage macro:engine "rate_limit.rules.$(full).hits" set value []\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"rate_limit ","color":"aqua"},{"text":"INIT ","color":"#55FFFF"},{"text":"player bucket: ","color":"#555555"},{"text":"$(full)","color":"white"}]\n'),
    ('./1_20_5/data/macro/functions/systems/string/announce.mcfunction', '$tellraw @a {"text":"$(message)","color":"$(color)"}\n'),
    ('./1_20_5/data/macro/functions/systems/string/announce_prefix.mcfunction', '$tellraw @a [{"text":"$(prefix) ","color":"$(prefix_color)","bold":true},{"text":"$(message)","color":"$(color)","bold":false}]\n'),
    ('./1_20_5/data/macro/functions/systems/string/format_number.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/string/format_number\n# Converts large numbers to readable abbreviations.\n#  Input : $(value) → integer\n# Output: macro:output text → abbreviated text (storage string)\n# macro:output value → original value\n# macro:output suffix → k / M / B / "" suffix\n# macro:output short → abbreviated integer part\n#\n# Examples:\n# 500 → "500"\n# 1500 → "1.5k"\n# 1000000 → "1M"\n# 2500000 → "2.5M"\n# 1000000000 → "1B"\n# ─────────────────────────────────────────────────────────────────\n\n$scoreboard players set $fn_v macro.tmp $(value)\nexecute store result storage macro:output value int 1 run scoreboard players get $fn_v macro.tmp\n\n# < 1000 → plain number\nexecute if score $fn_v macro.tmp matches ..999 run data modify storage macro:output suffix set value ""\nexecute if score $fn_v macro.tmp matches ..999 run execute store result storage macro:output short int 1 run scoreboard players get $fn_v macro.tmp\nexecute if score $fn_v macro.tmp matches ..999 run return 0\n\n# 1000 – 999999 → k\nexecute if score $fn_v macro.tmp matches 1000..999999 run data modify storage macro:output suffix set value "k"\nexecute if score $fn_v macro.tmp matches 1000..999999 run scoreboard players set $fn_div macro.tmp 100\nexecute if score $fn_v macro.tmp matches 1000..999999 run scoreboard players operation $fn_v macro.tmp /= $fn_div macro.tmp\nexecute if score $fn_v macro.tmp matches 1000..999999 run execute store result storage macro:output short int 1 run scoreboard players get $fn_v macro.tmp\nexecute if score $fn_v macro.tmp matches 1000..999999 run return 0\n\n# 1_000_000 – 999_999_999 → M\nexecute if score $fn_v macro.tmp matches 1000000..999999999 run data modify storage macro:output suffix set value "M"\nexecute if score $fn_v macro.tmp matches 1000000..999999999 run scoreboard players set $fn_div macro.tmp 100000\nexecute if score $fn_v macro.tmp matches 1000000..999999999 run scoreboard players operation $fn_v macro.tmp /= $fn_div macro.tmp\nexecute if score $fn_v macro.tmp matches 1000000..999999999 run execute store result storage macro:output short int 1 run scoreboard players get $fn_v macro.tmp\nexecute if score $fn_v macro.tmp matches 1000000..999999999 run return 0\n\n# >= 1_000_000_000 → B\nexecute if score $fn_v macro.tmp matches 1000000000.. run data modify storage macro:output suffix set value "B"\nexecute if score $fn_v macro.tmp matches 1000000000.. run scoreboard players set $fn_div macro.tmp 100000000\nexecute if score $fn_v macro.tmp matches 1000000000.. run scoreboard players operation $fn_v macro.tmp /= $fn_div macro.tmp\nexecute if score $fn_v macro.tmp matches 1000000000.. run execute store result storage macro:output short int 1 run scoreboard players get $fn_v macro.tmp\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/format_number ","color":"aqua"},{"text":"$(value) → ","color":"gray"},{"storage":"macro:output","nbt":"short","color":"green"},{"storage":"macro:output","nbt":"suffix","color":"green"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/string/format_ticks.mcfunction', '$scoreboard players set $ft_t macro.tmp $(ticks)\n\nscoreboard players set $ft_20 macro.tmp 20\nscoreboard players operation $ft_s macro.tmp = $ft_t macro.tmp\nscoreboard players operation $ft_s macro.tmp /= $ft_20 macro.tmp\n\nexecute store result storage macro:output total_seconds int 1 run scoreboard players get $ft_s macro.tmp\n\nscoreboard players set $ft_60 macro.tmp 60\nscoreboard players operation $ft_m macro.tmp = $ft_s macro.tmp\nscoreboard players operation $ft_m macro.tmp /= $ft_60 macro.tmp\n\nscoreboard players operation $ft_s macro.tmp %= $ft_60 macro.tmp\n\nexecute store result storage macro:output minutes int 1 run scoreboard players get $ft_m macro.tmp\nexecute store result storage macro:output seconds int 1 run scoreboard players get $ft_s macro.tmp\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/format_ticks ","color":"aqua"},{"text":"$(ticks)t","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"minutes","color":"green"},{"text":"m ","color":"#555555"},{"storage":"macro:output","nbt":"seconds","color":"green"},{"text":"s","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/string/header.mcfunction', '$tellraw $(target) [{"text":"◆── ","color":"$(color)"},{"text":"$(text)","color":"$(color)","bold":true},{"text":" ──◆","color":"$(color)"}]\n'),
    ('./1_20_5/data/macro/functions/systems/string/hover_text.mcfunction', '$tellraw $(target) {"text":"$(text)","color":"$(color)","hoverEvent":{"action":"show_text","contents":{"text":"$(hover)","color":"$(hover_color)"}}}\n'),
    ('./1_20_5/data/macro/functions/systems/string/ordinal.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/string/ordinal\n# Determines the English ordinal suffix for a positive integer.\n# Handles the 11th/12th/13th exception correctly.\n#\n#  Input : $(n) → positive integer (1-based)\n# Output: macro:output n → original value (int)\n# macro:output suffix → "st" / "nd" / "rd" / "th"\n#\n# To display "3rd place" in chat:\n# function macro:systems/string/ordinal {n:3}\n# tellraw @a ["",\n# {"storage":"macro:output","nbt":"n"},\n# {"storage":"macro:output","nbt":"suffix","color":"gold"},\n# {"text":" place"}]\n#\n# Examples:\n# {n:1} → suffix="st" {n:11} → suffix="th"\n# {n:2} → suffix="nd" {n:12} → suffix="th"\n# {n:3} → suffix="rd" {n:13} → suffix="th"\n# {n:4} → suffix="th" {n:21} → suffix="st"\n# {n:22} → suffix="nd" {n:103}→ suffix="rd"\n# ─────────────────────────────────────────────────────────────────\n\n$scoreboard players set $ord_n macro.tmp $(n)\nexecute store result storage macro:output n int 1 run scoreboard players get $ord_n macro.tmp\n\n# last-two-digits mod 100 (teen detection)\nscoreboard players operation $ord_h macro.tmp = $ord_n macro.tmp\nscoreboard players set $ord_100 macro.tmp 100\nscoreboard players operation $ord_h macro.tmp %= $ord_100 macro.tmp\n\n# last digit mod 10 (suffix selection)\nscoreboard players operation $ord_d macro.tmp = $ord_n macro.tmp\nscoreboard players set $ord_10 macro.tmp 10\nscoreboard players operation $ord_d macro.tmp %= $ord_10 macro.tmp\n\n# Default: th\ndata modify storage macro:output suffix set value "th"\n\n# Apply last-digit rules\nexecute if score $ord_d macro.tmp matches 1 run data modify storage macro:output suffix set value "st"\nexecute if score $ord_d macro.tmp matches 2 run data modify storage macro:output suffix set value "nd"\nexecute if score $ord_d macro.tmp matches 3 run data modify storage macro:output suffix set value "rd"\n\n# Teen override — 11, 12, 13 must always be "th"\nexecute if score $ord_h macro.tmp matches 11..13 run data modify storage macro:output suffix set value "th"\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/ordinal ","color":"aqua"},{"text":"$(n)","color":"white"},{"text":" → ","color":"#555555"},{"storage":"macro:output","nbt":"suffix","color":"green"}]\n'),
    ('./1_20_5/data/macro/functions/systems/string/pad_left.mcfunction', '$scoreboard players set $pl_v macro.tmp $(value)\n$scoreboard players set $pl_w macro.tmp $(width)\n\nscoreboard players set $pl_neg macro.tmp -1\nexecute if score $pl_v macro.tmp matches ..-1 run scoreboard players operation $pl_v macro.tmp *= $pl_neg macro.tmp\n\nscoreboard players set $pl_digits macro.tmp 1\nexecute if score $pl_v macro.tmp matches 10.. run scoreboard players set $pl_digits macro.tmp 2\nexecute if score $pl_v macro.tmp matches 100.. run scoreboard players set $pl_digits macro.tmp 3\nexecute if score $pl_v macro.tmp matches 1000.. run scoreboard players set $pl_digits macro.tmp 4\nexecute if score $pl_v macro.tmp matches 10000.. run scoreboard players set $pl_digits macro.tmp 5\nexecute if score $pl_v macro.tmp matches 100000.. run scoreboard players set $pl_digits macro.tmp 6\nexecute if score $pl_v macro.tmp matches 1000000.. run scoreboard players set $pl_digits macro.tmp 7\nexecute if score $pl_v macro.tmp matches 10000000.. run scoreboard players set $pl_digits macro.tmp 8\n\nscoreboard players operation $pl_pad macro.tmp = $pl_w macro.tmp\nscoreboard players operation $pl_pad macro.tmp -= $pl_digits macro.tmp\n\ndata modify storage macro:output result set value ""\n\nexecute if score $pl_pad macro.tmp matches 1.. run data modify storage macro:output result set value "0"\nexecute if score $pl_pad macro.tmp matches 2.. run data modify storage macro:output result set value "00"\nexecute if score $pl_pad macro.tmp matches 3.. run data modify storage macro:output result set value "000"\nexecute if score $pl_pad macro.tmp matches 4.. run data modify storage macro:output result set value "0000"\nexecute if score $pl_pad macro.tmp matches 5.. run data modify storage macro:output result set value "00000"\nexecute if score $pl_pad macro.tmp matches 6.. run data modify storage macro:output result set value "000000"\nexecute if score $pl_pad macro.tmp matches 7.. run data modify storage macro:output result set value "0000000"\n\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/pad_left ","color":"aqua"},{"text":"$(value) w=$(width) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"},{"text":"[NUM]","color":"#555555"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/string/player_raw.mcfunction', '$tellraw $(target) $(json)\n'),
    ('./1_20_5/data/macro/functions/systems/string/pluralize.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/string/pluralize\n# Stores the singular or plural form of a word based on count.\n# Simple English rule: count == 1 → singular, else → plural.\n#\n# INPUT : $(count)    → integer count\n#         $(singular) → singular form (e.g. "item")\n#         $(plural)   → plural form   (e.g. "items")\n# OUTPUT: macro:output result → chosen string\n# macro:output count → original count\n#\n# EXAMPLE:\n# function macro:systems/string/pluralize {count:3,singular:"apple",plural:"apples"}\n# → macro:output result = "apples"\n# ─────────────────────────────────────────────────────────────────\n\n$scoreboard players set #plr_c macro.tmp $(count)\nexecute store result storage macro:output count int 1 run scoreboard players get #plr_c macro.tmp\n\n$data modify storage macro:engine _plr_singular set value $(singular)\n$data modify storage macro:engine _plr_plural set value $(plural)\n\ndata modify storage macro:output result set from storage macro:engine _plr_plural\nexecute if score #plr_c macro.tmp matches 1 run data modify storage macro:output result set from storage macro:engine _plr_singular\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/pluralize ","color":"aqua"},{"text":"count=$(count) → ","color":"gray"},{"storage":"macro:output","nbt":"result","color":"green"}]\n'),
    ('./1_20_5/data/macro/functions/systems/string/progress_bar.mcfunction', '$scoreboard players set $pb1_seg macro.tmp $(current)\n$scoreboard players set $pb1_max macro.tmp $(max)\n\nexecute if score $pb1_max macro.tmp matches ..0 run return fail\n\nscoreboard players set $pb1_ten macro.tmp 10\nscoreboard players operation $pb1_seg macro.tmp *= $pb1_ten macro.tmp\nscoreboard players operation $pb1_seg macro.tmp /= $pb1_max macro.tmp\n\nexecute if score $pb1_seg macro.tmp matches ..0 run scoreboard players set $pb1_seg macro.tmp 0\nexecute if score $pb1_seg macro.tmp matches 10.. run scoreboard players set $pb1_seg macro.tmp 10\n\n$execute if score $pb1_seg macro.tmp matches 0 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) ░░░░░░░░░░"}\n$execute if score $pb1_seg macro.tmp matches 1 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) █░░░░░░░░░"}\n$execute if score $pb1_seg macro.tmp matches 2 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) ██░░░░░░░░"}\n$execute if score $pb1_seg macro.tmp matches 3 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) ███░░░░░░░"}\n$execute if score $pb1_seg macro.tmp matches 4 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) ████░░░░░░"}\n$execute if score $pb1_seg macro.tmp matches 5 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) █████░░░░░"}\n$execute if score $pb1_seg macro.tmp matches 6 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) ██████░░░░"}\n$execute if score $pb1_seg macro.tmp matches 7 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) ███████░░░"}\n$execute if score $pb1_seg macro.tmp matches 8 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) ████████░░"}\n$execute if score $pb1_seg macro.tmp matches 9 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) █████████░"}\n$execute if score $pb1_seg macro.tmp matches 10 run title @a[name=$(player),limit=1] actionbar {"text":"$(label) ██████████"}\n$tellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/progress_bar ","color":"aqua"},{"text":"$(player)","color":"white"},{"text":" → ","color":"#555555"},{"text":"$(label)","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/string/progress_bar_self.mcfunction', '$scoreboard players set $pbs_max macro.tmp $(pb_max)\nexecute if score $pbs_max macro.tmp matches ..0 run return fail\n\n$execute store result score $pbs_seg macro.tmp run scoreboard players get @s $(pb_obj)\n\nscoreboard players set $pbs_ten macro.tmp 10\nscoreboard players operation $pbs_seg macro.tmp *= $pbs_ten macro.tmp\nscoreboard players operation $pbs_seg macro.tmp /= $pbs_max macro.tmp\n\nexecute if score $pbs_seg macro.tmp matches ..0 run scoreboard players set $pbs_seg macro.tmp 0\nexecute if score $pbs_seg macro.tmp matches 10.. run scoreboard players set $pbs_seg macro.tmp 10\n\n$execute if score $pbs_seg macro.tmp matches 0 run title @s actionbar {"text":"$(pb_label) ░░░░░░░░░░"}\n$execute if score $pbs_seg macro.tmp matches 1 run title @s actionbar {"text":"$(pb_label) █░░░░░░░░░"}\n$execute if score $pbs_seg macro.tmp matches 2 run title @s actionbar {"text":"$(pb_label) ██░░░░░░░░"}\n$execute if score $pbs_seg macro.tmp matches 3 run title @s actionbar {"text":"$(pb_label) ███░░░░░░░"}\n$execute if score $pbs_seg macro.tmp matches 4 run title @s actionbar {"text":"$(pb_label) ████░░░░░░"}\n$execute if score $pbs_seg macro.tmp matches 5 run title @s actionbar {"text":"$(pb_label) █████░░░░░"}\n$execute if score $pbs_seg macro.tmp matches 6 run title @s actionbar {"text":"$(pb_label) ██████░░░░"}\n$execute if score $pbs_seg macro.tmp matches 7 run title @s actionbar {"text":"$(pb_label) ███████░░░"}\n$execute if score $pbs_seg macro.tmp matches 8 run title @s actionbar {"text":"$(pb_label) ████████░░"}\n$execute if score $pbs_seg macro.tmp matches 9 run title @s actionbar {"text":"$(pb_label) █████████░"}\n$execute if score $pbs_seg macro.tmp matches 10 run title @s actionbar {"text":"$(pb_label) ██████████"}\ntellraw @a[tag=macro.debug] {"text":"","extra":[{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/progress_bar_self ","color":"aqua"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/string/repeat.mcfunction', '# macro:systems/string/repeat\n# Repeats a single character (char) exactly `count` times (1–16).\n# Params: char (single character), count (integer 1–16)\n# Output: macro:output result = repeated string\n# Note: count is clamped to 1–16. Larger repeats should be assembled by the caller.\n#\n# Implementation: static dispatch to internal/repeat_N which sets the literal string.\n# Each internal file uses a single $data modify line with N $(char) expansions.\n\ndata modify storage macro:output result set value ""\n\n$scoreboard players set $sr_n macro.tmp $(count)\nexecute if score $sr_n macro.tmp matches ..0 run scoreboard players set $sr_n macro.tmp 1\nexecute if score $sr_n macro.tmp matches 17.. run scoreboard players set $sr_n macro.tmp 16\n\nexecute if score $sr_n macro.tmp matches 1 run function macro:systems/string/internal/repeat_1 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 2 run function macro:systems/string/internal/repeat_2 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 3 run function macro:systems/string/internal/repeat_3 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 4 run function macro:systems/string/internal/repeat_4 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 5 run function macro:systems/string/internal/repeat_5 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 6 run function macro:systems/string/internal/repeat_6 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 7 run function macro:systems/string/internal/repeat_7 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 8 run function macro:systems/string/internal/repeat_8 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 9 run function macro:systems/string/internal/repeat_9 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 10 run function macro:systems/string/internal/repeat_10 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 11 run function macro:systems/string/internal/repeat_11 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 12 run function macro:systems/string/internal/repeat_12 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 13 run function macro:systems/string/internal/repeat_13 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 14 run function macro:systems/string/internal/repeat_14 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 15 run function macro:systems/string/internal/repeat_15 with storage macro:input {}\nexecute if score $sr_n macro.tmp matches 16 run function macro:systems/string/internal/repeat_16 with storage macro:input {}\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/repeat ","color":"aqua"},{"text":"\'$(char)\'","color":"yellow"},{"text":" × $(count) → ","color":"#555555"},{"storage":"macro:output","nbt":"result","color":"white"}]\n'),
    ('./1_20_5/data/macro/functions/systems/string/score_display.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/string/score_display\n# Sends a formatted label: value line from a scoreboard objective.\n#  Input : $(target)    → selector to receive the message\n#          $(label)     → display label (e.g. "Points")\n#          $(player)    → scoreboard player name (e.g. "@s", "IronCrest")\n#          $(objective) → scoreboard objective name\n#          $(color)     → value color (e.g. "green", "gold")\n#\n# Example:\n# data modify storage macro:input target set value "@s"\n# data modify storage macro:input label set value "Points"\n# data modify storage macro:input player set value "@s"\n# data modify storage macro:input objective set value "myPoints"\n# data modify storage macro:input color set value "green"\n# function macro:systems/string/score_display with storage macro:input {}\n# # Output: "Points 42" (42 from scoreboard)\n# ─────────────────────────────────────────────────────────────────\n\n$tellraw $(target) {"text":"","extra":[{"text":"$(label)","color":"gray"},{"text":"  ","color":"#555555"},{"score":{"name":"$(player)","objective":"$(objective)"},"color":"$(color)","bold":true}]}\n'),
    ('./1_20_5/data/macro/functions/systems/string/separator.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/string/separator\n# Sends a decorative horizontal separator line.\n#  Input : $(target) → selector\n#          $(color)  → line color (e.g. "gray", "aqua", "#555555")\n#          $(label)  → optional center label (use "" for plain line)\n#\n# Example (plain line):\n# data modify storage macro:input target set value "@s"\n# data modify storage macro:input color set value "gray"\n# data modify storage macro:input label set value ""\n# function macro:systems/string/separator with storage macro:input {}\n#\n# Example (labeled):\n# data modify storage macro:input label set value " Settings "\n# function macro:systems/string/separator with storage macro:input {}\n# ─────────────────────────────────────────────────────────────────\n\n$tellraw $(target) {"text":"","extra":[{"text":"──────────","color":"$(color)"},{"text":"$(label)","color":"$(color)","bold":true},{"text":"──────────","color":"$(color)"}]}\n'),
    ('./1_20_5/data/macro/functions/systems/string/tag_badge.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/string/tag_badge\n# Sends a styled [TAG] badge with optional hover text.\n#  Input : $(target)     → selector\n#          $(tag)        → badge label (e.g. "ADMIN", "VIP")\n#          $(color)      → badge color (e.g. "red", "gold")\n#          $(hover)      → hover tooltip text\n#\n# Example:\n# data modify storage macro:input target set value "@s"\n# data modify storage macro:input tag set value "ADMIN"\n# data modify storage macro:input color set value "red"\n# data modify storage macro:input hover set value "Server Administrator"\n# function macro:systems/string/tag_badge with storage macro:input {}\n# ─────────────────────────────────────────────────────────────────\n\n$tellraw $(target) {"text":"","extra":[{"text":"[","color":"#555555","bold":false},{"text":"$(tag)","color":"$(color)","bold":true,"hoverEvent":{"action":"show_text","contents":{"text":"$(hover)","color":"gray","italic":true}}},{"text":"]","color":"#555555","bold":false}]}\n'),
    ('./1_20_5/data/macro/functions/systems/string/tooltip_item.mcfunction', '$tellraw $(target) {"text":"$(text)","color":"$(color)","hoverEvent":{"action":"show_item","contents":{"id":"$(item)","count":1}}}\n'),
    ('./1_20_5/data/macro/functions/systems/string/truncate.mcfunction', '# ─────────────────────────────────────────────────────────────────\n# macro:systems/string/truncate\n# Displays text in the named player\'s actionbar, optionally with a\n# suffix to indicate truncation. The caller decides whether the text\n# needs truncating and passes truncated:1b or truncated:0b.\n# Because mcfunction cannot measure string byte-length at runtime,\n# length-checking must be done externally.\n#\n# INPUT : $(player)    → player name\n#         $(text)      → string to display\n#         $(suffix)    → suffix shown when truncated (e.g. "...")\n#         $(truncated) → 1b = append suffix, 0b = show as-is\n# OUTPUT: macro:output text → stored original text\n#\n# EXAMPLE:\n# function macro:systems/string/truncate {player:"Steve",text:"Hello Wor",suffix:"...",truncated:1b}\n# → actionbar: "Hello Wor..."\n# ─────────────────────────────────────────────────────────────────\n\n$data modify storage macro:output text set value $(text)\n$data modify storage macro:engine _trunc_t set value $(truncated)\n\nscoreboard players set #trunc_flag macro.tmp 0\nexecute store result score #trunc_flag macro.tmp run data get storage macro:engine _trunc_t\n\n$execute if score #trunc_flag macro.tmp matches 0 run title @a[name=$(player),limit=1] actionbar {"storage":"macro:output","nbt":"text"}\n$execute if score #trunc_flag macro.tmp matches 1.. run title @a[name=$(player),limit=1] actionbar ["",{"storage":"macro:output","nbt":"text"},{"text":"$(suffix)","color":"gray"}]\n\n$tellraw @a[tag=macro.debug] ["",{"text":"[AME] ","color":"#00AAAA","bold":true},{"text":"string/truncate ","color":"aqua"},{"text":"$(player) truncated=$(truncated)","color":"gray"}]\n'),
    ('./1_20_5/data/macro/functions/systems/string/internal/repeat_1.mcfunction', '$data modify storage macro:output result set value "$(char)"\n'),
    ('./1_20_5/data/macro/functions/systems/string/internal/repeat_10.mcfunction', '$data modify storage macro:output result set value "$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)"\n'),
