    ('./1_20_5/data/macro/functions/systems/string/internal/repeat_13.mcfunction', '$data modify storage macro:output result set value "$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)"\n'),
