    ('./1_20_5/data/macro/functions/systems/string/internal/repeat_16.mcfunction', '$data modify storage macro:output result set value "$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)$(char)"\n'),
    ('./1_20_5/data/macro/functions/systems/string/internal/repeat_2.mcfunction', '$data modify storage macro:output result set value "$(char)$(char)"\n'),
    ('./1_20_5/data/macro/functions/systems/string/internal/repeat_3.mcfunction', '$data modify storage macro:output result set value "$(char)$(char)$(char)"\n'),
    ('./1_20_5/data/macro/functions/systems/string/internal/repeat_4.mcfunction', '$data modify storage macro:output result set value "$(char)$(char)$(char)$(char)"\n'),
